KinectDrawThread::KinectDrawThread(MainWindow* mw)
{
	mWindow = mw;
}
//-----------------------------
void KinectDrawThread::run()
{
	while (!isInterruptionRequested())
	{
		// Throttle the loop when Kinect is disabled or Stop is checked.
		if (!mWindow || !mWindow->kinect2Init || !mWindow->kinectEnabled ||
			(mWindow->GUIPanel && mWindow->GUIPanel->kinectOptionsCheckBox[7]->isChecked()))
		{
			QThread::msleep(50);
			continue;
		}

		SlotDrawKinectDepthMap();
		QThread::msleep(1);
	};
}
//----------------------
KinectDraw3DThread::KinectDraw3DThread(MainWindow* mw)
{
	mWindow = mw;
}
//-----------------------------
void KinectDraw3DThread::run()
{
	while (!isInterruptionRequested())
	{
		SlotRenderKinectDepthMap();
		int tt = mWindow->VWidget->Renderer->GetLastRenderTimeInSeconds() * 1000.0;
		//cout << tt;
		if (tt < 10)
			msleep(10);
		else
			msleep(tt);
	}
}
