//----------------------------------
void MainWindow::SlotShowMessage(const QString& Message)
{





	QString text = Message;

	if (Message.length() > 0)
	{
		if (text[0] == '&')
		{
			text.remove(0, 1);
			text = MessageText + text;
		}

		statBar->showMessage(text);
		MessageText = text;
	}

	//this->update();
	if (showMessageProcessEvents == true)
		QCoreApplication::processEvents();

}
//------------------------------------------------
void MainWindow::SlotShowMessage2(const QString& Message)
{

	QString text = Message;

	if (Message.length() > 0)
	{
		if (text[0] == '&')
		{
			text.remove(0, 1);
			text = MessageText + text;
		}

		statBar->showMessage(text);
		MessageText = text;
	}


}
