void CameraDrawThread::run()
{
	while (1)
	{
		SlotDrawCameraImage();
		int tt = mWindow->VWidget->Renderer->GetLastRenderTimeInSeconds() * 1000.0;
		//cout << tt;
		if (tt < 10)
			msleep(10);
		else
			msleep(tt);
	};

	/*while (1)
	{
	SlotDrawCameraImage();
	msleep(10);
	};*/
}
