{
	mWindow->slotCameraCaptureFrame();
}
//-------------------------------------
void	MainWindow::slotProcessCapturedImage(int requestId, const QImage& img)
{


	//qDebug("BB");
	if (VWidget != NULL)
	{
		if (VWidget->bckgRenderer == true)
		{

			//mogę przerzucić klatkę na tło
			qDebug("BB");
			//get image

			int w = img.width();
			int h = img.height();
			int newSize = w * h;
			if (VWidget->imageActor != NULL)
			{
				int ss[3];
				///	VWidget->imageActor->GetInput()->GetDimensions(ss);
				VWidget->imageData->GetDimensions(ss);

				int oldSize = ss[0] * ss[1];

				int x = VWidget->imageData->GetNumberOfScalarComponents();
				if (oldSize != newSize)
				{
					VWidget->imageData = vtkSmartPointer<vtkImageData>::New();
					VWidget->imageData->SetDimensions(w, h, 1);
					VWidget->imageData->AllocateScalars(VTK_UNSIGNED_CHAR, 3);//rgba

					VWidget->imageActor->SetInputData(VWidget->imageData);

				}
				//img.save("d:\\a.png");
				unsigned char* imageVtkBits = (unsigned char*)(VWidget->imageData->GetScalarPointer());
				unsigned char* imageQtBits = (unsigned char*)img.bits();

				if (GUIPanel->kinectOptionsCheckBox[8]->isChecked() == true)
				{
					int step1 = 0;
					int	step2 = 0;// (w* (h - 1)) * 3;
					for (int j = 0; j < h; j++)
					{
						for (int i = 0; i < w; i++)
						{
							imageVtkBits[step2 + 2] = imageQtBits[step1++];
							imageVtkBits[step2 + 1] = imageQtBits[step1++];
							imageVtkBits[step2] = imageQtBits[step1++];
							step2 += 3;
							step1++;
						}
						//step2 -= (2 * w) * 3;
					}
				}
				else
				{
					int step1 = 0;
					int	step2 = (w * (h - 1)) * 3;
					for (int j = 0; j < h; j++)
					{
						for (int i = 0; i < w; i++)
						{
							imageVtkBits[step2 + 2] = imageQtBits[step1++];
							imageVtkBits[step2 + 1] = imageQtBits[step1++];
							imageVtkBits[step2] = imageQtBits[step1++];
							step2 += 3;
							step1++;
						}
						step2 -= (2 * w) * 3;
					}
				}
				VWidget->imageData->Modified();


				double extent[4] = { 0, w, 0, h };
				double spacing[2] = { 1, 1 };
				double origin[2] = { 0, 0 };


				vtkCamera* cam = VWidget->backgroundRenderer->GetActiveCamera();

				double xc = origin[0] + 0.5 * (extent[0] + extent[1]) * spacing[0];
				double yc = origin[1] + 0.5 * (extent[2] + extent[3]) * spacing[1];

				double yd = (extent[3] - extent[2] + 1) * spacing[1];
				double d = cam->GetDistance();



				double zoom = (GUIPanel->kinectSlider[8]->value() - 5000) * 0.001;//10000

				cam->SetParallelScale(0.5 * yd * zoom);
				cam->SetFocalPoint(xc, yc, 0.0);
				cam->SetPosition(xc, yc, d);


				/*	double exp = GUIPanel->kinectSlider[9]->value() *0.001;
				double focus = GUIPanel->kinectSlider[10]->value() *0.001;
				double wb = GUIPanel->kinectSlider[11]->value() *0.001;

				camera->searchAndLock(QCamera::NoLock);
				camera->exposure()->setExposureCompensation(exp*0.5);

				bool xx = camera->focus()->isFocusModeSupported(QCameraFocus::ManualFocus);
				bool yy = camera->exposure()->isExposureModeSup*/
				//VWidget->imageMapper->Modified();
				//VWidget->imageMapper->Update();

				////	VWidget->imageActor->SetInputData(VWidget->imageData);
				//	VWidget->imageActor->SetVisibility(1);
				VWidget->Interactor->update();

			}

		}
	}


}
//-------------------

void	MainWindow::slotCameraCaptureFrame()
{
	if (VWidget != NULL)
	{
		if (VWidget->bckgRenderer == true)
		{
			if (imageCapture != NULL)
			{
				if ((imageCapture->isReadyForCapture()))
				{

					imageCapture->capture();
					qDebug("AA");
				}

			}
		}
	}
}
