	{
		QDir rDir(progDirPath);
		if (rDir.cd("prop"))
		{

			unsigned char cTab[768];
			int ii;
			QString text = "";
			QString TMP;

			rDir.setFilter(QDir::Files | QDir::Hidden | QDir::NoSymLinks);

			QStringList filters;
			filters << "*.act";
			rDir.setNameFilters(filters);

			QFileInfoList list = rDir.entryInfoList();
			//	QFileInfoListIterator it2( list.begin() );
			QListIterator<QFileInfo> it2(list);
			QFileInfo fi;
			int count = rDir.count();

			while (it2.hasNext())
				//for(it2=list.begin();it2!=list.end();++it2)
			{
				fi = it2.next();
				//	fi=*it2;
				text = fi.fileName();
				QString filename = rDir.absolutePath() + "/" + text;
				QFile file(filename);
				PalNames[_PalNr] = text;
				if (file.open(QIODevice::ReadOnly))
				{
					//QByteArray *b= QByteArray::fromRawData(PalTab,768*71);
					file.read((char*)(cTab), 768);

					file.close();


					for (int i = 0; i < 256; i++)
					{
						PalTab[_PalNr * 768 + i] = cTab[i * 3];
						PalTab[_PalNr * 768 + i + 256] = cTab[i * 3 + 1];
						PalTab[_PalNr * 768 + i + 512] = cTab[i * 3 + 2];
					}
					_PalNr++;
				}
				else
				{
					int aa = file.error();
					aa = aa;
				}

			}
		}
	}

