void MainWindow::CreateSphereStuff()
{
	if (shpereExplodeSource != NULL) shpereExplodeSource->Delete();
	if (mySphereDistanceTab != NULL) delete[]mySphereDistanceTab;
	//sphereExplodeSize = 5;

	shpereExplodeSource = NULL;
	mySphereDistanceTab = NULL;


	QDir rDir(progDirPath);
	QString filename = "";
	bool modelAlreadyGenerated = false;
	if (rDir.cd("models3d"))
	{
		filename = rDir.absolutePath() + "/" + QString::number(sphereExplodeSize);

		//jesli jest to wczytam
		QString filename2, filename0;
		bool test1 = false;
		bool test2 = false;


		filename0 = filename;
		if (filename0.lastIndexOf(".sdata") == -1)			filename0 += ".sdata";

		QFile file2(filename0);
		if (file2.open(QIODevice::ReadOnly))
		{
			test1 = true;
			file2.close();
		}


		filename2 = filename;
		if (filename2.lastIndexOf(".distElTab") == -1)			filename2 += ".distElTab";

		QFile file3(filename2);
		if (file3.open(QIODevice::ReadOnly))
		{
			test2 = true;
			file3.close();
		}

		if ((test1 == true) && (test2 == true))
		{
			LoadMySphereData(filename, shpereExplodeSource, mySphereDistanceTab);
			if ((shpereExplodeSource != NULL) && (mySphereDistanceTab != NULL))
			{
				modelAlreadyGenerated = true;
			}
			else
			{
				if (shpereExplodeSource != NULL) shpereExplodeSource->Delete();
				if (mySphereDistanceTab != NULL) delete[]mySphereDistanceTab;

				shpereExplodeSource = NULL;
				mySphereDistanceTab = NULL;
			}
		}



	}

	if (modelAlreadyGenerated == false)
	{
		shpereExplodeSource = CreateMySphere(sphereExplodeSize, 1);
		mySphereDistanceTab = CreateMySphereDistanceTabs(shpereExplodeSource, 0.0, 100);
		if (!filename.isEmpty())	SaveMySphereData(filename, shpereExplodeSource, mySphereDistanceTab);
	}
	/*QDir rDir(progDirPath);
	if (rDir.cd("models3d"))
	{
		QString filename = rDir.absolutePath() + "/" + QString::number(sphereExplodeSize) ;


	}*/
}
