bool MainWindow::LoadSnapshot(QString xname)
{
	QString fileIni = this->snapshotPath + "/image_export.ini";
	QString fileName = this->snapshotPath + "/image_export_stream.bin";

	QFile file2(fileName);
	bool test = file2.open(QIODevice::ReadOnly);
	if (test == false) return false;
	//usun wszystkie rawdata!

	//wczytaj dane
	//odpal filtr thickness_1

	//ustaw rysowanie polyline jako default


	int n[3] = { 1, 1, 1 };
	double scale[3] = { 1, 1, 1 };

	//QImage img;
	RawDataSet* tData = NULL;
	//if(img.load(fileName))


	//int nx=img.width();
	//int ny=img.height();
	//bool isGray=img.isGrayscale();


	{


		double left, top, bottom, right;

		QSettings sett(fileIni, QSettings::IniFormat);
		QString txt;
		sett.beginGroup("export");



		if (sett.contains("width"))
		{
			n[0] = sett.value("width").toInt();
		}
		if (sett.contains("height"))
		{
			n[1] = sett.value("height").toInt();
		}


		if (sett.contains("_left"))
		{
			left = sett.value("_left").toDouble();
		}
		if (sett.contains("_top"))
		{
			top = sett.value("_top").toDouble();
		}
		if (sett.contains("_right"))
		{
			right = sett.value("_right").toDouble();
		}
		if (sett.contains("_bottom"))
		{
			bottom = sett.value("_bottom").toDouble();
		}

		double rx = right - left;
		double ry = bottom - top;
		if (rx > 0) scale[0] = rx / (double)n[0];
		if (ry > 0) scale[1] = ry / (double)n[1];

		sett.endGroup();

		//parametry wczytane




		//if ((nx!=n[0])||(ny!=n[1])) return;








		tData = new RawDataSet(n[0], n[1], 1, scale[0], scale[1], 1);

		int pos = 0;
		int pos2 = 0;
		//if (isGray==false)

		//img=img.convertToFormat(QImage::Format_RGB32);
		unsigned short* data = tData->GetDataArray();
		//unsigned char *bits = img.bits

		unsigned char* xData = new unsigned char[tData->GetVolumeSize()];
		pos = 0;

		file2.read((char*)xData, tData->GetVolumeSize() * sizeof(unsigned char));

		for (int i = 0; i < tData->GetVolumeSize(); i++)
		{
			data[i] = xData[i];


		}
		tData->CalculateHistogram();
		delete[]xData;
		/*	unsigned short *data=tData->GetDataArray();
		unsigned char *bits=img.bits();
		pos=0;
		for(int i=0;i<nx*ny;i++)
		{
		data[pos2]=bits[pos+1];
		pos2++;
		pos+=4;

		}
		*/

	}

	file2.close();
	//dane wczytane
	if (tData != NULL)
	{


		DataSet* dataset = new DataSet(tData, Pal, NumberOfMasks);
		dataset->SetNewPalette(Pal, PalNr, PalInvert);
		DataSetList->InsertItem(dataset);





		if (data != NULL)
		{
			double oScale[3];
			data->GetScale(oScale);

			double tol = 1e-6;
			if ((fabs(oScale[0] - scale[0]) > tol) || (fabs(oScale[1] - scale[1]) > tol))
			{
				this->TransversalView->GetShapes()->shapeList.clear();
				this->TransversalView->GetShapes()->polygonList.clear();
				//this->TransversalView->GetShapes()=
			}
		}




		//QString xName = "ImG";
		tData->SetRawDataSetName(xname);


		MainDataPos = DataSetList->GetCurrentItemPos();
		//MainListItem=DataSetList->GetCurrentListItem();
		GUIPanel->SlotInsertRawDataItem(dataset, DataSetList);









		SlotSetNewRawDataSet(dataset->GetTreeWidgetItem());



		QString fileIni1 = this->snapshotPath + "/image_export_stream.bin";
		QFileInfo info1(fileIni1);
		QDateTime datetime1 = info1.lastModified();
		QTime time1 = datetime1.time();
		lastSnapshotTime1 = time1;

		QString fileIni2 = this->snapshotPath + "/image_export.ini";
		QFileInfo info2(fileIni2);
		QDateTime datetime2 = info2.lastModified();
		QTime time2 = datetime2.time();
		lastSnapshotTime2 = time2;


		for (int i = DataSetList->GetNumberOfItems() - 1; i >= 0; i--)
		{
			if ((DataSetList->GetItemAtPos(i)->GetData() != dataset) && (DataSetList->GetItemAtPos(i)->GetData()->GetRawData()->GetRawDataSetName().compare(xname) == 0))
				//	DataSetList->DeleteItem(i);
				SlotDeleteDataSet(DataSetList->GetItemAtPos(i)->GetData()->GetTreeWidgetItem());
		}




		return true;
	}
	return false;
}
