void MainWindow::SlotSetVolumeColors()
{
	//	qDebug() << "SlotSetVolumeColors";
	int i;
	int Range = data->GetMaxValue();

	ColorTransferFunction->RemoveAllPoints();

	double scale = 255.0 / data->GetMaxValue();

	GradientTransferFunction2->RemoveAllPoints();
	GradientTransferFunction2->AddPoint(0, 1);
	GradientTransferFunction2->AddPoint(data->GetMaxValue(), 1);

	if (StretchPalette == true)
	{
		int LowerThreshold = Histogram->GetLowerVolumeThreshold();
		int UpperThreshold = Histogram->GetUpperVolumeThreshold();

		double	StretchedScalePalette = (UpperThreshold - LowerThreshold) > 0 ? (double)(255.0 / (UpperThreshold - LowerThreshold)) : 1;
		int Step = Round(1 / StretchedScalePalette);
		if (Step == 0) Step = 1;

		if (LowerThreshold > 0)
		{
			ColorTransferFunction->AddRGBPoint(0, 0, 0, 0);
			ColorTransferFunction->AddRGBPoint(LowerThreshold - 1, 0, 0, 0);
		}
		int TMP;

		for (i = LowerThreshold; i <= UpperThreshold; i += Step)
		{
			TMP = Round((i - LowerThreshold) * StretchedScalePalette);
			//ColorTransferFunction->AddRGBPoint(i,(double)(View3DListItem->GetData()->Palette->R[TMP]/255.0),(double)(View3DListItem->GetData()->Palette->G[TMP]/255.0),(double)(View3DListItem->GetData()->Palette->B[TMP]/255.0));	
			ColorTransferFunction->AddRGBPoint(i, (double)(PalR->R[TMP]) / 255.0, (double)(PalR->G[TMP]) / 255.0, (double)(PalR->B[TMP]) / 255.0);

		}

		if (UpperThreshold + 1 < Range)
		{
			ColorTransferFunction->AddRGBPoint(UpperThreshold + 1, 0, 0, 0);
			ColorTransferFunction->AddRGBPoint(Range, 0, 0, 0);
		}
	}
	else
	{
		double ScalePalette = (double)(data->GetMaxValue()) / (double)(255.0);
		for (i = 0; i <= 255; i++)
			ColorTransferFunction->AddRGBPoint((double)i * ScalePalette, (double)(PalR->R[i]) / 255.0, (double)(PalR->G[i]) / 255.0, (double)(PalR->B[i]) / 255.0);

		//ColorTransferFunction->AddRGBPoint((double)i*scale*ScalePalette,(double)(Pal->R[i])/255.0,(double)(Pal->G[i])/255.0,(double)(Pal->B[i])/255.0);

		//		ColorTransferFunction->AddRGBPoint((double)i*ScalePalette,(double)(View3DListItem->GetData()->Palette->R[i]/255.0),(double)(View3DListItem->GetData()->Palette->G[i]/255.0),(double)(View3DListItem->GetData()->Palette->B[i]/255.0));
	}




	//	ColorTransferFunction2->DeepCopy(ColorTransferFunction);

	if (Volume->GetMapper() != NULL)
	{
		//VolumeMapper->SetInputData(VolumeStructuredPoints);

		//bool useMask = GUIPanel->useMaskFor3DViewCheckBox->isChecked();

		//if (useMask == true)
		//{
		//	VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);
		//}
		//else
		//{
		//	VolumeMapper->SetMaskInput(NULL);
		//}
		//Volume->SetProperty(VolumeProperty);

		//VolumeMapper->Update();

		////SlotUpdateVolumeSettings();


		//Volume->Update();



		//VWidget->Interactor->repaint();

		////AddMaskToVolumeStructuredPoints(NULL, 0);

		//if (noClearVolMaskPts == false)ClearVolumeStructuredPoints(0, true, true);
		int val = 0;


		VolumeStructuredPoints->Modified();
		if (isVolumeVisible == true)
		{
			VolumeMapper->SetInputData(VolumeStructuredPoints);

			bool useMask = GUIPanel->useMaskFor3DViewCheckBox->isChecked();
			if (useMask == true)
			{
				VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);
			}
			else
			{
				VolumeMapper->SetMaskInput(NULL);
			}
			VolumeMapper->Modified();
			Volume->Update();
			VWidget->Interactor->update();
		}
	}
}
//------------------------------------
void MainWindow::SlotUpdateVolumeOpacityFunction(QPolygonF p, int mode)
{
	if (data != NULL)
	{
		if (p.count() > 0)
		{
			vtkPiecewiseFunction* func = NULL;
			if (mode == 0) func = OpacityTransferFunction;
			else if (mode == 1) func = GradientTransferFunction;


			double pp0[4], pp1[4];
			double range[2];
			GradientTransferFunction2->GetRange(range);
			GradientTransferFunction2->GetNodeValue(0, pp0);
			GradientTransferFunction2->GetNodeValue(1, pp1);

			if (func == NULL)return;

			double min = 0;
			double max = 0;
			func->GetRange(min, max);

			vtkPiecewiseFunction* func2 = vtkPiecewiseFunction::New();
			//	func2->DeepCopy(func);
			//func2->Update();
			int i, j;

			int nrPts = func->GetSize();


			//qpolygonRange
			double minXpol = max;
			double maxXpol = 0;
			double xx, yy;

			//double histXMax = this->Histogram->XHSize;
			//OpacityTransferFunctionScaled->RemoveAllPoints();
			double scale = (data->GetMaxValue());// > 0) ? 1.0 / data->GetMaxValue() : 1;
			if (mode == 1) scale = 255;;

			for (i = 0; i < p.size(); i++)
			{
				QPointF point = p.at(i);
				xx = point.x() * scale;
				if (mode == 1) xx = (int)xx;
				yy = point.y();
				//yy = 1.0 - point.y() / 200.0;
				if (xx < minXpol) minXpol = xx;
				if (xx > maxXpol) maxXpol = xx;

				func2->AddPoint(xx, yy);
				//	OpacityTransferFunctionScaled->AddPoint(xx*scale, yy);

			}

			//if (mode == 1)
			//{
			//	//func2->AddPoint(0, 0);

			//	int pos1 = scale+1;
			//	int pos2 = OpacityTransferFunction->GetRange()[1];
			//	func2->AddPoint(pos1, 0);
			//	func2->AddPoint(pos2, 0);
			//}
			double val[4];
			double x, y;
			//dodaje wszystkie punkty poza zakresem kolizji z func
			for (i = 0; i < nrPts; i++)
			{
				func->GetNodeValue(i, val);
				x = val[0];
				y = val[1];

				if ((x < minXpol) || (x > maxXpol))
				{
					func2->AddPoint(x, y);
					//func2->AddPoint(x, y);
					//OpacityTransferFunctionScaled->AddPoint(xx*scale, yy);
				}
			}

			func->DeepCopy(func2);
			//		func->Update();
			func2->Delete();

		}
		SlotSetVolumeOpacity();
		Histogram->update();
		if (Volume->GetMapper() != NULL)
		{
			Volume->Update();
			VWidget->Interactor->repaint();
		}
	}
}

