void MainWindow::SlotLoadMixerSettings(const QString& filename)
{

	RTimer.Start("Loading file", false);
	//	int tmp=1;


	for (int i = 0; i < GUIPanel->filterCompositionsComboBox->count(); i++)
	{
		QDir rDir(progDirPath);
		rDir.cd("filter_compositions");
		QString txt2 = rDir.absolutePath() + "/" + GUIPanel->filterCompositionsComboBox->itemText(i) + ".layers";
		if (filename.compare(txt2) == 0)
		{
			GUIPanel->filterCompositionsComboBox->setCurrentIndex(i);
			break;
		}
	}

	if ((MainListItem != NULL) && (this->mixer != NULL))
	{

		if (!filename.isEmpty())
		{
			TransversalView->SetBlockMixer(true); SagittalView->SetBlockMixer(true); CoronalView->SetBlockMixer(true);
			mixer->LoadLayerSettings(filename, true);
			mixer->SlotItemSelectionChanged();
			//	TransversalView->SetBlockMixer(false); SagittalView->SetBlockMixer(false); CoronalView->SetBlockMixer(false);
			SlotUpdateDisableMixer(1);

			mixer->ClearShapes();
			mixer1->ClearShapes();
			mixer2->ClearShapes();
			RepaintViews();


			QSettings sett(configIniName, QSettings::IniFormat);
			sett.beginGroup("Data-Init");
			sett.setValue("LastFilterPath", filename);
			sett.setValue("FasFilterMode", "Off");
			sett.endGroup();
		}
	}
	RTimer.Stop();



}
