bool MainWindow::Shift2DRawData(RawDataSet* data, QString fix2DPath)
{
	QFileInfo check_file2f(fix2DPath);
	if ((check_file2f.exists() && check_file2f.isFile()))
	{
		int count = 0;
		unsigned short* tmpDataArray = new unsigned short[data->GetVolumeSize()];
		memset(tmpDataArray, 0, data->GetVolumeSize() * sizeof(unsigned short));

		//	int //count;
		int pos = 0;
		double fixTrans2d[2] = { 0 };
		int tP[3];
		int n1[3];
		data->GetN(n1);

		unsigned short* origDataArray = data->GetDataArray();

		QFile file2(fix2DPath);
		if (file2.open(QIODevice::ReadOnly))
		{
			QTextStream stream(&file2);//bo sprawdzilem wczesniej
			QString line = stream.readLine();
			QStringList fields = line.split(QRegExp(" |\t|:"), QString::SkipEmptyParts);
			int countFields = fields.count();
			if (countFields > 1)
			{
				fixTrans2d[0] = fields[0].toDouble();
				fixTrans2d[1] = fields[1].toDouble();
			}

			for (int k = 0; k < n1[2]; k++)
			{
				tP[2] = k;



				for (int j = 0; j < n1[1]; j++)
				{
					tP[1] = j - fixTrans2d[1];

					for (int i = 0; i < n1[0]; i++)
					{

						tP[0] = i - fixTrans2d[0];

						if (
							(tP[0] >= 0) && (tP[0] < n1[0]) &&
							(tP[1] >= 0) && (tP[1] < n1[1]) &&
							(tP[2] >= 0) && (tP[2] < n1[2])
							)
						{
							int tmp = origDataArray[data->GetVoxelPos(tP[0], tP[1], tP[2])];
							tmpDataArray[pos] = tmp;
							if (tmp > 0) count++;
						}
						pos++;



					}




				}
				//readFix2D next values

				line = stream.readLine();
				fields = fields = line.split(QRegExp(" |\t|:"), QString::SkipEmptyParts);
				int countFields = fields.count();
				if (countFields > 1)
				{
					fixTrans2d[0] = fields[0].toDouble();
					fixTrans2d[1] = fields[1].toDouble();
				}
			}

			file2.close();
		}

		//podmianka

		unsigned short* m = origDataArray;
		data->SetDataArray(tmpDataArray);
		//delete[]m;// bo samo sie kasuje w setdataarray


		return true;


	}
	return false;

}
