void MainWindow::SetCorners(int x, int y, int z)
{

	if (data != NULL)
	{
		//	chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);

		emit SignalSendShowMessageProcessEvents(false);
		PosX = x;
		PosY = y;
		PosZ = z;

		GUIPanel->seedPointXBox->setValue(x);
		GUIPanel->seedPointYBox->setValue(y);
		GUIPanel->seedPointZBox->setValue(z);

		int seed[3];
		seed[0] = GUIPanel->seedPointXBox->value();
		seed[1] = GUIPanel->seedPointYBox->value();
		seed[2] = GUIPanel->seedPointZBox->value();

		double origin[3];
		data->GetOrigin(origin);
		selectedDoublePoint[0] = seed[0] * data->GetXscale() + origin[0];
		selectedDoublePoint[1] = seed[1] * data->GetYscale() + origin[1];
		selectedDoublePoint[2] = seed[2] * data->GetZscale() + origin[2];
		//	qWarning()<<(QString::number(this->selectedDoublePoint[0])+" "+QString::number(this->selectedDoublePoint[1])+" "+QString::number(this->selectedDoublePoint[2])+" int");

		//	DataSet *TData=DataSetList->GetCurrentListItem()->GetData();


		double XSize = (double)GUIPanel->InspectionXSizeSlider->value() * data->GetXscale();
		double YSize = (double)GUIPanel->InspectionYSizeSlider->value() * data->GetYscale();
		double ZSize = (double)GUIPanel->InspectionZSizeSlider->value() * data->GetZscale();

		BoxActor->SlotTransformCylinderBoxActor(PosX * data->GetXscale(), PosY * data->GetYscale(), PosZ * data->GetZscale(),
			XSize, YSize, ZSize, 1.0);

		emit SignalSendBoundingBoxSize(BoxActor->Size);

		QString txt, txt2;
		txt = "Voxel position: ";
		int val = data->GetVoxelValue(x, y, z);
		int pos1d = data->GetVoxelPos(x, y, z);

		txt2.sprintf(" (%d,%d,%d)(1d=%d) = %d", x, y, z, pos1d, val);

		txt.append(txt2);
		double minV = (data->dicomMinValue > -100000) ? data->dicomMinValue : 0;
		double rescale = data->dicomRescaleValue;
		txt += " Hounsfield: " + QString::number((minV + val * rescale));


		if ((VolumeStructuredPoints != NULL))
		{
			unsigned short* ptr0 = (unsigned short*)(VolumeStructuredPoints->GetScalarPointer(0, 0, 0));
			int mPos = data->GetVoxelPos(x, y, z) * 2 + 1;
			txt += " 3DMask val: " + QString::number(ptr0[mPos]);
		}


		emit SendMessage(txt);

		emit SignalSendSectionParameters(GUIPanel->InspectionXSizeSlider->value(),
			GUIPanel->InspectionYSizeSlider->value(),
			GUIPanel->InspectionZSizeSlider->value(),
			PosX, PosY, PosZ);

		//	emit SignalSendShowMessageProcessEvents(true);
		if (videoTools->isRecordInProgress() == true) SlotGrabFrameForFFMpegAnimation();
	}
}
//-------------------------------------------------------------
void MainWindow::SlotSignalAmplitude()
{

	if (data != NULL)
	{
		RTimer.Start("sth");

		int i;
		RawDataSet* tData = new RawDataSet();
		tData->Copy(*MainListItem->GetData()->GetRawData(), false);

		unsigned short* src = data->GetDataArray();
		unsigned short* dst = tData->GetDataArray();


		unsigned short val, v1;


		int max = data->GetMaxValue();

		int center = (max / 2) + 1;
		int center1 = center - 1;
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{
			v1 = src[i];
			//val=(v1<center)?(center1-v1)*2:(v1-center1)*2;
			val = abs(v1 - center);
			dst[i] = val;
		}

		tData->CalculateHistogram();
		InsertRawDataSet(tData);
		RTimer.Stop();

	}
}
