void MainWindow::SlotFipXDataset()
{

	if (data != NULL)
	{
		int i, j, k;

		RTimer.Start("Flipping Volume");





		if (data->GetGChannelUCHARArray() == NULL)
		{

			RawDataSet* dataX = new RawDataSet(data->GetNx(), data->GetNy(), data->GetNz(), data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());
			QString name;
			name = data->GetRawDataSetName();
			name.append(" -Flipped");
			dataX->SetRawDataSetName(name);
			memcpy(dataX->GetDataArray(), data->GetDataArray(), sizeof(unsigned short) * data->GetVolumeSize());

			for (k = 0; k < data->GetNz(); k++)
				for (j = 0; j < data->GetNy(); j++)
					for (i = 0; i < data->GetNx(); i++)
						dataX->SetVoxelValue(i, j, k, data->GetVoxelValue(data->GetNx() - i, j, k));

			double origX[3];
			data->GetOrigin(origX);
			dataX->SetOrigin(origX);
			dataX->dicomMinValue = data->dicomMinValue;
			dataX->dicomLevelValue = data->dicomLevelValue;
			dataX->dicomWindowWidthValue = data->dicomWindowWidthValue;
			dataX->dicomRescaleValue = data->dicomRescaleValue;

			InsertRawDataSet(dataX);

		}
		else
		{
			int p1, p2;
			unsigned short a1;
			unsigned char a2;
			unsigned short* r = data->GetDataArray();
			unsigned char* g = data->GetGChannelUCHARArray();
			unsigned char* b = data->GetBChannelUCHARArray();
			for (k = 0; k < data->GetNz(); k++)
				for (j = 0; j < data->GetNy(); j++)
					for (i = 0; i < data->GetNx() / 2; i++)
					{
						p1 = data->GetVoxelPos(i, j, k);
						p2 = data->GetVoxelPos(data->GetNx() - i, j, k);

						//r[p1]=0;
						//g[p1]=0;
						//b[p1]=0;
						a1 = r[p1]; r[p1] = r[p2]; r[p2] = a1;
						a2 = g[p1]; g[p1] = g[p2]; g[p2] = a2;
						a2 = b[p1]; b[p1] = b[p2]; b[p2] = a2;


						//dataX->SetVoxelValue(i,j,k,data->GetVoxelValue(data->GetNx()-i,j,k));
					}
		}



		RTimer.Stop();

	}

}
