RawDataSet* MainWindow::AutoCropWithMask(RawDataSet* data, unsigned char*& mask)
{
	RawDataSet* dataX = NULL;
	if ((data != NULL) && (mask != NULL))
	{



		int i, j, k;

		RTimer.Start("Cropping Volume");

		int count = 0;
		int pos[3];
		int bounds[6] = { 10000, 0, 10000, 0, 10000, 0 };
		for (i = 0; i < data->GetVolumeSize(); i++)
		{
			if (mask[i] == 1)
			{
				data->GetVoxelXYZPos(i, pos);
				if (pos[0] < bounds[0]) bounds[0] = pos[0]; if (pos[0] > bounds[1]) bounds[1] = pos[0];
				if (pos[1] < bounds[2]) bounds[2] = pos[1]; if (pos[1] > bounds[3]) bounds[3] = pos[1];
				if (pos[2] < bounds[4]) bounds[4] = pos[2]; if (pos[2] > bounds[5]) bounds[5] = pos[2];
				count++;

			}
		}

		int nn[3];
		data->GetN(nn);
		if (bounds[0] > 0) bounds[0]--;
		if (bounds[2] > 0) bounds[2]--;
		if (bounds[4] > 0) bounds[4]--;

		if (bounds[1] < nn[0] - 1) bounds[1]++;
		if (bounds[3] < nn[1] - 1) bounds[3]++;
		if (bounds[5] < nn[2] - 1) bounds[5]++;


		if (count > 0)
		{
			int size[3];
			double scale[3];
			double origin[3];
			data->GetScale(scale);

			origin[0] = (bounds[0]) * scale[0];		origin[1] = (bounds[2]) * scale[1];		origin[2] = (bounds[4]) * scale[2];

			size[0] = bounds[1] - bounds[0];		size[1] = bounds[3] - bounds[2];		size[2] = bounds[5] - bounds[4];


			dataX = new RawDataSet(size[0], size[1], size[2], scale[0], scale[1], scale[2]);
			dataX->SetOrigin(origin);


			dataX->dicomMinValue = data->dicomMinValue;
			dataX->dicomLevelValue = data->dicomLevelValue;
			dataX->dicomWindowWidthValue = data->dicomWindowWidthValue;
			dataX->dicomRescaleValue = data->dicomRescaleValue;

			//trzeba dodac jeszcze stary origin


			QString name;
			name = data->GetRawDataSetName();
			name.append(" - Cropped");
			dataX->SetRawDataSetName(name);

			//unsigned char* newMask = new unsigned char[dataX->GetVolumeSize()];
			unsigned char* newMask = NULL;
			if (mask != NULL) newMask = new unsigned char[dataX->GetVolumeSize()];
			int pos0, pos1;
			int nx = dataX->GetNx();
			int ss = dataX->GetSliceSize();


			int nx0 = data->GetNx();
			int ss0 = data->GetSliceSize();

			for (j = 0; j < size[1]; j++)
				for (k = 0; k < size[2]; k++)
				{
					pos0 = j * nx + k * ss;
					pos1 = (bounds[2] + j) * nx0 + (bounds[4] + k) * ss0 + bounds[0];

					/*		int aa=j*dataX->GetNx()+k*dataX->GetSliceSize();
					int bb=(bounds[2]+j)*data->GetNx()+(bounds[4]+k)*data->GetSliceSize()+bounds[0];*/
					//	memcpy((dataX->GetDataArray()+j*dataX->GetNx()+k*dataX->GetSliceSize()),(data->GetDataArray()+(bounds[2]+j)*data->GetNx()+(bounds[4]+k)*data->GetSliceSize()+bounds[0]),sizeof(unsigned short)*size[0]);
					//	memcpy((newMask+j*dataX->GetNx()+k*dataX->GetSliceSize()),(MaskData+(bounds[2]+j)*data->GetNx()+(bounds[4]+k)*data->GetSliceSize()+bounds[0]),sizeof(unsigned char)*size[0]);


					memcpy(dataX->GetDataArray() + pos0, data->GetDataArray() + pos1, sizeof(unsigned short) * size[0]);
					if (newMask != NULL)
					{
						memcpy(newMask + pos0, mask + pos1, sizeof(unsigned char) * size[0]);
					}

					//		memcpy((dataX->GetDataArray()+j*dataX->GetNx()+k*dataX->GetSliceSize()),(data->GetDataArray()+(yyr0+j)*data->GetNx()+(zzr0+k)*data->GetSliceSize()+xxr0),sizeof(unsigned short)*(xxr1-xxr0));

				}

			dataX->CalculateHistogram();
			int count = 0;
			if (newMask != NULL)
			{
				unsigned char* tt = mask;

				mask = newMask;
				delete[]tt;


				for (int i = 0; i < dataX->GetVolumeSize(); i++)
				{
					if (mask[i] > 0) count++;
				}
			}





			return dataX;

		}
		RTimer.Stop();
	}
	return dataX;


}
