//----------------------------------------------------------
void MainWindow::SlotCropDataset()
{
	if (data != NULL)
	{
		int i, j, k;

		RTimer.Start("Cropping Volume");

		int xxr0, xxr1, yyr0, yyr1, zzr0, zzr1;

		int InspX = (int)(GUIPanel->InspectionXSizeSlider->value() / 2.0);
		int InspY = (int)(GUIPanel->InspectionYSizeSlider->value() / 2.0);
		int InspZ = (int)(GUIPanel->InspectionZSizeSlider->value() / 2.0);

		int rx = data->GetNx();
		int ry = data->GetNy();
		int rz = data->GetNz();



		xxr0 = ((PosX - InspX) > 0) ? PosX - InspX : 0;
		yyr0 = ((PosY - InspY) > 0) ? PosY - InspY : 0;
		zzr0 = ((PosZ - InspZ) > 0) ? PosZ - InspZ : 0;

		xxr1 = ((PosX + InspX) < rx) ? PosX + InspX : rx - 1;
		yyr1 = ((PosY + InspY) < ry) ? PosY + InspY : ry - 1;
		zzr1 = ((PosZ + InspZ) < rz) ? PosZ + InspZ : rz - 1;



		RawDataSet* dataX = new RawDataSet(xxr1 - xxr0, yyr1 - yyr0, zzr1 - zzr0, data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());
		double origin[3] = { xxr0 * data->GetXscale(), yyr0 * data->GetYscale(), zzr0 * data->GetZscale() };

		//trzeba dodac jeszcze stary origin
		double oldOrig[3];
		data->GetOrigin(oldOrig);
		for (i = 0; i < 3; i++)
		{
			origin[i] += oldOrig[i];
		}
		dataX->SetOrigin(origin);


		dataX->dicomMinValue = data->dicomMinValue;
		dataX->dicomLevelValue = data->dicomLevelValue;
		dataX->dicomWindowWidthValue = data->dicomWindowWidthValue;
		dataX->dicomRescaleValue = data->dicomRescaleValue;

		QString name;
		name = data->GetRawDataSetName();
		name.append(" - Cropped");
		dataX->SetRawDataSetName(name);

		for (j = 0; j < yyr1 - yyr0; j++)
			for (k = 0; k < zzr1 - zzr0; k++)
				memcpy((dataX->GetDataArray() + j * dataX->GetNx() + k * dataX->GetSliceSize()), (data->GetDataArray() + (yyr0 + j) * data->GetNx() + (zzr0 + k) * data->GetSliceSize() + xxr0), sizeof(unsigned short) * (xxr1 - xxr0));


		unsigned char* mmask = NULL;
		if (MaskData != NULL)
		{
			VolumeInt = 0;
			for (int i = 0; i < data->GetVolumeSize(); i++)
				if (MaskData[i] == 1) VolumeInt++;
		}
		if ((VolumeInt > 0) && (VolumeInt < data->GetVolumeSize()))
		{
			mmask = new unsigned char[dataX->GetVolumeSize()];
			for (j = 0; j < yyr1 - yyr0; j++)
				for (k = 0; k < zzr1 - zzr0; k++)
					memcpy((mmask + j * dataX->GetNx() + k * dataX->GetSliceSize()), (MaskData + (yyr0 + j) * data->GetNx() + (zzr0 + k) * data->GetSliceSize() + xxr0), sizeof(unsigned short) * (xxr1 - xxr0));


		}


		InsertRawDataSet(dataX);

		if (mmask != NULL)
		{
			if (MaskData != NULL)
			{
				delete[] MaskData;

			}
			MaskData = mmask;
			chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
			SagittalView->InsertMaskData(MaskData);
			CoronalView->InsertMaskData(MaskData);
			SlotInsertNewMask();
		}



		RTimer.Stop();
	}



}
