RawDataSet* MainWindow::SlotCropVolume(RawDataSet* inData, unsigned char*& mask, int* bounds)
{
	if ((inData != NULL) && (bounds != NULL))
	{
		int i, j, k;



		int xxr0, xxr1, yyr0, yyr1, zzr0, zzr1;

		//	int InspX=(int)(GUIPanel->InspectionXSizeSlider->value()/2.0);
		//int InspY=(int)(GUIPanel->InspectionYSizeSlider->value()/2.0);
		//int InspZ=(int)(GUIPanel->InspectionZSizeSlider->value()/2.0);

		int rx = data->GetNx();
		int ry = data->GetNy();
		int rz = data->GetNz();

		unsigned char* newMask = NULL;

		xxr0 = ((bounds[0] > 0) && (bounds[0] < rx)) ? bounds[0] : 0;
		yyr0 = ((bounds[2] > 0) && (bounds[2] < ry)) ? bounds[2] : 0;
		zzr0 = ((bounds[4] > 0) && (bounds[4] < rz)) ? bounds[4] : 0;

		xxr1 = ((bounds[1] > 0) && (bounds[1] < rx)) ? bounds[1] : 0;
		yyr1 = ((bounds[3] > 0) && (bounds[3] < ry)) ? bounds[3] : 0;
		zzr1 = ((bounds[5] > 0) && (bounds[5] < rz)) ? bounds[5] : 0;

		if ((xxr0 >= xxr1) || (yyr0 >= yyr1) || (zzr0 >= zzr1))
		{
			return NULL;
		}
		/*xxr1=((PosX+InspX)<rx)?PosX+InspX:rx-1;
		yyr1=((PosY+InspY)<ry)?PosY+InspY:ry-1;
		zzr1=((PosZ+InspZ)<rz)?PosZ+InspZ:rz-1;*/



		RawDataSet* dataX = new RawDataSet(xxr1 - xxr0, yyr1 - yyr0, zzr1 - zzr0, inData->GetXscale(), inData->GetYscale(), inData->GetZscale(), inData->GetGantryAngle());
		double origin[3] = { xxr0 * inData->GetXscale(), yyr0 * inData->GetYscale(), zzr0 * inData->GetZscale() };

		if (mask != NULL) newMask = new unsigned char[dataX->GetVolumeSize()];

		//trzeba dodac jeszcze stary origin
		double oldOrig[3];
		inData->GetOrigin(oldOrig);
		for (i = 0; i < 3; i++)
		{
			origin[i] += oldOrig[i];
		}
		dataX->SetOrigin(origin);
		dataX->dicomMinValue = data->dicomMinValue;
		dataX->dicomLevelValue = data->dicomLevelValue;
		dataX->dicomWindowWidthValue = data->dicomWindowWidthValue;
		dataX->dicomRescaleValue = data->dicomRescaleValue;


		QString name;
		name = inData->GetRawDataSetName();
		name.append(" - Cropped");
		dataX->SetRawDataSetName(name);

		for (j = 0; j < yyr1 - yyr0; j++)
			for (k = 0; k < zzr1 - zzr0; k++)
			{
				memcpy((dataX->GetDataArray() + j * dataX->GetNx() + k * dataX->GetSliceSize()), (inData->GetDataArray() + (yyr0 + j) * inData->GetNx() + (zzr0 + k) * inData->GetSliceSize() + xxr0), sizeof(unsigned short) * (xxr1 - xxr0));
				if (newMask != NULL)
				{
					memcpy((newMask + j * dataX->GetNx() + k * dataX->GetSliceSize()), (mask + (yyr0 + j) * inData->GetNx() + (zzr0 + k) * inData->GetSliceSize() + xxr0), sizeof(unsigned char) * (xxr1 - xxr0));
				}
			}



		if (newMask != NULL)
		{
			delete[]mask;
			mask = newMask;
		}
		return dataX;//InsertRawDataSet(dataX);

	}
	return NULL;

}
