void MainWindow::SlotCropVolume()
{
	if ((MainListItem != NULL))
	{

		data = MainListItem->GetData()->GetRawData();
		RawDataSet* objectData = NULL;
		int i, j, k;
		int bounds[6];
		bool t3d = false;
		if ((isVolumeVisible == true) && (VolumeMapper->GetClippingPlanes() != NULL))
		{
			//planes pos
			vtkPlane* pl;
			vtkPlaneCollection* pcol = VolumeMapper->GetClippingPlanes();
			vtkPlanes* planes = vtkPlanes::New();

			double s[3];
			int nn[3];
			nn[0] = data->GetNx();
			nn[1] = data->GetNy();
			nn[2] = data->GetNz();
			s[0] = data->GetXscale();
			s[1] = data->GetYscale();
			s[2] = data->GetZscale();

			double o[3];
			double n[3];

			for (i = 0; i < 6; i++)
			{
				pl = static_cast<vtkPlane*>(pcol->GetItemAsObject(i));
				pl->GetNormal(n);
				pl->GetOrigin(o);
				o[0] /= s[0];	o[1] /= s[1];	o[2] /= s[2];
				bounds[i] = o[0] + o[1] + o[2];
			}
			t3d = true;

		}
		else
		{
			for (int i = 0; i < 6; i++)
			{
				bounds[i] = GUIPanel->planeSliders[i]->value();
			}
		}

		//	bounds[1]-=1;bounds[3]-=1;bounds[5]-=1;
		for (i = 0; i < 6; i += 2)
		{
			if (bounds[i + 1] - bounds[i] < 1) return;
		}



		RTimer.Start("Cropping Volume");

		int xxr0, xxr1, yyr0, yyr1, zzr0, zzr1;

		//int InspX=(int)(GUIPanel->InspectionXSizeSlider->value()/2.0);
		//int InspY=(int)(GUIPanel->InspectionYSizeSlider->value()/2.0);
		//int InspZ=(int)(GUIPanel->InspectionZSizeSlider->value()/2.0);

		//int rx=data->GetNx();
		//int ry=data->GetNy();
		//int rz=data->GetNz();



		//xxr0=((PosX-InspX)>0)?PosX-InspX:0;
		//yyr0=((PosY-InspY)>0)?PosY-InspY:0;
		//zzr0=((PosZ-InspZ)>0)?PosZ-InspZ:0;						

		//xxr1=((PosX+InspX)<rx)?PosX+InspX:rx-1;
		//yyr1=((PosY+InspY)<ry)?PosY+InspY:ry-1;
		//zzr1=((PosZ+InspZ)<rz)?PosZ+InspZ:rz-1;
		double origX[3];
		data->GetOrigin(origX);
		double origSc[3];
		data->GetScale(origSc);
		for (i = 0; i < 3; i++)
		{
			origX[i] /= origSc[i];
		}
		xxr0 = bounds[0] - origX[0];
		yyr0 = bounds[2] - origX[1];
		zzr0 = bounds[4] - origX[2];

		xxr1 = bounds[1] - origX[0];
		yyr1 = bounds[3] - origX[1];
		zzr1 = bounds[5] - origX[2];




		RawDataSet* dataX = new RawDataSet(xxr1 - xxr0, yyr1 - yyr0, zzr1 - zzr0, data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());

		RawDataSet* dataXObject = NULL;

		if (ObjectListItem != NULL)
		{
			objectData = ObjectListItem->GetData()->GetRawData();
			if (objectData->CompareWithOtherDataSet(data) == true)
			{
				QMessageBox msgBox;
				msgBox.setText("Question ");
				msgBox.setInformativeText("Object Data with same size detected - crop it? ");
				msgBox.setStandardButtons(QMessageBox::Yes | QMessageBox::No);
				msgBox.setDefaultButton(QMessageBox::No);
				int ret = msgBox.exec();

				if (ret == QMessageBox::Yes)
				{
					dataXObject = new RawDataSet(xxr1 - xxr0, yyr1 - yyr0, zzr1 - zzr0, data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());

				}

			}

		}


		double origin[3] = { bounds[0] * origSc[0], bounds[2] * origSc[1], bounds[4] * origSc[2] };//{xxr0*data->GetXscale(),yyr0*data->GetYscale(),zzr0*data->GetZscale()};

		dataX->SetOrigin(origin);
		dataX->dicomMinValue = data->dicomMinValue;
		dataX->dicomLevelValue = data->dicomLevelValue;
		dataX->dicomWindowWidthValue = data->dicomWindowWidthValue;
		dataX->dicomRescaleValue = data->dicomRescaleValue;

		QString name;
		name = data->GetRawDataSetName();
		name.append(" - Cropped");
		dataX->SetRawDataSetName(name);

		dataX->dicomMinValue = data->dicomMinValue;
		dataX->dicomLevelValue = data->dicomLevelValue;
		dataX->dicomWindowWidthValue = data->dicomWindowWidthValue;
		dataX->dicomRescaleValue = data->dicomRescaleValue;

		for (j = 0; j < yyr1 - yyr0; j++)
			for (k = 0; k < zzr1 - zzr0; k++)
				memcpy((dataX->GetDataArray() + j * dataX->GetNx() + k * dataX->GetSliceSize()), (data->GetDataArray() + (yyr0 + j) * data->GetNx() + (zzr0 + k) * data->GetSliceSize() + xxr0), sizeof(unsigned short) * (xxr1 - xxr0));


		if (dataXObject != NULL)
		{
			dataXObject->SetOrigin(origin);
			dataXObject->dicomMinValue = objectData->dicomMinValue;
			dataXObject->dicomLevelValue = objectData->dicomLevelValue;
			dataXObject->dicomWindowWidthValue = objectData->dicomWindowWidthValue;
			dataXObject->dicomRescaleValue = objectData->dicomRescaleValue;

			QString name;
			name = objectData->GetRawDataSetName();
			name.append(" - Cropped");
			dataXObject->SetRawDataSetName(name);

			dataXObject->dicomMinValue = objectData->dicomMinValue;
			dataXObject->dicomLevelValue = objectData->dicomLevelValue;
			dataXObject->dicomWindowWidthValue = objectData->dicomWindowWidthValue;
			dataXObject->dicomRescaleValue = objectData->dicomRescaleValue;

			for (j = 0; j < yyr1 - yyr0; j++)
				for (k = 0; k < zzr1 - zzr0; k++)
					memcpy((dataXObject->GetDataArray() + j * dataXObject->GetNx() + k * dataXObject->GetSliceSize()), (objectData->GetDataArray() + (yyr0 + j) * objectData->GetNx() + (zzr0 + k) * objectData->GetSliceSize() + xxr0), sizeof(unsigned short) * (xxr1 - xxr0));

		}

		if (t3d == true)
			SlotShowHideVolume(10);
		DataSet* dataset = NULL;
		if (dataXObject != NULL)
		{
			dataset = new DataSet(dataXObject, Pal, NumberOfMasks);
			dataset->SetNewPalette(Pal, PalNr, PalInvert);
			DataSetList->InsertItem(dataset);
			//	ObjectDataPos = DataSetList->GetCurrentItemPos();
		//		ObjectListItem=DataSetList->GetCurrentListItem();
			GUIPanel->SlotInsertRawDataItem(dataset, DataSetList);

			//SlotRawTreeWidgetItemClicked2(ObjectListItem->GetData()->GetTreeWidgetItem(), 3);//zaznacz

			//SlotSetNewRawDataSet(dataset->GetTreeWidgetItem());
		}




		InsertRawDataSet(dataX);

		if (dataXObject != NULL)
		{
			SlotRawTreeWidgetItemClicked2(dataset->GetTreeWidgetItem(), 3);//zaznaczam jako obiekt
		}

		if (t3d == true)
			SlotShowHideVolume(10);
		RTimer.Stop();
	}



}
