void MainWindow::SlotRemovePart()
{
	if (data != NULL)
	{
		int i, j, k;

		RTimer.Start("Removing Section");

		int xxr0, xxr1, yyr0, yyr1, zzr0, zzr1;

		int InspX = (int)(GUIPanel->InspectionXSizeSlider->value() / 2.0);
		int InspY = (int)(GUIPanel->InspectionYSizeSlider->value() / 2.0);
		int InspZ = (int)(GUIPanel->InspectionZSizeSlider->value() / 2.0);

		int rx = data->GetNx();
		int ry = data->GetNy();
		int rz = data->GetNz();



		xxr0 = ((PosX - InspX) > 0) ? PosX - InspX : 0;
		yyr0 = ((PosY - InspY) > 0) ? PosY - InspY : 0;
		zzr0 = ((PosZ - InspZ) > 0) ? PosZ - InspZ : 0;

		xxr1 = ((PosX + InspX) < rx) ? PosX + InspX : rx - 1;
		yyr1 = ((PosY + InspY) < ry) ? PosY + InspY : ry - 1;
		zzr1 = ((PosZ + InspZ) < rz) ? PosZ + InspZ : rz - 1;



		RawDataSet* dataX = new RawDataSet(data->GetNx(), data->GetNy(), data->GetNz(), data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());


		QString name;
		name = data->GetRawDataSetName();
		name.append(" - Part Removed");
		dataX->SetRawDataSetName(name);

		memcpy(dataX->GetDataArray(), data->GetDataArray(), sizeof(unsigned short) * data->GetVolumeSize());
		int temp;
		for (j = 0; j < yyr1 - yyr0 + 1; j++)
			for (k = 0; k < zzr1 - zzr0 + 1; k++)
				for (i = 0; i < xxr1 - xxr0 + 1; i++)
				{
					temp = (yyr0 + j) * data->GetNx() + (zzr0 + k) * data->GetSliceSize() + xxr0;
					*(dataX->GetDataArray() + temp + i) = Histogram->GetLowerThreshold();

				}
		//memset((dataX->GetDataArray()+(yyr0+j)*data->GetNx()+(zzr0+k)*data->GetSliceSize()+xxr0),0,sizeof(unsigned short)*(xxr1-xxr0));
		double origX[3];
		data->GetOrigin(origX);
		dataX->SetOrigin(origX);
		dataX->dicomMinValue = data->dicomMinValue;
		dataX->dicomLevelValue = data->dicomLevelValue;
		dataX->dicomWindowWidthValue = data->dicomWindowWidthValue;
		dataX->dicomRescaleValue = data->dicomRescaleValue;


		InsertRawDataSet(dataX);

		RTimer.Stop();
	}


}

