void   MainWindow::SlotSaveRawData(int FileEndian)
{
	if (MainListItem != NULL)
	{
		//QString filename = QFileDialog::getOpenFileName(this, FileDefaultDir, "*.dat");
		QString filename = QFileDialog::getSaveFileName(this, "", FileDefaultDir + "/" + data->GetRawDataSetName(), "*.dat");
		if (!filename.isEmpty())
		{
			data->SaveRawDataSet(filename, FileEndian);

			QString tt;
			tt = filename;
			if (tt.mid(tt.length() - 4, 4) == ".dat")
				tt.remove(tt.length() - 4, 4);
			int pos = tt.lastIndexOf("/");
			if (pos >= 0)
				tt.remove(0, pos + 1);

			data->SetRawDataSetName(tt);
			//GUIPanel->RawDataListView->currentIndex()->setText(0,tt);

			SlotUpdateDefaultDir(filename);
		}
	}
}
