void   MainWindow::SlotLoadRawDataMaskAsUCharArray(const QString& maskBinaryName)
{

	if (MainListItem != NULL)
	{
		int n[3];
		double scale[3];
		double origin[3];
		data->GetN(n);
		data->GetScale(scale);
		data->GetOrigin(origin);

		QFileInfo check_file(maskBinaryName);
		// check if file exists and if yes: Is it really a file and no directory?
		if ((check_file.exists() && check_file.isFile()))
		{
			int size = check_file.size();

			int volSize = data->GetVolumeSize();

			if (size == volSize)
			{
				//teraz wczytam jako inknown i zrobie maske


				if (MaskData == NULL)
				{
					MaskData = new unsigned char[volSize];

				}


				QFile f(maskBinaryName);
				if (f.open(QIODevice::ReadOnly))
				{
					f.read((char*)MaskData, volSize);
					f.close();


					chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
					SagittalView->InsertMaskData(MaskData);
					CoronalView->InsertMaskData(MaskData);
					SlotInsertNewMask();

					SlotUpdateDefaultDir(maskBinaryName, 0);
					this->SlotUpdateVolumeMask();

					RawDataSet* labelData = new RawDataSet(n, scale, origin, 0, true);
					labelData->SetRawDataSetName(data->GetRawDataSetName() + "-mask");
					unsigned short* q = labelData->GetDataArray();
					for (int i = 0; i < volSize; ++i)
					{
						q[i] = static_cast<unsigned short>(MaskData[i]);
					}
					InsertRawDataSet(labelData);

				}





			}
		};



		////if (MainListItem->GetData()->GetMasks()->LoadMaskDataSetAndCombineWithCurrent(fn, GUIPanel->FillModeCombo->currentIndex(), MaskData))
		//{
		//	//if (MaskData != NULL)	delete[]MaskData;
		//	//MaskData = MainListItem->GetData()->GetMasks()->GetMask();

		//	if (MaskData == NULL) MaskData = new unsigned char[data->GetVolumeSize()];
		//	MainListItem->GetData()->GetMasks()->GetMask(MaskData);

		//	chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
		//	SagittalView->InsertMaskData(MaskData);
		//	CoronalView->InsertMaskData(MaskData);
		//	SlotUpdateDefaultDir(fn, 0);
		//	this->SlotUpdateVolumeMask();
		//}

	}
}
