void   MainWindow::SlotSaveRawDataMaskAsUCharArray(const QString& filename)
{
	if (!filename.isEmpty())
	{
		if (MainListItem != NULL)
		{
			if (MaskData != NULL)
			{
				QString	 filename2;
				FILE* plik;

				filename2 = filename;
				if (filename2.lastIndexOf(".mask") == -1)
					filename2 += ".mask";





				QFile file(filename2);
				if (file.open(QIODevice::WriteOnly))
				{
					file.write((const char*)MaskData, data->GetVolumeSize() * sizeof(unsigned char));
					file.close();
				}
				else
				{
					emit SendMessage("Problem witgh file");
				}

			}
			else
			{
				emit SendMessage("no mask");
			}
		}
		else
		{
			emit SendMessage("no raw data");
		}
	}
}
