void   MainWindow::SlotLive3DPointer(int x, int y)
{
	if (VolumePointerExists == true)
		if (SurfaceDataList->GetNumberOfItems() >= 0)
		{
			int Nr = SurfaceDataList->GetNumberOfItems();

			PolygonSurfaceData* Data;
			QString name;
			vtkSmartPointer <vtkPropCollection> props = vtkSmartPointer <vtkPropCollection>::New();
			vtkSmartPointer <vtkPropPicker> picker = vtkSmartPointer <vtkPropPicker> ::New();
			for (int i = 0; i < Nr; i++)
			{
				Data = SurfaceDataList->GetItemAtPos(i)->GetData();
				if (Data->GetVProperty()->GetOpacity() > 0)
					props->AddItem(Data->GetVActor());
			}

			int nr = picker->PickProp(x, y, VWidget->Renderer, props);
			double point[3];
			picker->GetPickPosition(point);
			//if (fabs(point[2])>0) 
			{
				SlotMoveSphereActor(point, true, 1);
				qWarning() << ("x: " + QString::number(x) + " y: " + QString::number(y) + " (" + QString::number(point[0]) + " " + QString::number(point[1]) + " " + QString::number(point[2]));

			}
		}


}
//--------------------------------------------------------
void   MainWindow::SlotMoveSphereActor(double* pos, bool repaint, int mode)

{
	if (mode == 0)
	{
		if (data != NULL)
		{
			int point[3];
			double sc0[3];
			double origin[3];
			int i;
			data->GetScale(sc0);
			data->GetOrigin(origin);
			for (i = 0; i < 3; i++)
				point[i] = (pos[i] - origin[i]) / sc0[i];

			bool problem = false;
			int nn[3];
			data->GetN(nn);
			for (i = 0; i < 3; i++)
			{
				if ((point[i] < 0) || (point[i] > nn[i] - 1)) { problem = true; break; };
			}

			if (problem == false)
			{
				TransversalView->SetSlice(point[0], point[1], point[2]);
				CoronalView->SetSlice(point[0], point[1], point[2]);
				SagittalView->SetSlice(point[0], point[1], point[2]);
			}

			emit signalEmitTransversalPos(point[0], point[1]);
		}
	}

	if (VolumePointerExists == true)
	{
		SphereActor->SetPosition(pos);
		XPointerActor->SetPosition(pos);
		YPointerActor->SetPosition(pos);
		ZPointerActor->SetPosition(pos);


		if (repaint == true)VWidget->Interactor->repaint();


	}
	int i;

	double tol = 1e-5;

	if ((fabs(selectedPrevDoublePoint[0] - selectedDoublePoint[0]) > tol) ||
		(fabs(selectedPrevDoublePoint[1] - selectedDoublePoint[1]) > tol) ||
		(fabs(selectedPrevDoublePoint[2] - selectedDoublePoint[2]) > tol))
	{


		for (i = 0; i < 3; i++)
		{
			selectedPrevDoublePoint[i] = selectedDoublePoint[i];
		}

	}
	//	Slot3DFilterLiveUpdate()
	for (i = 0; i < 3; i++)
	{
		selectedDoublePoint[i] = pos[i];
	}
	qWarning() << (QString::number(this->selectedDoublePoint[0]) + " " + QString::number(this->selectedDoublePoint[1]) + " " + QString::number(this->selectedDoublePoint[2]) + " double" + "   prev:" + QString::number(this->selectedPrevDoublePoint[0]) + " " + QString::number(this->selectedPrevDoublePoint[1]) + " " + QString::number(this->selectedPrevDoublePoint[2]));
}
//-------------------------------------------------
void   MainWindow::SlotMoveSphereActor(int x, int y, int z)
{
	if ((SelectedPoint[0] != x) || (SelectedPoint[1] != y) || (SelectedPoint[2] != z))
	{

		double pos[3];
		SelectedPoint[0] = x;
		SelectedPoint[1] = y;
		SelectedPoint[2] = z;


		double origin[3], scale[3];
		data->GetOrigin(origin);
		data->GetScale(scale);

		for (int i = 0; i < 3; i++)
		{
			pos[i] = origin[i] + SelectedPoint[i] * scale[i];
		}

		for (int i = 0; i < 3; i++)
		{
			selectedDoublePoint[i] = pos[i];
		}
		if (((this->isVolumeVisible) && (Planes3D == true))) SlotShowHide3DSlices();
		if (VolumePointerExists == true)
		{
			SphereActor->SetPosition(pos);
			XPointerActor->SetPosition(pos);
			YPointerActor->SetPosition(pos);
			ZPointerActor->SetPosition(pos);

			VWidget->Interactor->repaint();
		}
	}
}


