void MainWindow::SlotChangeBackgroundColor()
{
	QColor Bck1Col = BckColor;
	BckColor = QColorDialog::getColor(Bck1Col);
	if (BckColor.isValid() == true)
	{
		VWidget->SlotChangeBackgroundColor(BckColor.red(), BckColor.green(), BckColor.blue());

		double colRGB[3];

		colRGB[0] = BckColor.red() / 255.0;
		colRGB[1] = BckColor.green() / 255.0;
		colRGB[2] = BckColor.blue() / 255.0;


		QSettings sett(configIniName, QSettings::IniFormat);
		QString txt;
		sett.beginGroup("3DView");



		for (int i = 0; i < 3; i++)
		{
			bacground3DCol[i] = colRGB[i];
		}
		sett.setValue("Background3DRed", (int)(BckColor.red()));
		sett.setValue("Background3DGreen", (int)(BckColor.green()));
		sett.setValue("Background3DBlue", (int)(BckColor.blue()));

		sett.endGroup();
		VWidget->setBackgroundColor(colRGB);
		VWidget->Interactor->repaint();

	}

}


