//-----------

void	MainWindow::showHideVolume(bool mode)
{
	if (data != NULL)
	{

		if (mode == true)
		{
			UpdateVolume();
			GUIPanel->showCropLines2DCheckBox->setChecked(true);
		}
		else
		{
			VWidget->Renderer->RemoveVolume(Volume);
			//renderer->RemoveVolume(Volume);
			if (Volume->GetMapper() != NULL)
			{
				(Volume->GetMapper())->Delete();
				Volume->SetMapper(NULL);
			}
			GUIPanel->showCropLines2DCheckBox->setChecked(false);
			VWidget->Interactor->repaint();
		}
	}
}
//------------------------------

void	MainWindow::showHideVolumePointer(bool mode)
{
	if (data != NULL)
	{

		if (mode == true)
		{
			VWidget->Renderer->AddActor(SphereActor);
			VWidget->Renderer->AddActor(XPointerActor);
			VWidget->Renderer->AddActor(YPointerActor);
			VWidget->Renderer->AddActor(ZPointerActor);
			VolumePointerExists = true;
			VWidget->Interactor->repaint();
		}
		else
		{
			VWidget->Renderer->RemoveActor(SphereActor);
			VWidget->Renderer->RemoveActor(XPointerActor);
			VWidget->Renderer->RemoveActor(YPointerActor);
			VWidget->Renderer->RemoveActor(ZPointerActor);
			VolumePointerExists = false;
			VWidget->Interactor->repaint();
		}
	}
}

