	////	L00->setAutoMask(true);
	ResizeWidget->setLayout(new QVBoxLayout());


	SizeLabel = new QLabel("Size	(0.5/250.0) ", ResizeWidget);
	ResizeWidget->layout()->addWidget(SizeLabel);
	//	SizeLabel->setAutoMask(true);
	SizeSlider = new QSlider(Qt::Horizontal, ResizeWidget);
	ResizeWidget->layout()->addWidget(SizeSlider);
