void MainWindow::Grab3DWindow(QString filename)
{
	if (filename.isEmpty())
	{

		if (GrabWindowPath.isEmpty())
		{
			QString fn = QFileDialog::getExistingDirectory(this, "", FileDefaultDir);
			if (fn.isEmpty()) return;
			GrabWindowPath = fn + "/";
		}
	}

	vtkWindowToImageFilter* Filterek;
	{
		Filterek = vtkWindowToImageFilter::New();
		Filterek->SetInput(VWidget->Interactor->GetRenderWindow());
		Filterek->Update();
	}

	if ((!GrabWindowPath.isEmpty()) || (!filename.isEmpty()))
	{
		QString name;
		QString nameStereo;
		if (filename.isEmpty())
		{

			PictureIndex++;
			name = GrabWindowPath + GrabWindowName;
			nameStereo = QString(name + "-stereo-%2.jpg").arg(PictureIndex, 7, 10, QChar('0'));
			if (PictureIndex < 1000000) name += "0";
			if (PictureIndex < 100000) name += "0";
			if (PictureIndex < 10000) name += "0";
			if (PictureIndex < 1000) name += "0";
			if (PictureIndex < 100) name += "0";
			if (PictureIndex < 10) name += "0";
			name += QString::number(PictureIndex);

		}
		else
		{
			name = filename;
			nameStereo = filename + "stereo.jpg";
		}

		if (name.lastIndexOf(".jpg") == -1)
			name += ".jpg";

		/*if (stereoWidget && stereoWidget->isVisible()) {
			stereoWidget->grabCurrent(nameStereo);
		}
		else {*/
		if (Volume->GetMapper() != NULL) Volume->Update();

		VWidget->Renderer->ResetCameraClippingRange();
		VWidget->Interactor->GetRenderWindow()->Render();
		Filterek->Modified();
		vtkImageData* IData = Filterek->GetOutput();
		IData->Modified();

		int size[3];
		IData->GetDimensions(size);
		//		int s=size[0]*size[1];
		if (img3D == NULL)
		{
			img3D = new QImage(size[0], size[1], QImage::Format_RGB32);
		}
		else
			if ((img3D->size().width() != size[0]) || (img3D->size().height() != size[1]))
			{
				delete img3D;
				img3D = new QImage(size[0], size[1], QImage::Format_RGB32);
			}

		//QImage Image(size[0],size[1],32);
		unsigned char* pixeldata = img3D->bits();//new unsigned char[s*4];
		unsigned char* pixeldataV = (unsigned char*)IData->GetScalarPointer();
		int i, j;
		int step1 = 0;
		int	step2 = (size[0] * (size[1] - 1)) * 3;

		for (j = 0; j < size[1]; j++)
		{
			for (i = 0; i < size[0]; i++)
			{
				pixeldata[step1++] = pixeldataV[step2 + 2];
				pixeldata[step1++] = pixeldataV[step2 + 1];
				pixeldata[step1++] = pixeldataV[step2];
				step2 += 3;
				step1++;
			}
			step2 -= (2 * size[0]) * 3;
		}
		img3D->save(name, "JPG", 98);
		IData = NULL;
	}
	//	}

		/*if (!stereoWidget || !stereoWidget->isVisible()) {
			Filterek->Delete();
		}*/
}
