QWidget* MainWindow::getSelectedGrabWidget()
{
	stereoFlag = false;
	bool states[11];
	int i;
	for (i = 0; i < 11; i++)
	{
		states[i] = GUIPanel->videoAction[i]->isChecked();
	}

	QWidget* grabWidget = NULL;
	if (states[5] == true)
	{
		grabWidget = this;
	}
	else
		if (states[6] == true)
		{
			//3d 
			grabWidget = VWidget;
		}
		else
			if (states[7] == true)
			{
				//stereo
				/*if (stereoWidget && stereoWidget->isVisible())
				{
					stereoFlag = true;
				}*/
			}
			else
				if (states[8] == true)
				{
					grabWidget = this->TransversalView;
				}
				else
					if (states[9] == true)
					{
						grabWidget = this->SagittalView;
					}
					else
						if (states[10] == true)
						{
							grabWidget = this->CoronalView;
						}
	return grabWidget;

}
void MainWindow::SlotGrabApplicationWindow()
{

	if (GrabWindowPath.isEmpty())
	{
		QString fn = QFileDialog::getExistingDirectory(this, "", FileDefaultDir);
		if (fn.isEmpty()) return;
		GrabWindowPath = fn + "/";
	}

	QString name;
	PictureIndex++;
	//name=GrabWindowPath
	//QString imgName=GrabWindowName;
	if (PictureIndex < 1000000) name += "0";
	if (PictureIndex < 100000) name += "0";
	if (PictureIndex < 10000) name += "0";
	if (PictureIndex < 1000) name += "0";
	if (PictureIndex < 100) name += "0";
	if (PictureIndex < 10) name += "0";
	name += QString::number(PictureIndex);

	QString imgName = GrabWindowName + name;
	name = GrabWindowPath + imgName;
	QWidget* grabWidget = this->getSelectedGrabWidget();


	if (grabWidget != NULL)
	{
		SlotSaveGrabWidgetWindow(grabWidget, name);
		SlotAddLogText("Image " + imgName + " saved");
	}
}
