//----------------------------------------
void MainWindow::SlotShowHideAxes()
{
	if (data != NULL)
	{
		is3DAxesVisible = !is3DAxesVisible;// OtherMenu->setItemChecked(8, !OtherMenu->isItemChecked(8));

		if ((is3DAxesVisible == false) && (AxesExists == true))
		{
			VWidget->Renderer->RemoveActor(AxeXActor);
			VWidget->Renderer->RemoveActor(AxeYActor);
			VWidget->Renderer->RemoveActor(AxeZActor);
			VWidget->Renderer->RemoveActor(ConeXActor);
			VWidget->Renderer->RemoveActor(ConeYActor);
			VWidget->Renderer->RemoveActor(ConeZActor);

			ConeXActor->Delete();
			ConeYActor->Delete();
			ConeZActor->Delete();
			AxeXActor->Delete();
			AxeYActor->Delete();
			AxeZActor->Delete();
			AxesExists = false;

		}
		else if (is3DAxesVisible == true)
		{
			int sizeX = Round(data->GetNx() * data->GetXscale());
			int sizeY = Round(data->GetNy() * data->GetYscale());
			int sizeZ = Round(data->GetNz() * data->GetZscale());
			int Radius = 1;

			vtkCylinderSource* Axe = vtkCylinderSource::New();
			Axe->SetResolution(10);
			vtkConeSource* Cone = vtkConeSource::New();
			Cone->SetResolution(50);
			AxeXActor = vtkActor::New();
			AxeYActor = vtkActor::New();
			AxeZActor = vtkActor::New();
			ConeXActor = vtkActor::New();
			ConeYActor = vtkActor::New();
			ConeZActor = vtkActor::New();

			vtkPolyDataMapper* AxeXMapper = vtkPolyDataMapper::New();
			vtkPolyDataMapper* AxeYMapper = vtkPolyDataMapper::New();
			vtkPolyDataMapper* AxeZMapper = vtkPolyDataMapper::New();
			vtkPolyDataMapper* ConeXMapper = vtkPolyDataMapper::New();
			vtkPolyDataMapper* ConeYMapper = vtkPolyDataMapper::New();
			vtkPolyDataMapper* ConeZMapper = vtkPolyDataMapper::New();


			AxeXMapper->SetInputConnection(Axe->GetOutputPort());
			AxeXActor->SetMapper(AxeXMapper);
			AxeXActor->SetPosition(sizeX / 2.0, 0, 0);
			AxeXActor->SetOrientation(0, 0, 90.0);
			AxeXActor->GetProperty()->SetColor(51.0 / 255.0, 139.0 / 255.0, 107.0 / 255.0);
			AxeXActor->SetScale(Radius * 2.0, sizeX, Radius * 2.0);

			AxeYMapper->SetInputConnection(Axe->GetOutputPort());
			AxeYActor->SetMapper(AxeYMapper);
			AxeYActor->SetPosition(0, sizeY / 2, 0);
			AxeYActor->SetOrientation(0, 0, 0);
			AxeYActor->GetProperty()->SetColor(122.0 / 255.0, 100.0 / 255.0, 139.0 / 255.0);
			AxeYActor->SetScale(Radius * 2.0, sizeY, Radius * 2.0);

			AxeZMapper->SetInputConnection(Axe->GetOutputPort());
			AxeZActor->SetMapper(AxeZMapper);
			AxeZActor->SetOrientation(90, 0, 0);
			AxeZActor->SetPosition(0, 0, sizeZ / 2.0);
			AxeZActor->GetProperty()->SetColor(68.0 / 255.0, 109.0 / 255.0, 139.0 / 255.0);
			AxeZActor->SetScale(Radius * 2.0, sizeZ, Radius * 2.0);

			ConeXMapper->SetInputConnection(Cone->GetOutputPort());
			ConeXActor->SetMapper(ConeXMapper);
			ConeXActor->SetPosition(sizeX + 2.0, 0, 0);
			ConeXActor->SetOrientation(0, 0, 0);
			ConeXActor->GetProperty()->SetColor(51.0 / 255.0, 139.0 / 255.0, 107.0 / 255.0);
			ConeXActor->SetScale(8.0, Radius * 4.0, Radius * 4.0);

			ConeYMapper->SetInputConnection(Cone->GetOutputPort());
			ConeYActor->SetMapper(ConeYMapper);
			ConeYActor->SetPosition(0, sizeY + 2.0, 0);
			ConeYActor->SetOrientation(0, 0, 90.0);
			ConeYActor->GetProperty()->SetColor(122.0 / 255.0, 100.0 / 255.0, 139.0 / 255.0);
			ConeYActor->SetScale(8.0, Radius * 4.0, Radius * 4.0);
			ConeZMapper->SetInputConnection(Cone->GetOutputPort());
			ConeZActor->SetMapper(ConeZMapper);
			ConeZActor->SetPosition(0, 0, sizeZ + 2.0);
			ConeZActor->SetOrientation(0, -90, 0);
			ConeZActor->GetProperty()->SetColor(68.0 / 255.0, 109.0 / 255.0, 139.0 / 255.0);
			ConeZActor->SetScale(8.0, Radius * 4.0, Radius * 4.0);

			VWidget->Renderer->AddActor(AxeYActor);
			VWidget->Renderer->AddActor(AxeXActor);
			VWidget->Renderer->AddActor(AxeZActor);
			VWidget->Renderer->AddActor(ConeXActor);
			VWidget->Renderer->AddActor(ConeYActor);
			VWidget->Renderer->AddActor(ConeZActor);

			AxeXMapper->Delete();
			AxeYMapper->Delete();
			AxeZMapper->Delete();
			ConeXMapper->Delete();
			ConeYMapper->Delete();
			ConeZMapper->Delete();

			Axe->Delete();
			Cone->Delete();

			AxesExists = true;
		}

		VWidget->Renderer->ResetCamera();
		VWidget->Renderer->ViewToWorld();
		VWidget->Interactor->repaint();
	}
}
//------------------------------------------------------------------
void MainWindow::SlotCreateAxePointer()
{
	int Radius = 0.001;

	XPointerActor = vtkActor::New();
	YPointerActor = vtkActor::New();
	ZPointerActor = vtkActor::New();

	vtkCylinderSource* Axe = vtkCylinderSource::New();
	Axe->SetResolution(10);
	vtkPolyDataMapper* AxeXMapper = vtkPolyDataMapper::New();
	vtkPolyDataMapper* AxeYMapper = vtkPolyDataMapper::New();
	vtkPolyDataMapper* AxeZMapper = vtkPolyDataMapper::New();

	//AxeXMapper->SetInputData(Axe->GetOutput());
	AxeXMapper->SetInputConnection(Axe->GetOutputPort());
	XPointerActor->SetMapper(AxeXMapper);
	XPointerActor->SetPosition(0, 0, 0);
	XPointerActor->SetOrientation(0, 0, 90.0);
	XPointerActor->SetScale(Radius * 2.0, 5, Radius * 2.0);

	//AxeYMapper->SetInputData(Axe->GetOutput());
	AxeYMapper->SetInputConnection(Axe->GetOutputPort());
	YPointerActor->SetMapper(AxeYMapper);
	YPointerActor->SetPosition(0, 0, 0);
	YPointerActor->SetOrientation(0, 0, 0);
	YPointerActor->SetScale(Radius * 2.0, 5, Radius * 2.0);

	//AxeZMapper->SetInputData(Axe->GetOutput());
	AxeZMapper->SetInputConnection(Axe->GetOutputPort());
	ZPointerActor->SetMapper(AxeZMapper);
	ZPointerActor->SetOrientation(90, 0, 0);
	ZPointerActor->SetPosition(0, 0, 0);
	ZPointerActor->SetScale(Radius * 2.0, 5, Radius * 2.0);


	XPointerActor->SetProperty(VolumePointerProp);
	YPointerActor->SetProperty(VolumePointerProp);
	ZPointerActor->SetProperty(VolumePointerProp);

	AxeXMapper->Delete();
	AxeYMapper->Delete();
	AxeZMapper->Delete();
	Axe->Delete();

}
//-----------------------------------------------------------------
void MainWindow::SlotUpdate3DSlicesTextureAndPos()
{
	if (Planes3D == true)
	{
		if (DataSetList->GetNumberOfItems() >= 1)
		{
			RawDataSet* dataT;


			if (cycleTabList != NULL)
			{
				int cPos = cyclePos % cycleTabSize;
				if ((cycleTabSize > 1) && (cPos >= 0) && (cPos < cycleTabSize))
				{
					if ((DataSetList->GetItemAtPos(cycleTabList[cPos])) != NULL)
						dataT = DataSetList->GetItemAtPos(cycleTabList[cPos])->GetData()->GetRawData();
					else
						dataT = data;

				}
				else
					dataT = data;
			}
			else
				dataT = data;


			//---------------------------------
			//---------------------------------

			vtkImageData* Image;
			unsigned short* pointer;

			int PLL;
			int I, i, j;
			PLL = (is3DPlanesVisible == true) ? 3 : NumberOfPlanes;

			int z = Round((double)dataT->GetNz() / (NumberOfPlanes + 1));
			double zz = dataT->GetNz() * dataT->GetZscale() / (NumberOfPlanes + 1);
			int sizeX = Round(dataT->GetNx() * dataT->GetXscale());
			int sizeY = Round(dataT->GetNy() * dataT->GetYscale());
			int sizeZ = Round(dataT->GetNz() * dataT->GetZscale());

			for (I = 0; I < PLL; I++)
			{
				Image = planeActor[I]->GetTexture()->GetInput();
				if (is3DPlanesVisible == true)
				{

					switch (I)
					{
					case 0:

						pointer = (unsigned short*)Image->GetScalarPointer();
						for (j = 0; j < dataT->GetNy(); j++)
							for (i = 0; i < dataT->GetNx(); i++)
								*(pointer++) = dataT->GetVoxelValue(i, j, SelectedPoint[2]);
						planeActor[I]->SetPosition((double)(sizeX / 2.0), (double)(sizeY / 2.0), (double)(SelectedPoint[2]) * dataT->GetZscale());

						break;

					case 1:
						pointer = (unsigned short*)Image->GetScalarPointer();
						for (j = 0; j < dataT->GetNz(); j++)
							for (i = 0; i < dataT->GetNy(); i++)
								*(pointer++) = dataT->GetVoxelValue(SelectedPoint[0], i, j);

						planeActor[I]->SetPosition((double)(SelectedPoint[0]) * dataT->GetXscale(), (double)(sizeY / 2.0), (double)(sizeZ / 2.0));
						break;

					case 2:
						pointer = (unsigned short*)Image->GetScalarPointer();
						for (j = 0; j < dataT->GetNz(); j++)
							for (i = 0; i < dataT->GetNx(); i++)
								*(pointer++) = dataT->GetVoxelValue(i, SelectedPoint[1], j);
						planeActor[I]->SetPosition((double)(sizeX / 2.0), (double)(SelectedPoint[1]) * dataT->GetYscale(), (double)(sizeZ / 2.0));
						break;
					}
				}
				else
				{
					pointer = (unsigned short*)Image->GetScalarPointer();
					memcpy(pointer, dataT->GetDataArray() + Round(z + ((dataT->GetNz() - 2 * z) * I) / (NumberOfPlanes - 1)) * dataT->GetSliceSize(), dataT->GetSliceSize() * sizeof(unsigned short));
					planeActor[I]->SetPosition((double)(sizeX / 2.0), (double)(sizeY / 2.0), (double)(zz + ((sizeZ - 2 * zz) * I) / (NumberOfPlanes - 1)));
				}

				planeActor[I]->GetTexture()->Modified();
				//--------------------------------
				//--------------------------------
			}
			if (cycleSurfaceTabList == NULL)
				VWidget->RepaintWidget();

		}

	}
}
//-----------------------------------------------------------------
void MainWindow::SlotShowHide3DSlices()
{
	if (DataSetList->GetNumberOfItems() >= 1)
	{
		RawDataSet* dataT;


		if (cycleTabList != NULL)
		{
			int cPos = cyclePos % cycleTabSize;
			if ((cycleTabSize > 1) && (cPos >= 0) && (cPos < cycleTabSize))
			{
				if ((DataSetList->GetItemAtPos(cycleTabList[cPos])) != NULL)
					dataT = DataSetList->GetItemAtPos(cycleTabList[cPos])->GetData()->GetRawData();
				else
					dataT = data;

			}
			else
				dataT = data;
		}
		else
			dataT = data;

		double origin[3];
		data->GetOrigin(origin);


		if (dataT != NULL)
		{
			//		double Transp=1.0;

			int I;
			int i, j;

			if (Planes3D == true)
			{
				for (i = 0; i < NumberOfPlanes; i++)
				{
					VWidget->Renderer->RemoveActor(planeActor[i]);
					planeActor[i]->Delete();
				}
				theLUT->Delete();
			}

			if (is3DPlanesVisible == true)
				NumberOfPlanes = 3;
			else
				NumberOfPlanes = PlaneNumberSlider->value();

			vtkPlaneSource* plane;
			vtkPolyDataMapper* planeMapper;
			vtkTexture* texture;
			int sizeX = Round(dataT->GetNx() * dataT->GetXscale());
			int sizeY = Round(dataT->GetNy() * dataT->GetYscale());
			int sizeZ = Round(dataT->GetNz() * dataT->GetZscale());

			int Range = dataT->GetMaxValue();
			int LowerThreshold = Round(Histogram->GetLowerThreshold() * 255.0 / Range);
			int UpperThreshold = Round(Histogram->GetUpperThreshold() * 255.0 / Range);

			theLUT = vtkLookupTable::New();
			theLUT->SetAlphaRange(0, Range);
			theLUT->SetNumberOfColors(256);

			// kolorki

			PaletteRGBA* Palette = MainListItem->GetData()->GetPalette();

			if (StretchPalette != true)
			{
				theLUT->SetTableRange(0, Range);

				if (LowerThreshold > 0)
				{
					for (i = 0; i <= LowerThreshold; i++)
						theLUT->SetTableValue(i, 0, 0, 0, 0);
				}

				for (i = LowerThreshold; i <= UpperThreshold; i++)
				{

					theLUT->SetTableValue(i,
						(double)(Palette->R[i] / 255.0),
						(double)(Palette->G[i] / 255.0),
						(double)(Palette->B[i] / 255.0), 1.0);
				}

				if (UpperThreshold < 256)
				{
					for (i = UpperThreshold; i <= 255; i++)
						theLUT->SetTableValue(i, 0, 0, 0, 0);
				}
			}
			else
			{
				theLUT->SetTableRange(Histogram->GetLowerThreshold(), Histogram->GetUpperThreshold());


				for (i = 0; i <= 255; i++)
				{

					//	theLUT->SetTableValue(i,(double)(PalTab[PalNr*768+TempIndex]/255.0),(double)(PalTab[PalNr*768+256+TempIndex]/255.0),(double)(PalTab[PalNr*768+512+TempIndex]/255.0),1.0);

					theLUT->SetTableValue(i,
						(double)(Palette->R[i] / 255.0),
						(double)(Palette->G[i] / 255.0),
						(double)(Palette->B[i] / 255.0), 1.0);
				}


			}

			theLUT->Build();

			vtkImageData* Image;
			unsigned short* pointer;

			int PLL;
			PLL = (is3DPlanesVisible == true) ? 3 : NumberOfPlanes;

			int z = Round((double)dataT->GetNz() / (NumberOfPlanes + 1));
			double zz = dataT->GetNz() * dataT->GetZscale() / (NumberOfPlanes + 1);

			for (I = 0; I < PLL; I++)
			{
				plane = vtkPlaneSource::New();
				planeActor[I] = vtkActor::New();
				planeMapper = vtkPolyDataMapper::New();

				Image = vtkImageData::New();

				if (is3DPlanesVisible == true)
				{

					switch (I)
					{
					case 0:
						Image->SetDimensions(dataT->GetNx(), dataT->GetNy(), 1);
						Image->AllocateScalars(VTK_UNSIGNED_SHORT, 1);
						//Image->AllocateScalars();

						pointer = (unsigned short*)Image->GetScalarPointer();


						for (j = 0; j < dataT->GetNy(); j++)
							for (i = 0; i < dataT->GetNx(); i++)
								*(pointer++) = dataT->GetVoxelValue(i, j, SelectedPoint[2]);

						planeActor[I]->SetPosition(origin[0] + (double)(sizeX / 2.0), origin[1] + (double)(sizeY / 2.0), origin[2] + (double)(SelectedPoint[2]) * dataT->GetZscale());
						planeActor[I]->SetScale(sizeX, sizeY, 1.0);
						break;

					case 1:
						Image->SetDimensions(dataT->GetNy(), dataT->GetNz(), 1);
						Image->AllocateScalars(VTK_UNSIGNED_SHORT, 1);

						pointer = (unsigned short*)Image->GetScalarPointer();
						for (j = 0; j < dataT->GetNz(); j++)
							for (i = 0; i < dataT->GetNy(); i++)
								*(pointer++) = dataT->GetVoxelValue(SelectedPoint[0], i, j);

						planeActor[I]->SetPosition(origin[0] + (double)(SelectedPoint[0]) * dataT->GetXscale(), origin[1] + (double)(sizeY / 2.0), origin[1] + (double)(sizeZ / 2.0));
						planeActor[I]->SetOrientation(90, 90, 0);
						planeActor[I]->SetScale(sizeY, sizeZ, 1.0);
						break;

					case 2:

						Image->SetDimensions(dataT->GetNx(), dataT->GetNz(), 1);
						Image->AllocateScalars(VTK_UNSIGNED_SHORT, 1);

						pointer = (unsigned short*)Image->GetScalarPointer();

						for (j = 0; j < dataT->GetNz(); j++)
							for (i = 0; i < dataT->GetNx(); i++)
								*(pointer++) = dataT->GetVoxelValue(i, SelectedPoint[1], j);



						planeActor[I]->SetPosition(origin[0] + (double)(sizeX / 2.0), origin[1] + (double)(SelectedPoint[1]) * dataT->GetYscale(), origin[1] + (double)(sizeZ / 2.0));
						planeActor[I]->SetOrientation(90.0, 0, 0);
						planeActor[I]->SetScale(sizeX, sizeZ, 1.0);

						break;
					}
				}
				else
				{
					Image->SetDimensions(dataT->GetNx(), dataT->GetNy(), 1);
					Image->AllocateScalars(VTK_UNSIGNED_SHORT, 1);

					pointer = (unsigned short*)Image->GetScalarPointer();
					memcpy(pointer, dataT->GetDataArray() + Round(z + ((dataT->GetNz() - 2 * z) * I) / (NumberOfPlanes - 1)) * dataT->GetSliceSize(), dataT->GetSliceSize() * sizeof(unsigned short));
					planeActor[I]->SetPosition(origin[0] + (double)(sizeX / 2.0), origin[1] + (double)(sizeY / 2.0), origin[2] + (double)(zz + ((sizeZ - 2 * zz) * I) / (NumberOfPlanes - 1)));
					planeActor[I]->SetScale(sizeX, sizeY, 1.0);

				}

				texture = vtkTexture::New();
				texture->SetInputData(Image);
				texture->InterpolateOn();
				texture->SetLookupTable(theLUT);
				texture->SetColorModeToMapScalars();



				planeMapper->SetInputConnection(plane->GetOutputPort());
				planeActor[I]->SetMapper(planeMapper);
				planeActor[I]->SetTexture(texture);

				planeActor[I]->GetProperty()->SetOpacity(Histogram->GetLeftY());
				VWidget->Renderer->AddActor(planeActor[I]);

				planeMapper->Delete();
				texture->Delete();
				Image->Delete();
				plane->Delete();

			}

			if (Planes3D == false)
			{
				VWidget->Renderer->ResetCamera();
				VWidget->Renderer->ViewToWorld();
			}
			VWidget->Interactor->repaint();

		}
		Planes3D = true;
	}
}

