void	MainWindow::SlotCreateObjectSlicesActor()
{
	int i;

	if (ObjectPlanes3D == true)
	{
		for (i = 0; i < NumberOfPlanesO; i++)
		{
			VWidget->Renderer->RemoveActor(ObjectPlaneActor[i]);
			ObjectPlaneActor[i]->Delete();
		}
		ObjectPlanes3D = false;
	}
	else
		if (ObjectListItem != NULL)
		{
			RawDataSet* dataO = ObjectListItem->GetData()->GetRawData();
			//		double Transp=1.0;

			int I;
			int j;


			NumberOfPlanesO = PlaneNumberSlider->value();

			vtkPlaneSource* plane;
			vtkPolyDataMapper* planeMapper;
			vtkTexture* texture;


			int sizeX = Round(dataO->GetNx() * dataO->GetXscale());
			int sizeY = Round(dataO->GetNy() * dataO->GetYscale());
			int sizeZ = Round(dataO->GetNz() * dataO->GetZscale());

			int Range = dataO->GetMaxValue();

			int LowerThreshold = Round(dataO->GetMinValue() * 255.0 / Range);
			int UpperThreshold = Round(dataO->GetMaxValue() * 255.0 / Range);


			vtkLookupTable* theLUTO;
			theLUTO = vtkLookupTable::New();
			theLUTO->SetAlphaRange(0, Range);
			theLUTO->SetNumberOfColors(256);


			PaletteRGBA* Palette = (ObjectListItem->GetData()->GetPalette());
			// kolorki

			//if (StretchPalette!=true)
			{
				theLUTO->SetTableRange(0, Range);

				if (LowerThreshold > 0)
				{
					for (i = 0; i <= LowerThreshold; i++)
						theLUTO->SetTableValue(i, 0, 0, 0, 0);
				}

				for (i = LowerThreshold; i <= UpperThreshold; i++)
				{
					theLUTO->SetTableValue(i,
						(double)(Palette->R[i] / 255.0),
						(double)(Palette->G[i] / 255.0),
						(double)(Palette->B[i] / 255.0), 1.0);
				}

				if (UpperThreshold < 256)
				{
					for (i = UpperThreshold; i <= 255; i++)
						theLUTO->SetTableValue(i, 0, 0, 0, 0);
				}

			}

			theLUTO->Build();
			// paleta zrobiona
			double origin[3];
			data->GetOrigin(origin);
			vtkImageData* Image;
			unsigned short* pointer;

			int PLL;
			PLL = NumberOfPlanesO;
			//		vtkPolyData *TempPolyDataX=NULL;
			vtkTransformPolyDataFilter* TransformFilter;
			vtkTransform* Transform = NULL;

			//		vtkTriangleFilter *TFilter=NULL;
			//vtkMatrix4x4 *M=vtkMatrix4x4::New();
			vtkActor* TempActor = vtkActor::New();

			int x = Round((double)dataO->GetNx() / (NumberOfPlanesO + 1));
			double xx = dataO->GetNx() * dataO->GetXscale() / (NumberOfPlanesO + 1);

			for (I = 0; I < PLL; I++)
			{
				plane = vtkPlaneSource::New();
				ObjectPlaneActor[I] = vtkActor::New();
				planeMapper = vtkPolyDataMapper::New();

				Image = vtkImageData::New();


				Image->SetDimensions(dataO->GetNy(), dataO->GetNz(), 1);
				Image->AllocateScalars(VTK_UNSIGNED_SHORT, 1);

				pointer = (unsigned short*)Image->GetScalarPointer();
				for (j = 0; j < dataO->GetNz(); j++)
					for (i = 0; i < dataO->GetNy(); i++)
						*(pointer++) = dataO->GetVoxelValue(Round(x + ((dataO->GetNx() - 2 * x) * I) / (NumberOfPlanesO - 1)), i, j);

				TempActor->SetPosition(origin[0] + (double)(xx + ((sizeX - 2 * xx) * I) / (NumberOfPlanesO - 1)), origin[1] + (double)(sizeY / 2.0), origin[1] + (double)(sizeZ / 2.0));
				TempActor->SetScale(sizeY, sizeZ, 1.0);
				TempActor->SetOrientation(90, 90, 0);
				TempActor->SetOrigin(0, 0, 0);

				Transform = vtkTransform::New();

				Transform->SetMatrix(TempActor->GetMatrix());
				TransformFilter = vtkTransformPolyDataFilter::New();
				TransformFilter->SetInputData(plane->GetOutput());
				TransformFilter->SetTransform(Transform);

				texture = vtkTexture::New();

				texture->SetInputData(Image);
				texture->InterpolateOn();
				texture->SetLookupTable(theLUTO);
				texture->SetColorModeToMapScalars();

				planeMapper->SetInputData(TransformFilter->GetOutput());
				ObjectPlaneActor[I]->SetMapper(planeMapper);
				ObjectPlaneActor[I]->SetTexture(texture);
				ObjectPlaneActor[I]->GetProperty()->SetOpacity(Histogram->GetLeftY());

				ObjectPlaneActor[I]->Modified();
				VWidget->Renderer->AddActor(ObjectPlaneActor[I]);
				planeMapper->Delete();
				texture->Delete();
				Image->Delete();
				plane->Delete();

			}

			TempActor->Delete();
			ObjectPlanes3D = true;
		}

	//if (ObjectPlanes3D==false)
		{
			VWidget->Renderer->ResetCamera();
			VWidget->Renderer->ViewToWorld();
		}
		VWidget->Interactor->repaint();
}
