void	MainWindow::SlotRotateCenterOf3DObjectSlices(double* R)
{
	if (ObjectPlanes3D == true)
	{
		// bede przekrecal plaszczyznami
		int i;
		for (i = 0; i < NumberOfPlanesO; i++)
			ObjectPlaneActor[i]->SetOrigin(R[0], R[1], R[2]);
	}
}
