void	MainWindow::SlotTransform3DObjectSlices(double* T)
{
	if (ObjectPlanes3D == true)
	{
		// bede przekrecal plaszczyznami
		int i;
		for (i = 0; i < NumberOfPlanesO; i++)
		{
			ObjectPlaneActor[i]->SetOrientation(to_deg * T[4], to_deg * T[5], to_deg * T[6]);
			ObjectPlaneActor[i]->SetPosition(T[1], T[2], T[3]);
		}
		VWidget->Interactor->repaint();
	}
}
