void MainWindow::SlotGenerateScanlineHistogram()
{
	int i, j, k;
	int XResolution = 512;// -ile kolorkow
	int YResolution = data->GetNx();
	int temp, temp2;
	//	int size=XResolution*YResolution;

	RawDataSet* dataX = new RawDataSet(XResolution, YResolution, data->GetNz(), 1.0, 1.0, 1.0, 0.0);
	dataX->ZeroQ();
	data->FindMinMaxValue();
	//	int max=0;

	for (k = 0; k < data->GetNz(); k++)
		for (j = 0; j < data->GetNy(); j++)
			for (i = 0; i < data->GetNx(); i++)
			{
				temp2 = Round(j * (YResolution - 1) / data->GetNy());
				temp = Round((double)(data->GetVoxelValue(i, j, k) * (XResolution - 1)) / data->GetMaxValue());
				dataX->GetDataArray()[k * dataX->GetSliceSize() + temp2 * dataX->GetNx() + temp]++;
			}

	dataX->SaveRawDataSet("c:\\dataX");
	dataX->ZeroQ();
	for (k = 0; k < data->GetNz(); k++)
		for (j = 0; j < data->GetNy(); j++)
			for (i = 0; i < data->GetNx(); i++)
			{
				temp2 = Round(i * (YResolution - 1) / data->GetNx());
				temp = Round((double)(data->GetVoxelValue(i, j, k) * (XResolution - 1)) / data->GetMaxValue());
				//Bins[temp2*XResolution+temp]++;

				dataX->GetDataArray()[k * dataX->GetSliceSize() + (YResolution - temp2 - 1) * dataX->GetNx() + temp]++;
			}
	dataX->SaveRawDataSet("c:\\dataY");
	delete dataX;

}
