void MainWindow::InvertPalette(void)
{
	int i;
	int* NewPal = new int[256];
	for (i = 0; i < 256; i++)
		NewPal[i] = Palette[255 - i];

	for (i = 0; i < 256; i++)
		Palette[i] = NewPal[i];

	for (i = 0; i < 256; i++)
		NewPal[i] = Pal->R[255 - i];

	for (i = 0; i < 256; i++)
		Pal->R[i] = NewPal[i];

	for (i = 0; i < 256; i++)
		NewPal[i] = Pal->G[255 - i];

	for (i = 0; i < 256; i++)
		Pal->G[i] = NewPal[i];

	for (i = 0; i < 256; i++)
		NewPal[i] = Pal->B[255 - i];

	for (i = 0; i < 256; i++)
		Pal->B[i] = NewPal[i];

	delete[]NewPal;

	if (MainListItem != NULL)
	{
		MainListItem->GetData()->SetNewPalette(Pal, PalNr, !MainListItem->GetData()->GetPaletteInv());

		if (DataSetList->GetCurrentListItem() == MainListItem)
			GUIPanel->PaletteCombo->setCurrentIndex(PalNr);
		emit SendNewPalette();
	}

	if (Volume->GetMapper() != NULL)
		SlotSetVolumeColors();
	if (Planes3D == true)
		SlotUpdate3DSlices();
}
