void	MainWindow::SlotCalculateMaskVolume()
{
	if (data != NULL)
	{
		if (MaskData != NULL)
		{
			RTimer.Start("Mask Volume Calculation");

			int i;
			VolumeInt = 0;
			VolumeFloat = 0;

			for (i = 0; i < data->GetVolumeSize(); i++)
				if (MaskData[i] == 1) VolumeInt++;


			VolumeFloat = (double)VolumeInt * data->GetXscale() * data->GetYscale() * data->GetZscale();


			QMessageBox::about(0, "Mask Volume: ", QString::number(VolumeFloat, 'f', 6) + " mm^3");

			RTimer.Stop();
		}
	}
}
