void	MainWindow::SlotApplyScanlineSegmentation(void)
{
	if (data != NULL)
	{

		RTimer.Start("Scanline Segmentation");

		if (MaskData == NULL)
		{
			MaskData = new unsigned char[data->GetVolumeSize()];
			memset(MaskData, 0, data->GetVolumeSize());
		}

		if ((GUIPanel->ScanXCheck->isChecked() == true) || (GUIPanel->ScanYCheck->isChecked() == true) || (GUIPanel->ScanZCheck->isChecked() == true))
		{

			Segmentation* Segment = new Segmentation();

			/*	Segment->SlotScanLineSegmentation(GUIPanel->ScanXCheck->isChecked(),
					GUIPanel->ScanYCheck->isChecked(),
					GUIPanel->ScanZCheck->isChecked(),
					data, MaskData, Histogram->GetLowerThreshold(), Histogram->GetUpperThreshold(), GUIPanel->NeighSpinBox->value(), GUIPanel->PercentSpinBox->value(), GUIPanel->MaskAppendCheckBox->isChecked());
				delete Segment;*/
			SegCriterion* cr;


			unsigned short lTh = Histogram->GetLowerThreshold();
			if (lTh == 0)
			{
				RTimer.StopError("set left threshold");
				return;
			}
			unsigned short rTh = Histogram->GetUpperThreshold();
			bool revth = false;

			double neighPercentage = GUIPanel->PercentSpinBox->value() * 0.01;
			int neighType = GUIPanel->MorphologyKernelTypeSpinBox->value();
			int neighSize = GUIPanel->NeighSpinBox->value();


			bool directions[] = { GUIPanel->ScanXCheck->isChecked(),			GUIPanel->ScanYCheck->isChecked(),			GUIPanel->ScanZCheck->isChecked() };
			cr = new SegCriterionThresholds(data, lTh, rTh, rTh, revth, neighSize, neighType, neighPercentage);
			Segment->SlotScanLineSegmentation(directions, data, MaskData, cr);

			delete Segment;
			delete cr;

			UpdateSegmentationToUseCropPlanes(MaskData, data);

			chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
			SagittalView->InsertMaskData(MaskData);
			CoronalView->InsertMaskData(MaskData);
		}
		SlotInsertNewMask();

		RTimer.Stop();

	}
}
