void	MainWindow::SlotApplyFillSegmentation()
{
	if (data != NULL)
	{
		RTimer.Start("Region Growing Segmentation");
		if (MaskData == NULL)
		{
			MaskData = new unsigned char[data->GetVolumeSize()];
			memset(MaskData, 0, data->GetVolumeSize());
		}
		int  	Tolerance = GUIPanel->ToleranceValueEdit->text().toInt();
		int		LowerThreshold = Histogram->GetLowerThreshold();
		int		UpperThreshold = Histogram->GetUpperThreshold();
		int		ViewID = (GUIPanel->ThreeDimCheckBox->isChecked() == true) ? 3 : LastClickedView;

		int		Mode = GUIPanel->HomogenityCriterionCombo->currentIndex();

		int KernelSize = GUIPanel->MorphologyKernelSizeSpinBox->value();

		int KernelType = GUIPanel->MorphologyKernelTypeSpinBox->value();

		RawDataSet* ObjectData = NULL;
		Segmentation* Segment = new Segmentation();
		if ((GUIPanel->ObjectThresholdCritBox->isChecked() == true) && (ObjectListItem != NULL))
		{
			// sprawdz czy istnieje obiekt
			// zezeli tak czy rozdzielczosc jest taka sama
			// czy trhesholdy !=0
			// jesli tak to przekazac obiekt do region growingu
			// ustawic mode na ze sprawdzaniem volumenu

			ObjectData = ObjectListItem->GetData()->GetRawData();

			if ((data->GetVolumeSize() == ObjectData->GetVolumeSize()) && (UpperMemThreshold > 0))
				Segment->SlotSetSecondDataForThresholdingCriterion(ObjectData->GetDataArray(), LowerMemThreshold, UpperMemThreshold);
		}


		Segment->SlotRegionGrowingSegmentation(data, MaskData, LowerThreshold, UpperThreshold,
			Tolerance, ViewID, Mode, SelectedPoint[0], SelectedPoint[1], SelectedPoint[2], GUIPanel->MaskAppendCheckBox->isChecked(), KernelSize, KernelType);

		delete Segment;
		UpdateSegmentationToUseCropPlanes(MaskData, data);
		chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
		SagittalView->InsertMaskData(MaskData);
		CoronalView->InsertMaskData(MaskData);

		SlotInsertNewMask();

		RTimer.Stop();

	}
}
