void	MainWindow::SlotInvertMask()
{
	if (data != NULL)
	{
		if (MaskData == NULL)
		{
			MaskData = new unsigned char[data->GetVolumeSize()];
			memset(MaskData, 0, data->GetVolumeSize());
		}




		for (int i = 0; i < data->GetVolumeSize(); i++)
		{
			MaskData[i] = (MaskData[i] == 1) ? 0 : 1;
		}



		chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
		SagittalView->InsertMaskData(MaskData);
		CoronalView->InsertMaskData(MaskData);
		SlotInsertNewMask();
		if (this->isVolumeVisible == true)
		{
			VWidget->Interactor->repaint();
		}

	}
}

//------------------------------------------------
void	MainWindow::SlotMoveMaskByOneVoxel(int crossection, int direction)
{
	if (MaskData != NULL)
	{
		Segmentation* Segment = new Segmentation();
		Segment->SlotMoveMaskByOnePixel(data, MaskData, SelectedPoint, crossection, direction);
		SlotInsertNewMask();
		delete Segment;
		chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
		SagittalView->InsertMaskData(MaskData);
		CoronalView->InsertMaskData(MaskData);
	}
	else if (data != NULL)
	{
		//SYF NA TENCZAS!!!!! (poprawic to samo w segmentation gdzies w arc jest dla innych kierunkow)
		if (crossection == 0) // transversal
		{

			int* pos = SelectedPoint;
			//left right up down


			int i, j;
			unsigned short Temp;

			int b;
			unsigned short* Q = data->GetDataArray();
			switch (direction)
			{
			case 0:
				//left

				b = pos[2] * data->GetSliceSize();
				for (j = 0; j < data->GetNy(); j++)
				{
					Temp = Q[b];
					for (i = 0; i < data->GetNx() - 1; i++)
						Q[b + i] = Q[b + i + 1];
					Q[b + i] = Temp;
					b += data->GetNx();
				}
				break;

			case 1:
				//right
				b = pos[2] * data->GetSliceSize() + data->GetNx() - 1;
				for (j = 0; j < data->GetNy(); j++)
				{
					Temp = Q[b];
					for (i = 0; i < data->GetNx() - 1; i++)
						Q[b - i] = Q[b - i - 1];
					Q[b - i] = Temp;
					b += data->GetNx();
				}
				break;



			case 2:
				//up

				b = pos[2] * data->GetSliceSize();
				for (i = 0; i < data->GetNx(); i++)
				{
					Temp = Q[b + i];
					for (j = 0; j < data->GetNy() - 1; j++)
						Q[b + j * data->GetNx() + i] = Q[b + (j + 1) * data->GetNx() + i];
					Q[b + j * data->GetNx() + i] = Temp;
					//b+=data->GetNx();
				}
				break;


			case 3:
				//down
				b = (pos[2] + 1) * data->GetSliceSize() - 1;
				for (i = 0; i < data->GetNx(); i++)
				{
					Temp = Q[b - i];
					for (j = 0; j < data->GetNy() - 1; j++)
						Q[b - j * data->GetNx() - i] = Q[b - (j + 1) * data->GetNx() - i];
					Q[b - j * data->GetNx() - i] = Temp;
					//b+=data->GetNx();
				}
				break;
			}


		}

		TransversalView->SlotSetOpacity();
		SagittalView->SlotSetOpacity();
		CoronalView->SlotSetOpacity();

	}
}
