void MainWindow::SlotSaveMaskSet(QString fn)
{
	if (!fn.isEmpty())
	{
		//	MainListItem->GetData()->GetMasks()->SaveMaskDataSet(fn, -1, data);
			//SlotUpdateDefaultDir(fn, 0);
			//zapisze dodatiowo maski!!!
		ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nr = masks->GetMaskList()->GetNumberOfItems();
		if (nr > 0)
		{
			//zapiszę maski w pliku nazwa.masks
			//masks->SaveMasks(name);

			//uaktualnię nazwy:
			for (int i = 0; i < nr; i++)
			{
				QString newName = masks->GetMaskDataAtPos(i)->GetTreeItem()->text(0);
				if (!newName.isEmpty())
					masks->GetMaskDataAtPos(i)->SetMaskName(newName);
			}

			QString tt;
			tt = fn;
			if (tt.mid(tt.length() - 7, 7) == ".maskSet")
				tt.remove(tt.length() - 7, 7);

			QString mName = tt;
			masks->SaveMasks(mName, data);
		}
	}
}

