{
	if ((MainListItem != NULL) &&
		//(MainListItem->GetData()->GetMasks()->GetNumberOfMasks()>1))
		//&&
		(MainListItem->GetData()->GetMasks2()->GetNumberOfMasks() > 1))
	{
		if //((MaskData!=NULL))
			//&&
			((mask != NULL) && (MaskData != NULL))
		{

			int size = MainListItem->GetData()->GetRawData()->GetVolumeSize();
			if (MaskData == NULL)
			{
				MaskData = new unsigned char[size];
				memset(MaskData, 0, size);
			}

			int i;

			for (i = 0; i < size; i++)
			{
				MaskData[i] = BoolOperation(GUIPanel->FillModeCombo->currentIndex(), MaskData[i], mask[i]);
			}
			this->SlotInsertNewMask();
			chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
			SagittalView->InsertMaskData(MaskData);
			CoronalView->InsertMaskData(MaskData);
		}
	}
}




void MainWindow::SlotUpdateVolumeMask()
{

	if (data != NULL)
	{
		double volume = 0;
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{
			if (MaskData[i] > 0) volume++;
		}

		double scale[3];
		data->GetScale(scale);
		int count = volume;
		volume *= scale[0] * scale[1] * scale[2];
		lastVolumeMaskCount = count;
		//qWarning() << " Total Volume: " << volume << " mm^3" << "  - " << volume*0.001 << " cm^3";
		stringstream ss;
		ss << " Total Volume: " << volume << " mm^3" << "  - " << volume * 0.001 << " cm^3 - count: " << count;
		QString text = QString::fromStdString(ss.str());

		//qWarning() << text;// " Total Volume: " << volume << " mm^3" << "  - " << volume*0.001 << " cm^3";
		SlotAddLogText(text);

	}

	if ((isVolumeVisible == true) && (MaskVolumeStructuredPoints != NULL))
	{
		MaskVolumeStructuredPoints->Modified();
		//VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);

		bool useMask = GUIPanel->useMaskFor3DViewCheckBox->isChecked();

		if (useMask == true)
		{
			VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);
		}
		else
		{
			VolumeMapper->SetMaskInput(NULL);
		}
		VolumeMapper->Modified();



		//VolumeMapper->SetMaxMemoryInBytes(2.04e+9);
		//VolumeMapper->SetBlendModeToComposite();
		//Volume->SetMapper(VolumeMapper);
		//
		//VolumeMapper->SetInputData(VolumeStructuredPoints);
		//VolumeMapper->SetMaskType(0);
		//VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);

		//Volume->SetProperty(VolumeProperty);




		VWidget->Interactor->update();

	}
}
