void	MainWindow::SlotInsertMaskToModelOrObject(unsigned char* mask)
{
	// teraz trzeba zdecydowac gdzie wstawiam
	if ((MainListItem != NULL) && (ObjectListItem != NULL))
	{
		if (GUIPanel->ReversedTransformCheckBox->isChecked() == true)
		{
			TransversalView->InsertMaskData(mask);
			SagittalView->InsertMaskData(mask);
			CoronalView->InsertMaskData(mask);
			SlotInsertNewMask(MainListItem, mask);
		}
		else
			SlotInsertNewMask(ObjectListItem, mask);


	}


}
