void	MainWindow::SlotInsertNewMask(ListItem<DataSet*>* listItem, unsigned char* mask)
{
	listItem->GetData()->GetMasks()->InsertNewMask(mask);
	if (listItem == MainListItem)
	{
		(listItem->GetData()->GetMasks()->RedoPossible()) ? GUIPanel->RedoSegmentButton->setEnabled(true) : GUIPanel->RedoSegmentButton->setEnabled(false);
		(listItem->GetData()->GetMasks()->UndoPossible()) ? GUIPanel->UndoSegmentButton->setEnabled(true) : GUIPanel->UndoSegmentButton->setEnabled(false);
	}
}
