//------------------------------------
void MainWindow::SlotDeleteDataSet(QTreeWidgetItem* item)
{
	if (DataSetList->GetNumberOfItems() > 0)
	{

		int i;
		for (i = 0; i < DataSetList->GetNumberOfItems(); i++)
		{
			if (DataSetList->GetItemAtPos(i)->GetData()->GetTreeWidgetItem() == item) break;
		}

		if (i == DataSetList->GetNumberOfItems()) return;

		DataSet* selectedItem = DataSetList->GetItemAtPos(i)->GetData();


		if (ObjectListItem != NULL)

		{
			if (selectedItem == ObjectListItem->GetData())
			{
				oTreeWidgetItem = NULL;
			}

		}
		if (MainListItem != NULL)

		{
			if (selectedItem == MainListItem->GetData())
			{

				mTreeWidgetItem = NULL;

			}
		}

		//--------------
		if (selectedItem == MainListItem->GetData())
		{

			if (MainListItem != NULL)
			{
				if (MainListItem == DataSetList->GetCurrentListItem())
					MainListItem = NULL;
			}
			else if (ObjectListItem != NULL)
			{
				if (ObjectListItem == DataSetList->GetCurrentListItem())
					ObjectListItem = NULL;
			}

			if (DataSetList->GetNumberOfItems() > 1)
			{
				if (DataSetList->GetCurrentListItem()->GetData()->GetRawData() == data)
				{
					Histogram->DeleteData();
					TransversalView->DeleteData();
					SagittalView->DeleteData();
					CoronalView->DeleteData();

					if (MaskData != NULL) delete[]MaskData;
					MaskData = NULL;


					DataSetList->DeleteItem();


					SlotSetNewRawDataSet(DataSetList->GetCurrentListItem()->GetData()->GetTreeWidgetItem());
				}
				else
				{
					DataSetList->DeleteItem();
				}
			}
			else
			{
				Histogram->DeleteData();
				TransversalView->DeleteData();
				SagittalView->DeleteData();
				CoronalView->DeleteData();


				NoDataLoaded = true;
				data = NULL;

				if (MaskData != NULL)
				{
					delete[]MaskData;
					MaskData = NULL;
				}


				DataSetList->DeleteItem();


				GUIPanel->MaxToleranceValue = 0;
			}
		}
		else
		{
			DataSetList->DeleteItem(i);
		}

	}

}
