void MainWindow::SlotCheckModelCompatibity()
{
	//sprawdzam czy zbiory sa kompatybilne (takie same rozmiary )

	//GUIPanel->RawDataListView->setSelectionMode(QListView::Single );

	int i;
	int ItemsNr = DataSetList->GetNumberOfItems();
	int* CompatibilityArray = new int[ItemsNr];

	ListItem<DataSet*>* TempCurrentItem = DataSetList->GetCurrentListItem();

	DataSetList->SetCurrentListItem(DataSetList->GetHeadListItem());

	for (i = 0; i < ItemsNr; i++)
	{
		CompatibilityArray[i] = (MainListItem->GetData()->GetRawData()->CompareWithOtherDataSet(DataSetList->GetCurrentListItem()->GetData()->GetRawData())) ? 1 : 0;
		DataSetList->SetCurrentListItem(DataSetList->GetCurrentListItem()->NextListItem);
	}
	DataSetList->SetCurrentListItem(TempCurrentItem);
	emit SignalSendModelCopmatibility(CompatibilityArray);
	//	GUIPanel->RawDataListView->setSelectionMode(QListView::Extended );
	SlotChangeRawDataSetsSelection();
}
