void MainWindow::SlotCreateANDorNANDDataSet(bool a)
{
	if (MainListItem->GetData()->GetMasks()->GetNumberOfMasks() > 1)
	{

		RTimer.Start("Creating New Dataset");

		double origin[3];
		data->GetOrigin(origin);


		RawDataSet* dataX = new RawDataSet(data->GetNx(), data->GetNy(), data->GetNz(), data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());
		dataX->SetOrigin(origin);
		QString name;
		name = data->GetRawDataSetName();
		name.append(" - AND Segmented");
		dataX->SetRawDataSetName(name);

		int* Data = MainListItem->GetData()->GetMasks()->GetCurrentMask();
		int i;
		int temp = 0;
		int temp1 = 0;

		bool Mode = (bool)*(Data);
		int length = *(Data + 1);

		bool byte = *(Data + 2);
		temp1 += 3;
		int j;
		if (Mode == 0)
		{
			//przypadek binarny
			for (i = 1; i < length; i++)
			{
				if (byte == a)
					for (j = 0; j < *(Data + temp1); j++)
						*(dataX->GetDataArray() + temp + j) = Histogram->GetLowerThreshold();
				//memset(dataX->GetDataArray()+temp,Histogram->GetLowerThreshold(),*(Data+temp1)*sizeof(unsigned short));
				else
					memcpy(dataX->GetDataArray() + temp, data->GetDataArray() + temp, *(Data + temp1) * sizeof(unsigned short));

				temp += *(Data + temp1);
				temp1++;
				byte = !byte;
			}
		}
		InsertRawDataSet(dataX);
		RTimer.Stop();
	}
}
