void MainWindow::SlotGenerateParticlesModel()
{
	QString fn = QFileDialog::getOpenFileName(this, "", FileDefaultDir, "");
	if (!fn.isEmpty())
	{
		SlotUpdateDefaultDir(fn);
		int i;
		double Scale = 50.0;

		double SphereRadius = 0.5 * Scale;  //kula
		double Radius = 0.05 * Scale; //cylinderek
		double Color[3 * 100]; //kolorki atomow
		//randomowe kolorki atomow...
		for (i = 0; i < 100; i++)
		{
			Color[3 * i] = ((rand()) / RAND_MAX);		//r
			Color[3 * i + 1] = ((rand()) / RAND_MAX);	//g
			Color[3 * i + 2] = ((rand()) / RAND_MAX);	//b
		}
		//const char *header;

		QString hh = fn;
		//header =hh.toLocal8Bit();
		FILE* headerek;

		headerek = fopen(hh.toLocal8Bit(), "rt");


		int NumberOfParticles;
		double t1, t2;
		fscanf(headerek, "%d , %lf , %lf ,", &NumberOfParticles, &t1, &t2);

		NumberOfParticles = abs(NumberOfParticles);

		double* ParticlePosTab = new double[NumberOfParticles * 3];
		int* ParticleTypeTab = new int[NumberOfParticles];

		for (i = 0; i < NumberOfParticles; i++)
			fscanf(headerek, "%lf , %lf , %lf , %d ,", &ParticlePosTab[i * 3], &ParticlePosTab[i * 3 + 1], &ParticlePosTab[i * 3 + 2], &ParticleTypeTab[i]);

		for (i = 0; i < NumberOfParticles * 3; i++)
			ParticlePosTab[i] *= Scale;

		int NumberOfConnections;

		fscanf(headerek, "%d , ", &NumberOfConnections);
		NumberOfConnections = abs(NumberOfConnections);

		int* ConnectionsTab = new int[NumberOfConnections * 2];

		for (i = 0; i < NumberOfConnections; i++)
			fscanf(headerek, "%d , %d , ", &ConnectionsTab[i * 2], &ConnectionsTab[i * 2 + 1]);

		fclose(headerek);

		vtkSphereSource* Sphere = vtkSphereSource::New();
		Sphere->SetPhiResolution(30);
		Sphere->SetThetaResolution(30);

		vtkPolyDataMapper* SphereMapper = vtkPolyDataMapper::New();
		SphereMapper->SetInputConnection(Sphere->GetOutputPort());

		SurfaceData* ParticlesData = new SurfaceData[NumberOfParticles];
		vtkActor* TempActor;

		for (i = 0; i < NumberOfParticles; i++)
		{
			TempActor = vtkActor::New();
			TempActor->SetMapper(SphereMapper);
			ParticlesData[i].VActor = TempActor;
			ParticlesData[i].VActor->SetPosition(ParticlePosTab[i * 3], ParticlePosTab[i * 3 + 1], ParticlePosTab[i * 3 + 2]);
			ParticlesData[i].VActor->SetScale(SphereRadius);
			ParticlesData[i].VActor->GetProperty()->SetColor(Color[3 * ParticleTypeTab[i]], Color[3 * ParticleTypeTab[i] + 1], Color[3 * ParticleTypeTab[i] + 2]);
			VWidget->Renderer->AddActor(ParticlesData[i].VActor);
		}

		SurfaceData* ConnectionData = new SurfaceData[NumberOfConnections];
		vtkLineSource* Line;
		vtkTubeFilter* TubeFilter;

		vtkPolyDataMapper* CylinderMapper;


		int p1, p2, j;

		double sx, sy, sz;

		for (i = 0; i < NumberOfConnections; i++)
		{

			p1 = ConnectionsTab[i * 2] - 1;
			p2 = ConnectionsTab[i * 2 + 1] - 1;

			sx = (ParticlePosTab[p1 * 3] + ParticlePosTab[p2 * 3]) / 2.0;
			sy = (ParticlePosTab[p1 * 3 + 1] + ParticlePosTab[p2 * 3 + 1]) / 2.0;
			sz = (ParticlePosTab[p1 * 3 + 2] + ParticlePosTab[p2 * 3 + 2]) / 2.0;



			for (j = 0; j < 2; j++)
			{
				TubeFilter = vtkTubeFilter::New();
				CylinderMapper = vtkPolyDataMapper::New();
				Line = vtkLineSource::New();
				(j == 0) ? Line->SetPoint1(ParticlePosTab[p1 * 3], ParticlePosTab[p1 * 3 + 1], ParticlePosTab[p1 * 3 + 2]) : Line->SetPoint1(sx, sy, sz);
				(j == 0) ? Line->SetPoint2(sx, sy, sz) : Line->SetPoint2(ParticlePosTab[p2 * 3], ParticlePosTab[p2 * 3 + 1], ParticlePosTab[p2 * 3 + 2]);
				TubeFilter->SetInputData(Line->GetOutput());
				TubeFilter->SetRadius(Radius);
				TubeFilter->SetNumberOfSides(50);
				CylinderMapper->SetInputConnection(TubeFilter->GetOutputPort());
				TempActor = vtkActor::New();
				TempActor->SetMapper(CylinderMapper);
				(j == 0) ? TempActor->GetProperty()->SetColor(Color[3 * ParticleTypeTab[p1]], Color[3 * ParticleTypeTab[p1] + 1], Color[3 * ParticleTypeTab[p1] + 2]) :
					TempActor->GetProperty()->SetColor(Color[3 * ParticleTypeTab[p2]], Color[3 * ParticleTypeTab[p2] + 1], Color[3 * ParticleTypeTab[p2] + 2]);
				ConnectionData[i].VActor = TempActor;
				VWidget->Renderer->AddActor(ConnectionData[i].VActor);
				CylinderMapper->Delete();
				TubeFilter->Delete();
				Line->Delete();
			}
		}


		VWidget->Renderer->ResetCamera();
		VWidget->Renderer->ViewToWorld();
		VWidget->Interactor->repaint();
	}
}
