void MainWindow::SlotGenerateParticlesModelFromMol()
{

	QString fn = QFileDialog::getOpenFileName(this, "", FileDefaultDir, "");
	if (!fn.isEmpty())
	{
		SlotUpdateDefaultDir(fn, 0);
		int i;
		double Scale = 50.0;

		//		double SphereRadius=0.25*Scale;  //kula
		//		double Radius=0.15*Scale; //cylinderek
		int SphereResolution = 20;
		//		int	NumberOfTubeSides=10;
		double Color[3 * 100]; //kolorki atomow
		//randomowe kolorki atomow...
		for (i = 0; i < 300; i++)
			Color[i] = 0;		//r

		//default color
		i = 0;
		Color[i++] = 120; //r
		Color[i++] = 120; //g
		Color[i++] = 120; //b

		//O
		Color[i++] = 0;	//r
		Color[i++] = 0;	//g
		Color[i++] = 255; //b	

		//P
		Color[i++] = 0;	//r
		Color[i++] = 170; //g
		Color[i++] = 127; //b	

		//C
		Color[i++] = 170; //r
		Color[i++] = 170; //g
		Color[i++] = 255; //b	

		//H
		Color[i++] = 255; //r
		Color[i++] = 0;	//g
		Color[i++] = 0;	//b	

		//N

		Color[i++] = 85; //r
		Color[i++] = 170; //g
		Color[i++] = 255; //b	

		//S
		Color[i++] = 255; //r
		Color[i++] = 255; //g
		Color[i++] = 0;	//b	

		//Ru
		Color[i++] = 85; //r
		Color[i++] = 70; //g
		Color[i++] = 255; //b	

		//Cl
		Color[i++] = 255; //r
		Color[i++] = 15; //g
		Color[i++] = 45;	//b

		for (i = 0; i < 300; i++)
			Color[i] /= 255.0;

		const char* header;

		int NumberOfParticles;
		int NumberOfConnections;



		QString hh = fn;
		header = hh.toLocal8Bit();
		FILE* headerek;
		FILE* Do_opa;

		headerek = fopen(header, "rt");
		skipline(headerek);
		skipline(headerek);
		skipline(headerek);

		char c1[2];
		char c2[2];
		char c3[2];
		int tmpX;

		//	fscanf(headerek,"%3d%3d",&NumberOfParticles,&NumberOfConnections);
		c1[0] = fgetc(headerek); c2[0] = fgetc(headerek); c3[0] = fgetc(headerek); tmpX = atoi(c1) * 100 + atoi(c2) * 10 + atoi(c3);
		NumberOfParticles = tmpX;
		c1[0] = fgetc(headerek); c2[0] = fgetc(headerek); c3[0] = fgetc(headerek); tmpX = atoi(c1) * 100 + atoi(c2) * 10 + atoi(c3);
		NumberOfConnections = tmpX;

		skipline(headerek);
		NumberOfParticles = abs(NumberOfParticles);
		int NumberOfKnownTypes = 6;
		int* PartTab = new int[NumberOfKnownTypes + 1];

		for (i = 0; i <= NumberOfKnownTypes; i++)
			PartTab[i] = 0;

		double* ParticlePosTab = new double[NumberOfParticles * 3];
		int* ParticleTypeTab = new int[NumberOfParticles];
		char pierwiastek[3], sb[3];
		strcat(sb, "O ");

		for (i = 0; i < NumberOfParticles; i++)
		{
			fscanf(headerek, "%10f%10f%10f %3s", &ParticlePosTab[i * 3], &ParticlePosTab[i * 3 + 1], &ParticlePosTab[i * 3 + 2], pierwiastek);
			skipline(headerek);
			if (strcmp(sb, pierwiastek) == 0) ParticleTypeTab[i] = 1;
			else
				ParticleTypeTab[i] = 0;
			PartTab[ParticleTypeTab[i]]++;
		}

		for (i = 0; i < NumberOfParticles * 3; i++)
			ParticlePosTab[i] *= Scale;

		int NumberOfActors = 0;

		for (i = 0; i <= NumberOfKnownTypes; i++)
			if (PartTab[i] > 0) NumberOfActors++;

		int* ActorsIdTab = new int[NumberOfKnownTypes + 1];
		int pos = 0;
		int* ActorsIdTab2 = new int[NumberOfActors];
		for (i = 0; i <= NumberOfKnownTypes; i++)
		{
			if (PartTab[i] > 0)
			{
				ActorsIdTab2[pos] = i;
				ActorsIdTab[i] = pos++;

			}
		}

		NumberOfConnections = abs(NumberOfConnections);

		int* ConnectionsTab = new int[NumberOfConnections * 2];
		int* ConnectionTypeTab = new int[NumberOfConnections];

		for (i = 0; i < NumberOfConnections; i++)
		{
			c1[0] = fgetc(headerek); c2[0] = fgetc(headerek); c3[0] = fgetc(headerek); tmpX = atoi(c1) * 100 + atoi(c2) * 10 + atoi(c3);
			ConnectionsTab[i * 2] = tmpX;
			c1[0] = fgetc(headerek); c2[0] = fgetc(headerek); c3[0] = fgetc(headerek); tmpX = atoi(c1) * 100 + atoi(c2) * 10 + atoi(c3);
			ConnectionsTab[i * 2 + 1] = tmpX;
			c1[0] = fgetc(headerek); c2[0] = fgetc(headerek); c3[0] = fgetc(headerek); tmpX = atoi(c1) * 100 + atoi(c2) * 10 + atoi(c3);
			ConnectionTypeTab[i] = tmpX;
			skipline(headerek);
		}

		fclose(headerek);


		//Do_opa=fopen("c:\\mama.txt","wt");
		//	fprintf(Do_opa,"%d %d  \n",NumberOfParticles,NumberOfConnections);			
		/*	for(i=0;i<NumberOfParticles;i++)
		fprintf(Do_opa,"%lf %lf %lf %d \n",ParticlePosTab[i*3],ParticlePosTab[i*3+1],ParticlePosTab[i*3+2],ParticleTypeTab[i]);
		for(i=0;i<NumberOfConnections;i++)
		fprintf(Do_opa,"%d %d \n",ConnectionsTab[i*2],ConnectionsTab[i*2+1]);
		fclose(Do_opa);*/

		vtkSphereSource* Sphere = vtkSphereSource::New();
		Sphere->SetPhiResolution(SphereResolution);
		Sphere->SetThetaResolution(SphereResolution);

		SurfaceData* MolecularSurfaceData = new SurfaceData[NumberOfActors];

		for (i = 0; i < NumberOfActors; i++)
			MolecularSurfaceData[i].VAppendPolyData = vtkAppendPolyData::New();
	}
}

