void	MainWindow::SlotVolumeRegistrationLoadTrans(const QString& filename)
{
	if (!filename.isEmpty())
	{
		SlotUpdateDefaultDir(filename);
		double* FileTrans = new double[17];

		int i;

		FILE* plik;

		plik = fopen(filename.toLocal8Bit(), "rt");

		for (i = 1; i < 14; i++)
			fscanf(plik, "%lf\n", &FileTrans[i]);

		if (FileTrans[13] != 0)
			for (i = 14; i < 17; i++)
				fscanf(plik, "%lf\n", &FileTrans[i]);
		fclose(plik);
		GUIPanel->SlotInsertNewTransformation2(FileTrans);
	}
}
