void	MainWindow::SlotVolumeRegistrationSaveTrans(const QString& f)
{
	if (!f.isEmpty())
	{
		QString filename = f;

		SlotUpdateDefaultDir(filename, 0);
		if (filename.lastIndexOf(".trans") == -1)
			filename += ".trans";
		int i;
		FILE* plik;
		plik = fopen(filename.toLocal8Bit(), "wt");

		for (i = 0; i < 12; i++)
			fprintf(plik, "%lf\n", GUIPanel->TEdit[i]->text().toFloat());

		if (GUIPanel->AutoCenterCheckBox->isChecked() == false)
		{
			fprintf(plik, "%d\n", 1);
			for (i = 13; i < 16; i++)
				fprintf(plik, "%lf\n", GUIPanel->TEdit[i]->text().toFloat());
		}
		else
		{
			if (ObjectListItem != NULL)
			{
				fprintf(plik, "%d\n", 1);
				double RotateCenter[3];
				RawDataSet* ObjectData = ObjectListItem->GetData()->GetRawData();
				RotateCenter[0] = ((double)(ObjectData->GetNx() - 1) * (ObjectData->GetXscale())) / 2.0;
				RotateCenter[1] = ((double)(ObjectData->GetNy() - 1) * (ObjectData->GetYscale())) / 2.0;
				RotateCenter[2] = ((double)(ObjectData->GetNz() - 1) * (ObjectData->GetZscale())) / 2.0;
				for (i = 0; i < 3; i++)
					fprintf(plik, "%lf\n", RotateCenter[i]);


			}
		}
		fprintf(plik, "Reg:%f\n", this->lastRegFunctionValue);
		fclose(plik);
	}
}
