void MainWindow::SlotVolumeTransform(double* Trans)
{
	if ((MainListItem != NULL) && (ObjectListItem != NULL))
	{
		RTimer.Start("Transforming Volume");
		Registration* Reg = new Registration(MainListItem, ObjectListItem,
			ScatterImageWidget, GUIPanel->MissregInfoLabel, Trans);
		int nrTh = GUIPanel->parallelThreadSlider->value();
		Reg->SlotSetParalellComputing(this->GUIPanel->parallelRegistrationCheckBox->isChecked(), nrTh);
		//RawDataSet *NewData = Reg->TransformObjectToModelVolume(GUIPanel->invVolAffineCheckBox->isChecked());
		int inerpol = GUIPanel->InterpolationCombo->currentIndex();



		unsigned char* outMask = NULL;
		RawDataSet* NewData = Reg->TransformObjectToModelVolume(GUIPanel->invVolAffineCheckBox->isChecked(), outMask, inerpol);
		delete Reg;
		if (NewData != NULL) InsertRawDataSet(NewData);


		if (outMask != NULL)
		{
			if (MaskData != NULL)
			{
				delete[] MaskData;

			}
			MaskData = outMask;
			chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
			SagittalView->InsertMaskData(MaskData);
			CoronalView->InsertMaskData(MaskData);
			SlotInsertNewMask();
		}



		RTimer.Stop();
	}
}
