void MainWindow::SlotInsertPolygonSurface(PolygonSurfaceData* dataXX)
{
	//GUIPanel->qtab->setCurrentPage(1);

	blockChangeTempFlag = true;
	bool changePrevOpacity = GUIPanel->setOpacityToPrevCheckBox->isChecked();
	double changeOpacity = GUIPanel->opacityToPrevSlider->value() / 255.0;


	if (changePrevOpacity == true)
	{


		if (SurfaceDataList->GetNumberOfItems() >= 1)
		{
			GUIPanel->surfaceTreeWidget->expandAll();
			int nr = SurfaceDataList->GetNumberOfItems();
			int i;
			bool sel;
			PolygonSurfaceData* sData;

			//check
			bool anyOff = false;
			for (i = 0; i < nr; i++)
			{
				sData = SurfaceDataList->GetItemAtPos(i)->GetData();
				sel = sData->GetTreeItem()->isSelected();
				if (sel == true)
				{
					SurfaceDataList->GetItemAtPos(i)->GetData()->GetVProperty()->SetOpacity(changeOpacity);
				}


			}
		}


	}
	//	dataXX->CheckIfModified();
	SurfaceDataList->InsertItem(dataXX);
	//	dataXX->CheckIfModified();
	CurrentSurfaceDataPos = SurfaceDataList->GetCurrentItemPos();
	CurrentSurfaceDataSetListItem = SurfaceDataList->GetCurrentListItem();

	emit SignalPolygonSurfaceInserted();
	//dataXX->CheckIfModified();

	CurrentSurfaceDataSetListItem->GetData()->ShowActor();
	QString pName = SurfaceDataList->GetCurrentListItem()->GetData()->GetPolygonSurfaceName();
	//dataXX->CheckIfModified();
//	GUIPanel->SlotInsertPolygonSurfaceDataItem(pName);

	double col[3];
	//PolygonSurfaceData *dataS;
	//dataS=SurfaceDataList->GetItemAtPos(CurrentSurfaceDataPos)->GetData();
	dataXX->GetVProperty()->GetColor(col);

	//GUIPanel->SlotSetSurfaceColorPresentation(CurrentSurfaceDataPos, col[0], col[1], col[2]);
	//dataXX->GetVProperty()->SetColor(col);

	QString gName = dataXX->GetGroupName();

	GUIPanel->SlotInsertNewSurfaceTreeItem(pName, gName, dataXX);

	//QTreeWidgetItem *item=new  QTreeWidgetItem(
	//GUIPanel->treeW

	int polysNr = dataXX->GetVPolyData()->GetNumberOfPolys();

	if (dontSendSurfaceInfoAndBlockSelection == false)
	{
		emit SendtPolygonSurfaceDatasetInfo(dataXX->GetPN()[0], dataXX->GetPN()[1], dataXX->GetPN()[2], dataXX->GetPScale()[0],
			dataXX->GetPScale()[1], dataXX->GetPScale()[2], dataXX->GetPolygonSurfaceName(),
			dataXX->GetVPolyData()->GetNumberOfPoints(),
			polysNr,
			dataXX->GetOrigin()[0], dataXX->GetOrigin()[1], dataXX->GetOrigin()[2]);



		if (SurfaceDataList->GetNumberOfItems() >= 1)
		{
			GUIPanel->surfaceTreeWidget->expandAll();
			int nr = SurfaceDataList->GetNumberOfItems();
			int i;
			bool sel;
			PolygonSurfaceData* sData;

			//check
			bool anyOff = false;
			for (i = 0; i < nr; i++)
			{
				sData = SurfaceDataList->GetItemAtPos(i)->GetData();
				sData->GetTreeItem()->setSelected(false);



			}
		}

		dataXX->GetTreeItem()->setSelected(true);
		VWidget->SlotResetCube();
		blockChangeTempFlag = false;
	}
}
