void MainWindow::SlotSaveAllSelectedSurfaces()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{

		QString fn = QFileDialog::getExistingDirectory(this, "", FileDefaultDir);
		if (fn.isEmpty()) return;

		SlotUpdateDefaultDir(fn);

		int Nr = SurfaceDataList->GetNumberOfItems();
		int i;
		PolygonSurfaceData* Data;
		QString name;

		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (Data->GetTreeItem()->isSelected() == true)
			{
				name = fn + "/" + Data->GetPolygonSurfaceName();
				Data->SavePolygonSurfaceDataSet(name);
			}
		}
	}
}
