void MainWindow::SlotSetCurrentPolygonSurfaceDataSet(int pos)
{

	SurfaceDataList->SetCurrentItem(pos);
	CurrentSurfaceDataSetListItem = SurfaceDataList->GetCurrentListItem();

	if ((pos >= 0) || (CurrentSurfaceDataSetListItem != NULL))
	{
		PolygonSurfaceData* dataXX = CurrentSurfaceDataSetListItem->GetData();
		int polysNr = dataXX->GetVPolyData()->GetNumberOfPolys();
		emit SendtPolygonSurfaceDatasetInfo(dataXX->GetPN()[0], dataXX->GetPN()[1], dataXX->GetPN()[2], dataXX->GetPScale()[0],
			dataXX->GetPScale()[1], dataXX->GetPScale()[2], dataXX->GetPolygonSurfaceName(),
			dataXX->GetVPolyData()->GetNumberOfPoints(),
			polysNr,
			dataXX->GetOrigin()[0], dataXX->GetOrigin()[1], dataXX->GetOrigin()[2]);
		SProcessing->SlotSetCurrentSurface(dataXX);
		QString aa = dataXX->GetPolygonSurfaceName();
		GUIPanel->TransSurfacePointSlider->setRange(0, dataXX->GetVPolyData()->GetNumberOfPoints() - 1);
		if (ActorInteraction == 1) SlotInteractWithCurrentActor();
		int i;
		double SizeX[3];
		for (i = 0; i < 3; i++)
		{
			BoxActor->Center[i] = 0;
			BoxActor->Size[i] = 0;
			SizeX[i] = dataXX->GetMaxBound()[i] - dataXX->GetMinBound()[i];
			i = i;
		}
		BoxActor->Radius = 0.01 * MAX3(SizeX[0], SizeX[1], SizeX[2]);


		//mapper
		double params[3];
		int mode = dataXX->GetVMapper()->GetResolveCoincidentTopology();
		//qWarning()<<("mapper address: "+QString::number((long)(dataXX->GetVMapper())));
		GUIPanel->resolveConcidentGeometryComboBox->setCurrentIndex(mode);

		switch (mode)
		{

		case 0:
			params[0] = 0;					params[1] = 0;						params[2] = 0;
			break;

		case 1:
			params[0] = dataXX->GetVMapper()->GetResolveCoincidentTopologyPolygonOffsetFaces();
			dataXX->GetVMapper()->GetResolveCoincidentTopologyPolygonOffsetParameters(params[1], params[2]);
			break;

		case 2:
			params[0] = dataXX->GetVMapper()->GetResolveCoincidentTopologyZShift();
			params[1] = 0;						params[2] = 0;

			break;
		}
		GUIPanel->resolveParams[0]->setText(QString::number(params[0]));
		GUIPanel->resolveParams[1]->setText(QString::number(params[1]));
		GUIPanel->resolveParams[2]->setText(QString::number(params[2]));

		SlotUpdatePropertyWidget();
	}
	else
		SProcessing->SlotSetCurrentSurface(NULL);
}
