void MainWindow::DeletePolygonSurfaceDataSet(PolygonSurfaceData* pData)
{
	if (pData != NULL)
	{
		PolygonSurfaceData* tmp;
		for (int i = 0; i < SurfaceDataList->GetNumberOfItems(); i++)
		{
			tmp = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (pData == tmp)
			{
				SurfaceDataList->SetCurrentItem(i);
				DeletePolygonSurfaceDataSet();
				break;
			}
		}
	}
}

void MainWindow::DeletePolygonSurfaceDataSet()
{
	/*if (ModelSurfaceDataSetListItem == SurfaceDataList->GetCurrentListItem())
	{
		delete MapOfDistances;
		MapOfDistances = NULL;
		ModelSurfaceDataSetListItem = NULL;
	}*/

	int i;
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		bool nullExplode = false;;
		if (SurfaceDataList->GetCurrentListItem()->GetData() == shpereExplodeShadowSurfaceData)
		{
			nullExplode = true;
			//shpereExplodeShadowSurfaceData = NULL;
		}
		else if
			(SurfaceDataList->GetCurrentListItem()->GetData() == liveTmpSurfaceData)
		{
			liveTmpSurfaceData = NULL;
		}

		//****************

		QString groupName = SurfaceDataList->GetCurrentListItem()->GetData()->GetGroupName();

		QTreeWidgetItem* topLeveItemToDelete = NULL;
		QString tmp;
		int count = GUIPanel->surfaceTreeWidget->topLevelItemCount();
		for (i = 0; i < count; i++)
		{
			tmp = GUIPanel->surfaceTreeWidget->topLevelItem(i)->text(0);
			if (tmp.compare(groupName) == 0)
			{

				int childNr = GUIPanel->surfaceTreeWidget->topLevelItem(i)->childCount();

				if (childNr == 1)
				{
					topLeveItemToDelete = GUIPanel->surfaceTreeWidget->topLevelItem(i);//jesli jest ostatni w kategorii to usuwam kategorie
				}
			}
		}

		//*****************
		SurfaceDataList->DeleteItem();
		if (topLeveItemToDelete != NULL) delete topLeveItemToDelete;
		if (nullExplode == true)
		{
			shpereExplodeShadowSurfaceData = NULL;
		}

		//SurfaceDataList->setCurrentIndex(i);
		CurrentSurfaceDataSetListItem = SurfaceDataList->GetCurrentListItem();
		//i=SurfaceDataList->
		//GUIPanel->SlotChangeCurrentPolygonSurfaceDataItem(i);
	//	GUIPanel->SlotDeletePolygonSurfaceDataItem();
	}
	if (SurfaceDataList->GetNumberOfItems() == 0)
		SlotInteractWithCamera();

	if (dontSendSurfaceInfoAndBlockSelection == false)
	{
		if (SurfaceDataList->GetNumberOfItems() > 0) //to dla testu - bylo >1
		{
			SlotSetCurrentPolygonSurfaceDataSet(SurfaceDataList->GetCurrentItemPos());
			if (ActorInteraction == 1) SlotInteractWithCurrentActor();
		}
		else
			SlotSetCurrentPolygonSurfaceDataSet(-1);
	}

	VWidget->SlotResetCube();
}
