void MainWindow::SlotOpenSurfacePropertyWidget()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		QString first, name, rest;
		first = "Set ";
		name = CurrentSurfaceDataSetListItem->GetData()->GetPolygonSurfaceName();
		rest = " Property";
		first.append(name);
		first.append(rest);
		PropWidget->SlotSetInputProperty(CurrentSurfaceDataSetListItem->GetData()->GetVProperty(), first.toLocal8Bit());
		SlotDisconnectAllSlotsWithPropertyWidget();
		connect(PropWidget, SIGNAL(Updated()), this, SLOT(SlotUpdatePropertyOfAllSelectedSurfaces()));
	}
}
