void MainWindow::SlotResolveConcidentGeometryMode(int val, double* params)
{


	for (int i = 0; i < 3; i++)
	{
		GUIPanel->resolveParams[i]->setText(QString::number(params[i]));
	}

	switch (val)
	{
	case 0:
		vtkMapper::SetResolveCoincidentTopology(0);
		break;

	case 2:

		vtkMapper::SetResolveCoincidentTopologyToShiftZBuffer();
		vtkMapper::SetResolveCoincidentTopologyZShift(params[0]);

		break;

	case 1:

		vtkMapper::SetResolveCoincidentTopologyToPolygonOffset();
		// We offset lines/vertices.
		vtkMapper::SetResolveCoincidentTopologyPolygonOffsetFaces(params[0]);
		vtkMapper::SetResolveCoincidentTopologyPolygonOffsetParameters(params[1], params[2]);
		break;
	}

	VWidget->Renderer->ResetCameraClippingRange();
	VWidget->Interactor->GetRenderer()->Modified();;
	VWidget->RepaintWidget();


}
//--------------------------------------------
void MainWindow::SlotResolveConcidentGeometryMode()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		double params[3];
		int i;
		int val = GUIPanel->resolveConcidentGeometryComboBox->currentIndex();


		int nr = SurfaceDataList->GetNumberOfItems();


		for (i = 0; i < 3; i++)
		{
			params[i] = GUIPanel->resolveParams[i]->text().toDouble();
		}

		PolygonSurfaceData* sData;
		vtkPolyDataMapper* pMapper;

		for (i = 0; i < nr; i++)
		{
			sData = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (sData->GetTreeItem()->isSelected() == true)
			{

				//pMapper=sData->GetVMapper();
				vtkPolyDataMapper* nMapper = vtkPolyDataMapper::New();

				switch (val)
				{
				case 0:
					nMapper->SetResolveCoincidentTopology(0);
					break;

				case 2:

					nMapper->SetResolveCoincidentTopologyToShiftZBuffer();
					nMapper->SetResolveCoincidentTopologyZShift(params[0]);

					break;

				case 1:

					nMapper->SetResolveCoincidentTopologyToPolygonOffset();
					// We offset lines/vertices.
					nMapper->SetResolveCoincidentTopologyPolygonOffsetFaces(params[0]);
					nMapper->SetResolveCoincidentTopologyPolygonOffsetParameters(params[1], params[2]);
					break;



				}
				sData->SetVMapper(nMapper);
				sData->MapperModified();
			}
		}

		VWidget->Renderer->ResetCameraClippingRange();
		VWidget->Interactor->GetRenderer()->Modified();;
		VWidget->RepaintWidget();
	}
}

