void MainWindow::SlotTransformSelectedSurfaces()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{

		double rot[3];
		int i, j;
		for (j = 0; j < 3; j++)
		{
			rot[j] = GUIPanel->explodeRestRotLineEdit[j]->text().toDouble() * to_rad;
		}
		int Nr = SurfaceDataList->GetNumberOfItems();

		PolygonSurfaceData* Data;
		double bounds[6] = { 0 };
		double* tmpBounds;
		//wez widoczne powierzchnie zaznaczone i ich boundingboxy
		//policz srodek
		double opacity;
		double center[3];
		bool first = true;


		double orientation[3];
		double scale[3];
		double position[3];
		double origin[3];

		for (int i = 0; i < 3; i++)
		{
			position[i] = GUIPanel->TEdit[i]->text().toFloat();
			orientation[i] = GUIPanel->TEdit[i + 3]->text().toFloat() * to_rad;
			scale[i] = GUIPanel->TEdit[i + 9]->text().toFloat();
			origin[i] = GUIPanel->TEdit[i + 13]->text().toFloat();
		}



		double	matrix[16];
		double	transTemp[13];


		for (i = 0; i < 3; i++)
			transTemp[i + 1] = GUIPanel->TEdit[i]->text().toFloat();
		for (i = 3; i < 6; i++)
			transTemp[i + 1] = GUIPanel->TEdit[i]->text().toFloat() * to_rad;
		for (i = 6; i < 13; i++)
			transTemp[i + 1] = GUIPanel->TEdit[i]->text().toFloat();

		Transform* transX = new Transform(origin, 1, 1, 1);
		transX->CalculateTrigonometricFunctions(transTemp);
		transX->ScaleRotMatrix(transTemp);
		transX->CalculateShearParameters1(transTemp);
		//transX->MakeAffineMatrix(Matrix, TransT);

		transX->MakeAffineMatrix(matrix, transTemp);



		vtkTransform* transf = vtkTransform::New();

		transf->SetMatrix(matrix);



		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			opacity = Data->GetVProperty()->GetOpacity();
			if ((Data->GetTreeItem()->isSelected() == true))
			{
				Data->GetVActor()->SetUserTransform(transf);
				/*Data->GetVActor()->SetOrigin(origin);
				Data->GetVActor()->SetPosition(position);
				Data->GetVActor()->SetOrientation(orientation);
				Data->GetVActor()->SetScale(scale);*/
			}

		}



		VWidget->RepaintWidget();
	}
}
