void MainWindow::SlotExplodeUnselectedVisibleSurfaces(int value)
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		double factor = GUIPanel->explodeSliderScaleLineEdit->text().toDouble();
		double rot[3];
		int i, j;
		for (j = 0; j < 3; j++)
		{
			rot[j] = GUIPanel->explodeRestRotLineEdit[j]->text().toDouble() * to_rad;
		}
		int Nr = SurfaceDataList->GetNumberOfItems();

		PolygonSurfaceData* Data;
		double bounds[6] = { 0 };
		double* tmpBounds;
		//wez widoczne powierzchnie zaznaczone i ich boundingboxy
		//policz srodek
		double opacity;
		double center[3];
		bool first = true;
		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			opacity = Data->GetVProperty()->GetOpacity();
			if ((Data->GetTreeItem()->isSelected() == true) && (opacity > 0))
			{
				tmpBounds = Data->GetVPolyData()->GetBounds();
				if (first == true)
				{
					for (j = 0; j < 6; j++)
					{
						bounds[j] = tmpBounds[j];
					}
				}
				else
				{
					if (tmpBounds[0] < bounds[0]) bounds[0] = tmpBounds[0];
					if (tmpBounds[1] > bounds[1]) bounds[1] = tmpBounds[1];
					if (tmpBounds[2] < bounds[2]) bounds[2] = tmpBounds[2];
					if (tmpBounds[3] > bounds[3]) bounds[3] = tmpBounds[3];
					if (tmpBounds[4] < bounds[4]) bounds[4] = tmpBounds[4];
					if (tmpBounds[5] > bounds[5]) bounds[5] = tmpBounds[5];
				}

			}
		}

		//calculate center;

		center[0] = (bounds[0] + bounds[1]) * 0.5;
		center[1] = (bounds[2] + bounds[3]) * 0.5;
		center[2] = (bounds[4] + bounds[5]) * 0.5;



		//zapamietaj poczatkowe pozycje wszystkich powierzchni widocznych nie zaznaczonych
		// jesli poprzedni value byl zero to zapisz aktualna pozycje powierzchni i ja modyfikuj
		double pos[3], orient[3];
		double newPos[3], newOrient[3];
		double* origin;
		double vector[3];
		if (prevExplodeSliderVal == 0)
		{
			for (i = 0; i < Nr; i++)
			{
				Data = SurfaceDataList->GetItemAtPos(i)->GetData();
				opacity = Data->GetVProperty()->GetOpacity();
				if ((Data->GetTreeItem()->isSelected() == false) && (opacity > 0))
				{
					Data->GetVActor()->GetPosition(pos);
					origin = Data->GetOrigin();
					addV(pos, origin);
					Data->GetVActor()->GetOrientation(orient);
					Data->SetStartPos(pos);
					Data->SetStartOrient(orient);

					Data->SetRandVal(0, ((rand() * 2 - (double)(RAND_MAX)) / (double)(RAND_MAX)*rot[0]));
					Data->SetRandVal(1, ((rand() * 2 - (double)(RAND_MAX)) / (double)(RAND_MAX)*rot[1]));
					Data->SetRandVal(2, ((rand() * 2 - (double)(RAND_MAX)) / (double)(RAND_MAX)*rot[2]));
				}
			}

		}


		// jesli inne niz poprzednio zapamietane
		//dokonaj przesztalcenia w oparciu o suwak explodeRestSlider i skale explodeSliderScaleLineEdit

		if (prevExplodeSliderVal != value)
		{
			for (i = 0; i < Nr; i++)
			{
				Data = SurfaceDataList->GetItemAtPos(i)->GetData();
				opacity = Data->GetVProperty()->GetOpacity();
				if ((Data->GetTreeItem()->isSelected() == false) && (opacity > 0))
				{
					Data->GetStartPos(pos);
					Data->GetStartOrient(orient);
					double* origin;
					double randVals[3];
					randVals[0] = Data->GetRandVal(0);		randVals[1] = Data->GetRandVal(1);		randVals[2] = Data->GetRandVal(2);
					//liczne nowe
					double newfactor = (double)value * factor;
					diffV(pos, center, vector);
					normV(vector);
					origin = Data->GetOrigin();

					for (j = 0; j < 3; j++)
					{
						vector[j] *= newfactor;
						newPos[j] = pos[j] + vector[j] - origin[j];
						newOrient[j] = orient[j] + randVals[j] * newfactor;
					}
					Data->GetVActor()->SetPosition(newPos);
					Data->GetVActor()->SetOrientation(newOrient);
				}
			}
		}


		prevExplodeSliderVal = value;
		VWidget->RepaintWidget();
	}
}
