void MainWindow::SlotApplyVolOpacitySettings()
{

	if (data != NULL)
	{
		noClearVolMaskPts = true;
		bool volVis = isVolumeVisible;
		if (volVis)
			SlotShowHideVolume(10);

		int mode = GUIPanel->standardVolOpacityComboBox->currentIndex();
		QString txt = GUIPanel->standardVolOpacityComboBox->itemText(mode);
		QDir rDir(progDirPath);
		if (rDir.cd("volopacity"))
		{
			QString gr;
			QString filename = rDir.absolutePath() + "/" + txt + ".func";

			//wczyytuje



			QFile file(filename);


			if (file.open(QIODevice::ReadOnly))
			{
				QTextStream stream(&file);
				QString line;
				bool chgPalette = false;
				int palNr = 0;



				QSettings sett(filename, QSettings::IniFormat);

				sett.beginGroup("VolRenSettings");

				if (sett.contains("BlendMode"))
				{
					this->GUIPanel->volumeBlendComboBox->setCurrentIndex(sett.value("BlendMode").toInt());
				}
				QString tt[] = { "shading", "gradient_opacity", "interpolation","auto_sample_dist","shading1", "gradient_opacity1" };
				QString txt;
				for (int i = 0; i < 4 + 2; i++)
				{
					if (sett.contains(tt[i]))
					{

						txt = sett.value(tt[i]).toString();
						bool test = (txt.compare("On") == 0);
						GUIPanel->volumeRenCheckBox[i]->setChecked(test);
					}

				}
				for (int i = 0; i < 5 + 3; i++)
				{
					QString tt = "slider_" + QString::number(i);
					if (sett.contains(tt))
					{
						this->GUIPanel->volumeRenSettingsSliders[i]->setValue(sett.value(tt).toInt());
					}
					//sett.setValue("param" + QString::number(i), GUIPanel->imgMatchOptSlider[i]->value());
				}

				if (sett.contains("PaletteNr"))
				{
					this->SetNewPaletteR(sett.value("PaletteNr").toInt());
				}

				if (sett.contains("Left_Hounsfield_Threshold"))
				{
					int lth = sett.value("Left_Hounsfield_Threshold").toInt();
					if (data->dicomMinValue > -100000) lth -= data->dicomMinValue;
					Histogram->Thresh1VolSlider->setValue(lth);
				}
				if (sett.contains("Right_Hounsfield_Threshold"))
				{
					int rth = sett.value("Right_Hounsfield_Threshold").toInt();
					if (data->dicomMinValue > -100000) rth -= data->dicomMinValue;
					Histogram->Thresh2VolSlider->setValue(rth);
				}

				if (sett.contains("NrPts"))
				{
					int nrPts = sett.value("NrPts").toInt();
					if (nrPts > 0)
					{
						OpacityTransferFunction->RemoveAllPoints();
						//double mavVolValue = data->GetMaxValue();
						double x, y;
						for (int i = 0; i < nrPts; i++)
						{

							double v1, v2;
							bool t1 = false;
							bool t2 = false;
							QString tx1 = "point_Pos_" + QString::number(i);
							QString tx2 = "opacity_" + QString::number(i);

							if (sett.contains(tx1))
							{
								t1 = true;
								v1 = sett.value(tx1).toDouble();
							}

							if (sett.contains(tx2))
							{
								t2 = true;
								v2 = sett.value(tx2).toDouble();
							}

							if (t1 == true && t2 == true)
							{

								x = v1;// *mavVolValue;
								y = v2;;
								if (data->dicomMinValue > -100000) x -= data->dicomMinValue;

								if (x < 0) x = 0;
								if (x > data->GetMaxValue()) x = data->GetMaxValue();
								OpacityTransferFunction->AddPoint(x, y);

							}
						}
					}
				}

				if (sett.contains("grad_NrPts"))
				{
					int nrPts = sett.value("grad_NrPts").toInt();
					if (nrPts > 0)
					{
						GradientTransferFunction->RemoveAllPoints();
						//double mavVolValue = data->GetMaxValue();
						double x, y;
						for (int i = 0; i < nrPts; i++)
						{

							double v1, v2;
							bool t1 = false;
							bool t2 = false;
							QString tx1 = "grad_point_Pos_" + QString::number(i);
							QString tx2 = "grad_opacity_" + QString::number(i);

							if (sett.contains(tx1))
							{
								t1 = true;
								v1 = sett.value(tx1).toDouble();
							}

							if (sett.contains(tx2))
							{
								t2 = true;
								v2 = sett.value(tx2).toDouble();
							}

							if (t1 == true && t2 == true)
							{

								x = v1;// *mavVolValue;
								y = v2;;
								//	if (data->dicomMinValue > -100000) x -= data->dicomMinValue;

									//if (x < 0) x = 0;
									//if (x>data->GetMaxValue()) x = data->GetMaxValue();
								GradientTransferFunction->AddPoint(x, y);

							}
						}
					}
				}
				sett.endGroup();
				SlotSetVolumeOpacity();
				file.close();
			}

			//bool repeat=GUIPanel->repeatTexCheckBox->isChecked();//??
			//UpdateProperty(prop,filename,textureName,repeat,gr,Data->GetVMapper());
			if (volVis)
				SlotShowHideVolume(10);

			noClearVolMaskPts = false;
		}



	}



}
