void MainWindow::SlotTextureTest()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		int Nr = SurfaceDataList->GetNumberOfItems();
		int i;
		PolygonSurfaceData* Data;
		RTimer.Start("texturing");
		QString name;
		int tex = GUIPanel->testTextureSelectComboBox->currentIndex();
		QString txt = GUIPanel->testTextureSelectComboBox->itemText(tex);
		int mode = GUIPanel->testTextureModeComboBox->currentIndex();
		QString nname = this->progDirPath + "/texture/" + txt + ".jpg";
		nname.replace("/", "\\\\");
		const QString filename = nname;
		//Data->GetVProperty()->LoadMaterial(filename);

		vtkSmartPointer<vtkJPEGReader> imageIn = vtkSmartPointer<vtkJPEGReader>::New();
		imageIn->SetFileName(filename.toLocal8Bit());

		double params[50];
		int nrOfParams = 8 + 6 + 1;
		params[0] = GUIPanel->scaleTextureLineEdit->text().toDouble();//sth
		params[1] = GUIPanel->angleTextureLineEdit->text().toDouble();//angle
		params[2] = GUIPanel->startPointTextureLineEdit->text().toInt();//startPoint

		params[3] = GUIPanel->orientTextureLineEdit[0]->text().toDouble();//x orient
		params[4] = GUIPanel->orientTextureLineEdit[1]->text().toDouble();//y orient
		params[5] = GUIPanel->orientTextureLineEdit[2]->text().toDouble();//z orient
		params[6] = GUIPanel->iterTextureLineEdit->text().toInt();//iter


		params[7] = GUIPanel->normXTexCheckBox->isChecked(); //nromx
		params[8] = GUIPanel->normYTexCheckBox->isChecked(); //normy

		params[9] = GUIPanel->scaleXTextureLineEdit->text().toDouble();//scale x
		params[10] = GUIPanel->scaleYTextureLineEdit->text().toDouble();//scale y

		params[11] = GUIPanel->centerXTexLineEdit->text().toDouble();//scale x
		params[12] = GUIPanel->centerYTexLineEdit->text().toDouble();//scale y



		params[13] = GUIPanel->repeatTexCheckBox->isChecked(); //repeat texture

		bool ttest = GUIPanel->randomTexSeedCheckBox->isChecked();

		//if (ttest==true) params[2]=-1;
		bool repeat = (bool)params[13];

		int anwser = -1;
		bool useTexture = true;
		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (Data->GetTreeItem()->isSelected() == true)
			{

				if (ttest == true)
				{
					//wylosuj nowy i sprawdz
					int nr = Data->GetVPolyData()->GetNumberOfPoints() - 1;
					int startPos = (int)((rand() / (double)RAND_MAX) * nr);
					params[2] = startPos;
					GUIPanel->startPointTextureLineEdit->setText(QString::number((int)startPos));

				}
				if (Data->GetVPolyData()->GetPointData()->GetTCoords() != NULL)
				{
					if (anwser == -1)
					{
						QMessageBox msgBox;
						QPushButton* replaceButton = msgBox.addButton(tr("Replace Texture Coordinates"), QMessageBox::ActionRole);;
						QPushButton* leaveButton = msgBox.addButton(tr("Use Texture Only"), QMessageBox::ActionRole);;
						QPushButton* cancelButton = msgBox.addButton(QMessageBox::Discard);
						msgBox.setText("Texture Coordinates Already Exist");
						msgBox.exec();



						if (msgBox.clickedButton() == replaceButton)
						{
							SProcessing->AddTextureCoords(Data->GetVPolyData(), mode, params, nrOfParams);
							anwser = 1;
						}
						else if (msgBox.clickedButton() == leaveButton)
						{
							anwser = 0;
						}
						else
						{
							useTexture = false;
							anwser = 0;

						}
					}
					else
					{
						if (anwser == 1)
						{
							SProcessing->AddTextureCoords(Data->GetVPolyData(), mode, params, nrOfParams);
						}
					}
				}
				else
				{
					SProcessing->AddTextureCoords(Data->GetVPolyData(), mode, params, nrOfParams);
				}

				if (useTexture == true)
				{
					vtkSmartPointer<vtkTexture> imageTexture =
						vtkSmartPointer<vtkTexture>::New();
					if (repeat == true)
					{

						imageTexture->RepeatOn();
						imageTexture->EdgeClampOff();
					}
					else
					{
						imageTexture->EdgeClampOn();
						imageTexture->RepeatOff();
					}
					imageTexture->InterpolateOn();
					imageTexture->SetInputConnection(imageIn->GetOutputPort());



					Data->GetVActor()->SetTexture(imageTexture);
					Data->SetTextureName(txt);
					Data->SetTextureRepeat(repeat);
				}

			}

		}

		RTimer.Stop();
	}
}

