void MainWindow::SlotWriteUpdatedProps()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		int Nr = SurfaceDataList->GetNumberOfItems();
		int i;
		PolygonSurfaceData* Data;
		RTimer.Start("Updating props");
		QString name;
		int count = 0;
		double col[3];
		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (Data->GetTreeItem()->isSelected() == true)
			{

				name = Data->GetPolygonSurfacePath();
				if (!(name.mid(name.length() - 5, 5) == ".sdata"))
					Data->GetPolygonSurfaceName();
				if (!(name.isEmpty()))
				{
					if (name.mid(name.length() - 5, 5) == ".sdata")
						name.remove(name.length() - 5, 5);
					name += ".prop";
					QString textureName = Data->GetTextureName();
					QString groupName = Data->GetGroupName();
					bool repeat = GUIPanel->repeatTexCheckBox->isChecked();//??
					WriteProperty(Data->GetVProperty(), name, textureName, repeat, groupName, Data->GetVMapper());
					count++;
				}

			}

		}
		RTimer.SetText("Updated" + QString::number(count) + " props");
		RTimer.Stop();
	}
}
