void MainWindow::SetSurfaceGroupNumber(int grNr)
{
	int i;

	QString groupName = "";

	if (grNr == 0)
	{

		bool ok;
		QString text = QInputDialog::getText(this, tr("QInputDialog::getText()"),
			tr("Set New Group Name:"), QLineEdit::Normal,
			"", &ok);
		if (ok && !text.isEmpty())
		{

			groupName = text;
			QString tmp;
			int count = GUIPanel->surfaceTreeWidget->topLevelItemCount();
			for (i = 0; i < count; i++)
			{
				tmp = GUIPanel->surfaceTreeWidget->topLevelItem(i)->text(0);
				if (tmp.compare(text) == 0) break;
			}


			if (i == count)
			{
				//grNr++;
				// dodam nowa grupe
				int pos = GUIPanel->surfaceTreeWidget->topLevelItemCount();
				GUIPanel->surfaceTreeWidget->insertTopLevelItem(pos, new QTreeWidgetItem(QStringList(groupName)));
			}


		}



	}
	else
	{
		groupName = GUIPanel->surfaceTreeWidget->topLevelItem(grNr - 1)->text(0);
	}

	if (!groupName.isEmpty())
	{
		int groupPos = 0;
		QString tmp;
		int count = GUIPanel->surfaceTreeWidget->topLevelItemCount();
		for (i = 0; i < count; i++)
		{
			tmp = GUIPanel->surfaceTreeWidget->topLevelItem(i)->text(0);
			if (tmp.compare(groupName) == 0)
			{
				groupPos = i;
			}
		}

		QTreeWidgetItem* parentItem = GUIPanel->surfaceTreeWidget->topLevelItem(groupPos);
		QTreeWidgetItem* item;
		// teoretycznie mam nazwe
		if (SurfaceDataList->GetNumberOfItems() >= 1)
		{
			int Nr = SurfaceDataList->GetNumberOfItems();

			PolygonSurfaceData* Data;
			for (i = 0; i < Nr; i++)
			{
				Data = SurfaceDataList->GetItemAtPos(i)->GetData();
				if (Data->GetTreeItem()->isSelected() == true)
				{
					//zamieniam nazwy group
					SurfaceDataList->GetItemAtPos(i)->GetData()->SetGroupName(groupName);
					item = SurfaceDataList->GetItemAtPos(i)->GetData()->GetTreeItem();

					QTreeWidgetItem* actParent = item->parent();

					if (actParent != parentItem)
					{
						actParent->removeChild(item);
						parentItem->addChild(item);
					}


				}
			}
		}
	}


	/*

	*/
}
