void MainWindow::SlotFindPointClosestTo3DPointer()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		int Nr = SurfaceDataList->GetNumberOfItems();
		int i;
		PolygonSurfaceData* Data;

		int mode = GUIPanel->shaderSelectComboBox->currentIndex();
		bool showShaders = GUIPanel->showShadersCheckBox->isChecked();
		QString txt = GUIPanel->shaderSelectComboBox->itemText(mode);
		double col[3];
		//selectedDoublePoint
		double minDist = INT_MAX;
		int minPos = -1;
		double tempDist;;
		double p[3];
		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (Data->GetTreeItem()->isSelected() == true)
			{
				//if (mode>0)
				{
					/*QString nname=this->progDirPath+"/material/"+txt+".xml";
					nname.replace("/","\\\\");
					const QString filename=nname;
					Data->GetVProperty()->LoadMaterial(filename);
					if (showShaders) Data->GetVProperty()->ShadingOn();
					else Data->GetVProperty()->ShadingOff();*/
					vtkPoints* pts = Data->GetVPolyData()->GetPoints();
					int nrr = pts->GetNumberOfPoints();
					for (int j = 0; j < nrr; j++)
					{
						pts->GetPoint(j, p);
						tempDist = GetDistance(p, selectedDoublePoint);
						if (tempDist < minDist)
						{
							minDist = tempDist;
							minPos = j;
						}
					}

				}
				if (minPos >= 0) break;
				//PropWidget->SlotUpdateExternalProperty(Data->GetVProperty());
				//Data->GetVProperty()->GetColor(col);
				//GUIPanel->SlotSetSurfaceColorPresentation(i, col[0],col[1],col[2]);
				//if (Data->GetTreeItem()!=NULL)
				//GUIPanel->	SlotSetNewTreeItemColor(Data->GetTreeItem(),col);

			}

		}
		if (minPos >= 0)
		{
			GUIPanel->startPointTextureLineEdit->setText(QString::number(minPos));
		}
	}
	VWidget->RepaintWidget();
}
