void MainWindow::SlotInteractWithCamera()
{
	ActorInteraction = false;
	CuttingToolInteraction = false;
	VWidget->Interactor->SlotSetInteractionWithCamera();
	VWidget->Interactor->SetInteractionModeToCuttingPlane(CuttingToolInteraction);
	if (CubeActorInteraction == true)
		CubeActorInteraction = false;

}
//---------------------------------------
void MainWindow::SlotInteractWithCurrentActor()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		ActorInteraction = true;
		CuttingToolInteraction = false;

		VWidget->Interactor->SetInteractionActor(CurrentSurfaceDataSetListItem->GetData()->GetVActor());
		VWidget->Interactor->SlotSetInteractionWithActor();
		VWidget->Interactor->SetActorRotation(CurrentSurfaceDataSetListItem->GetData()->GetOrigin()[0],
			CurrentSurfaceDataSetListItem->GetData()->GetOrigin()[1],
			CurrentSurfaceDataSetListItem->GetData()->GetOrigin()[2]);

		if (CurrentSurfaceDataSetListItem->GetData()->GetCuttingEdgeActor() != NULL)
			VWidget->Interactor->SetSecondActorActor(CurrentSurfaceDataSetListItem->GetData()->GetCuttingEdgeActor());

		if (CubeActorInteraction == true)
			CubeActorInteraction = false;
		VWidget->Interactor->SetInteractionModeToCuttingPlane(CuttingToolInteraction);
	}
}
