void	MainWindow::SlotGenerateSphericalPointsCuts()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		//wez liste punktow 
		//sprawdzaj ktory widoczny
		//dodaj do listy punktow do ciecia wraz z nazwami
		//wez promien aktualny puntkow
		// w sprocessing - ciecie sferami o srodkach w punktach i promieniu r

		int nr = SurfaceDataList->GetNumberOfItems();
		PolygonSurfaceData* sData;
		int i, j;
		QStringList namesList;
		QVector <double> v;
		QString gName;
		double opacity;
		double p[3];
		double center[3];
		int nrpts;
		vtkPoints* pts;

		for (i = 0; i < nr; i++)
		{
			sData = SurfaceDataList->GetItemAtPos(i)->GetData();

			opacity = sData->GetVProperty()->GetOpacity();
			gName = sData->GetGroupName();
			center[0] = 0; center[1] = 0; center[2] = 0;
			if ((gName.compare("VIS POINTS") == 0) && (opacity > 0))
			{
				//calculate center
				pts = sData->GetVPolyData()->GetPoints();
				nrpts = pts->GetNumberOfPoints();
				if (nrpts > 0)
				{
					for (j = 0; j < nrpts; j++)
					{
						pts->GetPoint(j, p);
						center[0] += p[0]; center[1] += p[1]; center[2] += p[2];

					}

					center[0] /= (double)nrpts;	center[1] /= (double)nrpts;	center[2] /= (double)nrpts;
				}

				namesList.append(sData->GetPolygonSurfaceName());
				v.append(center[0]);	v.append(center[1]);	v.append(center[2]);
			}


		}
		if (v.count() > 0)
		{
			SProcessing->SlotGenerateSphericalPointsCuts(SurfaceDataList, namesList, v, selectedPointsRadius);
		}
		//selectedPointsRadius
		//mam liste punktow i nazw



	}
}
