void	MainWindow::SlotGenerateIslandsVolumeFromBuffers()
{

	//jesli dane posiadaja wiecej niz 1 bufor to robimy tak
	//tworze nowy pusty wolumen 
	//biore pierwsza maske i przebiegam wartosci - jesli zapalony dodaje 1 i tak po wszystkich


	if ((MainListItem != NULL) &&
		//(MainListItem->GetData()->GetMasks()->GetNumberOfMasks()>1))
		//&&
		(MainListItem->GetData()->GetMasks2()->GetNumberOfMasks() > 1))
	{
		SlotBooleanMaskToBuffer();

		RawDataSet* tData = new RawDataSet();
		tData->Copy(*MainListItem->GetData()->GetRawData(), false);
		tData->ZeroQ();

		int nrr = MainListItem->GetData()->GetMasks2()->GetNumberOfMasks();
		int i, j;
		unsigned short* dataArray = tData->GetDataArray();
		unsigned char* mask;
		int size = MainListItem->GetData()->GetRawData()->GetVolumeSize();
		unsigned short randx;
		for (i = 1; i < nrr; i++)
		{
			mask = MainListItem->GetData()->GetMasks2()->GetMaskDataAtPosAndSetAsCurrent(i);
			randx = (rand() * 256) / RAND_MAX;
			for (j = 0; j < size; j++)
			{
				if (mask[j] > 0)
				{
					dataArray[j] = dataArray[j] + randx;
				}
			}
			delete[]mask;
		}

		tData->SetRawDataSetName("Buffer Fusion");
		InsertRawDataSet(tData);

	}

}
