void	MainWindow::SlotOpenVHPFile()
{

	FILE* Fin;
	unsigned char* Header, * HeaderTMP, * TMP1, * TMP2;
	//	double FTM1,FTM2,FTM3;
	int	TM1, TM2, TM3;
	unsigned short* QTMP;
	int RGBConversionMode = 0;
	int NX, NY, NZ, SliceSize, Step, OffsetX, OffsetY, FullNX, FullNY, FullSliceSize;
	double DX, DY, DZ;
	bool Signed, Endian; // Endian=true - SGI/false -PC
	int Mode; //0 - intensity, 1 - RGB->Intensity
	bool OffsetExists;
	int StartStep;
	int StepX;
	int i, j, k;
	int Intensity;
	QColor Color;

	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//Photos - VHP male
	/*NX=648;
	NY=730;
	FullNX=2048;
	FullNY=1216;
	OffsetX=700;
	OffsetY=250;
	Step=0;
	DX=0.33;
	DY=0.33;
	DZ=1.0;

	Mode=1;
	Signed=false;
	Endian=false;
	RGBConversionMode=1;*/

	/// 3/4/5 - rgb


	//CT - VHP frozen
	NX = 512;
	NY = 512;
	FullNX = NX;
	FullNY = NY;
	OffsetX = 0;
	OffsetY = 0;
	Step = 3416;
	//DX=0.898438;
	//DY=0.898438;
	//DZ=2.0;
	DX = 0.527344;
	DY = 0.527344;
	DZ = 1.0;

	Mode = 0;
	Signed = true;
	Endian = true; //zmiana

	//------------------------------------

	//MRI

	/*
	NX=256;
	NY=256;
	FullNX=NX;
	FullNY=NY;
	OffsetX=0;
	OffsetY=0;
	Step=7900;

	DX=1.01562;
	DY=1.01562;
	DZ=4.0;

	Mode=0;
	Signed=true;
	Endian=true; //zmiana
	*/
	/*	NX=320;
	NY=320;
	FullNX=NX;
	FullNY=NY;
	OffsetX=0;
	OffsetY=0;
	Step=0;

	DX=1.0;
	DY=1.0;
	DZ=1.0;

	Mode=0;
	Signed=true;
	Endian=true; //zmiana
	*/
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	//---------------------------------------------------------------
	SliceSize = NX * NY;
	FullSliceSize = FullNX * FullNY; // to jest w bajtach!!!!!(znaczy sie bedzie)
	QString text;




	OffsetExists = ((OffsetX == 0) && (OffsetY == 0)) ? 0 : 1;

	StartStep = FullNX * OffsetY + OffsetX;
	StepX = OffsetX + (FullNX - NX - OffsetX);

	//------------------
	if (Mode == 0)
	{
		FullSliceSize *= 2;
		StepX *= 2;
		StartStep *= 2;
	}
	else if (Mode == 1)
	{
		FullSliceSize *= 3;

	}

	//-------------------
	QString filename = QFileDialog::getOpenFileName(this, "", FileDefaultDir, ""); //POPRAWIC!

	if (!filename.isEmpty())
	{
		SlotUpdateDefaultDir(filename);
		RTimer.Start("Analyzing VHP dir");
		QString Ntemp;

		int pos = filename.lastIndexOf("/");
		if (pos >= 0)
		{
			Ntemp = filename;
			Ntemp.remove(pos, Ntemp.length());
		}


		QString text = "";
		QString TMP, TMPX;
		QDir d;
		d.setPath(Ntemp);
		d.setFilter(QDir::Files | QDir::Hidden | QDir::NoSymLinks);
		d.setSorting(QDir::Reversed);

		QFileInfoList list = d.entryInfoList();
		//QFileInfoListIterator it( list.begin() );
		QListIterator<QFileInfo> it(list);
		QFileInfo fi;

		NZ = d.count();

		RawDataSet* dataset = new RawDataSet(NX, NY, NZ, DX, DY, DZ, 0.0, true);

		//przesuwac iterator i wczytywac dane...


		Header = new unsigned char[Step + FullSliceSize];

		k = 0;

		//while ( (fi = it.current()) != 0 )
		while (it.hasNext())
			//for(it=list.begin();it!=list.end();++it)
		{
			//fi=*it;
			fi = it.next();
			TMP = Ntemp;
			TMP += "/" + fi.fileName();
			//jest juz nazwa!

			TMPX = TMP;
			if ((Fin = fopen(TMP.toLocal8Bit(), "r")) == NULL)
				QMessageBox::about(0, "", "Something wrong with the %s !\n" + filename);
			else
			{


				//jesli skompresowane zipem	
				if ((TMPX.lastIndexOf(".Z") != -1) || (TMPX.lastIndexOf(".z") != -1))
				{

					//nie dziala :(


					// jak jest to rozpakuj!!
					int length;
					// char *Tab;
					//	unsigned long DestSize;
					QFile f1(TMPX);
					f1.open(QIODevice::Unbuffered | QIODevice::ReadOnly);
					length = f1.size();
					f1.close();
					//	Tab=new char[length];


					gzFile Zipek;
					Zipek = gzopen(TMPX.toLocal8Bit(), "rb");
					//					int CheckZ=gzread(Zipek,Header,Step+FullSliceSize);
					gzclose(Zipek);

				}
				else
				{
					// jak nie jest spakowane
					fread(Header, sizeof(unsigned char), Step + FullSliceSize, Fin);
				}


				if (OffsetExists == false)
				{
					if (Mode == 0)
					{
						//typowe caly plik przerzucany do tablicy;
						memcpy(dataset->GetDataArray() + k * SliceSize, (unsigned short*)(Header + Step), SliceSize * sizeof(unsigned short));

					}

				}
				else
				{
					if (Mode == 0)
					{
						// przesuniecie offsetowe



					}
					else if (Mode == 1)
					{
						//Konwersja z RGB na GrayValue i przesuniecie offsetowe
						if (k == 16)
						{
							OffsetX += 10;
							StartStep = FullNX * OffsetY + OffsetX;
							StepX = OffsetX + (FullNX - NX - OffsetX);
						}
						if (k == 38)
						{
							OffsetX -= 10;
							StartStep = FullNX * OffsetY + OffsetX;
							StepX = OffsetX + (FullNX - NX - OffsetX);
						}



						int FullSliceSizeTMP = FullSliceSize / 3;

						HeaderTMP = Header + Step + StartStep;
						TMP1 = HeaderTMP + FullSliceSizeTMP;
						TMP2 = HeaderTMP + FullSliceSizeTMP * 2;

						QTMP = dataset->GetDataArray() + k * SliceSize;

						for (j = 0; j < NY; j++)
						{
							for (i = 0; i < NX; i++)
							{
								if (RGBConversionMode == 0)
								{
									//konversja na 8 bitow
									Intensity = (int)(0.2989 * (*(HeaderTMP++)) + 0.5870 * (*(TMP1++)) + 0.1140 * (*(TMP2++)));
								}
								else if (RGBConversionMode == 1)
								{

									//konversja na 16 bitow
									Intensity = (int)(76.5184 * (*(HeaderTMP++)) + 150.4768 * (*(TMP1++)) + 29.184 * (*(TMP2++)));
								}
								else if (RGBConversionMode == 2)
								{
									Color.setRgb(*(HeaderTMP++), *(TMP1++), *(TMP2++));
									Color.getHsv(&TM1, &TM2, &TM3);
									//HSV - Hue
									//RGBtoHSV( *(HeaderTMP++), *(TMP1++), *(TMP2++), &FTM1, &FTM2, &FTM3 );//H,S,V;
									if (TM1 >= 0)
										Intensity = (unsigned short)(TM1);//Hue
									else Intensity = 0;
								}
								else if (RGBConversionMode == 3)
								{
									Intensity = *(HeaderTMP++); //R
								}
								else if (RGBConversionMode == 4)
								{
									Intensity = *(TMP1++); //G
								}
								else if (RGBConversionMode == 5)
								{
									Intensity = *(TMP2++); //G
								}


								*(QTMP) = Intensity;
								QTMP++;

							}
							HeaderTMP += StepX;
							TMP1 += StepX;
							TMP2 += StepX;
						}

					}
				}


				fclose(Fin);

			}
			k++;
			//++it;	
		}
		delete[]Header;

		if (Endian == true)	dataset->SwapData();
		if (Signed == true)	dataset->ConvertFromSignedData();

		for (int i = 0; i < dataset->GetVolumeSize(); i++)
		{
			int v = dataset->GetDataArray()[i] - 12800;;

			dataset->GetDataArray()[i] = (v > 0) ? v : 0;
		}

		InsertRawDataSet(dataset);
		RTimer.Stop();




	}


}
