void	MainWindow::SlotLoadLargestDicomSet()
{
	QString dirname = QFileDialog::getExistingDirectory(this, "", FileDefaultDir);
	if (!dirname.isEmpty())
	{

		//poszukuje katalogu wewnatrz podanego w ktorym znajduje sie najwiecej plikow
		//w tym zapuszczam analyze dicomdir i wczytuje najwiekszy
		RTimer.Start("Analyzing DICOM dir");
		QString path = DicomDirData->GetSubdirPathWithLargestVolume(dirname);
		//SlotUpdateDefaultDir(path);
		DicomDirData->setInvertPixelRepresentation(GUIPanel->InvertDicomPixelRepresentationCheckBox->isChecked());
		DicomDirData->setShiftValuesToZero(GUIPanel->ShiftValuesToZeroCheckBox->isChecked(), GUIPanel->ShiftValuesLineEdit->text().toInt());
		DicomDirData->setIgnoreWindowLevel(GUIPanel->IgnoreWindowLevelValuesCheckBox->isChecked());


		int i = DicomDirData->AnalyzeDicomDir(path, GUIPanel->DICOMDataTreeWidget, GUIPanel->ImportAllWithErrorsCheckBox->isChecked(), true, GUIPanel->dicomDistTolEdit->text().toDouble());
		//AnalyzeDicomDir(const QString &filename, QTreeWidget* ListView, bool ImportAll, bool isDir, double tolx)

		SlotImportDICOMDataSet(i);
		if (i > -1)
		{
			RTimer.Stop();
		}
		else
		{
			RTimer.StopError();
		}


	}
}
