//---------------------------------------------------
void	MainWindow::SlotImportDICOMDataSet(int pos)
{

	RTimer.Start("Importing DICOM file");

	QString text = "";
	QString Name;
	//	int ind;

	bool inv = GUIPanel->InvertDicomPixelRepresentationCheckBox->isChecked();
	bool shift = GUIPanel->ShiftValuesToZeroCheckBox->isChecked();
	int shiftVal = GUIPanel->ShiftValuesLineEdit->text().toInt();


	//DicomDirData->DICOMDirDataList->setCurrentIndex(pos);
	if (pos > DicomDirData->nrOfDicomItems - 1) return;
	if (DicomDirData->dicomItemsTab == NULL) return;
	//if (DicomDirData->DICOMDirDataList->GetNumberOfItems()==0) return;
	//	int aa=DicomDirData->DICOMDirDataList->GetNumberOfItems();

	//DicomDataSet **Temp=DicomDirData->DICOMDirDataList->GetCurrentListItem()->GetData();
	//teraz tylko create volume...

	double fGantryShift;
	double fSliceDistance;
	int start = DicomDirData->dicomItemsTab[pos * 2];
	int end = DicomDirData->dicomItemsTab[pos * 2 + 1];
	int nrOfSlices = end - start;
	DicomDataSet** Temp = &DicomDirData->DicomInfoTab[start];
	double fDx, fDy, fDz, fImageDistance;
	//if(Temp[0]->NumberOfSlices>1)
	if (nrOfSlices > 1)
	{
		fImageDistance = 0;
		double dist;
		//poprawka w razie gdyby byby pojedyncze przekroje z innym slice distance - biore najwiekszy

		double* distTab = new double[nrOfSlices];
		for (int i = 0; i < nrOfSlices - 1; i++)
		{

			fDx = Temp[i + 1]->Finfo.vImagePosition[0] - Temp[i]->Finfo.vImagePosition[0];
			fDy = Temp[i + 1]->Finfo.vImagePosition[1] - Temp[i]->Finfo.vImagePosition[1];
			fDz = Temp[i + 1]->Finfo.vImagePosition[2] - Temp[i]->Finfo.vImagePosition[2];
			dist = (double)sqrt(fDx * fDx + fDy * fDy + fDz * fDz);
			distTab[i] = dist;
			if (dist > fImageDistance)fImageDistance = dist;
		}

		fImageDistance = Median(distTab, nrOfSlices - 1);//nowosc - jak dobrac optymalnie odleglosc miedzy przekrojami
		delete[]distTab;


		double angle = Temp[0]->Finfo.fGantryTilt * to_rad;
		fSliceDistance = (double)(fImageDistance * cos(angle));
		fGantryShift = 0.0f;

		//fGantryShift = sin(angle) * fImageDistance / Temp[0]->Finfo.fPixelSpacing[0];
		fGantryShift = fSliceDistance * tan(angle);
	}
	else
	{
		fSliceDistance = 1;
		fGantryShift = 0;

	}
	//w sumie to nie wiem ile
	if (fSliceDistance == 0) fSliceDistance = 1.0;

	//Zamienilem linijke nizej rows/columns!!!!
	int	Ny = Temp[0]->Finfo.iRows + (int)(ceil((fabs(fGantryShift) * (double)(Temp[0]->NumberOfSlices))));


	RawDataSet* dataset = new RawDataSet(Temp[0]->Finfo.iColumns, Ny, Temp[0]->NumberOfSlices,
		Temp[0]->Finfo.fPixelSpacing[1], Temp[0]->Finfo.fPixelSpacing[0], fSliceDistance, Temp[0]->Finfo.fGantryTilt, true);

	dataset->ZeroQ();

	unsigned short* PixelData = dataset->GetDataArray();

	int i;
	int SliceSize = dataset->GetSliceSize();
	int globalMinValue = 0;
	//if (fGantryShift > 0) fGantryShift *= -1;

	if (fGantryShift == 0)
	{
		for (i = 0; i < Temp[0]->NumberOfSlices; i++)
		{
			//	cout << "nr: " << i;
			/*	if (i == 34)
				{
					i = i;
				}*/
			Temp[i]->GetPixelData(PixelData, 0, inv, shift, shiftVal, globalMinValue);
			PixelData += SliceSize;
			if (i == 0) globalMinValue = Temp[i]->Finfo.minValue;




		}
	}
	else
		if (fGantryShift > 0)
		{
			int start = (Temp[0]->NumberOfSlices - 1) * fGantryShift;

			for (i = 0; i < Temp[0]->NumberOfSlices; i++)
			{
				//int val = (int)ceil(i*fGantryShift)*Temp[0]->Finfo.iColumns;
				int val = (int)ceil(start - i * fGantryShift) * Temp[0]->Finfo.iColumns;
				//Temp[i]->GetPixelData(PixelData + (int)ceil(start-i*fGantryShift)*Temp[0]->Finfo.iColumns, 0, inv, shift, shiftVal);
				//Temp[i]->GetPixelData(PixelData + (int)ceil(i*fGantryShift)*Temp[0]->Finfo.iColumns, 0, inv, shift, shiftVal);
				Temp[i]->GetPixelData(PixelData + val, 0, inv, shift, shiftVal, globalMinValue);
				PixelData += SliceSize;
				if (i == 0) globalMinValue = Temp[i]->Finfo.minValue;



			}
		}
		else
		{
			for (i = 0; i < Temp[0]->NumberOfSlices; i++)
			{

				int val = -(int)ceil((Temp[0]->NumberOfSlices - 1 - i) * fGantryShift) * Temp[0]->Finfo.iColumns;
				Temp[i]->GetPixelData(PixelData + val, 0, inv, shift, shiftVal, globalMinValue);
				PixelData += SliceSize;
				if (i == 0) globalMinValue = Temp[i]->Finfo.minValue;
			}
		}
	dataset->SetRawDataSetName(QString::fromLatin1(Temp[0]->Finfo.chPatientName) + "_" + QString::fromLatin1(Temp[0]->Finfo.chModality));
	dataset->CalculateHistogram();

	//// a gdy signed to teraz wszystko przesune...
	//bool tt=Temp[0]->Finfo.uPixelRepresentation;
	//if (inv==true) tt=!tt;
	//if  (tt==1)
	//	//if (Temp[0]->Finfo.uPixelRepresentation==1)

	//{
	//	dataset->ConvertFromSignedData();//true,Temp[0]->Finfo.fRescaleIntercept);
	//}





	/*int wcenter = Temp[0]->Finfo.fWindowCenter;
	if (Temp[0]->Finfo.minValue<0) wcenter -= Temp[0]->Finfo.minValue;
	int wwidth = Temp[0]->Finfo.fWindowWidth;

	int minVal = wcenter - wwidth / 2;
	int maxVal = wcenter + wwidth / 2;

	dataset->dicomLeftThreshold = minVal;
	dataset->dicomRightThreshold = maxVal;*/

	if (Temp[0]->Finfo.uPixelRepresentation == 1)
	{
		dataset->dicomMinValue = Temp[0]->Finfo.minValue;
	}
	else
		dataset->dicomMinValue = Temp[0]->Finfo.fRescaleIntercept;
	//dataset->dicomMinValue = Temp[0]->Finfo.fRescaleIntercept;//minValue;
	dataset->dicomLevelValue = Temp[0]->Finfo.fWindowCenter;
	dataset->dicomWindowWidthValue = Temp[0]->Finfo.fWindowWidth;


	InsertRawDataSet(dataset);



	//Histogram->SetLowerThreshold(minVal);
	//Histogram->SetUpperThreshold(maxVal);
	//Histogram->Thresh1Slider->setValue(minVal);
	//Histogram->Thresh2Slider->setValue(maxVal);

	RTimer.Stop();


}


