				RTimer.Start("Distance Map Generation");




				//	double	LeftCorner[3];
				//		int		CuboidSize[3];
				double	CuboidScale[3];
				int i;

				int SizeTemp[3];

				int n[3];
				dataX->GetN(n);

				SizeTemp[0] = n[0];
				SizeTemp[1] = n[1];
				SizeTemp[2] = n[2];


