void MainWindow::SlotGenerateDistanceMapVolume()
{

	if ((MainListItem != NULL) && (ObjectListItem == NULL))
	{
		RTimer.Start("Data Processing");

		RawDataSet* ModelData = MainListItem->GetData()->GetRawData();
		int LThreshold = GUIPanel->LThreshLineEdit->text().toInt();
		int RThreshold = GUIPanel->RThreshLineEdit->text().toInt();
		if (MapOfDistances != NULL)
		{
			if (!((MapOfDistances->GetRawData() == ModelData)
				&& (MapOfDistances->GetLThreshold() == LThreshold)
				&& (MapOfDistances->GetRThreshold() == RThreshold)))
			{
				delete MapOfDistances;
				MapOfDistances = NULL;

			}
		}
		if (MapOfDistances == NULL)
		{
			MapOfDistances = new DistanceMap(ModelData, LThreshold, RThreshold);
			//MapOfDistances->PrecalucateDistanceMap();
			//	MapOfDistances->Precalculate2DSignedDistanceMap();

		}
		RawDataSet* dataX = MapOfDistances->Generate2DSignedDistanceMapVolume();
		GUIPanel->LThreshLineEdit->setText(QString::number(MapOfDistances->GetZeroLevel()));

		delete MapOfDistances;
		MapOfDistances = NULL;

		RTimer.Stop();
		InsertRawDataSet(dataX);

	}
	else
		if ((MainListItem != NULL) && (ObjectListItem != NULL))
		{
			RTimer.Start("Data Processing");

			RawDataSet* ModelData = MainListItem->GetData()->GetRawData();
			RawDataSet* ObjectData = ObjectListItem->GetData()->GetRawData();

			if (ModelData->GetVolumeSize() != ObjectData->GetVolumeSize()) return;


			//RawDataSet *dataX=new RawDataSet(ModelData->GetNx(),ModelData->GetNy(),ModelData->GetNz(),
			//	ModelData->GetXscale(),ModelData->GetYscale(),ModelData->GetZscale(),ModelData->GetGantryAngle());


			//QString name;
			//name="Distance Map";
			//dataX->GetRawDataSetName()=name;


			//int LThreshold =Histogram->GetLowerThreshold();
			//int RThreshold =Histogram->GetUpperThreshold();

			int LThreshold = GUIPanel->LThreshLineEdit->text().toInt();
			int RThreshold = GUIPanel->RThreshLineEdit->text().toInt();


			if (MapOfDistances != NULL)
			{
				if (!((MapOfDistances->GetRawData() == ModelData)
					&& (MapOfDistances->GetLThreshold() == LThreshold)
					&& (MapOfDistances->GetRThreshold() == RThreshold)))
				{
					delete MapOfDistances;
					MapOfDistances = NULL;

				}
			}

			if (MapOfDistances == NULL)
			{
				MapOfDistances = new DistanceMap(ModelData, LThreshold, RThreshold);
				MapOfDistances->PrecalucateDistanceMap();
			}
			int i, j, k;
			//memset(dataX->GetDataArray(), 0, dataX->GetVolumeSize() * sizeof(unsigned short));
			int nr = 0;
			long double sum = 0;

			unsigned short* Q = ObjectData->GetDataArray();
			double Dist;
			double max = 0;
			int ObPointsNr = 0;
			int ti, tj, tk = 0;
			for (k = 0; k < ModelData->GetNz(); k++)
				for (j = 0; j < ModelData->GetNy(); j++)
					for (i = 0; i < ModelData->GetNx(); i++)
					{
						/*				if ((i==409)&&(j==394)&&(k==10))
						{
						ti=ti;
						}
						*/
						if (((*Q) >= LThreshold) && ((*Q) <= RThreshold))
						{
							Dist = MapOfDistances->GetDistanceValue((double)i, (double)j, (double)k);
							ObPointsNr++;
							if (Dist > max)
							{
								max = Dist;
								ti = i; tj = j; tk = k;
							}
							if (Dist != 0)
								nr++;

							sum += Dist;

							//dataX->SetVoxelValue(i,j,k,(unsigned short)(Dist*100)+10);
						}
						Q++;

						//dataX->SetVoxelValue(i,j,k,MapOfDistances->GetDistanceValue((double)i,(double)j, (double)k));
					}




			double AverageDist = 0;

			if (ObPointsNr != 0) AverageDist = sum / ObPointsNr;

			double TSigma = 0;
			double Sigma = 0;

			double VolumeOrig = (double)MapOfDistances->GetNumberOfSeeds()
				* ModelData->GetXscale()
				* ModelData->GetYscale()
				* ModelData->GetZscale();


			double VolumeObj = (double)ObPointsNr
				* ObjectData->GetXscale()
				* ObjectData->GetYscale()
				* ObjectData->GetZscale();

			double VolumeDiff = VolumeOrig - VolumeObj;

			Q = ObjectData->GetDataArray();
			for (k = 0; k < ModelData->GetNz(); k++)
				for (j = 0; j < ModelData->GetNy(); j++)
					for (i = 0; i < ModelData->GetNx(); i++)
					{
						if (((*Q) >= LThreshold) && ((*Q) <= RThreshold))
						{
							Dist = MapOfDistances->GetDistanceValue((double)i, (double)j, (double)k);
							TSigma = (Dist - AverageDist);
							Sigma += TSigma * TSigma;

						}
						Q++;
					}

			Sigma = sqrt(Sigma / ObPointsNr);

			/*FILE *Do_opa;
			Do_opa=fopen("c:\\distance.txt","a");*/


			/*
			fprintf(Do_opa,"Model=%s\n",ModelData->GetRawDataSetName().toLocal8Bit());
			fprintf(Do_opa,"Object=%s\n",ObjectData->GetRawDataSetName().toLocal8Bit());

			fprintf(Do_opa,"left threshold=%d\n",LThreshold);
			fprintf(Do_opa,"right threshold=%d\n",RThreshold);
			fprintf(Do_opa,"missed voxels=%d\n",nr);
			fprintf(Do_opa,"max distance=%lf\n",max);
			fprintf(Do_opa,"avg distance=%lf\n",AverageDist);
			fprintf(Do_opa,"std dev =%lf\n",Sigma);
			fprintf(Do_opa,"volume original=(%d) %lf\n",MapOfDistances->numberOfSeeds,VolumeOrig);
			fprintf(Do_opa,"volume object =(%d) %lf\n",ObPointsNr,VolumeObj);
			fprintf(Do_opa,"volume diff =(%d) %lf\n",MapOfDistances->numberOfSeeds-ObPointsNr,VolumeDiff);
			fprintf(Do_opa,"--------------------------------------------\n");
			*/

			/*fprintf(Do_opa,"%s\n",ModelData->GetRawDataSetName().toLocal8Bit());
			fprintf(Do_opa,"%s\n",ObjectData->GetRawDataSetName().toLocal8Bit());

			fprintf(Do_opa,"%d\n",LThreshold);
			fprintf(Do_opa,"%d\n",RThreshold);
			fprintf(Do_opa,"%d\n",nr);
			fprintf(Do_opa,"%lf\n",max);
			fprintf(Do_opa,"%lf\n",AverageDist);
			fprintf(Do_opa,"%lf\n",Sigma);
			fprintf(Do_opa,"%d\n%lf\n",MapOfDistances->GetNumberOfSeeds(),VolumeOrig);
			fprintf(Do_opa,"%d\n%lf\n",ObPointsNr,VolumeObj);
			fprintf(Do_opa,"%d\n%lf\n",MapOfDistances->GetNumberOfSeeds()-ObPointsNr,VolumeDiff);
			fprintf(Do_opa,"--------------------------------------------\n");

			fclose(Do_opa);*/

			//delete MapOfDistances;
			//MapOfDistances=NULL;
			//InsertRawDataSet(dataX);
			//delete dataX;
			RTimer.Stop();


		}


}
