void MainWindow::SlotGetTubesStats()
{

	double maxDist = 0;
	double minDist = INT_MAX;

	if ((DataSetList->GetCurrentListItem() != NULL) && (SurfaceDataList->GetNumberOfItems() >= 1))
		if (SurfaceDataList->GetNumberOfItems() >= 1)
		{

			int Nr = SurfaceDataList->GetNumberOfItems();
			int i;
			PolygonSurfaceData* Data;

			//GUIPanel->SlotBlockUpdateSelectionList(true);
			int* selectedTab = new int[Nr];
			for (i = Nr - 1; i >= 0; i--)
			{
				selectedTab[i] = 0;
				Data = SurfaceDataList->GetItemAtPos(i)->GetData();
				if (Data->GetRoleIndex() >= 2)//tube
					if (Data->GetTreeItem()->isSelected() == true)
					{

						//teraz wrzuce do pary długość grt
						selectedTab[i] = 1;



					}
			}
			RTimer.SendTextMode(false);
			for (i = Nr - 1; i >= 0; i--)
			{
				if (selectedTab[i] == 1)
				{
					GUIPanel->surfaceTreeWidget->clearSelection();
					Data = SurfaceDataList->GetItemAtPos(i)->GetData();
					Data->GetTreeItem()->setSelected(true);
					pseudoSurfaceSelection = i;
					//	SlotCalculateParamsOfArteries();

					{
						sumDiameters = 0;
						nOfDiPts = 0;
						firstCall = true;
						ApplySurfaceProcessing(&MainWindow::GetAverageArteryDiameter, "...");

						if (nOfDiPts > 0)
						{
							double avg = sumDiameters / (double)nOfDiPts;
							veinParams[3] = avg;
							GUIPanel->avgDiEdit->setText(QString::number(avg));
						}
						if (testPoints != NULL)
							testPoints->Delete();
						testPoints = vtkPoints::New();
						ApplySurfaceProcessing(&MainWindow::GetSkeletalPoints, "...");
						double p0[3], p1[3];
						int nr = testPoints->GetNumberOfPoints();
						double length = 0;
						for (int j = 0; j < nr; j++)
						{

							testPoints->GetPoint(j, p0);

							if (j < nr - 1)
							{
								testPoints->GetPoint(j + 1, p1);
								length += sqrt((p0[0] - p1[0]) * (p0[0] - p1[0]) + (p0[1] - p1[1]) * (p0[1] - p1[1]) + (p0[2] - p1[2]) * (p0[2] - p1[2]));

							}
						}
						veinParams[2] = length;

					}

					RTimer.SendTextMode(false);
					pseudoSurfaceSelection = -1;

					QString txt = QString::number(veinParams[2]) + " "; //length
					txt += QString::number(veinParams[3]);//avgDi

					QString r = txt.replace(".", ",");

					QStringList splitList = r.split("   ");

					SlotAddLogText2(r);
				}


			}
			RTimer.SendTextMode(true);
			delete[]selectedTab;
		}
}
