void MainWindow::SlotLoadGrid3D(const QString& filename)
{
	if (!filename.isEmpty())
	{
		RTimer.Start("Loading Grid File", 0);

		SlotUpdateDefaultDir(filename);

		//-wczytac grid
		if (Grid != NULL) delete Grid;
		Grid = new FloatGrid3D();
		//int nr=Grid->GetNumberOfGrids(filename);
		if (!(Grid->LoadGrid(filename)))
		{
			delete Grid;
			Grid = NULL;
			RTimer.StopError();
		}
		else
			RTimer.Stop();



	}

}
