void MainWindow::SaveCurrentArrayAsUnsignedChar()
{

	if (DataSetList->GetCurrentListItem() != NULL)
	{

		QString filename = QFileDialog::getSaveFileName(this, "", FileDefaultDir, "");

		if (!filename.isEmpty())
		{
			SlotUpdateDefaultDir(filename);
			int i;
			RawDataSet* TempData = DataSetList->GetCurrentListItem()->GetData()->GetRawData();

			unsigned char* tempQ = new unsigned char[TempData->GetVolumeSize()];

			for (i = 0; i < TempData->GetVolumeSize(); i++)
				*(tempQ + i) = (char)(*(TempData->GetDataArray() + i) * 255.0 / (double)TempData->GetMaxValue());



			//const char *name1;	
			FILE* plik;
			//name1=filename.toLocal8Bit();
			plik = fopen(filename.toLocal8Bit(), "wb");
			fwrite(tempQ, sizeof(unsigned char), TempData->GetVolumeSize(), plik);
			fclose(plik);
			delete[]tempQ;


		}
	}
}


