void MainWindow::SlotAddMaskFromImageWidget(unsigned char* tab)
{

	if ((GUIPanel->segAction[7]->isChecked() == false) && (addBarrier == false)) return;
	//	if (GUIPanel->segAction[7]->isOn()==false) return; ??
	//QString file=QDir::current().path()+"/pic.png";
	//		img.save(file,"PNG");
	///unsigned char *tab11 = img.bits();
	//unsigned int *tab = (unsigned int *)tab11;

	//QMessageBox::about( 0,"hej",QString::number(LastClickedView));

	if (MaskData == NULL)
	{
		MaskData = new unsigned char[data->GetVolumeSize()];
		memset(MaskData, 0, data->GetVolumeSize());
	}



	bool	PaintThroughAllSlices = GUIPanel->FillThroughAllSlices->isChecked();
	int		BoolMode = GUIPanel->FillModeCombo->currentIndex();
	char	Mode = (GUIPanel->ClearWithFillCheckBox->isChecked() == true) ? 1 : 0;

	if (Mode == 1) BoolMode = 1;//CLEAR

	int StartSlice, EndSlice;


	//unsigned int *tab1;//=tab;
	int i, j, k;
	int pos;

	int XX, YY;
	int count = 0;
	switch (LastClickedView)
	{
	case 0:
		//--------------------------------------
		//transversal
		if (PaintThroughAllSlices == false)
		{
			StartSlice = EndSlice = SliceNumber;
		}
		else
		{
			StartSlice = 0; EndSlice = data->GetNz() - 1;
		}

		XX = data->GetNx();
		YY = data->GetNy();

		for (k = StartSlice; k <= EndSlice; k++)
		{
			//tab1 = tab;
			//tab1=new unsigned char[XX*YY];
			//memcpy(tab1,tab,XX*YY);
			int pos1 = 0;
			unsigned int val = *tab;
			for (j = 0; j < YY; j++)
				for (i = 0; i < XX; i++)
				{
					/*	if (*tab1!=val)
					{
					i=i;
					}*/
					pos = i + j * data->GetNx() + k * data->GetSliceSize();

					MaskData[pos] = BoolOperation(BoolMode, MaskData[pos], ((tab[pos1++]) == 1) ? 1 : 0);
					count += MaskData[pos];
				}
		}

		break;

	case 1:

		//--------------------------------------coronal		
		//--------------------------------------
		if (PaintThroughAllSlices == false)
		{
			StartSlice = EndSlice = SliceNumber;
		}
		else
		{
			StartSlice = 0; EndSlice = data->GetNy() - 1;
		}

		XX = data->GetNx();
		YY = data->GetNz();
		for (k = StartSlice; k <= EndSlice; k++)
		{
			int pos1 = 0;
			//tab1 = tab;
			//tab1=new unsigned char[XX*YY];
			//memcpy(tab1,tab,XX*YY);
			for (j = 0; j < YY; j++)
				for (i = 0; i < XX; i++)
				{

					pos = i + (data->GetNy() - k - 1) * data->GetNx() + (data->GetNz() - j - 1) * data->GetSliceSize();
					MaskData[pos] = BoolOperation(BoolMode, MaskData[pos], (tab[pos1++] == 1) ? 1 : 0);
					count += MaskData[pos];
				}

		}

		break;

	case 2:
		//--------------------------------------
		//--------------------------------------sagittal
		if (PaintThroughAllSlices == false)
		{
			StartSlice = EndSlice = SliceNumber;
		}
		else
		{
			StartSlice = 0; EndSlice = data->GetNx() - 1;
		}

		XX = data->GetNy();
		YY = data->GetNz();

		for (k = StartSlice; k <= EndSlice; k++)
		{
			int pos1 = 0;
			//tab1 = tab;
			//tab1=new unsigned char[XX*YY];
			//memcpy(tab1,tab,XX*YY);

			unsigned int xx = (0xffffffff) & (4278190082);
			for (j = 0; j < YY; j++)
				for (i = 0; i < XX; i++)
				{
					pos = k + (i)*data->GetNx() + (data->GetNz() - j - 1) * data->GetSliceSize();

					MaskData[pos] = BoolOperation(BoolMode, MaskData[pos], (tab[pos1++] == 1) ? 1 : 0);
					count += MaskData[pos];
				}


		}


		break;

	}

	qDebug() << "count: " << count;

	chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
	SagittalView->InsertMaskData(MaskData);
	CoronalView->InsertMaskData(MaskData);
	SlotInsertNewMask();


}
