void MainWindow::SlotImportVRMLData(const QString& filename)
{
	if (!filename.isEmpty())
	{
		SlotUpdateDefaultDir(filename);
		RTimer.Start("Loading VRML file and extracting surface", 0);


		PolygonSurfaceData* dataXX = new PolygonSurfaceData(VWidget);



		if (dataXX->LoadVRMLSurfaceDataSet(filename) == true)
		{
			SlotInsertPolygonSurface(dataXX);
			RTimer.Stop();
		}
		else
		{
			RTimer.StopError();
		}


		if (data == NULL) SlotSetNewLayout(5);
	}
}

//--------------------------------------	

void MainWindow::SlotImportVRMLData()
{
	QString filename = QFileDialog::getOpenFileName(this, "", FileDefaultDir, "*.wrl");
	SlotImportVRMLData(filename);
}

