void MainWindow::SlotImportNastranData(const QString& filename)
{
	if (!filename.isEmpty())
	{
		SlotUpdateDefaultDir(filename);
		RTimer.Start("Loading NASTRAN file and extracting surface", 0);


		PolygonSurfaceData* dataXX = new PolygonSurfaceData(VWidget);

		if (dataXX->LoadNASTRANSurfaceDataSet(filename) == true)
		{
			SlotInsertPolygonSurface(dataXX);
			RTimer.Stop();
		}
		else
		{
			RTimer.StopError();
		}

		if (data == NULL) SlotSetNewLayout(5);
	}
}


