void MainWindow::SlotExportGMeshFile()
{
	if ((SurfaceDataList->GetNumberOfItems() >= 1))
	{

		QString filename = QFileDialog::getSaveFileName(this, "", FileDefaultDir, "*.msh");

		if (!filename.isEmpty())
		{
			SlotUpdateDefaultDir(filename);

			//const char *name1;	
			if (filename.lastIndexOf(".msh") == -1)
				filename += ".msh";
			//name1=filename.toLocal8Bit();		





			int i;
			double Point1[3];
			vtkPolyData* MeshData = SurfaceDataList->GetCurrentListItem()->GetData()->GetVPolyData();

			vtkPoints* Points = MeshData->GetPoints();
			int			NumberOfPoints = Points->GetNumberOfPoints();


			vtkCellArray* Polys = MeshData->GetPolys();
			int NumberOfTriangles = Polys->GetNumberOfCells();

			//PLIK DLA GMESHU!!!


			FILE* Do_opa;

			Do_opa = fopen(filename.toLocal8Bit(), "w");

			fprintf(Do_opa, "$NOD\n");
			fprintf(Do_opa, "%d\n", NumberOfPoints);

			for (i = 0; i < NumberOfPoints; i++)
			{
				Points->GetPoint(i, Point1);
				fprintf(Do_opa, "%d %lf %lf %lf\n", i, Point1[0], Point1[1], Point1[2]);

			}

			fprintf(Do_opa, "$ENDNOD\n");
			fprintf(Do_opa, "$ELM\n");


			fprintf(Do_opa, "%d\n", NumberOfTriangles);


			vtkGenericCell* TriangleCell = vtkGenericCell::New();

			for (i = 0; i < NumberOfTriangles; i++)
			{
				MeshData->GetCell(i, TriangleCell);

				fprintf(Do_opa, "%d 2 0 0 3 ", i);
				fprintf(Do_opa, "%d %d %d\n", TriangleCell->GetPointId(0), TriangleCell->GetPointId(1), TriangleCell->GetPointId(2));


			}

			fprintf(Do_opa, "$ENDELM\n");

			fclose(Do_opa);

		}

	}



}


