void MainWindow::SlotExportNastranMeshFile()
{
	if ((SurfaceDataList->GetNumberOfItems() >= 1))
	{

		//TYLKO DLA QLEK!!!!

		QString filename = QFileDialog::getSaveFileName(this, "", FileDefaultDir, "*.bdf");

		if (!filename.isEmpty())
		{
			SlotUpdateDefaultDir(filename);

			//const char *name1;	
			if (filename.lastIndexOf(".bdf") == -1)
				filename += ".bdf";
			//name1=filename.toLocal8Bit();		





			int i;
			double Point1[3];
			vtkPolyData* MeshData = SurfaceDataList->GetCurrentListItem()->GetData()->GetVPolyData();

			SurfaceDataList->GetCurrentListItem()->GetData()->ComputeGeometricOrigin();
			double Origin[3];

			//	for(i=0;i<3;i++)
			//		Origin[i]=SurfaceDataList->GetCurrentListItem()->GetData()->GetOrigin()[i];


			Origin[0] = GUIPanel->SurfaceOriginXEdit->text().toFloat();
			Origin[1] = GUIPanel->SurfaceOriginYEdit->text().toFloat();
			Origin[2] = GUIPanel->SurfaceOriginZEdit->text().toFloat();




			vtkPoints* Points = MeshData->GetPoints();
			int			NumberOfPoints = Points->GetNumberOfPoints();


			vtkCellArray* Polys = MeshData->GetPolys();
			int NumberOfTriangles = Polys->GetNumberOfCells();

			//PLIK DLA Nastran!!!



			FILE* Do_opa;

			Do_opa = fopen(filename.toLocal8Bit(), "w");

			fprintf(Do_opa, "BEGIN BULK\n");



			vtkGenericCell* TriangleCell = vtkGenericCell::New();


			for (i = 0; i < NumberOfTriangles; i++)
			{
				MeshData->GetCell(i, TriangleCell);
				fprintf(Do_opa, "CTETRA  ");
				fprintf(Do_opa, "%d\t", i + 1);
				fprintf(Do_opa, "%d\t", 1);
				fprintf(Do_opa, "%d\t%d\t%d\t%d\n", TriangleCell->GetPointId(0) + 1, TriangleCell->GetPointId(1) + 1, TriangleCell->GetPointId(2) + 1, NumberOfPoints + 1);


			}


			for (i = 0; i < NumberOfPoints; i++)
			{
				fprintf(Do_opa, "GRID*   ");
				fprintf(Do_opa, "%d\t", i + 1);
				fprintf(Do_opa, "                        ");
				Points->GetPoint(i, Point1);

				fprintf(Do_opa, "%lf\t%lf\t\n", Point1[0], Point1[1]);
				fprintf(Do_opa, "*        ");
				fprintf(Do_opa, "%lf\n", Point1[2]);



			}
			fprintf(Do_opa, "GRID*   ");
			fprintf(Do_opa, "%d\t", i + 1);
			fprintf(Do_opa, "                        ");


			fprintf(Do_opa, "%lf\t%lf\t\n", Origin[0], Origin[1]);
			fprintf(Do_opa, "*        ");
			fprintf(Do_opa, "%lf\n", Origin[2]);


			//material



			fprintf(Do_opa, "MAT1*   1                  120000.000000                        0.490000/n*            1020.000000        0.000000\n");

			fprintf(Do_opa, "ENDDATA");

			fclose(Do_opa);

		}

	}



}

