void MainWindow::SlotCreateDefaultDirFileIfNotExists()
{

	QDir Dir;
	ProgramDirName = Dir.absolutePath();
	ProgramDefaultDirPath = ProgramDirName + "/.RibonXDefaultDir";
	//QMessageBox::about( 0,"DICOM",ProgramDefaultDirPath);

	// teraz sprawdze czy jest plik ze sciezka bazowa, jak jest to git a jak nie to go zrobie	
	FILE* plik;
	plik = fopen(ProgramDefaultDirPath.toLocal8Bit(), "rt");
	if (plik == NULL)
	{
		//	QMessageBox::about( 0,"DICOM","NieMa Pliku Zakladam jesli sie da");

		FILE* plik = fopen(ProgramDefaultDirPath.toLocal8Bit(), "wt");
		if (plik != NULL)
		{
			fprintf(plik, "%s\n", ProgramDirName.toLocal8Bit());
			fclose(plik);
		}

		FileDefaultDir = ProgramDirName;
	}
	else
	{
		//		QMessageBox::about( 0,"DICOM","JestPlik!");

		//WCZYTAJ TO!!!!!!!
		//FileDefaultDir=
		/*	char PathName[256];
		fscanf(plik,"%s",PathName);
		FileDefaultDir=QString::fromLatin1(PathName);
		fclose(plik);
		*/
		fclose(plik);


		QFile file(ProgramDefaultDirPath);
		if (file.open(QIODevice::ReadOnly))
		{
			QTextStream stream(&file);

			//while ( !stream.atEnd() ) 
			{
				if (!stream.atEnd()) FileDefaultDir = stream.readLine();

				lastFileName.clear();;



				do
				{
					lastFileName += stream.readLine();
					//if (!stream.atEnd()) lastFileName = stream.readLine();
				} while (!stream.atEnd());
			}
			file.close();
		}






		//	QMessageBox::about( 0,"DICOM",FileDefaultDir);
	}

}


