void MainWindow::SlotUpdateDefaultDir(const QString& filename, int Mode)
{
	if (blockUpdateDefaultDir == true)return;
	//moe cos ma pozniej robic!

	//podana sciezka (moze byc z danym plikien) jest ustalana jako default
	QString Ntemp;

	int pos = filename.lastIndexOf("/");
	if (pos >= 0)
	{
		Ntemp = filename;
		Ntemp.remove(pos, Ntemp.length());
	}


	FileDefaultDir = Ntemp;
	//if (isMultiDropEnabled==false)
	//		lastFileName=filename;
	QFile file(ProgramDefaultDirPath);
	if (file.open(QIODevice::WriteOnly))


		//FILE *plik=fopen(ProgramDefaultDirPath.toLocal8Bit(),"wt");
		//if (plik==NULL) return;

	{
		QTextStream stream(&file);
		//fprintf(plik,"%s\n",Ntemp.toLocal8Bit());
		stream << Ntemp << "\n";
		if (isMultiDropEnabled == false)
		{
			//fprintf(plik,"%s\n",filename.toLocal8Bit());

			stream << filename << "\n";
		}
		else
		{

			QString nam;

			if (Mode == 1)//znaczy ze last file bedzie updated
			{
				QStringList lastFileName2;
				lastFileName2.clear();
				lastFileName2 += filename;
				int nr = lastFileName2.count();
				int i;
				for (QStringList::Iterator it = lastFileName2.begin(); it != lastFileName2.end(); ++it)
				{
					nam = *it;
					//fprintf(plik,"%s\n",nam.toLocal8Bit());
					stream << nam << "\n";
				}

			}
			else
			{


				int nr = lastFileName.count();
				int i;
				for (QStringList::Iterator it = lastFileName.begin(); it != lastFileName.end(); ++it)
				{
					nam = *it;
					//fprintf(plik,"%s\n",nam.toLocal8Bit());
					stream << nam << "\n";
				}
			}
		}
		file.close();
	}
	//fclose(plik);	

}

