void	MainWindow::SlotLoadLastFilter()
{

	QSettings sett(configIniName, QSettings::IniFormat);
	sett.beginGroup("Data-Init");

	if (sett.contains("LastFilterPath"))
	{
		QDir rDir(progDirPath);
		rDir.cd("filter_compositions");


		QString ffMode = sett.value("FasFilterMode").toString();

		bool fMode = (ffMode.compare("On") == 0) ? true : false;
		QString txt = "";
		txt = sett.value("LastFilterPath").toString();

		if (!txt.isEmpty())
		{
			if (fMode == false)
			{
				SlotLoadMixerSettings(txt);
			}
			else
			{
				//ustawiam wlasciwy combobox od filtra



				for (int i = 0; i < GUIPanel->fastFiltersComboBox->count(); i++)
				{
					QString txt2 = rDir.absolutePath() + "/" + GUIPanel->fastFiltersComboBox->itemText(i) + ".layers";
					if (txt.compare(txt2) == 0)
					{
						GUIPanel->fastFiltersComboBox->setCurrentIndex(i);
						break;
					}
				}


				//porownaj tekst i odpal fastfilter
				LoadFastFilter(txt);
			}
		}
	}
	sett.endGroup();

}
