//----------------------------------
void MainWindow::SlotLoadUniversalData(const QString& filename2)
{


	QString filename;
	filename = filename2;


	if (filename.mid(filename.length() - 7, 7) == ".header")
		filename.remove(filename.length() - 7, 7);


	QString Name = filename;
	int pos = Name.lastIndexOf(".");

	if (pos >= 0)
		Name.remove(0, pos + 1);

	Name = Name.toLower();

	QFileInfo check_file(filename);
	// check if file exists and if yes: Is it really a file and no directory?
	if (!(check_file.exists() && check_file.isFile())) return;

	//	QMessageBox::about( 0,"DICOM",Name);
	if (!filename.isEmpty())
	{
		if (isMultiDropEnabled == false)
			SlotUpdateDefaultDir(filename, 0);
		if (Name == "seeds")
		{
			SlotLoadSeeds(filename);
		}
		else if (Name == "arterydata")
		{
			SlotLoadArteryData(filename);
		}
		else if (Name == "rdata")
		{
			SlotLoadRawDataSet2(filename);
		}
		else if (Name == "dat")
		{
			SlotLoadRawDataSet(filename);
		}
		else if (Name == "poly")
		{
			SlotLoadPolygonSurfaceDataSet(filename);
		}
		else if (Name == "sdata")
		{
			SlotLoadPolygonSurfaceDataSet2(filename);
		}
		else if (Name == "stl")
		{
			SlotLoadSTLSurfaceDataSet(filename);
		}
		else if (Name == "obj")
		{
			SlotLoadOBJSurfaceDataSet(filename);
		}
		else if (Name == "vtk")
		{
			LoadVTKSurfaceDataSet(filename);
		}
		else if (Name == "bdf")
		{
			SlotImportNastranData(filename);
		}
		else if (Name == "mask")
		{
			SlotLoadMask(filename);
		}
		else if (Name == "trans")
		{
			SlotVolumeRegistrationLoadTrans(filename);
		}
		else if (Name == "wrl")
		{
			SlotImportVRMLData(filename);
		}
		else if (Name == "animseq")
		{
			SlotLoadAnimationSequence(filename);
		}
		else if (Name == "animseq2")
		{
			SlotLoadAnimationSequence2(filename);
		}
		else if (Name == "script")
		{
			SlotLoadJobScriptSequence(filename);
		}
		else if (Name == "grid")
		{
			SlotLoadGrid3D(filename);
		}
		else if ((Name == "jpg") || (Name == "jpeg"))
		{
			SlotLoadJpegDataSet(filename);
		}
		else if ((Name == "png"))
		{
			SlotLoadPngDataSet(filename);
		}
		else if ((Name == "bmp"))
		{
			SlotLoadBmpDataSet(filename);
		}
		else if ((Name == "maskset"))
		{
			SlotLoadMaskSet(filename);
		}
		else if ((Name == "avi") || (Name == "mpg") || (Name == "mpeg"))
		{
			SlotLoadVideoDataSet(filename);
		}
		else if (((Name == "raw")) || (Name == "bin"))
		{
			SlotLoadUnknownRawDataSet(filename);
		}
		else if ((Name == "ttw"))
		{
			SlotLoadTTWDataSet(filename);
		}
		else if ((Name == "nii"))
		{
			SlotLoadNIFTIWDataSet(filename);
		}
		else if ((Name == "job"))
		{
			SlotStartJob(filename);
		}
		else if ((Name == "tre"))
		{
			SlotLoadTREFile(filename);
		}
		else if ((Name == "mha"))
		{
			SlotLoadMHAFIle(filename);
		}
		else
		{
			SlotOpenDicomFile(filename);
		}
	}




}


