//--------------------------------------
void MainWindow::dropEvent(QDropEvent* evt)
{
	dontSendSurfaceInfoAndBlockSelection = true;
	//	QListViewItem *item = itemAt( contentsToViewport(e->pos()) );
	//  if ( item )


	qDebug() << "drop" << evt->mimeData()->formats();

	//QList<QUrl> lst;
	//QUriDrag::decode( evt, lst );

	//QString str;
	QString tmp;
	lastFileName.clear();

	QList<QUrl> lst = evt->mimeData()->urls();
	droppedFileCount = lst.count();
	for (uint i = 0; i < lst.count(); ++i)
	{
		//	QString filename = lst.at( i );
		//	QUrl url(filename);//url.path()
		QUrl url = lst.at(i);
		QString pp = url.path();
		tmp = ((pp).replace("|", ":"));
		if (tmp.mid(3, 1) == ":") tmp = tmp.remove(0, 2);
		if (tmp.mid(0, 1) == "/") tmp.remove(0, 1);
		//	  str += tmp + "\n";
		lastFileName += tmp;

	}

	if (evt->keyboardModifiers() & Qt::ControlModifier)
	{
		tmp = tmp;
		isCTRLpressed = true;
	}
	else
	{
		isCTRLpressed = false;
	}
	isMultiDropEnabled = true;

	SlotUpdateDefaultDir(tmp);
	isMultiDropEnabled = false;

	blockUpdateDefaultDir = true;
	SlotLoadLastFile();
	blockUpdateDefaultDir = false;
	//	QMessageBox::about( 0,"",str);
	//QWidget* fw = qApp->focusWidget();

	qApp->processEvents();
	VWidget->setFocus();
	//qDebug() << "focus";
	droppedFileCount = 0;
	dontSendSurfaceInfoAndBlockSelection = false;
}

