void MainWindow::SlotApplySurfaceTransformation()
{



	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		int Nr = SurfaceDataList->GetNumberOfItems();
		int i, j;
		PolygonSurfaceData* Data;
		GUIPanel->SlotBlockUpdateSelectionList(true);

		double Origin[3];

		for (j = 0; j < 3; j++)
			Origin[j] = CurrentSurfaceDataSetListItem->GetData()->GetOrigin()[j];






		for (i = Nr - 1; i >= 0; i--)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (Data->GetTreeItem()->isSelected() == true)
			{
				SurfaceDataList->SetCurrentItem(i);
				CurrentSurfaceDataSetListItem = SurfaceDataList->GetCurrentListItem();
				GUIPanel->SlotChangeCurrentPolygonSurfaceDataItem(i);
				SProcessing->SlotSetCurrentSurface(Data);
				///////////////////////////////////

				CurrentSurfaceDataSetListItem->GetData()->SetCustomOrigin(Origin);
				SProcessing->SlotTransformPolygonalData(
					GUIPanel->SurfaceScaleXEdit->text().toFloat(),
					GUIPanel->SurfaceScaleYEdit->text().toFloat(),
					GUIPanel->SurfaceScaleZEdit->text().toFloat(),

					GUIPanel->SurfaceShearXEdit->text().toFloat(),
					GUIPanel->SurfaceShearYEdit->text().toFloat(),
					GUIPanel->SurfaceShearZEdit->text().toFloat(),

					GUIPanel->SurfaceOriginXEdit->text().toFloat(),
					GUIPanel->SurfaceOriginYEdit->text().toFloat(),
					GUIPanel->SurfaceOriginZEdit->text().toFloat());
				///////////////////////////////////
			}
		}

		GUIPanel->SlotBlockUpdateSelectionList(false);
		//		GUIPanel->SlotSurfaceListSelectionChanged();

	}




}


