void MainWindow::SlotShowCameraSettings()
{


	//if(SurfaceDataList->GetNumberOfItems()>=1)
	if (VWidget != NULL)
	{


		QString text = "Settings:\n";

		double* a = new double[3];

		vtkCamera* camera = VWidget->Renderer->GetActiveCamera();

		camera->GetPosition(a);
		text += "Position: ";
		text += QString::number(a[0]) + " ";
		text += QString::number(a[1]) + " ";
		text += QString::number(a[2]) + " ";
		text += "\n";

		camera->GetFocalPoint(a);
		text += "FocalPoint: ";
		text += QString::number(a[0]) + " ";
		text += QString::number(a[1]) + " ";
		text += QString::number(a[2]) + " ";
		text += "\n";

		camera->GetViewUp(a);
		text += "ViewUp: ";
		text += QString::number(a[0]) + " ";
		text += QString::number(a[1]) + " ";
		text += QString::number(a[2]) + " ";
		text += "\n";



		a = camera->GetOrientation();

		text += "Orientation: ";
		text += QString::number(a[0]) + " ";
		text += QString::number(a[1]) + " ";
		text += QString::number(a[2]) + " ";
		text += "\n";

		camera->GetViewPlaneNormal(a);
		text += "ViewPlaneNormal: ";
		text += QString::number(a[0]) + " ";
		text += QString::number(a[1]) + " ";
		text += QString::number(a[2]) + " ";
		text += "\n";



		QMessageBox::about(0, "Camera Settings", text);


	}

}

