//---------------------------

void MainWindow::SetCamSettings(int Mode)
{
	if (VWidget != NULL)
	{
		bool state = cameraActions[6]->isChecked();
		cameraUsesBase = state;



		if (Mode == 7)
		{
			VWidget->SlotSetCubeVisibility(cameraActions[7]->isChecked());
		}
		//if (Mode==6)
		//{
		//	
		//	//CameraMenu->setItemChecked(6,!state);
		//	state=!state;
		//	cameraUsesBase=state;
		//}


		double baseVec[9];
		if (cameraUsesBase == false)
		{
			baseVec[0] = 1;	baseVec[1] = 0;	baseVec[2] = 0;
			baseVec[3] = 0;	baseVec[4] = 1;	baseVec[5] = 0;
			baseVec[6] = 0;	baseVec[7] = 0;	baseVec[8] = 1;
		}
		else
		{
			int i;
			for (i = 0; i < 9; i++)
			{
				baseVec[i] = baseVectors[i];
			}
		}
		vtkRenderer* renderer = VWidget->Renderer;
		vtkCamera* camera = VWidget->Renderer->GetActiveCamera();
		vtkLightCollection* lightCollection = renderer->GetLights();
		lightCollection->InitTraversal();
		vtkLight* light = lightCollection->GetNextItem();


		double* a = renderer->ComputeVisiblePropBounds();
		double* c = new double[3];
		c[0] = (a[1] + a[0]) / 2.0;
		c[1] = (a[3] + a[2]) / 2.0;
		c[2] = (a[5] + a[4]) / 2.0;

		camera->SetFocalPoint(c[0], c[1], c[2]);

		if (Mode == 6)
		{
			Mode = lastCameraView;
		}


		switch (Mode)
		{

		case 0://Top

			camera->SetPosition(c[0] + baseVec[6], c[1] + baseVec[7], c[2] + baseVec[8]);
			camera->SetViewUp(baseVec[3], baseVec[4], baseVec[5]);
			lastCameraView = Mode;
			//camera->SetPosition(c[0],c[1],c[2]+1);
			//camera->SetViewUp(0,1,0);	
			break;



		case 1://Bottom

			//camera->SetPosition(c[0],c[1],c[2]-1);
			//camera->SetViewUp(0,-1,0);

			camera->SetPosition(c[0] - baseVec[6], c[1] - baseVec[7], c[2] - baseVec[8]);
			camera->SetViewUp(-baseVec[3], -baseVec[4], -baseVec[5]);
			lastCameraView = Mode;
			break;


		case 2://Front

			camera->SetPosition(c[0] - baseVec[3], c[1] - baseVec[4], c[2] - baseVec[5]);
			camera->SetViewUp(baseVec[6], baseVec[7], baseVec[8]);
			lastCameraView = Mode;
			//camera->SetPosition(c[0],c[1]-1,c[2]);
			//camera->SetViewUp(0,0,1);

			break;


		case 3://Back

			//camera->SetPosition(c[0],c[1]+1,c[2]);
			//camera->SetViewUp(0,0,1);

			camera->SetPosition(c[0] + baseVec[3], c[1] + baseVec[4], c[2] + baseVec[5]);
			camera->SetViewUp(baseVec[6], baseVec[7], baseVec[8]);
			lastCameraView = Mode;
			break;


		case 5://Left


			//camera->SetPosition(c[0]-1,c[1],c[2]);
			//camera->SetViewUp(0,0,1);
			camera->SetPosition(c[0] - baseVec[0], c[1] - baseVec[1], c[2] - baseVec[2]);
			camera->SetViewUp(baseVec[6], baseVec[7], baseVec[8]);
			lastCameraView = Mode;
			break;


		case 4://Right

			//camera->SetPosition(c[0]+1,c[1],c[2]);
			//camera->SetViewUp(0,0,1);
			camera->SetPosition(c[0] + baseVec[0], c[1] + baseVec[1], c[2] + baseVec[2]);
			camera->SetViewUp(baseVec[6], baseVec[7], baseVec[8]);
			lastCameraView = Mode;
			break;




		}

		/*vtkSmartPointer<vtkMatrix4x4> viewMat = vtkSmartPointer<vtkMatrix4x4>::New();
		viewMat = camera->GetViewTransformMatrix();
		double* m = viewMat->GetData();*/

		vtkMatrix4x4* ma = vtkMatrix4x4::New();
		ma->Identity();
		double* m = ma->GetData();
		m[0] = baseVec[0]; m[1] = baseVec[1]; m[2] = baseVec[2];
		m[4] = baseVec[3]; m[5] = baseVec[4]; m[6] = baseVec[5];
		m[8] = baseVec[6]; m[9] = baseVec[7]; m[10] = baseVec[8];
		VWidget->SetNewBaseMatrix(m);
		light->SetPosition(camera->GetPosition());
		light->SetFocalPoint(camera->GetFocalPoint());
		VWidget->SlotResetCamera();




	}


}
