void MainWindow::SlotCopyToClipBoardCamera()
{
	if (VWidget != NULL)
	{

		vtkRenderer* renderer = VWidget->Renderer;
		vtkCamera* camera = VWidget->Renderer->GetActiveCamera();
		vtkLightCollection* lightCollection = renderer->GetLights();
		lightCollection->InitTraversal();
		vtkLight* light = lightCollection->GetNextItem();


		double points[15];

		camera->GetPosition(points);
		camera->GetViewUp(points + 3);
		camera->GetFocalPoint(points + 6);

		light->GetPosition(points + 9);
		light->GetFocalPoint(points + 12);
		//renderer->ResetCameraClippingRange();
		//->Interactor->updateGL();

		QString txt = "";
		for (int i = 0; i < 15; i++)
		{
			txt += QString::number(points[i]);
			if (i < 14) txt += ",";
		}


		QClipboard* clipboard = QApplication::clipboard();
		clipboard->setText(txt);
		SlotShowMessage("camera settings copied to clipboard");
	}
}

//---------------------------------

void MainWindow::SlotPasteFromClipboardCamera()
{
	if (VWidget != NULL)
	{

		vtkRenderer* renderer = VWidget->Renderer;
		vtkCamera* camera = VWidget->Renderer->GetActiveCamera();
		vtkLightCollection* lightCollection = renderer->GetLights();
		lightCollection->InitTraversal();
		vtkLight* light = lightCollection->GetNextItem();


		double points[15];

		QString txt = "";
		QClipboard* clipboard = QApplication::clipboard();
		txt = clipboard->text();
		QStringList fields = txt.split(",", QString::SkipEmptyParts);

		//renderer->ResetCameraClippingRange();
		//->Interactor->updateGL();

		int c = fields.count();
		if (c == 15)
		{
			for (int i = 0; i < 15; i++)
			{
				points[i] = fields[i].toDouble();

			}


			camera->SetPosition(points);
			camera->SetViewUp(points + 3);
			camera->SetFocalPoint(points + 6);

			light->SetPosition(points + 9);
			light->SetFocalPoint(points + 12);

			//renderer->ResetCameraClippingRange();
			VWidget->Interactor->repaint();
			//	VWidget->Interactor->updateGL();

			SlotShowMessage("camera settings copied to clipboard");
		}
		else
		{
			SlotShowMessage("no camera info in clipboard");
		}
	}
}




