//---------------------------------

void MainWindow::SlotMoveCamera(double* Point1, double* Point2)
{

	if (VWidget != NULL)
	{
		vtkRenderer* renderer = VWidget->Renderer;
		vtkCamera* camera = VWidget->Renderer->GetActiveCamera();
		vtkLightCollection* lightCollection = renderer->GetLights();
		lightCollection->InitTraversal();
		vtkLight* light = lightCollection->GetNextItem();

		double Point3[3];
		int i;
		camera->GetFocalPoint(Point3);


		double viewup[3];
		double v1[3], v2[3];
		double den;

		for (i = 0; i < 3; i++)
		{
			v1[i] = Point3[i] - Point1[i];
			v2[i] = Point2[i] - Point1[i];
		}



		viewup[0] = v1[1] * v2[2] - v1[2] * v2[1];
		viewup[1] = v1[2] * v2[0] - v1[0] * v2[2];
		viewup[2] = v1[0] * v2[1] - v1[1] * v2[0];



		if ((den = (double)sqrt(viewup[0] * viewup[0] + viewup[1] * viewup[1] + viewup[2] * viewup[2])) != 0.0)
		{
			for (i = 0; i < 3; i++)
			{
				viewup[i] /= den;
			}

		}




		camera->SetPosition(Point1);
		camera->SetViewUp(viewup);


		light->SetPosition(camera->GetPosition());
		light->SetFocalPoint(camera->GetFocalPoint());

		renderer->ResetCameraClippingRange();

		//VWidget->Interactor->updateGL();
	}
}

