void MainWindow::SlotGrabAnimation()
{

	//if (GrabWindowPath.isEmpty())
	//{
	//	QString fn = Q3FileDialog::getExistingDirectory(FileDefaultDir,this);
	//	if (fn.isEmpty()) return;
	//	GrabWindowPath=fn+"/";
	//}
	//if (!GrabWindowPath.isEmpty())
	{
		bool states[11];
		int i;
		for (i = 0; i < 11; i++)
		{
			states[i] = GUIPanel->videoAction[i]->isChecked();
		}

		int mode = -1;
		for (i = 5; i < 11; i++)
		{
			if (states[i] == true)
			{
				mode = i - 4;
				break;
			}
		}

		recordMode = mode;
		//connect(Anim,SIGNAL( Signal3DFrameGenerated()),this,SLOT( SlotSaveGrab3DWindow()));
		grabAnim = true;
		Anim->SetGrabAnimMode(true);


		int val = GUIPanel->functionForGenAnimComboBox->currentIndex();
		if (val > 0)
		{
			specialValStart = 0;
			specialInit = true;
			switch (val)
			{
			case 1:
				connect(Anim, SIGNAL(Signal3DFrameGenerated()), this, SLOT(SlotSpecialFunctiionForGrowing1()));
				break;
			}
		}



		connect(Anim, SIGNAL(Signal3DFrameGenerated()), this, SLOT(SlotGrabFrameForFFMpegAnimation()));
		SlotGenerateAnimation();
		disconnect(Anim, SIGNAL(Signal3DFrameGenerated()), this, SLOT(SlotGrabFrameForFFMpegAnimation()));
		if (val > 0)
		{

			switch (val)
			{
			case 1:
				disconnect(Anim, SIGNAL(Signal3DFrameGenerated()), this, SLOT(SlotSpecialFunctiionForGrowing1()));
				break;
			}
		}
		grabAnim = false;
		Anim->SetGrabAnimMode(false);
		//disconnect(Anim,SIGNAL( Signal3DFrameGenerated()),this,SLOT( SlotSaveGrab3DWindow()));
	}


}

//-----------------------------------------
void MainWindow::GenAnimation(int start)
{
	//if (recordMode<0) return;
//int tab[4];
//tab[0]=GUIPanel->LoopVisibilityChechBox->isChecked();
//tab[1]=GUIPanel->NrOfTotalLoopSurfacesBox->value();
//tab[2]=GUIPanel->NrOfFrameSurfacesBox->value();
//	tab[3]=GUIPanel->FrameStepNr->value();
	int series = GUIPanel->NrOfFrameSurfacesBox->value();
	bool loopVisibility = GUIPanel->LoopVisibilityChechBox->isChecked();

	//-------------
	// stworzyc tablice z numerami zaznaczonych powierzchni i przekazac ja do anim
	int Nr = SurfaceDataList->GetNumberOfItems();

	int* activeSurfacesTab = new int[Nr];
	ListItem<PolygonSurfaceData*>* tmpItem;
	int nr = 0;
	int j;
	for (j = 0; j < Nr; j++)
	{
		tmpItem = SurfaceDataList->GetItemAtPos(j);
		if (tmpItem->GetData()->GetTreeItem()->isSelected() == true) // czy zaznaczony
		{
			activeSurfacesTab[nr] = j;
			nr++;

		}
	}



	bool smooth = GUIPanel->smoothAnimationCheckBox->isChecked();
	if ((grabAnim == true) && (recordMode >= 0)) SlotStartRecordVideo(recordMode);

	Anim->SetAnimOnlyOpacityOfGroups(GUIPanel->animOnlyOpacityOfGroupsCheckBox->isChecked());
	Anim->SetUpdateVolume(GUIPanel->updateVolumeCheckBox->isChecked());




	Anim->GenerateAnimationSequence(GUIPanel->LoopAnimationCheckBox->isChecked(), loopVisibility, series, activeSurfacesTab, nr, smooth, start);

	if ((grabAnim == true) && (recordMode >= 0)) SlotStopRecordVideo();
	GUIPanel->CurrentKeyFrameNrEdit->setText(QString::number(Anim->GetCurrentItemNumber()));
	delete[]activeSurfacesTab;
}
