//------------------------------------------------------									
void MainWindow::SlotLoadJobScriptSequence(const QString& filename)
{
	if (!filename.isEmpty())
	{
		SlotUpdateDefaultDir(filename);
		//const char *name1;	
		//	name1=filename.toLocal8Bit();


		FILE* plik;
		plik = fopen(filename.toLocal8Bit(), "rt");

		//		int size=500;
		int i;

		//		char *lin=new char[size];

		char character;

		/// tu trzeba bedzie zrobic parsowanie!

		QString text;
		QString text2;
		character = ReadFileLine(plik, &text);


		if ((DataSetList->GetNumberOfItems() > 0) || (SurfaceDataList->GetNumberOfItems() > 0)) LockLayout = true;


		do
		{

			if (text[0] == '#')
			{
				//character=ReadFileLine(plik,&text);

				////////////////////////////////////////////////////////////////
				if (text == "#IMPORT_DATA")
				{
					// wczytywanie danych

					do
					{
						character = ReadFileLine(plik, &text);
						if (text[0] == '#') break;


						if (text == "IMPORT_DICOM_VOLUME")
						{
							character = ReadFileLine(plik, &text);
							if (text[0] == '#') break;

							SlotAnalyzeDICOMdir(text);
							if (DicomDirData->CurrentDicomDataSet != -1)
								SlotImportDICOMDataSet(DicomDirData->CurrentDicomDataSet);

						}
						else
							SlotLoadUniversalData(text);

					} while (character != EOF);
					// popelnione


					/////////////////////////////////////////////////////////////////////
				}
				else if (text == "#SET_ANIMSEQ_LOOP")
				{

					character = ReadFileLine(plik, &text);
					if (text[0] != '#')
					{
						if ((text == "ON") || (text == "true") || (text == "1"))
						{
							GUIPanel->LoopAnimationCheckBox->setChecked(true);
						}
						else
						{
							GUIPanel->LoopAnimationCheckBox->setChecked(false);
						}
						character = ReadFileLine(plik, &text);
					}

				}
				//////////////////////////////////////////////////////////////////////
				else if (text == "#GENERATE_ANIMSEQ_TO_FILE")
				{

					character = ReadFileLine(plik, &text);
					if (text[0] != '#')
					{
						bool direxists = false;

						QDir tempdir;
						if (tempdir.exists(text))
							direxists = true;
						else
							direxists = tempdir.mkdir(text);

						if (direxists == true)
						{

							// teraz trzeba zalozyc inny katalog
							text = text + "/" + GetTimeDateName();
							direxists = tempdir.mkdir(text);
							GrabWindowPath = text + "/";
							//pokaz volume zanim odpalisz!!!!!!!
							if ((DataSetList->GetNumberOfItems() > 0) && (Volume->GetMapper() != NULL)) SlotShowHideVolume(10);
							SlotGrabAnimation();

						}
						else
							QMessageBox::about(0, "", "Problem with animation path");

						character = ReadFileLine(plik, &text);
					}
				}
				//////////////////////////////////////////////////////////////////////////
				else if (text == "#REMOVE_ALL_DATA")
				{
					LockLayout = true;
					//	Reparent=false;
					//schowaj volume!!!
					if ((DataSetList->GetNumberOfItems() > 0) && (Volume->GetMapper() != NULL)) SlotShowHideVolume(10);

					DataSetList->DeleteAllItems();;// ? ?
					//for(i=0;i<DataSetList->GetNumberOfItems();i++)
					//SlotDeleteDataSet(DataSetList->G);

					for (i = 0; i < SurfaceDataList->GetNumberOfItems(); i++)
						SlotDeletePolygonSurfaceDataSet();


					//	GUIPanel->RawDataListView->clear();
					//	GUIPanel->SurfaceDataListView->clear();
					character = ReadFileLine(plik, &text);

					//Reparent=true;	

				}
				/////////////////////////////////////////////////////////////////////////////
				else if (text == "#SET3D_WINDOW_SIZE")
				{
					int aa = 0;
					if (LockLayout == true)
					{
						aa = 1;
						LockLayout = false;
					}

					for (i = 0; i < 1; i++)
					{

						character = ReadFileLine(plik, &text);
						if (text[0] == '#') break;
						int W = text.toInt();
						character = ReadFileLine(plik, &text);
						if (text[0] == '#') break;
						int H = text.toInt();

						SlotSet3DWindowSize(W, H);

						character = ReadFileLine(plik, &text);
					}

					if (aa == 1)
						LockLayout = true;


				}
				else
				{
					//QMessageBox::about( 0,"unknown command",text);
					character = ReadFileLine(plik, &text);
				}


				// to oznacza, ze tu padlo slowo kluczowe i trzeba zobaczyc jakie to slowo
			}


			if (text[0] != '#') 	character = ReadFileLine(plik, &text);

		} while (character != EOF);

		//		LockLayout=false;

		fclose(plik);


	}

}


