void MainWindow::SlotVoxelizeClosedVolume()
{


	if ((SurfaceDataList->GetNumberOfItems() >= 1))
	{



		RTimer.Start("Voxelization in Proggress");

		vtkPolyData* meshData = SurfaceDataList->GetCurrentListItem()->GetData()->GetVPolyData();


		//GraftVoxelize *GV=new GraftVoxelize();

		int SizeTemp[3];
		SizeTemp[0] = 128;//GUIPanel->DistStepXBox->value();
		SizeTemp[1] = 128;//GUIPanel->DistStepYBox->value();
		SizeTemp[2] = 128;//GUIPanel->DistStepZBox->value();

		//RawDataSet *dataX= GV->CreateVolumeFormSurface(MeshData,SizeTemp[0],SizeTemp[1],SizeTemp[2]);

		double scale[3] = { 0.5, 0.5, 0.5 };

		if (data != NULL) data->GetScale(scale);

		scale[0] /= 4; scale[1] /= 4; scale[2] /= 4;

		double bounds[6];
		meshData->GetBounds(bounds);

		int n[3];
		n[0] = ((bounds[1] - bounds[0])) / (double)scale[0];
		n[1] = ((bounds[3] - bounds[2])) / (double)scale[1];
		n[2] = ((bounds[5] - bounds[4])) / (double)scale[2];

		n[0] += 2; n[1] += 2; n[2] += 2;

		RawDataSet* dataX = new RawDataSet(n[0], n[1], n[2], scale[0], scale[1], scale[2]);
		dataX->ZeroQ();
		int i;
		vtkImageData* image = vtkImageData::New();
		image->SetSpacing(scale);
		image->SetOrigin(bounds[0] - scale[0], bounds[2] - scale[1], bounds[4] - scale[2]);
		image->SetExtent(0, n[0] - 1, 0, n[1] - 1, 0, n[2] - 1);

		//	image->SetScalarTypeToUnsignedChar();
		//	image->AllocateScalars();
		image->AllocateScalars(VTK_UNSIGNED_CHAR, 1);

		vtkPolyDataToImageStencil* p2s = vtkPolyDataToImageStencil::New();
		p2s->SetInputData(meshData);

		p2s->SetOutputSpacing(scale);
		p2s->SetOutputOrigin(bounds[0] - scale[0], bounds[2] - scale[1], bounds[4] - scale[2]);
		p2s->SetOutputWholeExtent(0, n[0] - 1, 0, n[1] - 1, 0, n[2] - 1);

		vtkImageStencil* stencil = vtkImageStencil::New();
		stencil->SetInputData(image);
		stencil->SetStencilConnection(p2s->GetOutputPort());
		stencil->ReverseStencilOn();
		stencil->SetBackgroundValue(1);
		stencil->Update();


		unsigned char* tt = (unsigned char*)stencil->GetOutput()->GetPointData()->GetScalars()->GetVoidPointer(0);
		//memcpy(Data2,tt,dataX->GetVolumeSize());
		unsigned short* dataTab = dataX->GetDataArray();
		for (i = 0; i < dataX->GetVolumeSize(); i++)
		{
			//if (tt[i]!=0) 
			dataTab[i] = tt[i];
			if (tt[i] == 1)
			{
				i = i;
			}
		}

		//-------------------------
		image->Delete();
		p2s->Delete();
		stencil->Delete();


		dataX->SetRawDataSetName("Voxelized-" + SurfaceDataList->GetCurrentListItem()->GetData()->GetPolygonSurfaceName());
		InsertRawDataSet(dataX);


		RTimer.Stop();
	}
}

