void MainWindow::SlotChangeLightIntensity(int value)
{
	double val = (double)value / 100;
	vtkCollectionIterator* iter = VWidget->Renderer->GetLights()->NewIterator();
	iter->GoToFirstItem();
	vtkLight* Light;
	int pos = 0;

	int Nr = VWidget->Renderer->GetLights()->GetNumberOfItems();


	do
	{
		if ((pos > 0) || (Nr == 1))
		{
			Light = ((vtkLight*)(iter->GetCurrentObject()));
			Light->SetIntensity(val);
		}
		pos++;

		iter->GoToNextItem();

	} while (iter->GetCurrentObject() != NULL);

	VWidget->Interactor->repaint();
	VWidget->Renderer->ResetCameraClippingRange();
	//	VWidget->Interactor->updateGL();
}

