void MainWindow::SlotGenerateThresholdedMCSurface()
{

	int Nr = DataSetList->GetNumberOfItems();
	if (Nr > 0)
	{
		RTimer.Start("Generating Surfaces");

		RawDataSet* tempRawData;
		int LThreshold = GUIPanel->LThreshLineEdit->text().toInt();
		int RThreshold = GUIPanel->RThreshLineEdit->text().toInt();
		int j;

		int nr = 0;
		for (j = 0; j < Nr; j++)
			if (DataSetList->GetItemAtPos(j)->GetData()->GetDataSelected() == true)
				nr++;

		int pos = 1;
		for (j = 0; j < Nr; j++)
		{
			if (DataSetList->GetItemAtPos(j)->GetData()->GetDataSelected() == true)
			{
				tempRawData = DataSetList->GetItemAtPos(j)->GetData()->GetRawData();
				//tu odpalic z surface processing robienie powierzchni opartej na thresholdach
				RTimer.TemporaryAppendToMainText("(" + QString::number(pos) + "/" + QString::number(nr) + ") ");
				SProcessing->SlotGenerateMarchingCubesSurface(tempRawData, LThreshold, RThreshold);
				pos++;
			}
		}
		tempRawData = NULL;

		RTimer.Stop();
	}



}
