void MainWindow::SlotMultiGridMultiVolumeDeform()
{
	//RawDataListView
	///////////////////////////////////////////
	if (DataSetList->GetNumberOfItems() >= 1)
	{
		DataSet* Data = DataSetList->GetCurrentListItem()->GetData();
		if (Data->GetDataSelected() == true)
		{
			RTimer.Start("Deforming Volume");
			QString filename = QFileDialog::getOpenFileName(this, "", FileDefaultDir, "*.*grid");
			if (!filename.isEmpty())
			{

				SlotUpdateDefaultDir(filename);
				FloatGrid3D* grid;//,*grid0,*tmpgrid;
				grid = NULL;
				VolumeElasticRegistration* Reg = NULL;
				grid = new FloatGrid3D();
				int nr = grid->GetNumberOfGrids(filename);
				int nnx = grid->GetNx();
				int nny = grid->GetNy();
				int nnz = grid->GetNz();
				delete grid; grid = NULL;

				ListItem<DataSet*>* tempData = NULL;

				int	DataSetNr = DataSetList->GetNumberOfItems();
				int* tabnr = new	int[DataSetNr];
				int	nrr = 0;
				int i, j;
				bool aa;
				//for	(j=DataSetNr-1;j>=0;j--)
				for (j = 0; j < DataSetNr; j++)
				{
					aa = DataSetList->GetItemAtPos(j)->GetData()->GetDataSelected();
					if (aa == true)
						tabnr[nrr++] = j;

					//nrr+=tabnr[j];
				}
				qApp->processEvents();
				if (nrr < nr) nr = nrr;

				if (nr > 0)
				{

					int pos = 1;
					for (i = 0; i < nr; i++)
					{
						//usun i stworz nowy i wczytaj z pliku
						grid = new FloatGrid3D();
						grid->LoadGrid(filename, i);
						//grid wczytany teraz petla po amount w obrebie kazdego gridu

						tempData = DataSetList->GetItemAtPos(tabnr[i]);
						Reg = new VolumeElasticRegistration(tempData, tempData, grid);
						RawDataSet* NewData = Reg->ApplyTransformation();
						//RawDataSet *NewData=Reg->GenerateAbsoluteDisplacementDataSet();
						delete Reg;
						qApp->processEvents();
						if (NewData != NULL)InsertRawDataSet(NewData);

						/////////////////////
						//deform klatki glownej
						//SProcessing->SlotApplyFFDDeformation(grid1,Poly,1.0,name+"_"+QString::number(i+1),N,S,pal);
						//----------------
						if (grid != NULL) { delete grid; grid = NULL; }

					}

					RTimer.Stop();
				}
				else
					RTimer.StopError("Nothing to deform");

				delete[]tabnr;
				tempData = NULL;

			}
			else
				RTimer.StopError("Bad file name!");

		}
	}

	//////////////////////////////////////////////
}
