void MainWindow::SlotVolumeGaussianSmoothing()
{

	RTimer.Start("doing sth");
	RawDataSet* Data = new RawDataSet();
	Data->Copy(*data, false);
	Data->ZeroQ();
	double stddev = 4.5;
	int radius = 3.0;
	GaussianSmoothingFiltering(stddev, radius, data, Data);
	QString name;
	name = data->GetRawDataSetName();
	name.append("-prop");
	Data->SetRawDataSetName(name);
	InsertRawDataSet(Data);
	RTimer.Stop();

}
