void MainWindow::SlotGetIntensityProbabilityData()
{
	RTimer.Start("doing sth");
	RawDataSet* data2 = new RawDataSet();
	data2->Copy(*data, false);
	data2->ZeroQ();
	//TextureSegmentation *tex = new TextureSegmentation(data, MaskData);
	//tex->GetIntensityProbabilityMap(Data);
	//RawDataSet *Data=tex->ExtractEdgesMap();




	double intensityFactor = 1.0;
	double sigma = 1.5;
	int xSize = data->GetMaxValue() + 1;
	unsigned short* samplesTab = new unsigned short[xSize];
	int expMax = data->GetMaxValue();
	double* expTab = new double[expMax * 2 + 1];
	GetExpTab(expTab, expMax, sigma, intensityFactor);
	memset(samplesTab, 0, xSize * sizeof(unsigned short));
	int nrOfSamples = 0;
	//	double sigma = 0;
		//double intensityFactor = 0;

	unsigned short* samplingTab1 = new unsigned short[xSize];
	unsigned short* samplingTabIndex = new unsigned short[xSize];
	int totalCount = 0;
	int maxPosNew = 0;


	//hist
	unsigned short* dataQ = data->GetDataArray();
	for (int i = 0; i < data->GetVolumeSize(); i++)
	{
		if (MaskData[i] > 0)
		{
			samplesTab[dataQ[i]]++;
		}
	}

	for (int i = 0; i < expMax; i++)
	{
		if (samplesTab[i] > 0)
		{
			samplingTab1[maxPosNew] = samplesTab[i];
			samplingTabIndex[maxPosNew] = i;
			maxPosNew++;
			totalCount += samplesTab[i];
			//teraz wystarczy biec po index tab do maxpos new zeby dobrac sie do wszystkich
		}

	}
	nrOfSamples = totalCount;
	delete[]samplesTab;
	//qDebug() << "sampling3DMode: " << sampling3DMode << " : " << totalCount;


	double* intensityProbabilityTab = new double[expMax];
	double min, max;

	GetIntensityProbabilityTab2(intensityProbabilityTab, expMax, min, max, sigma, expTab, samplingTab1, samplingTabIndex, maxPosNew, nrOfSamples);//ta	sie	przyda
	double factor = (max != 0) ? 1.0 / (max) : 1;
	delete[]samplingTab1;
	delete[]samplingTabIndex;

	double factor1 = (max - min != 0) ? 4096.0 / (max - min) : 1;

	int mmin = 65535;
	int mmax = 0;
	unsigned short* usData = data2->GetDataArray();
	for (int i = 0; i < data->GetVolumeSize(); i++)
	{
		usData[i] = (unsigned short)((intensityProbabilityTab[dataQ[i]]) * factor1);
		//	if (usData[i] < mmin)mmin = usData0[i];
		//	if (usData[i]>mmax)mmax = usData0[i];
	}


	int arrNx = 1024;
	int arrNy = 768;
	QImage arrowImg(arrNx, arrNy, QImage::Format_RGB32);

	arrowImg.fill(Qt::white);
	QPainter Painter2x(&arrowImg);
	Painter2x.setBrush(Qt::black);
	Painter2x.setPen(1);
	int maxValue = data->GetMaxValue();
	unsigned short* remapTab = new unsigned short[maxValue];
	double ff = (double)maxValue / max;
	for (int i = 0; i < maxValue; i++)
	{
		remapTab[i] = (intensityProbabilityTab[i]) * ff;
	}

	double scx = (maxValue > 0) ? (double)arrNx / maxValue : 1;
	for (int i = 0; i < maxValue; i++)
	{
		Painter2x.drawLine(QPoint(i * scx, 0), QPoint(remapTab[i] * scx, arrNy));
	}
	delete[]remapTab;
	arrowImg.save("d:\\mapping-lines.png");



	delete[]intensityProbabilityTab;
	delete[]expTab;

	/////////
	QString name;
	name = data->GetRawDataSetName();
	name.append("-prop");
	data2->SetRawDataSetName(name);
	InsertRawDataSet(data2);
	RTimer.Stop();
}

