void MainWindow::SetOpacityWithChildren(PolygonSurfaceData* data, double opacity)
{

	if ((data != NULL) && (data->childrenPolygonSurfaceDataList != NULL))
	{
		int nr = data->childrenPolygonSurfaceDataList->GetNumberOfItems();
		data->GetVProperty()->SetOpacity(opacity);
		int i;
		for (i = 0; i < nr; i++)
		{
			//double op=data->childrenPolygonSurfaceDataList->GetItemAtPos(i)->GetData()->GetVProperty()->GetOpacity();
			//if (op>0)
			SetOpacityWithChildren(data->childrenPolygonSurfaceDataList->GetItemAtPos(i)->GetData(), opacity);
		}
	}

}
