void	MainWindow::SlotChangeCurrentSurfaceOpacity(int ii)
{





	int nr = SurfaceDataList->GetNumberOfItems();

	if ((nr >= 0))//&&(nr<=100))
	{
		int j;
		double opacity = ((double)ii);
		SendMessage("Setting Opacity to: " + QString::number(opacity) + "%");

		ListItem<PolygonSurfaceData*>* tmpItem;
		for (j = 0; j < nr; j++)
		{
			tmpItem = SurfaceDataList->GetItemAtPos(j);
			if (tmpItem->GetData()->GetTreeItem()->isSelected() == true)
			{
				double alpha = opacity * 0.01;
				tmpItem->GetData()->GetVProperty()->SetOpacity(alpha);

				GUIPanel->SlotSetSurfaceOpacityPresentation(tmpItem->GetData()->GetTreeItem(), alpha);
			}
		}
		VWidget->RepaintWidget();

	}



}
