void MainWindow::keyPressEvent(QKeyEvent* event)
{
	//if (data == NULL) return;
	if ((event->modifiers() & Qt::ShiftModifier))//&&(event->state()&LeftButton))
		//isSHIFTpressed=true;
		isSHIFTpressed = !isSHIFTpressed;

	qDebug() << "jestem w keypress w main";

	if (event->modifiers() & Qt::ControlModifier)
	{

		isCTRLpressed = true;
	}
	else
	{
		isCTRLpressed = false;
	}

	//	if ((event->state()&Qt::CTRL)&&(event->key()>=48)&&(event->key()<=57))
	//if ((event->key() == 16777249))
//	if ((event->key() & 16777249))
	if (event->modifiers() & Qt::ControlModifier)
	{
		//isCTRLpressed=true;
		//SendMessage("ctrl press");


		int nrr = -1;
		for (int i = 0; i < 10; i++)
		{
			//if (QString::number(i).compare(event->text() )
			//qDebug() << "klaw: " << event->text();
			if (QString::compare(QString::number(i), event->text()) == 0)
			{
				nrr = i;
				break;
			}
		}
		//int ii=event->key();
		if (nrr > -1)
		{
			keyboardBuffer += QString::number(nrr);

		}
		else
		{
			keyboardBuffer = "";
		}
		SendMessage("Keyboard buffer: " + keyboardBuffer);
	}


	int currentOpacityFunction = GUIPanel->standardVolOpacityComboBox->currentIndex();
	int nrOfOpacityFunctions = GUIPanel->standardVolOpacityComboBox->count();

	double stepAngle = 10;
	double stepZoom = 10;
	if ((event->key() == Qt::Key_Space))
	{
		SlotSetCameraSetting(3);
		qDebug() << "Reset - front Camera";
	}
	if ((event->key() == Qt::Key_Left))
	{
		VWidget->SlotCameraRotation(stepAngle, 0, 0);
		qDebug() << "left";
	}
	if ((event->key() == Qt::Key_Right))
	{
		VWidget->SlotCameraRotation(-stepAngle, 0, 0);
		qDebug() << "right";
	}
	if ((event->key() == Qt::Key_Up))
	{
		VWidget->SlotCameraRotation(0, -stepAngle, 0);
		qDebug() << "up";
	}
	if ((event->key() == Qt::Key_Down))
	{
		VWidget->SlotCameraRotation(0, stepAngle, 0);
		qDebug() << "down";
	}
	if ((event->key() == Qt::Key_PageUp))
	{
		zoomCameraValue += stepZoom;
		double p0[] = { VWidget->width() / 2, VWidget->height() / 2 };
		double p1[] = { p0[0], p0[1] + zoomCameraValue };

		VWidget->Interactor->mainHandPress(p0[0], p0[1], Qt::RightButton, true);
		VWidget->Interactor->mainHandMoved(p1[0], p1[1], Qt::RightButton);

		//	VWidget->Interactor->lastMousePos[0] = p1[0];
		//	VWidget->Interactor->lastMousePos[1] = p1[1];

		VWidget->SlotCameraRotation(0, 0, 0);
		qDebug() << "zoom in";

	}
	if ((event->key() == Qt::Key_PageDown))
	{
		zoomCameraValue -= stepZoom;
		double p0[] = { VWidget->width() / 2, VWidget->height() / 2 };
		double p1[] = { p0[0], p0[1] + zoomCameraValue };

		VWidget->Interactor->mainHandPress(p0[0], p0[1], Qt::RightButton, true);
		VWidget->Interactor->mainHandMoved(p1[0], p1[1], Qt::RightButton);

		//	VWidget->Interactor->lastMousePos[0] = p1[0];
		//	VWidget->Interactor->lastMousePos[1] = p1[1];

		VWidget->SlotCameraRotation(0, 0, 0);

		qDebug() << "zoom out";
	}
	if ((event->key() == Qt::Key_Home))
	{
		currentOpacityFunction = (currentOpacityFunction + 1) % nrOfOpacityFunctions;
		GUIPanel->standardVolOpacityComboBox->setCurrentIndex(currentOpacityFunction);
		GUIPanel->standardVolOpacityComboBox2->setCurrentIndex(currentOpacityFunction);
		qDebug() << "opacity+";
	}
	if ((event->key() == Qt::Key_End))
	{
		currentOpacityFunction = (currentOpacityFunction - 1 + nrOfOpacityFunctions) % nrOfOpacityFunctions;
		GUIPanel->standardVolOpacityComboBox->setCurrentIndex(currentOpacityFunction);
		GUIPanel->standardVolOpacityComboBox2->setCurrentIndex(currentOpacityFunction);
		qDebug() << "opacity-";
	}


	/*if(event->key()&Qt::Key_L)
	{
	lKeyPressed=true;
	}
	else
	{
	lKeyPressed=false;
	}*/
	/*int ii=event->key();
	int ss=event->state();
	if ((	(ii>=48)&&	(ii<=57)	)&&(ss==512))
	{
	int cc=event->count();
	ii-=48;
	if (ii==0) ii+=10;
	ii--;
	double opacity=((double)ii)/9.0;
	SlotChangeCurrentSurfaceOpacity(opacity);



	}*/
	//if (	(event->stateAfter()&Qt::CTRL) )//&&(	(ii>=48)&&	(ii<=57)	)	)
	//{
	// 
	// ii=ii;
	// SlotChangeCurrentSurfaceOpacity(ii);
	//}

	// //&&(event->state()&LeftButton))
	qDebug() << "out of  keypress w main";

}
