void	MainWindow::SlotScaleGrid()
{
	if (Grid != NULL)
	{
		RTimer.Start("Scaling grid");

		int nx = GUIPanel->GridSizeXBox->value();
		int ny = GUIPanel->GridSizeYBox->value();
		int nz = GUIPanel->GridSizeZBox->value();

		//Grid->Scale(nx,ny,nz);
		BSplineGridTransformation b(Grid, Grid->GetNx(), Grid->GetNy(), Grid->GetNz(), 0, 0, 0);
		FloatGrid3D* tempGrid = new FloatGrid3D(nx, ny, nz);
		b.ScaleGrid(tempGrid);

		//swap

		FloatGrid3D* tmp = Grid;
		Grid = tempGrid;
		delete tmp;

		RTimer.Stop();

	}
}
