bool MainWindow::GetTTWSizes(const QString& filename, double* tab)
{
	if (!filename.isEmpty())
	{

		int n[3];
		int bits;
		double s[3];
		int depth = 16;
		bool ok;

		//sprawze czy ten raw ma dodatkowo plik dat o odpowiednim formacie

		QFile file(filename);


		// dane 48bit - bede wrzucal na poczatek do tablicy double

		if (file.open(QIODevice::ReadOnly))
		{
			unsigned char* input48Data = NULL;
			int size = file.size();
			input48Data = new unsigned char[size];
			file.read((char*)input48Data, size);

			int sizeDiv6 = size / 6;
			int nx, ny;
			double minVal = INT_MAX;
			double maxVal = -INT_MAX;
			for (int i = 0; i < sizeDiv6; i++)
			{
				double val = Real48ToDouble(input48Data + i * 6);
				if (i > 7) //dane sa od 8 w gore
				{
					if (val < minVal) minVal = val;
					if (val > maxVal) maxVal = val;
				}
				if (i == 4)
				{
					nx = val; ny = val;
				}
			}


			tab[0] = nx;
			tab[1] = ny;
			tab[2] = minVal;
			tab[3] = maxVal;

			delete[]input48Data;
			//unsigned short *tab = new unsigned short[nx*ny];


			file.close();

		}
		else
		{
			return false;
		}


	}
	else
	{
		emit SendMessage("No File ...");
		return false;
	}
	return true;

}

bool MainWindow::GetTTWPixels(const QString& filename, unsigned short* pixels, double* tab)
{
	if ((!filename.isEmpty()) || (tab == NULL) || (pixels == NULL))
	{

		int n[3];
		int bits;
		double s[3];
		int depth = 16;
		bool ok;

		//sprawze czy ten raw ma dodatkowo plik dat o odpowiednim formacie

		QFile file(filename);


		// dane 48bit - bede wrzucal na poczatek do tablicy double

		int nx = tab[0];
		int ny = tab[1];
		double minVal = tab[2];
		double maxVal = tab[3];
		if (file.open(QIODevice::ReadOnly))
		{
			unsigned char* input48Data = NULL;
			int size = file.size();
			input48Data = new unsigned char[size];
			file.read((char*)input48Data, size);
			int sizeDiv6 = size / 6;


			int pos;
			double scale = (maxVal - minVal);
			if (scale > 0) scale = 16384.0 / scale;

			for (int i = 0; i < nx * ny; i++)
			{
				pos = i + 8;
				double val = Real48ToDouble(input48Data + pos * 6);

				pixels[i] = (val - minVal) * scale;
				if (pixels[i] > 17000)
				{
					i = i;
				}
			}


			delete[]input48Data;


			//unsigned short *tab = new unsigned short[nx*ny];


			file.close();

		}
		else
		{
			emit SendMessage("file error");
			return false;
		}


	}
	else
	{
		emit SendMessage("error");
		return false;
	}
	return true;

}




void MainWindow::SlotLoadNIFTIWDataSet(const QString& filename)
{
	if (!filename.isEmpty())
	{
		//vtkJPEGReader *Reader;
		vtkImageData* IData;


		QString Ntemp;
		int pos2 = filename.lastIndexOf("/");
		if (pos2 >= 0)
		{
			Ntemp = filename;
			Ntemp.remove(pos2, Ntemp.length());
		}


		QString text = "";
		QString TMP, TMPX;
		QDir d;
		d.setPath(Ntemp);
		d.setFilter(QDir::Files | QDir::Hidden | QDir::NoSymLinks);
		//	d.setSorting(  QDir::Reversed );

		QFileInfoList list = d.entryInfoList();
		QListIterator<QFileInfo> it(list);
		//QFileInfoListIterator it( list.begin());
		QFileInfo fi;

		//int NZ;
	//	NZ = d.count();

		//Reader = vtkJPEGReader::New();

		vtkSmartPointer<vtkNIFTIImageReader> reader =
			vtkSmartPointer<vtkNIFTIImageReader>::New();



		reader->SetFileName(filename.toLocal8Bit());
		reader->Update();
		IData = reader->GetOutput();
		IData->Modified();
		int dims[3];
		IData->GetDimensions(dims);
		int scalarSize = IData->GetNumberOfScalarComponents();
		double scale[3];
		IData->GetSpacing(scale);

		int pos = 0;
		//while ( (fi = it.current()) != 0 )
		//if (scalarSize > 2) tData->initRGBArrays();

		int scalarType = IData->GetScalarType();



		if ((scalarType == 4) || (scalarType == 5))
		{

			int i, j;


			RawDataSet* tData = new RawDataSet(dims[0], dims[1], dims[2], scale[0], scale[1], scale[2]);
			unsigned char* pixeldataV = (unsigned char*)IData->GetScalarPointer();
			unsigned short* dataR = tData->GetDataArray();



			//memcpy(dataR, pixeldataV, tData->GetVolumeSize() * 2);

			int sliceSize = dims[0] * dims[1];
			for (int k = 0; k < dims[2]; k++)
			{
				memcpy(dataR + k * sliceSize, pixeldataV + (dims[2] - 1 - k) * sliceSize * 2, sliceSize * 2);
			}


			tData->SetRawDataSetName("nifti");

			InsertRawDataSet(tData);
		}

	}


}
