void MainWindow::SlotTansformVolume()
{
	if (data != NULL)
	{

		RTimer.Start("Depth Data Set Generation");

		int i, j, k;
		int max = 0;

		int nx = data->GetNx();
		int ny = data->GetNy();
		int nz = data->GetNz();
		double dx = data->GetXscale();
		double dy = data->GetYscale();
		double dz = data->GetZscale();


		double dx1 = (dx > 0) ? 1 / dx : 1;
		double dy1 = (dy > 0) ? 1 / dy : 1;
		double dz1 = (dz > 0) ? 1 / dz : 1;



		///////////////////////////////////////////////////////////////////
		double RotateCenter[3] = { nx * dx * 0.5, ny * dy * 0.5, nz * dz * 0.5 };



		//	for (i=0;i<12;i++)
		//		fprintf(plik,"%lf\n",GUIPanel->TEdit[i]->text().toFloat());

		double	Matrix[16];
		double	TransTemp[13];


		for (i = 0; i < 3; i++)
			TransTemp[i + 1] = GUIPanel->TEdit[i]->text().toFloat();
		for (i = 3; i < 6; i++)
			TransTemp[i + 1] = GUIPanel->TEdit[i]->text().toFloat() * to_rad;
		for (i = 6; i < 13; i++)
			TransTemp[i + 1] = GUIPanel->TEdit[i]->text().toFloat();

		Transform* transX = new Transform(RotateCenter, 1, 1, 1);

		transX->MakeCompleteAffineMatrixInv(Matrix, TransTemp);

		double zRot = GUIPanel->TEdit[6]->text().toFloat();

		RawDataSet* FinalData = new RawDataSet(data->GetNx(), data->GetNy(), data->GetNz(), data->GetXscale(), data->GetYscale(), data->GetZscale(), 0);
		FinalData->ZeroQ();
		FinalData->SetRawDataSetName("xx");

		unsigned short* TempPointer = FinalData->GetDataArray();


		double Point1[3], Point[3];




		//	transX->SetTransformationSteps(	FinalData->GetXscale(),FinalData->GetYscale(),FinalData->GetZscale(),
		//									data->GetXscale(),data->GetYscale(),data->GetZscale(),
		//									data->GetNx(),data->GetNy(),data->GetNz());


		double t1 = (double)(data->GetNx() - 1);
		double t2 = (double)(data->GetNy() - 1);
		double t3 = (double)(data->GetNz() - 1);


		double t = 0.5;
		double f;
		double c;
		int inerpol = GUIPanel->InterpolationCombo->currentIndex();
		for (k = 0; k < FinalData->GetNz(); k++)
		{

			Point[2] = k * dz;
			for (j = 0; j < FinalData->GetNy(); j++)
			{
				Point[1] = j * dy;
				Point[0] = 0;
				for (i = 0; i < FinalData->GetNx(); i++)
				{

					//c=sqrt(		(Point[0]-RotateCenter[0])*(Point[0]-RotateCenter[0]) 
					//		+	(Point[1]-RotateCenter[1])*(Point[1]-RotateCenter[1]));
					//+	(Point[2]-RotateCenter[2])*(Point[2]-RotateCenter[2]));
					//if (c<0.000000001) c=1;
					//f=t/c+(Point[2]-RotateCenter[2])*t/100;
					f = (Point[2] - RotateCenter[2]) * t / 100;
					TransTemp[6] = f;

					transX->MakeCompleteAffineMatrixInv(Matrix, TransTemp);
					transX->MultiplyPoint(Point1, Point);
					Point1[0] *= dx1; Point1[1] *= dy1; Point1[2] *= dz1;

					if ((Point1[0] >= 0) && (Point1[0] < t1) &&
						(Point1[1] >= 0) && (Point1[1] < t2) &&
						(Point1[2] >= 0) && (Point1[2] < t3))
						if (inerpol == 1)
						{
							*(TempPointer) = Interpolation3Linear(data, Point1[0], Point1[1], Point1[2]);
						}
						else
						{
							*(TempPointer) = data->GetVoxelValue((int)(Point1[0]), (int)(Point1[1]), (int)(Point1[2]));
						}
					TempPointer++;
					Point[0] += dx;

				}

			}


		}

		/*	Transform *t




		//////////////////////////////////////////////////////////////////



		//unsigned short *q=data->GetDataArray();
		/*for(i=0;i<data->GetVolumeSize();i++)
		if (q[i]>max) max=q[i];

		double factor=1.0;

		int nr=20;

		factor=(double)(nr-1)/(double)max;

		//if (max>255) factor=(255.0/(double)max);

		unsigned short val;

		if (max>0)
		{
		RawDataSet *tempRawData=NULL;
		tempRawData=new RawDataSet(nx,ny,nr,dx,dy,dz);
		tempRawData->ZeroQ();

		for(j=0;j<ny;j++)
		for(i=0;i<nx;i++)
		{
		val=(unsigned short)(Round(data->GetVoxelValue(i,j,0)*factor));
		tempRawData->SetVoxelValue(i,j,val,100);
		}
		QString name;
		name=data->GetRawDataSetName();
		name.append("-map");
		tempRawData->SetRawDataSetName(name);

		InsertRawDataSet(tempRawData);

		}
		*/
		InsertRawDataSet(FinalData);
		RTimer.Stop();

	}


}
