void	MainWindow::SlotSwitchSurfaceTransformMode(int i)
{


	if (i == 2)
	{



		double RotateCenter[3] = { 0, 0, 0 };
		if (data != NULL)
		{

			int nx = data->GetNx();
			int ny = data->GetNy();
			int nz = data->GetNz();
			double dx = data->GetXscale();
			double dy = data->GetYscale();
			double dz = data->GetZscale();
			RotateCenter[0] = nx * dx * 0.5;
			RotateCenter[1] = ny * dy * 0.5;
			RotateCenter[2] = nz * dz * 0.5;
		}
		else
		{
			if (SurfaceDataList->GetNumberOfItems() > 0)
			{
				RotateCenter[0] = SurfaceDataList->GetCurrentListItem()->GetData()->GetOrigin()[0];
				RotateCenter[1] = SurfaceDataList->GetCurrentListItem()->GetData()->GetOrigin()[1];
				RotateCenter[2] = SurfaceDataList->GetCurrentListItem()->GetData()->GetOrigin()[2];
			}
		}
		double trans[15];
		int i;
		for (i = 0; i < 3; i++)
			trans[i + 1] = GUIPanel->TEdit[i]->text().toFloat();
		for (i = 3; i < 6; i++)
			trans[i + 1] = GUIPanel->TEdit[i]->text().toFloat() * to_rad;
		for (i = 6; i < 13; i++)
			trans[i + 1] = GUIPanel->TEdit[i]->text().toFloat();


		trans[14] = GUIPanel->AverageAmountEdit->text().toFloat(); //z-twist

		SProcessing->SlotEnableAffineTransform(trans, 15, RotateCenter);
	}
	else
		SProcessing->SlotDisableAffineTransform();


}
