void MainWindow::SlotCreateAverageSlice()
{
	if (data != NULL)
	{

		RawDataSet* d = data;

		RawDataSet* d1 = new RawDataSet(d->GetNx(), d->GetNy(), 1, 1, 1, 1);
		d1->SetRawDataSetName(d->GetRawDataSetName() + "-avgslc");
		unsigned short* d1R, * dR;
		unsigned char* d1G, * d1B, * dG, * dB;
		d1R = d1->GetDataArray();
		dR = d->GetDataArray();
		bool rgb = false;
		if (d->GetRGBExists() == true)
		{
			d1->initRGBArrays();
			d1G = d1->GetGChannelUCHARArray();
			d1B = d1->GetBChannelUCHARArray();
			dG = d->GetGChannelUCHARArray();
			dB = d->GetBChannelUCHARArray();
			rgb = true;
		}
		else
		{
			d1G = NULL;
			d1B = NULL;
			dG = NULL;
			dB = NULL;

		}

		int i, j, k;

		int v1, v2;

		int pos1;
		int pos2;
		int pos;
		int max;
		int slicesize = d->GetSliceSize();
		unsigned char r1, g1, b1, r, g, b;

		unsigned short* tab = new unsigned short[data->GetNz()];

		pos2 = 0;
		for (j = 0; j < d->GetNy(); j++)
		{
			for (i = 0; i < d->GetNx(); i++)
			{
				memset(tab, 0, data->GetNz() * sizeof(unsigned char));
				max = 0;
				r1 = 0; g1 = 0; b1 = 0;
				r = 0; g = 0; b = 0;
				for (k = 0; k < d->GetNz(); k++)
				{
					pos = data->GetVoxelPos(i, j, k);

					if (d->GetRGBExists() == true)
					{
						r = dR[pos];
						g = dG[pos];
						b = dB[pos];
					}
					else
					{
						r = dR[pos];;
						g = 0;
						b = 0;
					}
					//if ((b-r>90)&&(b-g>90))
					//	tab[k]=0;
					//else
					tab[k] = (0.299 * r + 0.587 * g + 0.114 * b);

					/*if (tab[k]==65535)
					{
					r1=200;g1=200;b1=200;
					}
					else*/
					if (tab[k] > max)
					{
						max = tab[k];
						r1 = r;
						g1 = g;
						b1 = b;


					}
				}

				d1R[pos2] = r1;
				if (d->GetRGBExists() == true)
				{
					if ((b1 - r1 > 90) && (b1 - g1 > 90))
					{
						d1R[pos2] = 255;
						d1G[pos2] = 255;
						d1B[pos2] = 255;

					}
					else
					{
						d1G[pos2] = g1;
						d1B[pos2] = b1;
					}
				}
				pos2++;




			}
		}

		QString nn = d->GetRawDataSetName() + "_" + "Sth";
		d1->SetRawDataSetName(nn);
		InsertRawDataSet(d1);


		//calculate smoothness!!!


		//int i;
		//FILE *plik;

		//	QString t="c:\\smoothness-"+d->GetRawDataSetName()+".txt";
		//	plik=fopen(t.toLocal8Bit(),"wt");

		double val1, val2, en;
		pos = 0;
		double enAvg = 0;
		for (k = 0; k < d->GetNz() - 1; k++)
		{
			en = 0;
			for (j = 0; j < d->GetNy(); j++)
			{
				for (i = 0; i < d->GetNx(); i++)
				{
					if (d->GetRGBExists() == true)
					{
						r = dR[pos];
						g = dG[pos];
						b = dB[pos];
						r1 = dR[pos + data->GetSliceSize()];
						g1 = dG[pos + data->GetSliceSize()];
						b1 = dB[pos + data->GetSliceSize()];
						val1 = (0.299 * r + 0.587 * g + 0.114 * b);
						val2 = (0.299 * r1 + 0.587 * g1 + 0.114 * b1);

					}
					else
					{
						val1 = dR[pos];
						val2 = dR[pos + data->GetSliceSize()];
					}
					en += (val1 - val2) * (val1 - val2);

					pos++;
				}

			}
			en /= (double)d->GetSliceSize() * 255;
			enAvg += en;

			//fprintf(plik,"%d %lf\n",k,en);
			//fprintf(plik,"%lf\n",en);
		}
		enAvg /= (double)d->GetNz();
		//	fclose(plik);

		/*	plik=fopen("c:\\SmoothnessAvg.txt","at");

		fprintf(plik,"%s %lf\n",d->GetRawDataSetName().toLocal8Bit(),enAvg);



		fclose(plik);*/
		//return d1;


	}


}

RawDataSet* MainWindow::CreateBlendingDataSet(RawDataSet* d)
{

	RawDataSet* d1 = new RawDataSet(d->GetNx(), d->GetNy(), d->GetNz() * 2, 1, 1, 1);
	d1->SetRawDataSetName(d->GetRawDataSetName() + "-blend");
	unsigned short* d1R, * dR;
	unsigned char* d1G, * d1B, * dG, * dB;
	d1R = d1->GetDataArray();
	dR = d->GetDataArray();
	bool rgb = false;
	if (d->GetRGBExists() == true)
	{
		d1->initRGBArrays();
		d1G = d1->GetGChannelUCHARArray();
		d1B = d1->GetBChannelUCHARArray();
		dG = d->GetGChannelUCHARArray();
		dB = d->GetBChannelUCHARArray();
		rgb = true;
	}
	else
	{
		d1G = NULL;
		d1B = NULL;
		dG = NULL;
		dB = NULL;

	}

	int i, j, k;

	int v1, v2;

	int pos1;
	int pos2;
	int pos;

	int slicesize = d->GetSliceSize();

	for (k = 0; k < d->GetNz(); k++)
	{
		j = (k + 1) % (d->GetNz() - 1);
		//skopiowac 1
		memcpy(d1R + k * 2 * slicesize, dR + k * slicesize, slicesize * sizeof(unsigned short));
		if (rgb)
		{
			memcpy(d1G + k * 2 * slicesize, dG + k * slicesize, slicesize * sizeof(unsigned char));
			memcpy(d1B + k * 2 * slicesize, dB + k * slicesize, slicesize * sizeof(unsigned char));
		}

		pos1 = k * slicesize;
		pos2 = j * slicesize;
		pos = (k * 2 + 1) * slicesize;
		for (i = 0; i < d->GetSliceSize(); i++)
		{
			//wyliczyc srednia z i i j i wstawic na slice 2i+1;
			v1 = (dR[pos1] + dR[pos2]) / 2;
			d1R[pos] = v1;

			if (rgb)
			{
				v1 = (dG[pos1] + dG[pos2]) / 2;
				d1G[pos] = v1;

				v1 = (dB[pos1] + dB[pos2]) / 2;
				d1B[pos] = v1;
			}
			pos1++;
			pos2++;
			pos++;
		}



	}

	return d1;

}
//-------------------------
void MainWindow::SlotCreateBlendData()
{
	if (data != NULL)
	{
		RawDataSet* a = CreateBlendingDataSet(data);
		InsertRawDataSet(a);

	}
}
