void MainWindow::SlotCreateCarRawModel()
{

	if ((data != NULL) && (data->GetRGBExists()))
	{
		int fNr = 6;
		int bNr = 26;
		int rNr = 16;

		// znalezc wspolny srodek - obliczyc min max dla zbioru
		int fBnds[4];
		int bBnds[4];
		int rBnds[4];

		rBnds[0] = INT_MAX;
		rBnds[1] = INT_MIN;
		rBnds[2] = INT_MAX;
		rBnds[3] = INT_MIN;
		fBnds[0] = INT_MAX;
		fBnds[1] = INT_MIN;
		fBnds[2] = INT_MAX;
		fBnds[3] = INT_MIN;
		bBnds[0] = INT_MAX;
		bBnds[1] = INT_MIN;
		bBnds[2] = INT_MAX;
		bBnds[3] = INT_MIN;
		int i, j, k;


		unsigned char r, g, b;

		unsigned short* rTab = data->GetRChannelArray();
		unsigned char* gTab = data->GetGChannelUCHARArray();
		unsigned char* bTab = data->GetBChannelUCHARArray();

		int pos;

		unsigned char* tF = new unsigned char[data->GetSliceSize() * 3];
		unsigned char* tB = new unsigned char[data->GetSliceSize() * 3];
		unsigned char* tR = new unsigned char[data->GetSliceSize() * 3];

		int xx, yy;







		int pos2 = 0;
		for (j = 0; j < data->GetNy(); j++)
		{
			for (i = 0; i < data->GetNx(); i++)
			{


				//prawo
				pos = data->GetVoxelPos(i, j, rNr);
				r = (unsigned char)rTab[pos];		g = gTab[pos];		b = bTab[pos];

				if (!((r < 25) && (g < 25) && (b > 200)))
				{
					if (i > rBnds[1]) rBnds[1] = i;			if (j > rBnds[3]) rBnds[3] = j;
					if (i < rBnds[0]) rBnds[0] = i;			if (j < rBnds[2]) rBnds[2] = j;
					tR[3 * pos2] = r;
					tR[3 * pos2 + 1] = g;
					tR[3 * pos2 + 2] = b;
				}
				else
				{
					tR[3 * pos2] = 0;
					tR[3 * pos2 + 1] = 0;
					tR[3 * pos2 + 2] = 255;
				}


				//przod
				pos = data->GetVoxelPos(i, j, fNr);
				r = (unsigned char)rTab[pos];		g = gTab[pos];		b = bTab[pos];

				if (!((r < 25) && (g < 25) && (b > 200)))
				{
					if (i > fBnds[1]) fBnds[1] = i;			if (j > fBnds[3]) fBnds[3] = j;
					if (i < fBnds[0]) fBnds[0] = i;			if (j < fBnds[2]) fBnds[2] = j;
					tF[3 * pos2] = r;
					tF[3 * pos2 + 1] = g;
					tF[3 * pos2 + 2] = b;
				}
				else
				{
					tF[3 * pos2] = 0;
					tF[3 * pos2 + 1] = 0;
					tF[3 * pos2 + 2] = 255;
				}
				//tyl
				pos = data->GetVoxelPos(i, j, bNr);
				r = (unsigned char)rTab[pos];		g = gTab[pos];		b = bTab[pos];
				if (!((r < 25) && (g < 25) && (b > 200)))
				{
					if (i > bBnds[1]) bBnds[1] = i;			if (j > bBnds[3]) bBnds[3] = j;
					if (i < bBnds[0]) { bBnds[0] = i; }			if (j < bBnds[2]) bBnds[2] = j;
					tB[3 * pos2] = r;
					tB[3 * pos2 + 1] = g;
					tB[3 * pos2 + 2] = b;
				}
				else
				{
					tB[3 * pos2] = 0;
					tB[3 * pos2 + 1] = 0;
					tB[3 * pos2 + 2] = 255;
				}
				pos2++;
			}
		}


		// wyliczam skale!

		int sizeRight = rBnds[3] - rBnds[2];
		int sizeFront = fBnds[3] - fBnds[2];

		double scale = (double)sizeRight / (double)sizeFront;

		int sizeX = (int)(data->GetNx() * scale + 0.5);
		int sizeY = (int)(data->GetNy() * scale + 0.5);

		//zrobic qimage dla gory i tylu przeskalowane do sizeX i sizeY

		QImage 	fImage(data->GetNx(), data->GetNy(), QImage::Format_RGB32);
		QImage 	bImage(data->GetNx(), data->GetNy(), QImage::Format_RGB32);

		unsigned char* bitsF = fImage.bits();
		unsigned char* bitsB = bImage.bits();

		pos = 0;
		pos2 = 0;
		for (i = 0; i < data->GetNx() * data->GetNy(); i++)
		{

			bitsF[pos] = tF[pos2 + 2];//b
			bitsB[pos++] = tB[pos2 + 2];//b
			bitsF[pos] = tF[pos2 + 1];//g
			bitsB[pos++] = tB[pos2 + 1];//g
			bitsF[pos] = tF[pos2];//r
			bitsB[pos++] = tB[pos2];//r
			pos2 += 3;
			pos++;
		}

		//QImage 	fImageSc=fImage.smoothScale(sizeX,sizeY);
		QImage fImageSc = fImage.scaled(sizeX, sizeY, Qt::IgnoreAspectRatio, Qt::SmoothTransformation);

		//QImage 	bImageSc=bImage.smoothScale(sizeX,sizeY);
		QImage bImageSc = bImage.scaled(sizeX, sizeY, Qt::IgnoreAspectRatio, Qt::SmoothTransformation);

		bitsF = fImageSc.bits();
		bitsB = bImageSc.bits();

		fImageSc.save("c:\\a.png", "PNG");
		bImageSc.save("c:\\.png", "PNG");
		int nx = rBnds[1] - rBnds[0] + 2;
		int ny = rBnds[3] - rBnds[2] + 2;
		int nz = (fBnds[1] - fBnds[0]) * scale + 2;

		RawDataSet* d = new RawDataSet(nx, ny, nz, 1, 1, 1);
		RawDataSet* d1 = new RawDataSet(nx, ny, nz, 1, 1, 1);
		d->initRGBArrays();

		unsigned short* tt = d->GetDataArray();
		unsigned short* rTab2 = d->GetRChannelArray();
		unsigned char* gTab2 = d->GetGChannelUCHARArray();
		unsigned char* bTab2 = d->GetBChannelUCHARArray();
		memset(rTab2, 0, d->GetVolumeSize() * sizeof(unsigned short));
		memset(gTab2, 0, d->GetVolumeSize());
		memset(bTab2, 0, d->GetVolumeSize());
		d1->ZeroQ();
		// uzupelnic zbior kopia prawo


		int posy;
		int posx;
		int posz;

		pos2 = 0;

		for (k = 1; k < d->GetNz() - 1; k++)
		{
			posy = rBnds[2];
			for (j = 1; j < d->GetNy() - 1; j++)
			{
				posx = rBnds[0];
				for (i = 1; i < d->GetNx() - 1; i++)
				{
					r = tR[(posx + posy * data->GetNx()) * 3];
					g = tR[(posx + posy * data->GetNx()) * 3 + 1];
					b = tR[(posx + posy * data->GetNx()) * 3 + 2];
					//if (((r!=0)||(g!=0)||(b!=255)))
					if (!((r == 0) && (g == 0) && (b == 255)))
					{
						//tt[pos2]=255;
						pos = d->GetVoxelPos(i, j, k);
						//if (k<d->GetNz()-1) 
						d1->SetVoxelValue(i, j, k, 255);
						rTab2[pos] = r;
						gTab2[pos] = g;
						bTab2[pos] = b;
					}
					pos2++;
					posx++;
				}
				posy++;
			}


		}


		//wyciac z tego to co definiuje spasowany front:)
		int ss = d->GetNx() / 2;
		pos2 = 0;
		posz = fBnds[0] * scale;


		for (k = 1; k < d->GetNz() - 1; k++)
		{
			posy = fBnds[2] * scale;
			for (j = 1; j < d->GetNy() - 1; j++)
			{
				//posx=rBnds[0];
				for (i = 1; i < d->GetNx() - 1; i++)
				{
					b = bitsF[(posz + posy * sizeX) * 4];
					g = bitsF[(posz + posy * sizeX) * 4 + 1];
					r = bitsF[(posz + posy * sizeX) * 4 + 2];
					if (((r == 0) && (g == 0) && (b == 255)))
					{
						//tt[pos2]=255;
						d1->SetVoxelValue(i, j, k, 0);
					}
					pos2++;
					//posx++;
				}
				posy++;
			}
			posz++;

		}

		//wyciac z tego to co definiuje spasowany back:)

		/*pos2=0;
		posz=bBnds[0];

		for (k=1;k<d->GetNz()-1;k++)
		{
		posy=bBnds[2];
		for(j=1;j<d->GetNy()-1;j++)
		{
		//posx=rBnds[0];
		for(i=1;i<d->GetNx()-1-ss;i++)
		{
		if (tB[posz+posy*data->GetNx()]==0)
		{
		//tt[pos2]=255;
		d->SetVoxelValue(i,j,k,0);
		}
		pos2++;
		//posx++;
		}
		posy++;
		}
		posz++;

		}
		*/


		// nastrzelamy teksture na przod
		unsigned short vl, vp, v;
		int l;

		//RawDataSet *nData=new RawDataSet(nz,ny,1,1,1,1);
		//	nData->initRGBArrays();

		int pos0z = fBnds[0] * scale;
		int pos0y = fBnds[2] * scale;

		for (j = 1; j < d->GetNy() - 1; j++)
		{
			for (k = 1; k < d->GetNz() - 1; k++)
			{
				for (i = d->GetNx() - 2; i > ss; i--)
				{
					v = d1->GetVoxelValue(i, j, k - 1);
					vl = d1->GetVoxelValue(i, j, k);
					vp = d1->GetVoxelValue(i, j, k + 1);

					if ((v != 0) && (vl != 0) && (vp != 0))
					{
						//r=bitsF[(posz+posy*sizex)*4];
						//g=bitsF[(posz+posy*sizex)*4+1];
						//b=bitsF[(posz+posy*sizex)*4+2];

						pos = (k + pos0z + (j + pos0y) * sizeX) * 4;
						r = bitsF[pos + 2];
						g = bitsF[pos + 1];
						b = bitsF[pos];

						if (!((r == 0) && (g == 0) && (b == 255)))
						{
							//nData->GetRChannelArray()[nz*j+k]=r;
							//nData->GetGChannelUCHARArray()[nz*j+k]=g;
							//nData->GetBChannelUCHARArray()[nz*j+k]=b;

							for (l = -60; l < 5; l++)
							{
								if (i - l < d->GetNx())
								{
									pos = d->GetVoxelPos(i - l, j, k);
									rTab2[pos] = r;
									gTab2[pos] = g;
									bTab2[pos] = b;
								}
							}
						}
						break;
						// tu nastrzelam odpowiednia teksture na 5 pixeli pod rzad i spadam

					}



				}

			}
		}
		//tyl
		for (j = 1; j < d->GetNy() - 1; j++)
		{
			for (k = 1; k < d->GetNz() - 1; k++)
			{
				for (i = 1; i < ss; i++)
				{
					vl = d1->GetVoxelValue(i, j, k - 1);
					v = d1->GetVoxelValue(i, j, k);
					vp = d1->GetVoxelValue(i, j, k + 1);

					if ((vl != 0) && (k > 1)) vl = d1->GetVoxelValue(i, j, k - 2);
					if ((vp != 0) && (k < d->GetNz() - 1 - 1)) vp = d1->GetVoxelValue(i, j, k + 2);

					if ((v != 0) && (vl != 0) && (vp != 0))
					{
						/*pos=(((d->GetNz()-1-k)+bBnds[0])+(j+bBnds[2])*data->GetNx())*3;
						r=tB[pos];
						g=tB[pos+1];
						b=tB[pos+2];*/

						pos = ((d->GetNz() - 1 + pos0z - k) + (j + pos0y) * sizeX) * 4;
						r = bitsB[pos + 2];
						g = bitsB[pos + 1];
						b = bitsB[pos];



						if (!((r == 0) && (g == 0) && (b == 255)))
						{
							//nData->GetRChannelArray()[nz*j+k]=r;
							//nData->GetGChannelUCHARArray()[nz*j+k]=g;
							//nData->GetBChannelUCHARArray()[nz*j+k]=b;


							for (l = -5; l < 60; l++)
							{
								if (i + l >= 0)
								{
									pos = d->GetVoxelPos(i + l, j, k);
									rTab2[pos] = r;
									gTab2[pos] = g;
									bTab2[pos] = b;
								}
							}
						}
						break;
						// tu nastrzelam odpowiednia teksture na 5 pixeli pod rzad i spadam
					}
				}
			}
		}

		delete[]tF;
		delete[]tR;
		delete[]tB;

		d->SetRawDataSetName("macha");
		InsertRawDataSet(d);
		d1->SetRawDataSetName("macha-mask");
		InsertRawDataSet(d1);
		//nData->SetRawDataSetName("nn-mask");
		//InsertRawDataSet(nData);

	}


}
