void	MainWindow::SlotCreateHeightMapFromPictureData()
{
	if ((data != NULL))
	{

		RTimer.Start("Generating Marching Cubes Surface");
		double	scale[3];
		int* N = new int[3];

		scale[0] = data->GetXscale();
		scale[1] = data->GetYscale();
		scale[2] = 1.0;

		SProcessing->SlotCreateHeightMapFromPictureData(data, scale);
		RTimer.Stop();
	}
}
