	int ny = GUIPanel->GridSizeY1Box->value();
	int nz = GUIPanel->GridSizeZ1Box->value();
	int multiressteps = GUIPanel->MultiResolutionStepBox->value();
	bool fixedbounds = GUIPanel->ElasticRegistrationFixedBoundsBox->isChecked();

	QString text = "Elastic Trans";

	unsigned char* mask = NULL;
	int nrOfMasks = MainListItem->GetData()->GetMasks()->GetNumberOfMasks();
