void	MainWindow::SlotArterySegmentation()
{

	int nr = DataSetList->GetNumberOfItems();
	if (nr > 0)
	{


		int px = PosX;
		int py = PosY;
		int pz = PosZ;

		int lowerThreshold = Histogram->GetLowerThreshold();
		int upperThreshold = Histogram->GetUpperThreshold();


		//tworze zbior wolumetryczny wypwlniony kulka

		int size = 5;
		RawDataSet* sData = new RawDataSet(size, size, size, 1, 1, 1);//data->GetXscale(),data->GetYscale(),data->GetZscale());
		sData->ZeroQ();
		int i, j, k;
		double intensity = 0;
		int nr = 0;
		int ot = 1;
		for (k = -ot; k < ot + 1; k++)
			for (j = -ot; j < ot + 1; j++)
				for (i = -ot; i < ot + 1; i++)
				{
					intensity += data->GetVoxelValue(PosX + i, PosY + j, PosZ + k);
					nr++;
				}
		if (nr > 0) intensity /= (double)nr;



		//



		double rs2 = (size / 2);
		rs2 *= rs2;
		rs2 = 1.0 / rs2;

		double x = size / 2;
		double y = size / 2;
		double z = size / 2;

		for (k = 0; k < sData->GetNz(); k++)
			for (j = 0; j < sData->GetNy(); j++)
				for (i = 0; i < sData->GetNx(); i++)
				{

					/*if (
					(double)((i-x)*(i-x))*rs2+
					(double)((j-y)*(j-y))*rs2+
					(double)((k-z)*(k-z))*rs2<1+1e-6
					)*/
					if ((double)((i - x) * (i - x)) * rs2 + (double)((j - y) * (j - y)) * rs2 < 1 + 1e-6)
					{

						sData->SetVoxelValue(i, j, k, intensity);
					}

				}

		//InsertRawDataSet(sData);
		SlotSetNewRawDataSet(DataSetList->GetItemAtPos(0)->GetData()->GetTreeWidgetItem());



		//-------------------------------------------

		double trans[50];
		double rot[3] = { 0 };

		GUIPanel->AutoCenterCheckBox->setChecked(true);
		GUIPanel->AlignCentersCheckBox->setChecked(false);

		//parametry do optymalizacji
		//blokuje rot,sh,scy,scz
		GUIPanel->TCheckBox[3]->setChecked(false);
		GUIPanel->TCheckBox[4]->setChecked(false);
		GUIPanel->TCheckBox[5]->setChecked(false);
		GUIPanel->TCheckBox[6]->setChecked(false);
		GUIPanel->TCheckBox[7]->setChecked(false);
		GUIPanel->TCheckBox[8]->setChecked(false);
		GUIPanel->TCheckBox[10]->setChecked(false);
		GUIPanel->TCheckBox[11]->setChecked(false);




		SlotGetTransformation(trans);
		trans[0] = px * data->GetXscale() - (double)size / 2;
		trans[1] = py * data->GetYscale() - (double)size / 2;
		trans[2] = pz * data->GetZscale() - (double)size / 2;


		//poblokowac wszystko oprocz skali x i pozycji




		double constraints[13];

		int e = 0;
		constraints[e++] = 5.0;		//trans x
		constraints[e++] = 5.0;		//trans y
		constraints[e++] = 5.0;		//trans z
		constraints[e++] = 180 * to_rad;	//rot x
		constraints[e++] = 180 * to_rad;	//rot y
		constraints[e++] = 180 * to_rad;	//rot z

		constraints[e++] = 1.0;			//shear x
		constraints[e++] = 1.0;			//shear y
		constraints[e++] = 1.0;			//shear z

		constraints[e++] = 1.0;		//scale x;
		constraints[e++] = 1.0;		//scale y;
		constraints[e++] = 1.0;		//scale z;


		/////////////////////


		ListItem<DataSet*>* modelItem = DataSetList->GetItemAtPos(0);
		//ListItem<DataSet*> *objectItem=DataSetList->GetItemAtPos(1);
		ListItem<DataSet*>* objectItem = new ListItem<DataSet*>;
		DataSet* objectDataset = new DataSet(sData, Pal, NumberOfMasks);
		objectDataset->SetNewPalette(Pal, PalNr, PalInvert);

		objectItem->SetData(objectDataset);
		//objectItem->SetData(sData);
		objectItem->GetData()->SetOpacity(128);
		bool oneScale = true;
		for (i = 0; i < 10; i++)
		{
			SlotStartRegistration(trans, modelItem, objectItem, NULL, 0, data->GetMaxValue(), data, sData, rot, constraints, oneScale);
			constraints[0] += 5.0;
			constraints[1] += 5.0;
			constraints[2] += 5.0;

		}




		//---------------------------------------


		//pounkt klikniety - pozycja i intensity

		//dopasowuje do niego kulke wypelniona cala kolorem kilknietego

		//startuje z kolejna kulka - biegam po kulio



	}


}


