void	MainWindow::SlotCreatePointMaskedDataSet()
{
	int nr = DataSetList->GetNumberOfItems();
	int radius = 10;
	if (nr > 0)
	{
		//const char *header;
		//QString hh=FileDefaultDir+"/p.txt";
		////		QByteArray adata=hh.totoLocal8Bit();
		////		header =adata.constData();
		//header=hh.toLocal8Bit();
		//FILE *headerek;
		//headerek=fopen(header,"rt");
		//if (headerek!=NULL)
		//{
		//	

		//}


		QString filename = QFileDialog::getOpenFileName(this, "", FileDefaultDir, "*.txt");

		QFile file(filename);
		QString line;


		int nrOfPoints = 0;
		int* pointTab = NULL;
		int i, j, k;
		int a, b, c;
		int pos;
		if (file.open(QIODevice::ReadOnly))
		{
			QTextStream stream(&file);



			/*while ( !stream.atEnd() )
			{
			FileDefaultDir = stream.readLine();
			}*/
			line = stream.readLine();

			line = stream.readLine();
			QStringList fields = line.split(" ", QString::SkipEmptyParts);

			pos = 0;
			if (QString::compare(fields[0], QString("points")) == 0)
			{

				nrOfPoints = fields[1].toInt();
				if (nrOfPoints > 0)
				{

					pointTab = new int[3 * nrOfPoints];
					for (i = 0; i < nrOfPoints; i++)
					{
						line = stream.readLine();
						fields = line.split("\t", QString::SkipEmptyParts);
						//int x=fields.count();

						pointTab[pos++] = fields[1].toInt();
						pointTab[pos++] = fields[2].toInt();
						pointTab[pos++] = fields[3].toInt();
					}



				}

			}


			file.close();

			if (nrOfPoints > 0)
			{
				RawDataSet* dataX = new RawDataSet();
				dataX->Copy(*data, false);
				pos = 0;
				dataX->ZeroQ();
				int x, y, z;
				int xx, yy, zz;
				int radius2 = radius * radius;
				for (a = 0; a < nrOfPoints; a++)
				{

					x = pointTab[pos++];
					y = pointTab[pos++];
					z = pointTab[pos++];

					for (k = -radius; k < radius + 1; k++)
					{
						for (j = -radius; j < radius + 1; j++)
						{
							for (i = -radius; i < radius + 1; i++)
							{

								if (i * i + j * j + k * k < radius2)
								{
									xx = x + i; yy = y + j; zz = z + k;
									if ((xx >= 0) && (xx < data->GetNx()) &&
										(yy >= 0) && (yy < data->GetNy()) &&
										(zz >= 0) && (zz < data->GetNz()))
									{
										dataX->SetVoxelValue(xx, yy, zz, data->GetVoxelValue(xx, yy, zz));
									}
								}

							}
						}


					}

					///	maxX=(l+3<GridNx2)?4:GridNx2-l;	maxY=(m+3<GridNy2)?4:GridNy2-m;	maxZ=(n+3<GridNz2)?4:GridNz2-n;

					//dataX->SetVoxelValue(pointTab[pos],pointTab[pos+1],pointTab[pos+2],255);
					pos += 3;
				}
				dataX->SetRawDataSetName("points");
				this->InsertRawDataSet(dataX);
			}
		}

	}


}

