//------------------------------------------------------------------------
unsigned char* MainWindow::SlotApplyThresholdSegmentation(int lthresh, int rthresh, RawDataSet* d)
{
	if (data != NULL)
	{
		RTimer.Start("Thresholding Segmentation");
		unsigned char* maskData = new unsigned char[d->GetVolumeSize()];
		memset(maskData, 0, d->GetVolumeSize());
		Segmentation* Segment = new Segmentation();
		int boolMode = GUIPanel->FillModeCombo->currentIndex();
		Segment->SlotThresholdSegmentation(d, maskData, lthresh, rthresh, GUIPanel->MaskAppendCheckBox->isChecked(), boolMode);
		RTimer.Stop();
		return maskData;

	}
	return NULL;
}
