//--------------------------------------------------
void MainWindow::SlotTestArteryMesh()
{
	if (data == NULL)
	{
		emit SendMessage("No data ...");
		return;
	}

	MaskData = MainListItem->GetData()->GetMasks()->GetCurrentMaskData();
	int nrOfMasks = MainListItem->GetData()->GetMasks()->GetNumberOfMasks();
	if (nrOfMasks < 2)
	{
		emit SendMessage("No mask!");
		return;
	}
	RTimer.Start("TEsting ...");
	Segmentation* Segment = new Segmentation(VWidget);
	RawDataSet* pData = Segment->SlotTestFieldGeneration(data, MaskData);


	delete Segment;


	if (pData != NULL)
	{
		pData->CalculateHistogram();
		pData->SetRawDataSetName("front map");
		this->InsertRawDataSet(pData);
	}

	RTimer.Stop();




}
