bool MainWindow::GetSelectedLineParams(double* p1, double* p2, QLineEdit2** lineEdits, QLineEdit2** angleEdits)
{

	// biorę dane co są kreską jeśli działa to liczę wektor od początku do konca - normalizuje liczę kąty w aktualnej bazie i wstawiam gdzie trzeba
	int nrr = -1;
	if (SurfaceDataList->GetNumberOfItems() > 0)
	{
		int Nr = SurfaceDataList->GetNumberOfItems();
		int i;
		PolygonSurfaceData* Data;
		QString name;

		//double col[3];
		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (Data->GetTreeItem()->isSelected() == true)
			{
				int nrPts = Data->GetVPolyData()->GetNumberOfPoints();
				if (nrPts == 2)
				{
					nrr = i;
					//	double p0[3], p1[3];
					Data->GetVPolyData()->GetPoint(0, p1);
					Data->GetVPolyData()->GetPoint(1, p2);
					double line[3];

					for (int i = 0; i < 3; i++)
					{
						line[i] = p2[i] - p1[i];
					}
					normV(line);

					lineEdits[0]->setText(QString::number(line[0]));
					lineEdits[1]->setText(QString::number(line[1]));
					lineEdits[2]->setText(QString::number(line[2]));





					double v[3], v1[3], v2[3], v3[3];

					v[0] = line[0]; v[1] = line[1]; v[2] = line[2];

					v1[0] = GUIPanel->v1Edit[0]->text().toFloat();
					v1[1] = GUIPanel->v1Edit[1]->text().toFloat();
					v1[2] = GUIPanel->v1Edit[2]->text().toFloat();

					v2[0] = GUIPanel->v2Edit[0]->text().toFloat();
					v2[1] = GUIPanel->v2Edit[1]->text().toFloat();
					v2[2] = GUIPanel->v2Edit[2]->text().toFloat();

					v3[0] = GUIPanel->v3Edit[0]->text().toFloat();
					v3[1] = GUIPanel->v3Edit[1]->text().toFloat();
					v3[2] = GUIPanel->v3Edit[2]->text().toFloat();


					double angle[3];
					angle[0] = GetAngleBetweenNormalizedVectors(v, v1) * to_deg;
					angle[1] = GetAngleBetweenNormalizedVectors(v, v2) * to_deg;
					angle[2] = GetAngleBetweenNormalizedVectors(v, v3) * to_deg;

					angleEdits[0]->setText(QString::number(angle[0]));
					angleEdits[1]->setText(QString::number(angle[1]));
					angleEdits[2]->setText(QString::number(angle[2]));



					return true;


				}
			}


		}
	}
	return false;
}
