void MainWindow::SlotGetFirstLineParamsFromSelectedSkeletons()
{

	QLineEdit2* lineEdits[3] = { GUIPanel->aFirstLineEdit ,GUIPanel->bFirstLineEdit,GUIPanel->cFirstLineEdit };

	bool test = GetSelectedLineParams(p1L1, p2L1, lineEdits, GUIPanel->l1AnglesEdit);

	if (test == true)return;


	double line[6] = { 0 };



	SlotGetSkeletalPoints();

	SlotGetFittedLineParams(line);
	GUIPanel->aFirstLineEdit->setText(QString::number(line[0]));
	GUIPanel->bFirstLineEdit->setText(QString::number(line[1]));
	GUIPanel->cFirstLineEdit->setText(QString::number(line[2]));

	double p[3];
	double length = 10;

	p[0] = line[3];//pts[0];
	p[1] = line[4];//pts[1];
	p[2] = line[5];//pts[2];

	vtkPoints* p1 = vtkPoints::New();

	p1->InsertNextPoint(p);
	p[0] += length * line[0];
	p[1] += length * line[1];
	p[2] += length * line[2];
	p1->InsertNextPoint(p)
		;
	vtkCellArray* newPolys = vtkCellArray::New();
	vtkIdType newCellPts[2];

	newCellPts[0] = 0;
	newCellPts[1] = 1;
	newPolys->InsertNextCell(2, newCellPts);

	vtkPolyData* output = vtkPolyData::New();
	output->SetPoints(p1);
	output->SetLines(newPolys);
	output->BuildCells();
	//output->Update();

	PolygonSurfaceData* o1 = new PolygonSurfaceData(output, VWidget);
	o1->SetPolygonSurfaceDataSetName("cos");
	o1->ComputeGeometricOrigin();
	SlotInsertPolygonSurface(o1);




	double v[3], v1[3], v2[3], v3[3];

	v[0] = line[0]; v[1] = line[1]; v[2] = line[2];

	v1[0] = GUIPanel->v1Edit[0]->text().toFloat();
	v1[1] = GUIPanel->v1Edit[1]->text().toFloat();
	v1[2] = GUIPanel->v1Edit[2]->text().toFloat();

	v2[0] = GUIPanel->v2Edit[0]->text().toFloat();
	v2[1] = GUIPanel->v2Edit[1]->text().toFloat();
	v2[2] = GUIPanel->v2Edit[2]->text().toFloat();

	v3[0] = GUIPanel->v3Edit[0]->text().toFloat();
	v3[1] = GUIPanel->v3Edit[1]->text().toFloat();
	v3[2] = GUIPanel->v3Edit[2]->text().toFloat();


	double angle[3];
	angle[0] = GetAngleBetweenNormalizedVectors(v, v1) * to_deg;
	angle[1] = GetAngleBetweenNormalizedVectors(v, v2) * to_deg;
	angle[2] = GetAngleBetweenNormalizedVectors(v, v3) * to_deg;

	GUIPanel->l1AnglesEdit[0]->setText(QString::number(angle[0]));
	GUIPanel->l1AnglesEdit[1]->setText(QString::number(angle[1]));
	GUIPanel->l1AnglesEdit[2]->setText(QString::number(angle[2]));

	if (testPoints == NULL) return;
	int nrOfPoints = testPoints->GetNumberOfPoints();

	testPoints->GetPoint(0, p1L1);
	testPoints->GetPoint(nrOfPoints - 1, p2L1);
	//middleL1[0] = line[3]; middleL1[1] = line[4]; middleL1[2] = line[5];







}
