void MainWindow::SlotCalculateAngleBetweenTwoLines()
{

	double v0[3];
	double v1[3];


	//middleL1[0]=line[3];middleL1[1]=line[4];middleL1[2]=line[5];


	double l1[3], l2[3];
	double tol = 1e-5;

	int i, j;



	double d11 = sqrt((p1L1[0] - p1L2[0]) * (p1L1[0] - p1L2[0]) + (p1L1[1] - p1L2[1]) * (p1L1[1] - p1L2[1]) + (p1L1[2] - p1L2[2]) * (p1L1[2] - p1L2[2]));
	double d12 = sqrt((p1L1[0] - p2L2[0]) * (p1L1[0] - p2L2[0]) + (p1L1[1] - p2L2[1]) * (p1L1[1] - p2L2[1]) + (p1L1[2] - p2L2[2]) * (p1L1[2] - p2L2[2]));
	double d21 = sqrt((p2L1[0] - p1L2[0]) * (p2L1[0] - p1L2[0]) + (p2L1[1] - p1L2[1]) * (p2L1[1] - p1L2[1]) + (p2L1[2] - p1L2[2]) * (p2L1[2] - p1L2[2]));
	double d22 = sqrt((p2L1[0] - p2L2[0]) * (p2L1[0] - p2L2[0]) + (p2L1[1] - p2L2[1]) * (p2L1[1] - p2L2[1]) + (p2L1[2] - p2L2[2]) * (p2L1[2] - p2L2[2]));

	double min = MIN3(d11, d12, d21);
	min = MIN(min, d22);
	double angle = 0;

	if (fabs(d11 - min) < tol) //1 1
	{
		//2-1
		l1[0] = (p2L1[0] - p1L1[0]);
		l1[1] = (p2L1[1] - p1L1[1]);
		l1[2] = (p2L1[2] - p1L1[2]);

		//2-1
		l2[0] = (p2L2[0] - p1L2[0]);
		l2[1] = (p2L2[1] - p1L2[1]);
		l2[2] = (p2L2[2] - p1L2[2]);

	}
	else if (fabs(d12 - min) < tol) // 1 2 
	{
		//2-1
		l1[0] = (p2L1[0] - p1L1[0]);
		l1[1] = (p2L1[1] - p1L1[1]);
		l1[2] = (p2L1[2] - p1L1[2]);

		//1-2
		l2[0] = (p1L2[0] - p2L2[0]);
		l2[1] = (p1L2[1] - p2L2[1]);
		l2[2] = (p1L2[2] - p2L2[2]);
	}
	else if (fabs(d21 - min) < tol) // 2 1
	{

		//1-2
		l1[0] = (p1L1[0] - p2L1[0]);
		l1[1] = (p1L1[1] - p2L1[1]);
		l1[2] = (p1L1[2] - p2L1[2]);

		//2-1
		l2[0] = (p2L2[0] - p1L2[0]);
		l2[1] = (p2L2[1] - p1L2[1]);
		l2[2] = (p2L2[2] - p1L2[2]);
	}
	else // 2 2 
	{
		//1-2
		l1[0] = (p1L1[0] - p2L1[0]);
		l1[1] = (p1L1[1] - p2L1[1]);
		l1[2] = (p1L1[2] - p2L1[2]);

		//1-2
		l2[0] = (p1L2[0] - p2L2[0]);
		l2[1] = (p1L2[1] - p2L2[1]);
		l2[2] = (p1L2[2] - p2L2[2]);
	}


	// mam wektory - normalizuje

	double length;

	length = DOT(l1, l1);
	if (length > 0)
	{
		length = sqrt(length);
		l1[0] /= length; l1[1] /= length; l1[2] /= length;

	}

	length = DOT(l2, l2);
	if (length > 0)
	{
		length = sqrt(length);
		l2[0] /= length; l2[1] /= length; l2[2] /= length;

	}


	v0[0] = GUIPanel->aFirstLineEdit->text().toFloat();
	v0[1] = GUIPanel->bFirstLineEdit->text().toFloat();
	v0[2] = GUIPanel->cFirstLineEdit->text().toFloat();

	v1[0] = GUIPanel->aSecondLineEdit->text().toFloat();
	v1[1] = GUIPanel->bSecondLineEdit->text().toFloat();
	v1[2] = GUIPanel->cSecondLineEdit->text().toFloat();


	double vx[3], vx1[3], vx2[3], vx3[3];
	vx1[0] = GUIPanel->v1Edit[0]->text().toFloat();
	vx1[1] = GUIPanel->v1Edit[1]->text().toFloat();
	vx1[2] = GUIPanel->v1Edit[2]->text().toFloat();

	vx2[0] = GUIPanel->v2Edit[0]->text().toFloat();
	vx2[1] = GUIPanel->v2Edit[1]->text().toFloat();
	vx2[2] = GUIPanel->v2Edit[2]->text().toFloat();

	vx3[0] = GUIPanel->v3Edit[0]->text().toFloat();
	vx3[1] = GUIPanel->v3Edit[1]->text().toFloat();
	vx3[2] = GUIPanel->v3Edit[2]->text().toFloat();

	//kat miedzy l1 i v0
	angle = acos(DOT(l1, v0)) * to_deg;
	if (angle > 90)
	{
		//zamiana znakow
		v0[0] *= -1; v0[1] *= -1; v0[2] *= -1;
		GUIPanel->aFirstLineEdit->setText(QString::number(v0[0]));
		GUIPanel->bFirstLineEdit->setText(QString::number(v0[1]));
		GUIPanel->cFirstLineEdit->setText(QString::number(v0[2]));

		vx[0] = v0[0]; vx[1] = v0[1]; vx[2] = v0[2];
		double anglex[3];
		anglex[0] = GetAngleBetweenNormalizedVectors(vx, vx1) * to_deg;
		anglex[1] = GetAngleBetweenNormalizedVectors(vx, vx2) * to_deg;
		anglex[2] = GetAngleBetweenNormalizedVectors(vx, vx3) * to_deg;

		GUIPanel->l1AnglesEdit[0]->setText(QString::number(anglex[0]));
		GUIPanel->l1AnglesEdit[1]->setText(QString::number(anglex[1]));
		GUIPanel->l1AnglesEdit[2]->setText(QString::number(anglex[2]));

	}


	//kat miedzy l2 i v1;

	angle = acos(DOT(l2, v1)) * to_deg;
	if (angle > 90)
	{
		//zamiana znakow
		v1[0] *= -1; v1[1] *= -1; v1[2] *= -1;
		GUIPanel->aSecondLineEdit->setText(QString::number(v1[0]));
		GUIPanel->bSecondLineEdit->setText(QString::number(v1[1]));
		GUIPanel->cSecondLineEdit->setText(QString::number(v1[2]));


		vx[0] = v1[0]; vx[1] = v1[1]; vx[2] = v1[2];
		double anglex[3];
		anglex[0] = GetAngleBetweenNormalizedVectors(vx, vx1) * to_deg;
		anglex[1] = GetAngleBetweenNormalizedVectors(vx, vx2) * to_deg;
		anglex[2] = GetAngleBetweenNormalizedVectors(vx, vx3) * to_deg;

		GUIPanel->l2AnglesEdit[0]->setText(QString::number(anglex[0]));
		GUIPanel->l2AnglesEdit[1]->setText(QString::number(anglex[1]));
		GUIPanel->l2AnglesEdit[2]->setText(QString::number(anglex[2]));



	}




	//znalezc 2 najblizsze
	//wyznaczyc 2 wektory
	//policzyc katy - jesli wieksze od 90 to zamienic znaki i katy




	double len1 = sqrt(v0[0] * v0[0] + v0[1] * v0[1] + v0[2] * v0[2]);
	double len2 = sqrt(v1[0] * v1[0] + v1[1] * v1[1] + v1[2] * v1[2]);

	double scalar = v0[0] * v1[0] + v0[1] * v1[1] + v0[2] * v1[2];

	double m = len1 * len2;
	angle = 0;

	if (m > 1e-5)
	{

		angle = acos(scalar / m) * to_deg;

		GUIPanel->lineAngleEdit->setText(QString::number(angle));


	}


	v0[0] = cos(GUIPanel->l1AnglesEdit[0]->text().toFloat() * to_rad);
	v0[1] = cos(GUIPanel->l1AnglesEdit[1]->text().toFloat() * to_rad);
	v0[2] = cos(GUIPanel->l1AnglesEdit[2]->text().toFloat() * to_rad);

	v1[0] = cos(GUIPanel->l2AnglesEdit[0]->text().toFloat() * to_rad);
	v1[1] = cos(GUIPanel->l2AnglesEdit[1]->text().toFloat() * to_rad);
	v1[2] = cos(GUIPanel->l2AnglesEdit[2]->text().toFloat() * to_rad);

	double vv = acos(DOT(v0, v1)) * to_deg;









}
