void MainWindow::SlotGetSkeletalPoints()
{
	if (testPoints != NULL)
		testPoints->Delete();
	testPoints = vtkPoints::New();


	ApplySurfaceProcessing(&MainWindow::GetSkeletalPoints, "...");
	//	GUIPanel->meshVolumeEdit->setText(QString::number(testPoints->GetNumberOfPoints()));
	//emit SendMessage(QString::number(temptimer++));

	vtkPoints* tPoints = vtkPoints::New();
	tPoints->DeepCopy(testPoints);


	vtkCellArray* newPolys = vtkCellArray::New();
	vtkIdType newCellPts[2];
	vtkIdType ID;
	double	p1[3];
	int i, j, k;

	double radius = 0.1;
	int pos = 0;
	int nrOfPts2 = 0;
	int x, y, z;
	for (j = 0; j < tPoints->GetNumberOfPoints(); j++)
	{

		if (j > 0)
		{
			newCellPts[0] = j;
			newCellPts[1] = j - 1;
			ID = newPolys->InsertNextCell(2, newCellPts);
		}

	}

	vtkPolyData* output = vtkPolyData::New();
	output->SetPoints(tPoints);
	output->SetLines(newPolys);
	output->BuildCells();
	//output->Update();

	PolygonSurfaceData* o2 = new PolygonSurfaceData(output, VWidget);
	o2->SetPolygonSurfaceDataSetName("Szkielet laczny");
	o2->GetVActor()->GetProperty()->SetColor(0, 0, 0);
	o2->ComputeGeometricOrigin();
	SlotInsertPolygonSurface(o2);

}



void MainWindow::GetSkeletalPoints()
{
	vtkPoints* tmpPoints = SProcessing->GetSkeletalPoints();

	if ((testPoints == NULL) || (tmpPoints == NULL))return;
	//inaczej dodaje teraz - tak zeby byla ciaglosc

	// sprawdzam ktory z pktow nowej prostej (pierwszy i ostatni) lezy blizej punktu pierwszego
	// lub ostatniego aktualnych punktow
	// dodaje w odpowiednie miejse ew. zamieniam kolejnosc
	//
	//-------------------------------------------------------

	int nrTestPoints = testPoints->GetNumberOfPoints();
	int nrTmpPoints = tmpPoints->GetNumberOfPoints();
	int i;
	double p[3];

	if (nrTestPoints == 0)
	{
		for (i = 0; i < nrTmpPoints; i++)
		{
			tmpPoints->GetPoint(i, p);
			testPoints->InsertNextPoint(p);
		}


	}
	else
	{

		double tol = 1e-5;
		//aktualne
		double p1L1x[3], p2L1x[3];
		testPoints->GetPoint(0, p1L1x);
		testPoints->GetPoint(nrTestPoints - 1, p2L1x);


		//dodaje


		double p1L2x[3], p2L2x[3];
		tmpPoints->GetPoint(0, p1L2x);
		tmpPoints->GetPoint(nrTmpPoints - 1, p2L2x);


		double d11 = sqrt((p1L1x[0] - p1L2x[0]) * (p1L1x[0] - p1L2x[0]) + (p1L1x[1] - p1L2x[1]) * (p1L1x[1] - p1L2x[1]) + (p1L1x[2] - p1L2x[2]) * (p1L1x[2] - p1L2x[2]));
		double d12 = sqrt((p1L1x[0] - p2L2x[0]) * (p1L1x[0] - p2L2x[0]) + (p1L1x[1] - p2L2x[1]) * (p1L1x[1] - p2L2x[1]) + (p1L1x[2] - p2L2x[2]) * (p1L1x[2] - p2L2x[2]));
		double d21 = sqrt((p2L1x[0] - p1L2x[0]) * (p2L1x[0] - p1L2x[0]) + (p2L1x[1] - p1L2x[1]) * (p2L1x[1] - p1L2x[1]) + (p2L1x[2] - p1L2x[2]) * (p2L1x[2] - p1L2x[2]));
		double d22 = sqrt((p2L1x[0] - p2L2x[0]) * (p2L1x[0] - p2L2x[0]) + (p2L1x[1] - p2L2x[1]) * (p2L1x[1] - p2L2x[1]) + (p2L1x[2] - p2L2x[2]) * (p2L1x[2] - p2L2x[2]));

		double min = MIN3(d11, d12, d21);
		min = MIN(min, d22);
		double angle = 0;


		if (fabs(d11 - min) < tol) //1 1
		{

			//doklejam z przodu w odwrotnej kolejnosci
			vtkPoints* xPoints = vtkPoints::New();
			for (i = 0; i < nrTmpPoints; i++)
			{
				tmpPoints->GetPoint(nrTmpPoints - 1 - i, p);
				xPoints->InsertNextPoint(p);
			}

			for (i = 0; i < nrTestPoints; i++)
			{
				testPoints->GetPoint(i, p);
				xPoints->InsertNextPoint(p);
			}

			testPoints->DeepCopy(xPoints);

			xPoints->Delete();


		}
		else if (fabs(d12 - min) < tol) // 1 2 
		{

			//doklejam z przodu w normalnej kolejnosci


			for (i = 0; i < nrTestPoints; i++)
			{
				testPoints->GetPoint(i, p);
				tmpPoints->InsertNextPoint(p);
			}
			testPoints->DeepCopy(tmpPoints);
		}
		else if (fabs(d21 - min) < tol) // 2 1
		{

			//doklejam z tylu w normalnej kolejnosci
			for (i = 0; i < nrTmpPoints; i++)
			{
				tmpPoints->GetPoint(i, p);
				testPoints->InsertNextPoint(p);
			}


		}
		else // 2 2 
		{
			//doklejam z tylu w kolejnosci odwrotnej
			for (i = 0; i < nrTmpPoints; i++)
			{
				tmpPoints->GetPoint(nrTmpPoints - 1 - i, p);
				testPoints->InsertNextPoint(p);
			}

		}
	}

	//-------------------------------------------------------


	tmpPoints->Delete();


}

