void MainWindow::SlotGetFittedLineParams(double* line)
{
	if (testPoints == NULL) return;
	int nrOfPoints = testPoints->GetNumberOfPoints();

	if (nrOfPoints < 3) return;

	double* pts = new double[nrOfPoints * 3];
	double p[3];
	int i;
	int pos = 0;
	//double line[6]={0};
	memset(line, 0, sizeof(double) * 6);
	for (i = 0; i < nrOfPoints; i++)
	{
		testPoints->GetPoint(i, p);
		pts[pos++] = p[0];
		pts[pos++] = p[1];
		pts[pos++] = p[2];
	}

	int err = fitLine3D_wodsFull(pts, nrOfPoints, line, 0.01, 100);
	delete[]pts;
}
