void	MainWindow::SlotGetP4PlaneFromBase4Points(double* pts, double* base, bool  vis, QString name)
{
	if ((base == NULL) || (pts == NULL))
	{
		SendMessage("PlanePoints not defined!");
		return;
	}

	double length;
	double v1[3], v2[3], cross[3];

	//double * p2, * p3;
	//double py1[3], py2[3];
	//double px1[3], px2[3];
	//double p[3];


	int i, j;

	for (i = 0; i < 4; i++)
	{
		for (j = 0; j < 3; j++)
		{
			base4Point[i][j] = pts[i * 3 + j];
		}

	}
	double* p0 = base4Point[0];
	double* p1 = base4Point[1];
	double* pA = base4Point[2];
	double* pB = base4Point[3];


	bool orthogonal = true;


	// double v1[3], v2[3];
	for (int k = 0; k < 3; k++)
	{
		v1[k] = p1[k] - p0[k];
		v2[k] = pB[k] - p0[k];
	}
	normV(v1);
	normV(v2);

	SlotGetBaseVectors(v1, v2, base, orthogonal);
	SlotSetBaseOrigin(p0);

	double v3[3];
	CROSS(v3, v1, v2);
	//	orthogonal=true;
	base[9] = p0[0];
	base[10] = p0[1];
	base[11] = p0[2];
	if (vis == true)
	{
		VisualizePlanes(data, p0, v1, v2, v3, name);
	}

}
