void	MainWindow::SlotGetP4Plane(double* pts, double* base, bool  vis, QString name)
{
	if ((base == NULL) || (pts == NULL))
	{
		SendMessage("PlanePoints not defined!");
		return;
	}

	double length;
	double v1[3], v2[3], cross[3];

	double* p0, * p1, * p2, * p3;
	double py1[3], py2[3];
	double px1[3], px2[3];
	double p[3];


	int i, j;

	for (i = 0; i < 4; i++)
	{
		for (j = 0; j < 3; j++)
		{
			base4Point[i][j] = pts[i * 3 + j];
		}

	}

	p1 = base4Point[0];
	p0 = base4Point[1];
	p3 = base4Point[2];
	p2 = base4Point[3];

	// punkt srodkowy
	p[0] = 0.25 * (p0[0] + p1[0] + p2[0] + p3[0]);
	p[1] = 0.25 * (p0[1] + p1[1] + p2[1] + p3[1]);
	p[2] = 0.25 * (p0[2] + p1[2] + p2[2] + p3[2]);

	py1[0] = 0.5 * (p0[0] + p2[0]);
	py1[1] = 0.5 * (p0[1] + p2[1]);
	py1[2] = 0.5 * (p0[2] + p2[2]);

	py2[0] = 0.5 * (p1[0] + p3[0]);
	py2[1] = 0.5 * (p1[1] + p3[1]);
	py2[2] = 0.5 * (p1[2] + p3[2]);

	px1[0] = 0.5 * (p2[0] + p3[0]);
	px1[1] = 0.5 * (p2[1] + p3[1]);
	px1[2] = 0.5 * (p2[2] + p3[2]);

	px2[0] = 0.5 * (p0[0] + p1[0]);
	px2[1] = 0.5 * (p0[1] + p1[1]);
	px2[2] = 0.5 * (p0[2] + p1[2]);

	bool orthogonal = true;

	v1[0] = py2[0] - py1[0];
	v1[1] = py2[1] - py1[1];
	v1[2] = py2[2] - py1[2];

	v2[0] = px2[0] - px1[0];
	v2[1] = px2[1] - px1[1];
	v2[2] = px2[2] - px1[2];

	SlotGetBaseVectors(v1, v2, base, orthogonal);
	SlotSetBaseOrigin(p);

	double v3[3];
	CROSS(v3, v1, v2);
	//	orthogonal=true;
	base[9] = p[0];
	base[10] = p[1];
	base[11] = p[2];
	if (vis == true)
	{
		VisualizePlanes(data, p, v1, v2, v3, name);
	}

}
