void	MainWindow::VisualizePlanes(RawDataSet* data, double* p, double* v1, double* v2, double* v3, QString name)
{
	if (data != NULL)
	{

		//dodaje dane krzyzykowe!

		//

		vtkPoints* pts = vtkPoints::New();
		double s[3];
		//double pA[3],pB[3],pC[3],pD[3],s[3];
		s[0] = data->GetNx() * data->GetXscale();
		s[1] = data->GetNy() * data->GetYscale();
		s[2] = data->GetNz() * data->GetZscale();

		//pierwsza
		//obliczam 4 punkty

		double xv1[3], xv2[3], xp[3];

		double origin[3];
		double scale[3];
		int nn[3];
		data->GetOrigin(origin);
		data->GetN(nn);
		data->GetScale(scale);
		double bounds[6] = { origin[0], origin[0] + nn[0] * scale[0], origin[1], origin[1] + nn[1] * scale[1], origin[2], origin[2] + nn[2] * scale[2] };


		int i, j;

		//biore unit v - rownanie prostej i punkty przeciecia z boundingbox

		//pierwsza

		double p1[3];

		//origin
		//vtkBox *box=vtkBox::New();
		vtkPlanes* box = vtkPlanes::New();
		box->SetBounds(bounds);



		//vtkClipPolyData *clipper=vtkClipPolyData::New();
		//clipper->SetClipFunction(box);
		//clipper->SetValue(0.0);
		vtkPlaneSource* plane = vtkPlaneSource::New();;

		vtkIntArray* scalars = vtkIntArray::New(); // przypisuje skalar do danego el luta

		vtkLookupTable* lut = vtkLookupTable::New();
		lut->SetAlphaRange(0, 3);
		lut->SetTableRange(0, 3);
		lut->SetNumberOfColors(3);
		lut->SetTableValue(0, 1, 0, 0); //r
		lut->SetTableValue(1, 0, 1, 0); //g
		lut->SetTableValue(2, 0, 0, 1); //b
		lut->Build();

		for (j = 0; j < 3; j++)
		{
			for (i = 0; i < 4; i++)
			{
				scalars->InsertNextValue(j);
			}
		}
		scalars->SetLookupTable(lut);

		//plane->SetResolution(21,21);
		double ssize = MAX3(nn[0] * scale[0], nn[1] * scale[1], nn[1] * scale[2]) / 2;
		//x
		double vv1 = acos(DOT(v1, v2)) * to_deg;
		double vv2 = acos(DOT(v3, v2)) * to_deg;
		double vv3 = acos(DOT(v1, v3)) * to_deg;

		vtkPolyData* planePolys1 = vtkPolyData::New();;
		for (i = 0; i < 3; i++)
		{
			p1[i] = p[i] - (v1[i] + v2[i]) * ssize;
			xv1[i] = p1[i] + v1[i] * ssize * 2;
			xv2[i] = p1[i] + v2[i] * ssize * 2;
		}
		plane->SetOrigin(p1);	plane->SetPoint1(xv1);	plane->SetPoint2(xv2); plane->Update();
		planePolys1->DeepCopy(plane->GetOutput());
		//		planePolys1->Update();		

		int nrr = planePolys1->GetNumberOfPoints();
		//y


		vtkPolyData* planePolys2 = vtkPolyData::New();;
		for (i = 0; i < 3; i++)
		{
			p1[i] = p[i] - (v3[i] + v2[i]) * ssize;
			xv1[i] = p1[i] + v3[i] * ssize * 2;
			xv2[i] = p1[i] + v2[i] * ssize * 2;
		}
		plane->SetOrigin(p1);	plane->SetPoint1(xv1);	plane->SetPoint2(xv2); 	plane->Update();
		planePolys2->DeepCopy(plane->GetOutput());
		//		planePolys2->Update();		

		//z
		vtkPolyData* planePolys3 = vtkPolyData::New();;
		for (i = 0; i < 3; i++)
		{
			p1[i] = p[i] - (v1[i] + v3[i]) * ssize;
			xv1[i] = p1[i] + v1[i] * ssize * 2;
			xv2[i] = p1[i] + v3[i] * ssize * 2;
		}
		plane->SetOrigin(p1);	plane->SetPoint1(xv1);	plane->SetPoint2(xv2);	plane->Update();
		planePolys3->DeepCopy(plane->GetOutput());

		QString groupName = "planes";

		PolygonSurfaceData* o1 = new PolygonSurfaceData(planePolys1, VWidget);
		o1->SetPolygonSurfaceDataSetName("Plane " + name + " x");
		o1->GetVActor()->GetProperty()->SetColor(1.0, 0, 0);
		o1->ComputeGeometricOrigin();
		o1->SetGroupName(groupName);
		SlotInsertPolygonSurface(o1);

		o1 = new PolygonSurfaceData(planePolys2, VWidget);
		o1->SetPolygonSurfaceDataSetName("Plane " + name + " y");
		o1->GetVActor()->GetProperty()->SetColor(0, 1.0, 0);
		o1->ComputeGeometricOrigin();
		o1->SetGroupName(groupName);
		SlotInsertPolygonSurface(o1);

		o1 = new PolygonSurfaceData(planePolys3, VWidget);
		o1->SetPolygonSurfaceDataSetName("Plane " + name + " z");
		o1->GetVActor()->GetProperty()->SetColor(0, 0, 1.0);
		o1->ComputeGeometricOrigin();
		o1->SetGroupName(groupName);
		SlotInsertPolygonSurface(o1);
	}
}
