void	MainWindow::SlotSetBaseVectors(double* v1, double* v2, bool orthogonal)
{
	double length;
	double cross[3];
	length = DOT(v1, v1);
	if (length > 0)
	{
		length = sqrt(length);
		v1[0] /= length; v1[1] /= length; v1[2] /= length;
	}

	length = DOT(v2, v2);
	if (length > 0)
	{
		length = sqrt(length);
		v2[0] /= length; v2[1] /= length; v2[2] /= length;
	}



	double vv = acos(DOT(v1, v2)) * to_deg;

	//improve dodaje zeby baza byla ortogonalna -
	// biore roznice vv i 90 stopni i dziele na 2
	// kazdy z vektorow v1 i v2 obroce tak w plaszczyznie v1,v2 zeby kat miedzy nimi byl 90 stopni - nastepnie policze cross


	double deltaAngle = (acos(DOT(v1, v2)) - M_PI / 2) / 2;

	double v1a[3], v2a[3];
	if (orthogonal == true)
	{
		RotateVectorInPlane(v1, v1a, v1, v2, -deltaAngle);
		RotateVectorInPlane(v2, v2a, v1, v2, deltaAngle);

		int i;
		for (i = 0; i < 3; i++)
		{
			v1[i] = v1a[i];	v2[i] = v2a[i];
		}
	}
	else
	{
		int i;
		for (i = 0; i < 3; i++)
		{
			v1a[i] = v1[i];	v2a[i] = v2[i];
		}
	}


	double vv2 = acos(DOT(v1a, v2a)) * to_deg;
	//-------------------------------------------------




	CROSS(cross, v1a, v2a);
	length = DOT(cross, cross);
	if (length > 0)
	{
		length = sqrt(length);
		cross[0] /= length; cross[1] /= length; cross[2] /= length;

	}





	GUIPanel->v1Edit[0]->setText(QString::number(v1a[0]));
	GUIPanel->v1Edit[1]->setText(QString::number(v1a[1]));
	GUIPanel->v1Edit[2]->setText(QString::number(v1a[2]));

	GUIPanel->v2Edit[0]->setText(QString::number(v2a[0]));
	GUIPanel->v2Edit[1]->setText(QString::number(v2a[1]));
	GUIPanel->v2Edit[2]->setText(QString::number(v2a[2]));


	GUIPanel->v3Edit[0]->setText(QString::number(cross[0]));
	GUIPanel->v3Edit[1]->setText(QString::number(cross[1]));
	GUIPanel->v3Edit[2]->setText(QString::number(cross[2]));

	//znormalizowac i wektor prostopadly do nich



	baseVectors[0] = v1a[0];	baseVectors[1] = v1a[1];	baseVectors[2] = v1a[2];
	baseVectors[3] = v2a[0];	baseVectors[4] = v2a[1];	baseVectors[5] = v2a[2];
	baseVectors[6] = cross[0];	baseVectors[7] = cross[1];	baseVectors[8] = cross[2];



	emit SendMessage("Base vectors angle: " + QString::number(vv));
}
