void	MainWindow::SlotSpecialCut()
{
	if (data == NULL)
	{
		emit SendMessage("No data ...");
		return;
	}

	MaskData = MainListItem->GetData()->GetMasks()->GetCurrentMaskData();
	int nrOfMasks = MainListItem->GetData()->GetMasks()->GetNumberOfMasks();
	if (nrOfMasks < 2)
	{
		emit SendMessage("No mask!");
		return;
	}
	int sNr = SurfaceDataList->GetNumberOfItems();
	if (sNr == 0)
	{
		emit SendMessage("No surface!");
		return;
	}



	//spr czy sphere cutter

	if (SProcessing->GetCuttingMode() != 1)
	{
		emit SendMessage("Set Cutting tool to sphere!");
		return;
	}

	RTimer.Start("TEsting ...");
	double center[3], size;
	SProcessing->GetCuttingSphereParams(center, size);

	int p[3];
	int psize[3];
	psize[0] = Round(size / data->GetXscale());
	psize[1] = Round(size / data->GetYscale());
	psize[2] = Round(size / data->GetZscale());


	p[0] = Round(center[0] / data->GetXscale());
	p[1] = Round(center[1] / data->GetYscale());
	p[2] = Round(center[2] / data->GetZscale());


	int iX2 = psize[0] * psize[0];
	int iY2 = psize[1] * psize[1];
	int iZ2 = psize[2] * psize[2];
	int i, j, k;

	double s;
	int pos = 0;
	for (k = 0; k < data->GetNz(); k++)
	{
		for (j = 0; j < data->GetNy(); j++)
		{
			for (i = 0; i < data->GetNx(); i++)
			{
				s = (double)((i - p[0]) * (i - p[0])) / (iX2)+
					(double)((j - p[1]) * (j - p[1])) / (iY2)+
					(double)((k - p[2]) * (k - p[2])) / (iZ2);

				if (s < 1 + 1e-6) MaskData[pos] = 0;

				pos++;

			}
		}
	}



	chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
	SagittalView->InsertMaskData(MaskData);
	CoronalView->InsertMaskData(MaskData);
	SlotInsertNewMask();

	SlotReplaceCurrentSurfaceWithMask();

	RTimer.Stop();


}
