void	MainWindow::SlotReplaceCurrentSurfaceWithMask()
{
	int sNr = SurfaceDataList->GetNumberOfItems();
	if (sNr == 0)
	{
		emit SendMessage("No surface!");
		return;
	}
	double color[4];
	QString name = SurfaceDataList->GetCurrentListItem()->GetData()->GetPolygonSurfaceName();
	SurfaceDataList->GetCurrentListItem()->GetData()->GetVActor()->GetProperty()->GetColor(color);
	color[3] = SurfaceDataList->GetCurrentListItem()->GetData()->GetVActor()->GetProperty()->GetOpacity();
	SurfaceDataList->GetCurrentListItem()->GetData()->SetHideWithoutRefresh(true);

	//SetHideWithoutRefresh
	SlotDeleteCurrentPolygonSurfaceDataSet();

	//	SlotGenerateNewMarchingCubesSurface();
	if ((MaskData != NULL) && (data != NULL))
	{

		//RTimer.Start("Generating Marching Cubes Surface");
		double* Scale = new double[3];
		int* N = new int[3];

		Scale[0] = data->GetXscale();
		Scale[1] = data->GetYscale();
		Scale[2] = data->GetZscale();

		N[0] = data->GetNx();
		N[1] = data->GetNy();
		N[2] = data->GetNz();

		double origin[3];
		data->GetOrigin(origin);
		SProcessing->SlotGenerateNewMarchingCubesSurface(MaskData, N, Scale, origin, name, true, true, color);
		/*	SurfaceDataList->GetCurrentListItem()->GetData()->SetRepaintWidget(true);
		SurfaceDataList->GetCurrentListItem()->GetData()->SetResetCamera(true);*/
		//RTimer.Stop();
	}

}

