void	MainWindow::SlotCropData()
{
	if (data == NULL) {
		emit SendMessage("No data ...");
		return;
	}

	int i, j, k;
	int seed[3];
	seed[0] = GUIPanel->seedPointXBox->value();
	seed[1] = GUIPanel->seedPointYBox->value();
	seed[2] = GUIPanel->seedPointZBox->value();



	int winSize[3];
	winSize[0] = GUIPanel->cropSizeXBox->value() / 2;
	winSize[1] = GUIPanel->cropSizeYBox->value() / 2;
	winSize[2] = GUIPanel->cropSizeZBox->value() / 2;
	//int maxSeeds=GUIPanel->maxSeedsBox->value();


	int InspX = winSize[0];
	int InspY = winSize[1];
	int InspZ = winSize[2];

	int xxr0, xxr1, yyr0, yyr1, zzr0, zzr1;

	int PosX = seed[0];
	int PosY = seed[1];
	int PosZ = seed[2];


	int rx = data->GetNx();
	int ry = data->GetNy();
	int rz = data->GetNz();

	int tolX = 10;
	if ((InspX * 2 + tolX > rx) && (InspY * 2 + tolX > ry) && (InspY * 2 + tolX > rz))
	{
		//zozmiary cropa takie same
		xxr0 = 0;
		yyr0 = 0;
		zzr0 = 0;

		xxr1 = rx;
		yyr1 = ry;
		zzr1 = rz;
	}
	else
	{
		xxr0 = ((PosX - InspX) > 0) ? PosX - InspX : 0;
		yyr0 = ((PosY - InspY) > 0) ? PosY - InspY : 0;
		zzr0 = ((PosZ - InspZ) > 0) ? PosZ - InspZ : 0;

		xxr1 = ((PosX + InspX) < rx) ? PosX + InspX : rx - 1;
		yyr1 = ((PosY + InspY) < ry) ? PosY + InspY : ry - 1;
		zzr1 = ((PosZ + InspZ) < rz) ? PosZ + InspZ : rz - 1;
	}


	RawDataSet* dataY = new RawDataSet(xxr1 - xxr0, yyr1 - yyr0, zzr1 - zzr0, data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());
	double origin[3] = { xxr0 * data->GetXscale(), yyr0 * data->GetYscale(), zzr0 * data->GetZscale() };
	dataY->SetOrigin(origin);
	QString name;
	name = data->GetRawDataSetName();
	name.append(" - Cropped");
	dataY->SetRawDataSetName(name);

	unsigned char* maskData = NULL;
	unsigned char* boundaryMask = NULL;

	for (j = 0; j < yyr1 - yyr0; j++)
		for (k = 0; k < zzr1 - zzr0; k++)
			memcpy((dataY->GetDataArray() + j * dataY->GetNx() + k * dataY->GetSliceSize()), (data->GetDataArray() + (yyr0 + j) * data->GetNx() + (zzr0 + k) * data->GetSliceSize() + xxr0), sizeof(unsigned short) * (xxr1 - xxr0));





	unsigned char* mmask = NULL;
	if (MaskData != NULL)
	{
		VolumeInt = 0;
		for (int i = 0; i < data->GetVolumeSize(); i++)
			if (MaskData[i] == 1) VolumeInt++;
	}
	if ((VolumeInt > 0) && (VolumeInt < data->GetVolumeSize()))
	{
		mmask = new unsigned char[dataY->GetVolumeSize()];
		for (j = 0; j < yyr1 - yyr0; j++)
			for (k = 0; k < zzr1 - zzr0; k++)
				memcpy((mmask + j * dataY->GetNx() + k * dataY->GetSliceSize()), (MaskData + (yyr0 + j) * data->GetNx() + (zzr0 + k) * data->GetSliceSize() + xxr0), sizeof(unsigned short) * (xxr1 - xxr0));


	}









	dataY->dicomMinValue = data->dicomMinValue;
	dataY->dicomLevelValue = data->dicomLevelValue;
	dataY->dicomWindowWidthValue = data->dicomWindowWidthValue;
	dataY->dicomRescaleValue = data->dicomRescaleValue;

	this->InsertRawDataSet(dataY);



	if (mmask != NULL)
	{
		if (MaskData != NULL)
		{
			delete[] MaskData;

		}
		MaskData = mmask;
		chgMaskTimeStamp = elapsedTimer.elapsed(); TransversalView->InsertMaskData(MaskData);
		SagittalView->InsertMaskData(MaskData);
		CoronalView->InsertMaskData(MaskData);
		SlotInsertNewMask();
	}
}
