void	MainWindow::SlotSpecialFunctiionForGrowing1()
{
	bool checkDisabled = GUIPanel->disableRawDataMixerCheckBox2->isChecked();
	if (checkDisabled == true)return;

	int minVal = (GUIPanel->functionForGenAnimLineEdit[0])->text().toInt();
	int maxVal = (GUIPanel->functionForGenAnimLineEdit[1])->text().toInt();
	int frameStep = (GUIPanel->functionForGenAnimLineEdit[2])->text().toInt();


	//int frame = this->videoTools->getFrameCount();




	if (specialInit == true)
	{
		specialValStart = minVal;
		specialFrameCount = 0;

	}

	if (specialFrameCount % frameStep == 0)
	{



		specialValStart += 1;
		if (specialValStart >= maxVal)specialValStart = minVal;

		if ((mixer != NULL) && (mixer->GetNumberOfLayers() > 1))
		{



			LinkedList <RawDataLayer*>* rawDataLayerList = mixer->GetLayerList();
			LinkedList <LayerMaskFilter*>* layerMaskFilterList = mixer->GetLayerMaskFilterList();

			LinkedList <LayerFilter*>* layerFilterList = mixer->GetLayerFilterList();


			int nrLayers = mixer->GetNumberOfLayers();

			RawDataLayer* layer;
			int filterMode;
			LayerMaskFilter* layerMaskFilter;
			LayerFilter* layerFilter;
			int i;
			for (i = 1; i < nrLayers; i++)
			{
				layer = rawDataLayerList->GetItemAtPos(i)->GetData();
				filterMode = layer->GetFilterMode();
				//layerMaskFilter = layerMaskFilterList->GetItemAtPos(filterMode)->GetData();
				layerFilter = layerFilterList->GetItemAtPos(filterMode)->GetData();
				QString filterName = layerFilter->GetFilterName();

				if (filterName.contains("LayerGrowingRegionFilter") == true)	break;
			}

			if (i < nrLayers)
			{
				int j;
				for (j = 0; j < layerFilter->GetNumberOfParams(); j++)
				{
					QString paramName = layerFilter->GetParamName(j);
					if (paramName.compare("maxDist") == 0) break;

				}

				if (j < layerFilter->GetNumberOfParams())
				{
					double val = GUIPanel->MagnifyingGlassSlider->value() * 0.1;

					layer->SetFilterParam(j, specialValStart);
					newMaskInserted = true;;
					RepaintViews();

					//layer->GetMaskFilterParam(j);
					//->tunningThicknessFilterSlider->setValue(val * 1000);
					//GUIPanel->tunningLabel->setText(QString::number(val));

				}
			}

		}
	}
	specialFrameCount++;
	if (specialInit == true)
	{
		specialInit = false;
	}

}

