void MainWindow::Slot3DFilterLiveUpdate()
{
	qDebug() << "IM IN!";

	if (disable3DUpdateFilter == false)
		if ((mixer != NULL) && (mixer1 != NULL) && (mixer2 != NULL))
		{
			int mixer0TimeStampNew = mixer->getTimeStamp();
			int mixer1TimeStampNew = mixer1->getTimeStamp();
			int mixer2TimeStampNew = mixer2->getTimeStamp();

			if ((explode3DFinal == true) ||
				((mixer0TimeStampNew != mixer0TimeStamp) ||
					(mixer1TimeStampNew != mixer1TimeStamp) ||
					(mixer2TimeStampNew != mixer2TimeStamp)))
			{

				//wchodzi tu tylko w sytuacji gdy wszystkie 3 mixery są odświeżone i zaznaczony checkbox ExplodeLiveUpdateCheckBox
				if ((GUIPanel->ExplodeLiveUpdateCheckBox->isChecked() == true) || (explode3DFinal == true))
				{

					//1.sprawdzic czy istnieej shpereExplodeShadowSurfaceData - jesli nie - zrobic i dodac do listy
					//2.
					if (isVolumeVisible == true)
					{

						if (TestFilterForName("LayerMaskExplodeSegmentationRegionFilter") == true)
						{
							SlotExplode3DSegmentationLiveUpdate();
						}
					}
					//	else
					if (TestFilterForName("LayerGrowingRegionFilter") == true)
					{
						SlotGrowing3DSegmentationLiveUpdate();
					}



				}
				mixer0TimeStamp = mixer0TimeStampNew;
				mixer1TimeStamp = mixer1TimeStampNew;
				mixer2TimeStamp = mixer2TimeStampNew;




			}
			else
			{
				int i = 1;
			}


			disable3DUpdateFilter = false;
			//LastClickedView = 3;

		}
}

