void	MainWindow::SlotExtractMaskedVolume()
{
	if (data == NULL) {
		emit SendMessage("No data ...");
		return;
	}


	if (MainListItem->GetData()->GetMasks()->GetNumberOfMasks() > 1)
	{

		RTimer.Start("Creating New Dataset");
		int i, j, k;
		int pos;

		int bounds[6];
		bounds[0] = INT_MAX;
		bounds[1] = INT_MIN;
		bounds[2] = INT_MAX;
		bounds[3] = INT_MIN;
		bounds[4] = INT_MAX;
		bounds[5] = INT_MIN;

		//Find corner of the objectus
		pos = 0;

		for (k = 0; k < data->GetNz(); k++)
			for (j = 0; j < data->GetNy(); j++)
				for (i = 0; i < data->GetNx(); i++)
				{
					//Points->GetPoint(Tab[i],Point);
					if (MaskData[pos] > 0)
					{

						if (i > bounds[1]) bounds[1] = i;
						if (j > bounds[3]) bounds[3] = j;
						if (k > bounds[5]) bounds[5] = k;

						if (i < bounds[0]) bounds[0] = i;
						if (j < bounds[2]) bounds[2] = j;
						if (k < bounds[4]) bounds[4] = k;

					}
					pos++;
				}


		RawDataSet* dataX = new RawDataSet(bounds[1] - bounds[0], bounds[3] - bounds[2], bounds[5] - bounds[4], data->GetXscale(), data->GetYscale(), data->GetZscale(), data->GetGantryAngle());
		dataX->ZeroQ();

		unsigned short* dataXArray = dataX->GetDataArray();
		unsigned short* modelArray = data->GetDataArray();
		int val;
		int pos2 = 0;
		for (k = 0; k < dataX->GetNz(); k++)
			for (j = 0; j < dataX->GetNy(); j++)
				for (i = 0; i < dataX->GetNx(); i++)
				{
					pos = data->GetVoxelPos(i + bounds[0], j + bounds[2], k + bounds[4]);
					val = MaskData[pos];

					if (val > 0) dataXArray[pos2] = modelArray[pos];
					pos2++;
				}

		QString name = data->GetRawDataSetName();
		name.append(" - Seg");
		dataX->SetRawDataSetName(name);


		InsertRawDataSet(dataX);
		RTimer.Stop();
	}

}
