void	MainWindow::SlotSelect3DVolumePointOnSurface(int x, int y)
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		if (data != NULL)
		{
			//if ((MainListItem->GetData()->GetMasks()->GetNumberOfMasks()>0)&&(MainListItem->GetData()->GetMasks()->GetCurrentMaskNumber()>0))
			{
				//	double sc[3];
				//	data->GetScale(sc);
				//	double tol=1e-3;
				//double *sc2=SurfaceDataList->GetCurrentListItem()->GetData()->GetPScale();

				//if((fabs(sc[0]-sc2[0])<tol)&&(fabs(sc[1]-sc2[1])<tol)&&(fabs(sc[2]-sc2[2])<tol))
				{


					int Nr = SurfaceDataList->GetNumberOfItems();

					PolygonSurfaceData* Data;
					//QString name;
					vtkPointPicker* picker = vtkPointPicker::New();
					int shoot = picker->Pick(x, y, 0, VWidget->Renderer);

					if (shoot == 1)
					{
						int i;

						int id = picker->GetPointId();
						i = 1;

						double p[3];
						vtkProp* testProp = picker->GetActor();


						for (i = 0; i < Nr; i++)
						{
							if (SurfaceDataList->GetItemAtPos(i)->GetData()->GetVActor() == picker->GetActor())
							{

								break;
							}
						}

						if (i == Nr) return;





						vtkPolyData* pData = SurfaceDataList->GetItemAtPos(i)->GetData()->GetVPolyData();
						pData->GetPoints()->GetPoint(id, p);

						double origin[3];
						data->GetOrigin(origin);


						int x, y, z;
						double scale[3];
						data->GetScale(scale);

						x = (int)((p[0] - origin[0]) / scale[0]);
						y = (int)((p[1] - origin[1]) / scale[1]);
						z = (int)((p[2] - origin[2]) / scale[2]);
						//SlotMoveSphereActor(point[0],point[1],point[2]);

						int pos = data->GetVoxelPos(x, y, z);
						if ((pos >= 0) && (pos < data->GetVolumeSize()))
						{
							TransversalView->SetSlice(x, y, z);
							CoronalView->SetSlice(x, y, z);
							SagittalView->SetSlice(x, y, z);
							PosX = x;	PosY = y; PosZ = z;
						}



					}
				}
			}
		}
	}

}

