void	MainWindow::UpdateVeinDefs()
{
	// w czym trzymam definicje // nazwy mozna w zwyklej tablicy
	// a fragmetny w strukture jakas wsadze

	//	double	veinCameraOrientation[600];
	//unsigned char	veinColor[300];

	//QString veinStringTab[100];
	//veinNr=3;





	QFile file(progDirPath + "/" + "veindef.txt");

	//to dla "none"


	int i, j;
	int pos;


	if (file.open(QIODevice::WriteOnly))
	{
		QTextStream stream(&file);

		stream << "default:\n\n";
		for (i = 0; i < 9; i++)
		{
			stream << veinColor[i] << " ";
		}
		stream << "\n\n";

		stream << "single:\n\n";

		int posVein = 3;
		int posCol = posVein * 3;
		int posOrient = posVein * 6;

		for (i = 0; i < nrOfSingleVeins; i++)
		{
			stream << veinStringTab[posVein++] << " ";
			for (j = 0; j < 3; j++)
			{
				stream << veinColor[posCol++] << " ";
			}
			for (j = 0; j < 6; j++)
			{
				stream << veinCameraOrientation[posOrient++] << " ";
			}
			stream << "\n";

		}
		stream << "\n";

		stream << "symetric:\n\n";

		QString cutName;
		for (i = 0; i < nrOfSymetricVeins; i++)
		{
			cutName = veinStringTab[posVein];
			pos = cutName.indexOf("_");
			if (pos >= 0)
			{
				cutName = cutName.mid(0, pos);
			}

			stream << cutName << " ";
			for (j = 0; j < 3; j++)
			{
				stream << veinColor[posCol++] << " ";
			}
			for (j = 0; j < 6; j++)
			{
				stream << veinCameraOrientation[posOrient++] << " ";
			}

			for (j = 0; j < 3; j++)
			{
				stream << veinColor[posCol++] << " ";
			}
			for (j = 0; j < 6; j++)
			{
				stream << veinCameraOrientation[posOrient++] << " ";
			}
			stream << "\n";
			posVein += 2;
		}


		file.close();

	}



}
