void MainWindow::SlotDefineSelectedPoint(QAction* action)
{
	int nr = action->data().toInt();
	if (nr < 0) return;
	VWidget->SetResetCameraMode(false);
	//wybieram punkt - sprawdzam czy exists - jesli nie to zapisuje nowa pozycje
	// jesli tak - pytam czy pokazac, czy nadpisac, czy nic nie robic

	bool chgs = false;
	if (nr >= selectedPointsNr)
	{
		QMessageBox::about(0, "", "User Can only define selected points!");
	}
	else if (selectedPointExist[nr] == false)
	{
		selectedPointExist[nr] = true;
		selectedPoints[nr * 3] = selectedDoublePoint[0];
		selectedPoints[nr * 3 + 1] = selectedDoublePoint[1];
		selectedPoints[nr * 3 + 2] = selectedDoublePoint[2];
		chgs = true;
	}
	else
	{
		QMessageBox msgBox;

		QPushButton* showButton = msgBox.addButton(tr("Show Saved Position"), QMessageBox::ActionRole);;
		QPushButton* replaceButton = msgBox.addButton(tr("Replace Position"), QMessageBox::ActionRole);;
		QPushButton* clearButton = msgBox.addButton(tr("Clear Position"), QMessageBox::ActionRole);;
		QPushButton* cancelButton = msgBox.addButton(QMessageBox::Discard);
		msgBox.setText("Point already defined: ");
		msgBox.setInformativeText("Do you want to replace it?");
		msgBox.exec();

		if (msgBox.clickedButton() == showButton)
		{
			double* point = selectedPoints + nr * 3;
			SlotMoveSphereActor(point);


			/*if (data!=NULL)
			{
			double sc0[3];
			double origin[3];
			int i;
			double ppp[3];
			data->GetScale(sc0);
			data->GetOrigin(origin);
			for(i=0;i<3;i++)
			ppp[i]=(point[i]-origin[i])/sc0[i];

			if (ppp[0]<0) ppp[0]=0;			if (ppp[1]<0) ppp[1]=0;			if (ppp[2]<0) ppp[2]=0;
			if (ppp[0]>data->GetNx()-1) ppp[0]=data->GetNx()-1;			if (ppp[1]>data->GetNy()-1) ppp[1]=data->GetNy()-1;			if (ppp[2]>data->GetNz()-1) ppp[2]=data->GetNz()-1;

			TransversalView->SetSlice(ppp[0],ppp[1],point[2]);
			CoronalView->SetSlice(ppp[0],ppp[1],ppp[2]);
			SagittalView->SetSlice(ppp[0],ppp[1],ppp[2]);
			}
			VWidget->RepaintWidget();*/
		}
		else if (msgBox.clickedButton() == clearButton)
		{
			selectedPointExist[nr] = false;
			selectedPoints[nr * 3] = 0;
			selectedPoints[nr * 3 + 1] = 0;
			selectedPoints[nr * 3 + 2] = 0;
			chgs = true;
		}
		else if (msgBox.clickedButton() == replaceButton)
		{
			selectedPoints[nr * 3] = selectedDoublePoint[0];
			selectedPoints[nr * 3 + 1] = selectedDoublePoint[1];
			selectedPoints[nr * 3 + 2] = selectedDoublePoint[2];
			chgs = true;
		}
		else if (msgBox.clickedButton() == cancelButton)
		{

		}


	}
	if (chgs == true)
	{
		if (arePointsVisible)
		{
			SlotShowHidePoints(false);
			SlotShowHidePoints(true);
		}
		else
		{
			SlotShowHidePoints(true);

		}

	}
	VWidget->SetResetCameraMode(true);
}
