void	MainWindow::SlotChangeSurfaceColor()
{
	int nr = SurfaceDataList->GetNumberOfItems();

	if (nr > 0)
	{
		int j;
		ListItem<PolygonSurfaceData*>* tmpItem;

		int start = 0;
		if (surfaceActivatedFromMenuIndex != -1) { nr = surfaceActivatedFromMenuIndex + 1; start = surfaceActivatedFromMenuIndex; };

		for (j = start; j < nr; j++)
		{
			tmpItem = SurfaceDataList->GetItemAtPos(j);

			if ((tmpItem->GetData()->GetTreeItem()->isSelected() == true) || (j == surfaceActivatedFromMenuIndex))
			{
				if (currentVeinRole < 3)
				{
					double colRGB[4];

					tmpItem->GetData()->GetVProperty()->GetColor(colRGB);
					QColor col = QColor(colRGB[0] * 255, colRGB[1] * 255, colRGB[2] * 255);
					QColor col2 = QColorDialog::getColor(col);
					if (col2.isValid() == true)
					{
						colRGB[0] = col2.red() / 255.0;
						colRGB[1] = col2.green() / 255.0;
						colRGB[2] = col2.blue() / 255.0;
						colRGB[3] = tmpItem->GetData()->GetVProperty()->GetOpacity();

						tmpItem->GetData()->GetVProperty()->SetColor(colRGB);
						GUIPanel->SlotSetSurfaceColorPresentation(j, colRGB[0], colRGB[1], colRGB[2]);
						GUIPanel->SlotSetNewTreeItemColor(tmpItem->GetData()->GetTreeItem(), colRGB);
					}
				}
				else
				{
					QMessageBox msgBox;
					msgBox.setText(" Question " + veinStringTab[currentVeinRole] + " ? ");
					msgBox.setInformativeText("Do you want to update the default \n color forfor current object ? ");
					msgBox.setStandardButtons(QMessageBox::Yes | QMessageBox::No);
					msgBox.setDefaultButton(QMessageBox::Save);
					int ret = msgBox.exec();
					/*if (!(QMessageBox::question(
					this,
					tr(" Question "+veinStringTab[currentVeinRole]+"?"),
					tr("Do you want to update the default \n color forfor current object?"),
					tr("&Yes"), tr("&No"),
					QString::null, 0, 1 ) ))*/
					if (ret == QMessageBox::Yes)
					{

						double colRGB[4];

						tmpItem->GetData()->GetVProperty()->GetColor(colRGB);
						QColor col = QColor(colRGB[0] * 255, colRGB[1] * 255, colRGB[2] * 255);
						QColor col2 = QColorDialog::getColor(col);
						if (col2.isValid() == true)
						{
							colRGB[0] = col2.red() / 255.0;
							colRGB[1] = col2.green() / 255.0;
							colRGB[2] = col2.blue() / 255.0;
							colRGB[3] = tmpItem->GetData()->GetVProperty()->GetOpacity();

							tmpItem->GetData()->GetVProperty()->SetColor(colRGB);
							GUIPanel->SlotSetSurfaceColorPresentation(j, colRGB[0], colRGB[1], colRGB[2]);
							GUIPanel->SlotSetNewTreeItemColor(tmpItem->GetData()->GetTreeItem(), colRGB);
							tmpItem->GetData()->GetVProperty()->SetColor(colRGB);

							//tu robie update koloru

							veinColor[currentVeinRole * 3] = col2.red();
							veinColor[currentVeinRole * 3 + 1] = col2.green();
							veinColor[currentVeinRole * 3 + 2] = col2.blue();


							UpdateVeinDefs();
						}


					}
				}

				VWidget->RepaintWidget();

			}
		}

	}

}
//-------------------------------------
void	MainWindow::SlotUpdateVeinCameraOrientation()
{

	//currentVeinRole

	//SurfaceDataList->GetItemAtPos(nr0)->GetData()->GetPolygonSurfaceName();


	//pobrac wektor kamery
	//zrobic macierz z wektorow bazowych
	//pomnozyc macierz razy wektor bazowy
	//zamienic aktualny z tym - narazie

	double vUp[4], vUp1[4];
	double vOr[4], vOr1[4];

	vtkCamera* camera = VWidget->Renderer->GetActiveCamera();
	double* orient;
	double focalPoint[3], viewUp[3], position[3];
	//orient=camera->GetOrientation();
	camera->GetFocalPoint(focalPoint);
	camera->GetViewUp(viewUp);
	camera->GetPosition(position);

	int i;
	for (i = 0; i < 3; i++)
	{
		vUp[i] = viewUp[i];
		vOr[i] = focalPoint[i] - position[i];
	}
	vUp[3] = 1;

	normV(vOr);
	vOr[3] = 1;




	double* b = baseVectors;
	vtkMatrix4x4* matrix = vtkMatrix4x4::New();
	double m[] = { b[0], b[3], b[6], 0,
		b[1], b[4], b[7], 0,
		b[2], b[5], b[8], 0,
		0, 0, 0, 1 };
	matrix->DeepCopy(m);

	vtkMatrix4x4* matrixInv = vtkMatrix4x4::New();

	vtkMatrix4x4::Invert(matrix, matrixInv);

	matrixInv->MultiplyPoint(vUp, vUp1);
	matrixInv->MultiplyPoint(vOr, vOr1);

	if (!(QMessageBox::question(
		this,
		tr("Question"),
		tr("Do you want to update camera \n orientation  for current object?"),
		tr("&Yes"), tr("&No"),
		QString::null, 0, 1)))
	{
		for (i = 0; i < 3; i++)
		{
			veinCameraOrientation[currentVeinRole * 6 + i] = vUp1[i];
			veinCameraOrientation[currentVeinRole * 6 + i + 3] = vOr1[i];
		}
		UpdateVeinDefs();

	}


}

