void	MainWindow::SlotLoadArteryData(const QString filename)
{

	dontSendSurfaceInfoAndBlockSelection = true;
	if (!filename.isEmpty())
	{
		arteryDataName = filename;
		//SlotUpdateDefaultDir(filename);
		bool fields[15] = { false };
		arteryData->LoadState(filename, fields);
		//this->selectedPointsNr=	arteryData->GetSelectedPointsNr();

		SlotUpdateDefaultDir(filename, 1);
		if (fields[0] == true) 	GUIPanel->SlotSetArteryButtonState(0, true);//main
		if (fields[1] == true) 	GUIPanel->SlotSetArteryButtonState(4, true);//crop
		if (fields[2] == true) 	GUIPanel->SlotSetArteryButtonState(1, true);//mainmasks
		if (fields[3] == true) 	GUIPanel->SlotSetArteryButtonState(2, true);
		if (fields[4] == true) 	GUIPanel->SlotSetArteryButtonState(3, true);
		if (fields[5] == true) 	GUIPanel->SlotSetArteryButtonState(5, true);//cropmasks
		if (fields[6] == true) 	GUIPanel->SlotSetArteryButtonState(6, true);
		if (fields[7] == true) 	GUIPanel->SlotSetArteryButtonState(7, true);
		if (fields[8] == true) 	GUIPanel->SlotSetArteryButtonState(8, true);//front
		if (fields[9] == true) 	GUIPanel->SlotSetArteryButtonState(9, true);//tube
		if ((fields[10] == true) && (fields[11] == true))
		{
			GUIPanel->SlotSetArteryButtonState(10, true);// origin and vectors
			SlotSetBaseVectorsAndOrigin(arteryData->GetBaseOrigin(), arteryData->GetBaseVectors());
		}
		if (fields[11] == true)
		{
			GUIPanel->SlotSetArteryButtonState(11, true); //seed point
			SlotSetSeedPoint(arteryData->GetSeedPoint());
		}
		//if (fields[12]==true) 	GUIPanel->SlotSetArteryButtonState(0,true);

		if (arteryData->GetSeeds().count() > 0)
		{
			this->seeds = arteryData->GetSeeds();
			SlotAddLogText2("ADDED SEEDS: " + QString::number(seeds.count()));
		}
		if (arteryData->GetIgnorePoints().count() > 0)
		{
			this->ignorePoints = arteryData->GetIgnorePoints();
			SlotAddLogText2("ADDED Ignore Poitns: " + QString::number(ignorePoints.count()));
		}
		//	GUIPanel->qtab->setCurrentPage(2);



		/*ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nr = masks->GetMaskList()->GetNumberOfItems();
		if (nr > 0)
		{
			SlotClearVolMask();
			for (int i = 0; i < nr; i++)
			{
				int col = FindFirstEmptyMaskUseHist();				volMaskUseHist[col] = 1;
				ByteMask* newMask = masks->GetMaskDataAtPos(i);
				GUIPanel->SlotInsertMaskDataItem(newMask, col);
				newMask->SetColorIndex(col);
			}
		}*/

		QString ext = ".arterydata";
		QString tt;
		tt = filename;

		int extCount = ext.count();

		if (tt.mid(tt.length() - extCount, extCount) == ext)
			tt.remove(tt.length() - extCount, extCount);
		tt += ".seeds";

		bool exists = QFile::exists(tt);

		bool test = true;
		if (exists == true)
		{
			if (test == false)
			{
				QMessageBox msgBox;
				QPushButton* loadButton = msgBox.addButton(tr("Load"), QMessageBox::ActionRole);;

				QPushButton* cancelButton = msgBox.addButton(QMessageBox::Discard);
				msgBox.setText("Corresponding TSeed points exist");
				msgBox.exec();



				if (msgBox.clickedButton() == loadButton)
				{

					SlotLoadSeeds(tt);


				}
			}
			else
			{
				SlotLoadSeeds(tt);
			}



		}


		QApplication::processEvents();
		SlotMasksUpdated();
		SlotUpdateDefaultDir(filename, 1);

	}

	dontSendSurfaceInfoAndBlockSelection = false;

}
