void	MainWindow::SlotSaveArteryData()
{
	QString ext = ".arterydata";
	QString filename = QFileDialog::getSaveFileName(this, "", FileDefaultDir, "*" + ext);
	if (!filename.isEmpty())
	{
		//SlotWriteUpdatedProps();
		arteryData->SetSelectedPointsNr(this->selectedPointsNr);


		arteryData->SaveState(filename);

		if (seeds.count() == 0)
		{

			QMessageBox msgBox;
			QPushButton* addButton = msgBox.addButton(tr("yes"), QMessageBox::ActionRole);;

			QPushButton* cancelButton = msgBox.addButton(QMessageBox::Discard);
			msgBox.setText("No seeds added - add curernt point?");
			msgBox.exec();



			if (msgBox.clickedButton() == addButton)
			{
				SlotAddSeedPoint();
			}
		}
		if (seeds.count() > 0)
		{
			//zapisze seeds jako cos o takiej samej nazwie jak artery data - jesli bedize exists to mam zapytac!
			QString tt;
			tt = filename;

			int extCount = ext.count();

			if (tt.mid(tt.length() - extCount, extCount) == ext)
				tt.remove(tt.length() - extCount, extCount);
			tt += ".seeds";

			bool exists = QFile::exists(tt);
			bool allowWrite = true;
			if (exists == true)
			{

				QMessageBox msgBox;
				QPushButton* replaceButton = msgBox.addButton(tr("Overwrite"), QMessageBox::ActionRole);;

				QPushButton* cancelButton = msgBox.addButton(QMessageBox::Discard);
				msgBox.setText("TSeed points already exist overwrite");
				msgBox.exec();



				if (msgBox.clickedButton() == replaceButton)
				{

				}
				else if (msgBox.clickedButton() == cancelButton)
				{
					allowWrite = false;
				}
			}
			if (allowWrite == true)
			{
				QFile file(tt);

				bool test = false;
				unsigned char xx[3] = { 0 };
				int count;
				double p[3];
				if (file.open(QIODevice::WriteOnly))
				{
					QTextStream stream(&file);
					for (int i = 0; i < seeds.count(); i++)
					{
						stream << seeds.at(i).x() << "\t";
						stream << seeds.at(i).y() << "\t";
						stream << seeds.at(i).z() << "\n";

					}

				}
				file.close();
			}



		}


		SlotUpdateDefaultDir(filename, 1);
	}

}
