void	MainWindow::SlotArteryClearDataButtonClicked(int nr)
{
	if ((nr < 13) && (MainListItem != NULL))
	{
		//	GUIPanel->SlotSetArteryButtonState(nr,true);
		bool test = false;
		int i;

		DataSet* mainData = MainListItem->GetData();

		switch (nr)
		{
		case 0:

			arteryData->ClearMainData(0);
			break;
		case 1:
			arteryData->ClearMainDataMask(0, 0);// (nr danych,nrmaski,maindataset,nrmaski w orgin bytemaskdata);
			break;
		case 2:
			arteryData->ClearMainDataMask(0, 1);
			break;
		case 3:
			arteryData->ClearMainDataMask(0, 2);
			break;
		case 4:
			arteryData->ClearMainData(1);
			break;
		case 5:
			arteryData->ClearMainDataMask(1, 0);
			break;
		case 6:
			arteryData->ClearMainDataMask(1, 1);
			break;
		case 7:
			arteryData->ClearMainDataMask(1, 2);
			break;

		case 8:
			arteryData->ClearFrontSurfaces();
			break;
		case 9:
			arteryData->ClearTubeSurfaces();
			break;

		case 10:
			//base vectors
		{
			baseOrigin[0] = 0; baseOrigin[1] = 0;	baseOrigin[2] = 0;
			baseVectors[0] = 1;	baseVectors[1] = 0;	baseVectors[2] = 0;
			baseVectors[3] = 0;	baseVectors[4] = 1;	baseVectors[5] = 0;
			baseVectors[6] = 0;	baseVectors[7] = 0;	baseVectors[8] = 1;
		}

		//if (data!=NULL)
		{
			arteryData->SetOriginAndBaseVectors(baseOrigin, baseVectors);
			QString text = "BaseOrigin: (";
			for (i = 0; i < 3; i++)
			{
				text += QString::number(baseOrigin[i]);
				if (i < 2) text += ", "; else text += ") ";
			}
			text += " Base Vectors: ";
			for (i = 0; i < 9; i++)
			{
				if (i % 3 == 0) text += "(";
				text += QString::number(baseVectors[i]);
				if ((i % 3) != 2) text += ", "; else text += ") ";
			}
			emit SendMessage(text);
			test = true;
		}




		break;
		case 11:
			// seed
			if (data != NULL)
			{
				arteryData->ClearSeeds();
				seeds.clear();
				seedPoint[0] = 0; seedPoint[1] = 0; seedPoint[2] = 0;
				test = true;
			}

			break;
		case 12:
			// seed
			if (data != NULL)
			{
				arteryData->ClearIgnorePoints();
				test = true;

			}

			break;

		}

		//if (nr < 10) 
		GUIPanel->SlotSetArteryButtonState(nr, false);
		emit SendMessage("cleared");


	}
}
