void	MainWindow::ArteryDataButtonClicked(int nr, ListItem<DataSet*>* mainListItem)
{

	RawDataSet* _data = mainListItem->GetData()->GetRawData();


	if ((nr < 13))
	{
		//	GUIPanel->SlotSetArteryButtonState(nr,true);
		bool test = false;
		int i;

		DataSet* mainData = NULL;
		if (mainListItem != NULL)
			mainData = mainListItem->GetData();

		switch (nr)
		{
		case 0:
			if (mainListItem != NULL)
				test = arteryData->SetMainData(0, mainData);
			break;
		case 1:
			if ((arteryData->GetMainRawData(0) != NULL) && (mainListItem != NULL) && (_data != NULL) && (_data->CompareWithOtherDataSet(arteryData->GetMainRawData(0)->GetRawData())) && (mainData->GetMasks()->GetCurrentMask() != NULL))	test = arteryData->SetMainDataMask(0, 0, mainData, mainData->GetMasks()->GetCurrentMaskNumber());// (nr danych,nrmaski,maindataset,nrmaski w orgin bytemaskdata);
			break;
		case 2:
			//if  ((data!=NULL)&&(data==arteryData->GetMainRawData(0)))	test=arteryData->SetMainDataMask(0,1,mainData,mainData->GetMasks()->GetCurrentMaskNumber());
			if ((arteryData->GetMainRawData(0) != NULL) && (mainListItem != NULL) && (_data != NULL) && (_data->CompareWithOtherDataSet(arteryData->GetMainRawData(0)->GetRawData())) && (mainData->GetMasks()->GetCurrentMask() != NULL))	test = arteryData->SetMainDataMask(0, 1, mainData, mainData->GetMasks()->GetCurrentMaskNumber());
			break;
		case 3:
			if ((arteryData->GetMainRawData(0) != NULL) && (mainListItem != NULL) && (_data != NULL) && (_data->CompareWithOtherDataSet(arteryData->GetMainRawData(0)->GetRawData())) && (mainData->GetMasks()->GetCurrentMask() != NULL))		test = arteryData->SetMainDataMask(0, 2, mainData, mainData->GetMasks()->GetCurrentMaskNumber());
			break;
		case 4:
			test = arteryData->SetMainData(1, mainData);
			break;
		case 5:
			if ((arteryData->GetMainRawData(1) != NULL) && (mainListItem != NULL) && (_data != NULL) && (_data->CompareWithOtherDataSet(arteryData->GetMainRawData(1)->GetRawData())) && (mainData->GetMasks()->GetCurrentMask() != NULL))		test = arteryData->SetMainDataMask(1, 0, mainData, mainData->GetMasks()->GetCurrentMaskNumber());
			break;
		case 6:
			if ((arteryData->GetMainRawData(1) != NULL) && (mainListItem != NULL) && (_data != NULL) && (_data->CompareWithOtherDataSet(arteryData->GetMainRawData(1)->GetRawData())) && (mainData->GetMasks()->GetCurrentMask() != NULL))		test = arteryData->SetMainDataMask(1, 1, mainData, mainData->GetMasks()->GetCurrentMaskNumber());
			break;
		case 7:
			if ((arteryData->GetMainRawData(1) != NULL) && (mainListItem != NULL) && (_data != NULL) && (_data->CompareWithOtherDataSet(arteryData->GetMainRawData(1)->GetRawData())) && (mainData->GetMasks()->GetCurrentMask() != NULL))		test = arteryData->SetMainDataMask(1, 2, mainData, mainData->GetMasks()->GetCurrentMaskNumber());
			break;

		case 8:
			test = arteryData->SetFrontSurfaces(SurfaceDataList);
			break;
		case 9:
			test = arteryData->SetTubeSurfaces(SurfaceDataList);
			break;

		case 10:
			//base vectors
			if (_data != NULL)
			{
				arteryData->SetOriginAndBaseVectors(baseOrigin, baseVectors);
				QString text = "BaseOrigin: (";
				for (i = 0; i < 3; i++)
				{
					text += QString::number(baseOrigin[i]);
					if (i < 2) text += ", "; else text += ") ";
				}
				text += " Base Vectors: ";
				for (i = 0; i < 9; i++)
				{
					if (i % 3 == 0) text += "(";
					text += QString::number(baseVectors[i]);
					if ((i % 3) != 2) text += ", "; else text += ") ";
				}
				emit SendMessage(text);
				test = true;
			}




			break;
		case 11:
			// seed
			if (_data != NULL)
			{

				if (seeds.count() == 0)
				{
					double* seedP = selectedDoublePoint;
					//SlotSetCurrentPointAndText(seedP,"");
					arteryData->SetSeedPoint(selectedDoublePoint);
					this->SlotSetSeedPoint(seedP);
					emit SendMessage("SeedPoint: (" + QString::number(seedP[0]) + " " + QString::number(seedP[1]) + " " + QString::number(seedP[2]) + ")");
					GUIPanel->seedLabel[0]->setText(QString::number(seedP[0]));
					GUIPanel->seedLabel[1]->setText(QString::number(seedP[1]));
					GUIPanel->seedLabel[2]->setText(QString::number(seedP[2]));
					test = true;
				}
				else
				{
					arteryData->SetSeeds(seeds);
					test = true;
				}

			}

			break;

		case 12:
			// seed
			if (_data != NULL)
			{

				if (ignorePoints.count() != 0)
				{
					arteryData->SetIgnorePoints(ignorePoints);
					test = true;
				}

			}

			break;


		}
		if (test == true)
		{
			//if (nr < 10)
			GUIPanel->SlotSetArteryButtonState(nr, true);

			//jesli zmienilem dane to przy okazji ustawie tez maske moze zapomnialem?
			if ((nr == 0) || (nr == 4))
			{
				SlotArteryDataButtonClicked(nr + 1);
			}


		}
		else
		{
			//if (nr < 10) 	
			GUIPanel->SlotSetArteryButtonState(nr, false);
			emit SendMessage("Error");
		}



	}

}
