//--------------
void	MainWindow::SlotSetSurfaceRole(int ii)
{
	//co chce zmienic:
	//gdy wybiore powierzchnie to - zmieniam jej kolor, a jesli jakas
	//wczesniej byla na taki kolor to ustalam na default
	//powinno dzialac tylko dla rurek


	//bedzie dzis update:
	//opcja clear - dodam
	//dodam M
	// sprawdzam czy jakas juz ma taka role jesli tak pytam czy add/replace
	//

	int nr = SurfaceDataList->GetNumberOfItems();

	if (nr > 0)
	{
		int j;
		ListItem<PolygonSurfaceData*>* tmpItem;




		int countx = 0;
		//sprawdzam czy inna ma taka role, jesli tak to ile
		bool alreadySet = false;

		//int nrClicked=
		{

			for (j = 0; j < nr; j++)
			{
				int index;
				tmpItem = SurfaceDataList->GetItemAtPos(j);
				index = tmpItem->GetData()->GetRoleIndex();

				//if((tmpItem->GetData()->GetTreeItem()->isSelected()==true)&&(index!=ii))
				if ((tmpItem == SurfaceDataList->GetItemAtPos(surfaceActivatedFromMenuIndex)) && (index != ii))

				{
					if (index > 2) alreadySet = true;
				}

				//	if ((ii>0)&&(index==ii)&&(tmpItem->GetData()->GetTreeItem()->isSelected()==false))
				if ((ii > 0) && (index == ii) && (tmpItem != SurfaceDataList->GetItemAtPos(surfaceActivatedFromMenuIndex)))
				{
					countx++;
				}


			}

		}

		//count x >0 dodac opcje add/replace


		QMessageBox msgBox;

		QPushButton* addButton = NULL;
		QPushButton* replaceAllButton = NULL;
		QPushButton* replaceCurrentButton = NULL;
		QPushButton* cancelButton = NULL;

		bool noExec = true;

		if ((countx > 0))
		{
			addButton = msgBox.addButton(tr("Add Current Tube"), QMessageBox::ActionRole);
			replaceAllButton = msgBox.addButton(tr("Replace"), QMessageBox::ActionRole);
			cancelButton = msgBox.addButton(QMessageBox::Discard);
			msgBox.setText("There are already" + QString::number(countx) + QString(" tubes with selected role"));
			msgBox.setInformativeText("Do you want to replace them?");
			msgBox.exec();
			noExec = false;
		}
		else if (alreadySet == true)
		{
			replaceCurrentButton = msgBox.addButton(tr("Replace"), QMessageBox::ActionRole);
			cancelButton = msgBox.addButton(QMessageBox::Discard);
			msgBox.setText("Current tube already has a role");
			msgBox.setInformativeText("Do you want to replace it?");
			msgBox.exec();
			noExec = false;
		}


		int selCount = 0;
		for (j = 0; j < nr; j++)
		{
			bool sel = SurfaceDataList->GetItemAtPos(j)->GetData()->GetTreeItem()->isSelected();
			if (sel == true) selCount++;
		}


		if (((msgBox.clickedButton() == addButton) || (msgBox.clickedButton() == replaceAllButton) || (msgBox.clickedButton() == replaceCurrentButton) || (countx == 0)))
		{
			//add
			if ((msgBox.clickedButton() != cancelButton) || ((countx == 0) && (noExec == true)))
			{
				if (msgBox.clickedButton() == replaceAllButton)
				{
					//czyszcze
					if (ii > 2)
						for (j = 0; j < nr; j++)
						{
							int index;
							tmpItem = SurfaceDataList->GetItemAtPos(j);
							index = tmpItem->GetData()->GetRoleIndex();
							//bool isSel = tmpItem->GetData()->GetTreeItem()->isSelected();
						//	if (isSel==true)
							{
								if (index == ii)

								{
									/*int nrrr;
									if(tmpItem->GetData()->GetPolygonSurfaceName().indexOf("*/
									int roleX = 2;//default rurka
									tmpItem->GetData()->SetRoleIndex(roleX);
									double r = this->veinColor[roleX * 3] / 255.0;
									double g = this->veinColor[roleX * 3 + 1] / 255.0;
									double b = this->veinColor[roleX * 3 + 2] / 255.0;

									tmpItem->GetData()->GetVProperty()->SetColor(r, g, b);
								}

							}
						}

				}

				//ustawiam role dla aktywnej powierzchni
				for (j = 0; j < nr; j++)
				{
					tmpItem = SurfaceDataList->GetItemAtPos(j);
					//if(tmpItem->GetData()->GetTreeItem()->isSelected()==true)
					bool isSel = tmpItem->GetData()->GetTreeItem()->isSelected();

					bool test = false;
					if (selCount > 1)
					{
						test = isSel == true;
					}
					else
					{
						test = tmpItem == SurfaceDataList->GetItemAtPos(surfaceActivatedFromMenuIndex);
					}
					//if (isSel == true)
					//if (tmpItem == SurfaceDataList->GetItemAtPos(surfaceActivatedFromMenuIndex))
					if (test == true)
					{

						tmpItem->GetData()->SetRoleIndex(ii);
						double r = this->veinColor[(ii) * 3] / 255.0;
						double g = this->veinColor[(ii) * 3 + 1] / 255.0;
						double b = this->veinColor[(ii) * 3 + 2] / 255.0;
						tmpItem->GetData()->GetVProperty()->SetColor(r, g, b);

					}
				}
			}
		} //else if (msgBox.clickedButton() == replaceButton)
		else
		{
			// do nothing
		}

		delete addButton;
		delete replaceAllButton;
		delete replaceCurrentButton;
		delete cancelButton;





		//czyszcze jesli inna ma taka role



		//for	(j=0;j<nr;j++)
		//{
		//	tmpItem=SurfaceDataList->GetItemAtPos(j);
		//	if(tmpItem->GetData()->GetTreeItem()->isSelected()==true)
		//	{
		//		
		//			tmpItem->GetData()->SetRoleIndex(ii);
		//			double r=this->veinColor[(ii)*3]/255.0;
		//			double g=this->veinColor[(ii)*3+1]/255.0;
		//			double b=this->veinColor[(ii)*3+2]/255.0;

		//			tmpItem->GetData()->GetVProperty()->SetColor(r,g,b);
		//		
		//	}
		//}
		VWidget->RepaintWidget();
	}
}
