QString	MainWindow::GrabVeinSurfaces()
{
	int nr = SurfaceDataList->GetNumberOfItems();
	QString resutlsDirName = "results";
	QString mainArteryDataDir = arteryData->GetMainDataDir();
	int windowSize = 512;
	//QMessageBox::about( 0,"",mainArteryDataDir	);
	if ((nr > 0) && (!mainArteryDataDir.isEmpty()))
	{
		int i, j;
		int index;
		ListItem<PolygonSurfaceData*>* tmpItem;
		QString tmpName;

		//pobiore z arterydata odpowiedni katalog do zapisu wynikow


		QDir rDir(mainArteryDataDir);
		rDir.mkdir(resutlsDirName);
		bool test = rDir.cd(resutlsDirName);
		// probuje przejsc do zalozonego katalogu - jesli sie udalo moge isc dalej
		if (test == true)
		{
			QString dirPath = rDir.path();
			//QMessageBox::about( 0,"",dirPath	);




			//resize screen
			VWidget->setParent(0);// , QPoint(0, 0));
			VWidget->show();
			VWidget->resize(windowSize + 2, windowSize + 2);
			VWidget->RepaintWidget();
			VWidget->raise();
			//SlotSet3DWindowSize(windowSize);
			//{

			//	QWidgetList  *list = QApplication::allWidgets();
			//	QWidgetListIt it( *list );         // iterate over the widgets
			//	QWidget * w;
			//	while ( (w=it.current()) != 0 ) {  // for each widget...
			//		++it;
			//		w->update();
			//	}
			//	delete list;                      // delete the list, not the widgets

			//}
			//zapamietaj stan wsyzstkich
			//schowaj wszystkie
			double* opacityTab = new double[nr];
			for (j = 0; j < nr; j++)
			{
				tmpItem = SurfaceDataList->GetItemAtPos(j);
				opacityTab[j] = tmpItem->GetData()->GetVProperty()->GetOpacity();
				tmpItem->GetData()->GetVProperty()->SetOpacity(0);
			}


			for (i = 3; i < nrOfPossibleVeins + 3; i++)
			{
				for (j = 0; j < nr; j++)
				{
					tmpItem = SurfaceDataList->GetItemAtPos(j);
					index = tmpItem->GetData()->GetRoleIndex();

					if (index == i)
					{
						QDir dir;
						QString subdir = dirPath + "/" + veinStringTab[index];
						if (!dir.exists(subdir))
						{
							dir.mkdir(subdir);
						}
						//pokaz tylko i
						tmpItem->GetData()->GetVProperty()->SetOpacity(opacityTab[j]);
						//reset kamery wzgledem roleindexu
						currentVeinRole = index;
						SlotApplyVeinCameraOrientation();
						//zapisz 
						//tmpName=dirPath+"/"+veinStringTab[index]+"_custom"+".png";
						tmpName = subdir + "/" + "_custom" + ".png";
						//QMessageBox::about( 0,"",tmpName	);
						Grab3DWindow(tmpName);
						//schowaj i

						if (grabSixSides == true)
						{
							for (j = 0; j < 6; j++)
							{
								SlotSetCameraSetting(j);
								//tmpName=dirPath+"/"+veinStringTab[index]+"_"+QString::number(j)+".png";
								tmpName = subdir + "/" + "_" + QString::number(j) + ".png";
								//QMessageBox::about( 0,"",tmpName	);
								Grab3DWindow(tmpName);

							}
						}
						tmpItem->GetData()->GetVProperty()->SetOpacity(0);


						break;
					}
				}
			}
			//pokaz wszytkie

			for (j = 0; j < nr; j++)
			{
				tmpItem = SurfaceDataList->GetItemAtPos(j);
				tmpItem->GetData()->GetVProperty()->SetOpacity(opacityTab[j]);
			}
			delete[]opacityTab;
			SlotSetNewLayout(ActualLayout);
			VWidget->Renderer->ResetCamera();

			return dirPath;
		}
		return QString("");
	}
	return QString("");
}

//-----------------------------
void MainWindow::SlotGenerateCenteredPoints(int mode)
{

	int i, j, k;
	int pp[3];
	int ppos[3];
	vtkPolyData* pData;
	vtkPoints* pts;
	double ends[18];
	double tol = 1e-6;
	int pos, rolePos;
	int ind[3];
	if (mode == 0)
	{
		for (i = 0; i < centeredPointsNr; i++)
		{
			rolePos = centeredPointsDefs[i];
			pos = GetPositionOfRoleSurface(rolePos, SurfaceDataList);
			if (pos != -1)//nie zostala taka zdefiniowana
			{
				pData = SurfaceDataList->GetItemAtPos(pos)->GetData()->GetVPolyData();
				pts = pData->GetPoints();
				double point[3] = { 0, 0, 0 };
				double p[3];
				int nrr = pts->GetNumberOfPoints();
				if (nrr > 0)
				{
					for (j = 0; j < nrr; j++)
					{
						pts->GetPoint(j, p);
						point[0] += p[0];	point[1] += p[1];	point[2] += p[2];
					}

					for (j = 0; j < 3; j++)
						centeredPoints[i * 3 + j] = point[j] / (double)nrr;


					centeredPointExist[i] = true;
				}
			}
		}
	}
	else if (mode == 1)
	{
		for (i = 0; i < centeredPointsNr; i++)
		{
			rolePos = centeredPointsDefs[i];
			pos = GetPositionOfRoleSurface(rolePos, SurfaceDataList);
			if (pos != -1)//nie zostala taka zdefiniowana
			{
				pData = SurfaceDataList->GetItemAtPos(pos)->GetData()->GetVPolyData();

				CalculateMeshCenterOfMass(pData, centeredPoints + i * 3);
				centeredPointExist[i] = true;
			}
		}

	}



}
