//--------------------------------------------
void MainWindow::SlotSavePolyDataPts()
{
	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{

		QString fn = QFileDialog::getExistingDirectory(this, "", FileDefaultDir);
		if (fn.isEmpty()) return;

		SlotUpdateDefaultDir(fn);

		int Nr = SurfaceDataList->GetNumberOfItems();
		int i;
		PolygonSurfaceData* Data;
		QString name;

		for (i = 0; i < Nr; i++)
		{
			Data = SurfaceDataList->GetItemAtPos(i)->GetData();
			if (Data->GetTreeItem()->isSelected() == true)
			{
				name = fn + "/" + Data->GetPolygonSurfaceName() + ".pts";

				QFile file(name);
				if (file.open(QIODevice::WriteOnly))
				{

					QTextStream stream(&file);


					vtkPoints* pts = Data->GetVPolyData()->GetPoints();

					int nrPts = pts->GetNumberOfPoints();

					double point[3];
					stream << nrPts << endl;

					for (int j = 0; j < nrPts; j++)
					{

						pts->GetPoint(j, point);
						stream << point[0] << "\t" << point[1] << "\t" << point[2] << endl;
					}



					file.close();
				}
			}
		}
	}
}
