int MainWindow::GetPositionOfRoleSurface(int role, LinkedList<PolygonSurfaceData*>* sList)
{

	ListItem<PolygonSurfaceData*>* tmpItem;
	int index;
	int i;
	if (sList == NULL) return -1;
	int nr = sList->GetNumberOfItems();
	if (nr == 0)return -1;
	for (i = 0; i < nr; i++)
	{
		tmpItem = sList->GetItemAtPos(i);
		index = tmpItem->GetData()->GetRoleIndex();
		if (index == role)
		{
			return i;
		}
	}

	return -1;

}
//---------------------
void MainWindow::SlotGetAngleParamsFromTwoPointSets(vtkPolyData* pDataA, vtkPolyData* pDataB, double* baseVectors, double* dirCosA, double* dirCosB, double* li1, double* li2, double& angle, bool fit, QString name, bool genSurfaces, bool commonCenter)
{
	// zbieram punkty szkieletu 1 i punkty szkieletu 2
	if ((pDataA == NULL) || (pDataB == NULL))
	{
		emit SendMessage("bad input data");
	}
	vtkPoints* ptsA = SProcessing->GetSkeletalPoints(pDataA);
	vtkPoints* ptsB = SProcessing->GetSkeletalPoints(pDataB);
	double p1A[3], p2A[3], p1B[3], p2B[3];
	ptsA->GetPoint(0, p1A);
	ptsA->GetPoint(ptsA->GetNumberOfPoints() - 1, p2A);
	ptsB->GetPoint(0, p1B);
	ptsB->GetPoint(ptsB->GetNumberOfPoints() - 1, p2B);
	bool swap[2];
	double lA[3], lB[3];
	double lenA, lenB;
	double testAngle;

	int i;
	OrientTwoVectorsUsingStartingClosestPoint(p1A, p1B, p2A, p2B, lA, lB, swap);
	lenA = sqrt(lA[0] * lA[0] + lA[1] * lA[1] + lA[2] * lA[2]);
	lenB = sqrt(lB[0] * lB[0] + lB[1] * lB[1] + lB[2] * lB[2]);

	if (lenA > 0) { lA[0] /= lenA;	lA[1] /= lenA;	lA[2] /= lenA; }
	if (lenB > 0) { lB[0] /= lenB;	lB[1] /= lenB;	lB[2] /= lenB; }

	if (fit == true)
	{
		double lineA[6] = { 0 };
		double lineB[6] = { 0 };


		SlotGetFittedLineParams1(lineA, ptsA);
		SlotGetFittedLineParams1(lineB, ptsB);

		//fitowanie olewa kierunek punktow wiec trzeba bedzie odwracac 
		testAngle = acos(DOT(lineA, lA)) * to_deg;
		if (testAngle > 90) { for (i = 0; i < 3; i++)lineA[i] *= -1; }
		testAngle = acos(DOT(lineB, lB)) * to_deg;
		if (testAngle > 90) { for (i = 0; i < 3; i++)lineB[i] *= -1; }


		//fitowane wektorki o dlugosci jak oryginaly i zaczepione w punktach oryginalnych
		for (i = 0; i < 3; i++) { p2A[i] = p1A[i] + lenA * lineA[i]; }
		for (i = 0; i < 3; i++) { p2B[i] = p1B[i] + lenB * lineB[i]; }

		OrientTwoVectorsUsingStartingClosestPoint(p1A, p1B, p2A, p2B, lA, lB, swap);
		lenA = sqrt(lA[0] * lA[0] + lA[1] * lA[1] + lA[2] * lA[2]);
		lenB = sqrt(lB[0] * lB[0] + lB[1] * lB[1] + lB[2] * lB[2]);

		if (lenA > 0) { lA[0] /= lenA;	lA[1] /= lenA;	lA[2] /= lenA; }
		if (lenB > 0) { lB[0] /= lenB;	lB[1] /= lenB;	lB[2] /= lenB; }

	}



	//---------------tymczasowe wektorki
	if (genSurfaces == true)
	{
		if (commonCenter == true)
		{
			//policze srodek z p1A i p1B - wezme na pol i o takie delty przesune oba wektory
			double cV[3], dA[3], dB[3];
			for (i = 0; i < 3; i++) cV[i] = (p1A[i] + p1B[i]) / 2;
			for (i = 0; i < 3; i++)
			{
				dA[i] = cV[i] - p1A[i];
				dB[i] = cV[i] - p1B[i];
			}
			for (i = 0; i < 3; i++)
			{
				p1A[i] += dA[i]; p2A[i] += dA[i];
				p1B[i] += dB[i]; p2B[i] += dB[i];

			}


		}
		vtkPoints* pts = vtkPoints::New();
		pts->InsertNextPoint(p1A); pts->InsertNextPoint(p2A);
		pts->InsertNextPoint(p1B); pts->InsertNextPoint(p2B);

		vtkCellArray* newPolys = vtkCellArray::New();
		vtkIdType newCellPts[2];

		newCellPts[0] = 0;	newCellPts[1] = 1;
		newPolys->InsertNextCell(2, newCellPts);
		newCellPts[0] = 2;	newCellPts[1] = 3;
		newPolys->InsertNextCell(2, newCellPts);


		vtkPolyData* output = vtkPolyData::New();
		output->SetPoints(pts);
		output->SetLines(newPolys);
		output->BuildCells();
		output->BuildLinks();
		//output->Update();

		PolygonSurfaceData* o1 = new PolygonSurfaceData(output, VWidget);
		o1->SetPolygonSurfaceDataSetName(name);
		o1->GetVProperty()->SetColor(0, 0, 0);
		o1->ComputeGeometricOrigin();
		o1->setTmpData(true);
		o1->SetGroupName("tube_lines");
		SlotInsertPolygonSurfaceAtTheAnd(o1);
	}
	//------------koniec wektorkow

	//double *baseVectors,double *dirCos1,double *dirCos2,double &angle

	if ((baseVectors != NULL) && (dirCosA != NULL) && (dirCosB != NULL))
	{
		for (i = 0; i < 3; i++)
		{	//tak naprawde licze katy a nie cosinusy - jak bedzie trzeba to zmienie
			dirCosA[i] = GetAngleBetweenNormalizedVectors(lA, baseVectors + i * 3) * to_deg;
			dirCosB[i] = GetAngleBetweenNormalizedVectors(lB, baseVectors + i * 3) * to_deg;
		}

	}
	angle = GetAngleBetweenNormalizedVectors(lA, lB) * to_deg;


	if ((li1 != NULL) && (li2 != NULL))
	{
		for (i = 0; i < 3; i++)
		{
			li1[i] = lA[i];
			li2[i] = lB[i];
		}
	}





}
