void MainWindow::SlotStartRecordVideo(int mode)
{
	//this->videoTools->InitVideoRecord();
	//connect this - sendframe videotoolsrecordframe

	int pos = GUIPanel->fpsComboBox->currentIndex();
	int fps = GUIPanel->fpsComboBox->itemText(pos).toInt();
	int framerate = fps;
	if (videoTools->isRecordInProgress() == false)
	{
		int ww = 0;
		int hh = 0;
		QString name = "";
		AVCodecID codec = AV_CODEC_ID_MPEG4;//AV_CODEC_ID_H264 ;//
		//AVCodecID codec=AV_CODEC_ID_H263 ;

		int bitrate = 100000000;



		//w zaleznosci od mode przypne timera do generowania qimage z odpowiedniego obiektu

		if (GrabWindowPath.isEmpty())
		{
			QString fn = QFileDialog::getExistingDirectory(this, "", FileDefaultDir);
			if (fn.isEmpty()) return;
			GrabWindowPath = fn + "/";
		}



		GrabWindowName = "_" + GetTimeDateName();
		//QString name;
		PictureIndex++;
		name = GrabWindowPath + GrabWindowName + ".avi";
		QWidget* grabWidget = this->getSelectedGrabWidget();

		SlotAddLogText("Recording " + GrabWindowName + ".avi" + " animation");

		if ((grabWidget != NULL))
		{


			videoTools->initVariablesForRecord(name, grabWidget->width(), grabWidget->height(), codec, bitrate, framerate);

			grabTimer->setInterval(1000.0 / framerate);
			this->grabTimer->start(false);
		}
		else
		{
			SendMessage("Problem with selected widget");
		}

	}
	else
	{
		grabTimer->setInterval(1000.0 / framerate);
		this->grabTimer->start(false);
	}




	//videotoolsstartrecord = startrecordtimer
}
