void MainWindow::SlotStopRecordVideo()
{
	//stop timer
	//if videotimeris running
	if (videoTools->isRecordInProgress() == true)
	{
		SlotAddLogText("Recording ...stopped");
		grabTimer->stop();
		videoTools->freeVariablesForRecord();
	}
	//videoTools->stopRecord
}
//------------------------------------------
void MainWindow::SlotPlayLastRecordedVideo()
{
	if (ffplayexePath.isEmpty())
	{
		SlotAddLogText("ffplay.exe not found");
		return;
	}
	QDir d;
	d.setPath(GrabWindowPath);
	QStringList filters;
	filters << "*.avi";


	//d.setFilter("*.avi");
	d.setNameFilters(filters);
	d.setSorting(QDir::Time);
	QFileInfoList list = d.entryInfoList();
	//QFileInfoListIterator it2( list.begin() );

	QListIterator<QFileInfo> it2(list);
	QFileInfo fi;

	while (it2.hasNext())
	{
		//QProcess pr(this);
		//fi=*it2;
		fi = it2.next();
		QString nn = GrabWindowPath + "/" + fi.fileName();
		QStringList arguments;
		//arguments << " -i " << nn << " -fs";
		arguments << "-fs" << nn;
		process->start(ffplayexePath, arguments);
		break;
	}
}
//------------------------------------------
void  MainWindow::SlotPauseRecordVideo()
{
	if (videoTools->isRecordInProgress() == true)
		grabTimer->stop();
}
//------------------------------------------
void MainWindow::SlotVideoModeChanged(int nr)
{

	bool states[11];
	int i;
	for (i = 0; i < 11; i++)
	{
		states[i] = GUIPanel->videoAction[i]->isChecked();
	}

	int mode = -1;
	for (i = 5; i < 11; i++)
	{
		if (states[i] == true)
		{
			mode = i - 4;
			break;
		}
	}

	recordMode = mode;

	if (states[0] == true)
	{
		//start record


		if (mode < 0)
		{
			GUIPanel->videoAction[1]->setChecked(false);

		}
		else
		{
			SlotStartRecordVideo(mode);
		}
	}
	else if (states[1] == true)
	{
		//stop record
		SlotStopRecordVideo();
		if (states[4] == true) SlotPlayLastRecordedVideo();

	}
	else if (states[2] == true)
	{
		SlotPauseRecordVideo();
		//pause record


	}
	else if (states[3] == true)
	{
		//ewentualnie stop record

		SlotPlayLastRecordedVideo();

	}


}
