void	MainWindow::SlotForSignalSendShape(vtkPoints* pts)
{
	if ((pts != NULL) && (pts->GetNumberOfPoints() > 0) && (GUIPanel->segAction[8]->isChecked()))
	{
		vtkCellArray* newPolys = vtkCellArray::New();
		vtkIdType newCellPts[2];
		vtkIdType ID;

		int i;
		int nr = pts->GetNumberOfPoints();
		for (i = 0; i < nr - 1; i++)
		{
			newCellPts[0] = i;
			newCellPts[1] = (i + 1);//%(nr-1);
			newPolys->InsertNextCell(2, newCellPts);
		}

		vtkPoints* newPts = vtkPoints::New();
		newPts->DeepCopy(pts);
		vtkPolyData* output = vtkPolyData::New();
		output->SetPoints(newPts);
		output->SetLines(newPolys);
		output->BuildCells();
		//output->Update();

		PolygonSurfaceData* o1 = new PolygonSurfaceData(output, VWidget);
		o1->SetPolygonSurfaceDataSetName("Shape");
		o1->GetVActor()->GetProperty()->SetColor(0, 0, 0);
		o1->GetVActor()->GetProperty()->SetRepresentationToWireframe();
		o1->ComputeGeometricOrigin();
		o1->setTmpData(true);
		SlotInsertPolygonSurface(o1);

		VWidget->SlotResetCamera();
		//VWidget->RepaintWidget();
	}


}
