void	MainWindow::SlotShowTmpSurfaces()
{
	int j;
	int nr = SurfaceDataList->GetNumberOfItems();
	ListItem<PolygonSurfaceData*>* tmpItem;
	for (j = 0; j < nr; j++)
	{
		tmpItem = SurfaceDataList->GetItemAtPos(j);
		if (tmpItem->GetData()->isTmpData() == true)
		{
			tmpItem->GetData()->GetVProperty()->SetOpacity(1.0);
		}
	}
	VWidget->SlotResetCube();
	VWidget->RepaintWidget();
}
//---------------------
void	MainWindow::SlotHideTmpSurfaces()
{
	int j;
	int nr = SurfaceDataList->GetNumberOfItems();
	ListItem<PolygonSurfaceData*>* tmpItem;
	for (j = 0; j < nr; j++)
	{
		tmpItem = SurfaceDataList->GetItemAtPos(j);
		if (tmpItem->GetData()->isTmpData() == true)
		{
			tmpItem->GetData()->GetVProperty()->SetOpacity(0.0);
		}
	}
	VWidget->SlotResetCube();
	VWidget->RepaintWidget();
}
