void	MainWindow::SlotSetBackgroundMode(int nr)
{
	if (nr < 3)
	{
		VWidget->SlotSetBackgroundMode(nr);
	}
	else if (nr == 5)
	{
		//image zaslepka

		//start

		if (camera != NULL)
		{

		}

		VWidget->SlotSetBackgroundMode(5);



	}
	else if (nr == 3)
	{
		double colRGB[3];
		VWidget->getBackgroundColor(colRGB);
		QColor col(colRGB[0] * 255, colRGB[1] * 255, colRGB[2] * 255);
		//QColor col(;
		QColor col2 = QColorDialog::getColor(col, this, "Select Background Color");
		if (col2.isValid() == true)
		{
			colRGB[0] = col2.red() / 255.0;
			colRGB[1] = col2.green() / 255.0;
			colRGB[2] = col2.blue() / 255.0;


			QSettings sett(configIniName, QSettings::IniFormat);
			QString txt;
			sett.beginGroup("3DView");



			for (int i = 0; i < 3; i++)
			{
				bacground3DCol[i] = colRGB[i];
			}
			sett.setValue("Background3DRed", (int)(col2.red()));
			sett.setValue("Background3DGreen", (int)(col2.green()));
			sett.setValue("Background3DBlue", (int)(col2.blue()));

			sett.endGroup();
			VWidget->setBackgroundColor(colRGB);
		}
		VWidget->SlotSetBackgroundMode(0);
	}
	else if (nr == 4)
	{
		{
			double colRGB[3];
			VWidget->getGradientBackgroundColor1(colRGB);
			QColor col(colRGB[0] * 255, colRGB[1] * 255, colRGB[2] * 255);
			//QColor col(;
			QColor col2 = QColorDialog::getColor(col, this, "Select Background Gradient First Color");
			if (col2.isValid() == true)
			{
				colRGB[0] = col2.red() / 255.0;
				colRGB[1] = col2.green() / 255.0;
				colRGB[2] = col2.blue() / 255.0;

				VWidget->setGradientBackgroundColor1(colRGB);
			}
		}
		{
			double colRGB[3];
			VWidget->getGradientBackgroundColor2(colRGB);
			QColor col(colRGB[0] * 255, colRGB[1] * 255, colRGB[2] * 255);
			//QColor col(;
			QColor col2 = QColorDialog::getColor(col, this, "Select Background Gradient Second Color");
			if (col2.isValid() == true)
			{
				colRGB[0] = col2.red() / 255.0;
				colRGB[1] = col2.green() / 255.0;
				colRGB[2] = col2.blue() / 255.0;

				VWidget->setGradientBackgroundColor2(colRGB);
			}
		}
		VWidget->SlotSetBackgroundMode(1);
	}

}
