//--
void MainWindow::SlotTreeWidgetItemSelectionChanged()
{
	//disconnect(GUIPanel->surfaceTreeWidget, SIGNAL(itemSelectionChanged()), this, SLOT(SlotTreeWidgetItemSelectionChanged()));

	if (SurfaceDataList->GetNumberOfItems() >= 1)
	{
		int nr = SurfaceDataList->GetNumberOfItems();
		int i;
		bool sel;

		ByteMaskCollection* masks = NULL;
		if (MainListItem != NULL)
		{

			masks = MainListItem->GetData()->GetByteMaskInternal();

			if (masks != NULL)
			{
				for (int j = 0; j < masks->GetNumberOfMasks(); j++)
				{
					masks->GetMaskDataAtPos(j)->GetTreeItem()->setSelected(false);
				}
			}
		}

		PolygonSurfaceData* sData;
		for (i = 0; i < nr; i++)
		{
			sData = SurfaceDataList->GetItemAtPos(i)->GetData();
			sel = sData->GetTreeItem()->isSelected();

			QString sDataName = sData->GetPolygonSurfaceName();


			if (sel == true)
			{
				SendMessage("Selected surface:" + sData->GetPolygonSurfaceName());

				if (masks != NULL)
				{
					for (int j = 0; j < masks->GetNumberOfMasks(); j++)
					{
						QString maskName = masks->GetMaskDataAtPos(j)->GetMaskName();
						if (QString::compare(maskName, sDataName) == 0)
						{
							masks->GetMaskDataAtPos(j)->GetTreeItem()->setSelected(true);
						}

					}
				}
			}


			//	sData->SetSurfaceActive(sel);
			if (blockChangeTempFlag == false)
			{
				sData->SetIsSegTemp(false);
			}

		}




	}
	//connect(GUIPanel->surfaceTreeWidget, SIGNAL(itemSelectionChanged()), this, SLOT(SlotTreeWidgetItemSelectionChanged()));
}
