void MainWindow::SlotSetSelectedPointsRadius()
{
	bool ok;
	double radius = QInputDialog::getDouble(this, tr("Show Points As Spheres "),
		tr("Radius:"), 1.0, 0.00001, 256, 3, &ok);
	bool any = false;
	if (ok)
	{
		selectedPointsRadius = radius;
		any = true;
	}

	double opacity = QInputDialog::getDouble(this, tr("Show Points As Spheres "),
		tr("Opacity:"), 1.0, 0.0, 1, 2, &ok);
	if (ok)
	{
		selectedPointsOpacity = opacity;
		any = true;
	}

	if (any)
	{
		SlotShowHidePoints(false);
		SlotShowHidePoints(true);
	}
}
