void MainWindow::SlotMoveSphereActorToPos()
{
	if (data != NULL)
	{
		bool ok;
		QString text = QInputDialog::getText(this, tr("Enter Volumetric or world Position"),
			tr("Abs or in x,y,z or w,xd,yd,zd format"), QLineEdit::Normal,
			"0,0,0", &ok);

		if (ok && !text.isEmpty())
		{
			QStringList fields = text.split(",", QString::SkipEmptyParts);

			bool calc = false;
			int pos[3];
			int p;
			if (fields.count() == 1)
			{
				p = fields[0].toInt();

				if ((p >= 0) && (p < data->GetVolumeSize()))
				{

					data->GetVoxelXYZPos(p, pos);
					//this->SlotMoveSphereActor(pos[0],pos[1],pos[2]);
					calc = true;
				}

			}
			else if (fields.count() == 3)
			{

				pos[0] = Round(fields[0].toDouble());		pos[1] = Round(fields[1].toDouble());		pos[2] = Round(fields[2].toDouble());
				p = data->GetVoxelPos(pos[0], pos[1], pos[2]);
				if ((p >= 0) && (p < data->GetVolumeSize()))
				{

					//this->SlotMoveSphereActor(pos[0],pos[1],pos[2]);
					calc = true;
				}
			}

			else if ((fields.count() == 4) && (QString::compare(fields[0], QString("w")) == 0))
			{

				double point[3];
				point[0] = fields[1].toDouble();		point[1] = fields[2].toDouble();		point[2] = fields[3].toDouble();
				//p=data->GetVoxelPos(pos[0],pos[1],pos[2]);
				//if ((p>=0)&&(p<data->GetVolumeSize()))
				//{

				//	//this->SlotMoveSphereActor(pos[0],pos[1],pos[2]);
				//	calc=true;
				//}
				SlotMoveSphereActor(point);
				SendMessage(" world pos:" + QString::number(point[0]) + " " + QString::number(point[1]) + " " + QString::number(point[2]));
			}

			if (calc == true)
			{
				double point[3];
				double sc0[3];
				double origin[3];
				int i;
				data->GetScale(sc0);
				data->GetOrigin(origin);
				for (i = 0; i < 3; i++)
					point[i] = pos[i] * sc0[i] + origin[i];

				SlotMoveSphereActor(point);

				SendMessage("Pos VOL: " + QString::number(p) + " Voxel Pos: " + QString::number(pos[0]) + " " + QString::number(pos[1]) + " " + QString::number(pos[2]) + " world pos:" + QString::number(point[0]) + " " + QString::number(point[1]) + " " + QString::number(point[2]));
			}

		}
	}
}
