void MainWindow::SlotTextureAnim()
{
	int msec = GUIPanel->msecTexAnimLineEdit->text().toInt();
	if (!(testTimer->isActive()))
	{
		testTimer->setInterval(msec);
		testTimer->start(false);
		SendMessage("TestTimer Start");
		testCycleCounter = 0;
	}
	else
	{
		testTimer->stop();
		SendMessage("TestTimer Stop");
		testCycleCounter = 0;
	}

}
