void MainWindow::SlotAddVolOpacityProperty()
{
	if (data != NULL)
	{

		// odczuytaj nazwe 

		QString name = GUIPanel->standardVolOpacityLineEdit->text();

		//sprawdz czy istnieje taka nazwa wsrod settings
		//jesli tak dodaj do nazwy1
		QDir rDir(progDirPath);

		if (rDir.cd("volopacity"))
		{
			rDir.setFilter(QDir::Files | QDir::Hidden | QDir::NoSymLinks);
			QStringList filters;
			filters << "*.func";
			rDir.setNameFilters(filters);

			QFileInfoList list = rDir.entryInfoList();
			QListIterator<QFileInfo> it2(list);
			QFileInfo fi;
			QString text;
			int count = rDir.count();
			QMessageBox msgBox;
			QPushButton* overwriteButton = msgBox.addButton(tr("Overwrite"), QMessageBox::ActionRole);;
			QPushButton* uniqueButton = msgBox.addButton(tr("Use Unique Names"), QMessageBox::ActionRole);;
			QPushButton* cancelButton = msgBox.addButton(QMessageBox::Discard);
			msgBox.setText("File already exists");
			bool discard = false;
			while (it2.hasNext())
				//for(it2=list.begin();it2!=list.end();++it2)
			{
				fi = it2.next();
				text = fi.fileName();
				text.remove(text.count() - 5, 5);

				if (name.compare(text) == 0)
				{
					//zapytaj czy nadpisac czy zmienic nazwe

					msgBox.exec();
					if (msgBox.clickedButton() == overwriteButton)
					{
						//nic nie robie bo nadpisze
					}
					else if (msgBox.clickedButton() == uniqueButton)
					{
						name += "_1";
					}
					else if (msgBox.clickedButton() == cancelButton)
					{
						discard = true;
					}
					break;
				}
			}

			if (discard == false)
			{
				QString filename = rDir.absolutePath() + "/" + name + ".func";
				QFile file(filename);
				if (file.open(QIODevice::WriteOnly))
				{
					file.close();



					QSettings sett(filename, QSettings::IniFormat);

					sett.beginGroup("VolRenSettings");



					sett.setValue("BlendMode", GUIPanel->volumeBlendComboBox->currentIndex());
					QString tt[] = { "shading", "gradient_opacity", "interpolation" ,"auto_sample_dist", "shading1", "gradient_opacity1" };
					QString txt;
					for (int i = 0; i < 4 + 2; i++)
					{
						txt = (GUIPanel->volumeRenCheckBox[i]->isChecked() == true) ? "On" : "Off";
						sett.setValue(tt[i], txt);
					}
					for (int i = 0; i < 5 + 3; i++)
					{
						sett.setValue("slider_" + QString::number(i), GUIPanel->volumeRenSettingsSliders[i]->value());
					}

					sett.setValue("PaletteNr", this->PalNrR);
					double range[2];
					OpacityTransferFunction->GetRange(range);

					//LowerMemThreshold = Histogram->GetLowerThreshold();
				//	UpperMemThreshold = Histogram->GetUpperThreshold();
					int minV = (data->dicomMinValue > -100000) ? data->dicomMinValue : 0;
					sett.setValue("Left_Hounsfield_Threshold", Histogram->GetLowerVolumeThreshold() + minV);
					sett.setValue("Right_Hounsfield_Threshold", Histogram->GetUpperVolumeThreshold() + minV);


					int nrPts = OpacityTransferFunction->GetSize();
					sett.setValue("NrPts", nrPts);
					if ((nrPts > 0) && (range[1] > 0))
					{
						//double range1 = 1.0 / range[1];

						//	stream << "POINTS:\n";
						double p[4];
						for (int i = 0; i < nrPts; i++)
						{
							OpacityTransferFunction->GetNodeValue(i, p);


							//	OpacityTransferFunction jest w zakresie od 0-1
							// przeskaluję x na range i dodam dicom min value
							//p[0] = p[0] * data->GetMaxValue();
							if (data->dicomMinValue > -100000) p[0] += minV;


							sett.setValue("point_Pos_" + QString::number(i), p[0]);//* range1);
							sett.setValue("opacity_" + QString::number(i), p[1]);
							//stream << p[0] * range1 << " " << p[1] << "\n";
						}
					}


					nrPts = this->GradientTransferFunction->GetSize();
					GradientTransferFunction->GetRange(range);
					sett.setValue("grad_NrPts", nrPts);
					if ((nrPts > 0) && (range[1] > 0))
					{
						//double range1 = 1.0 / range[1];

						//	stream << "POINTS:\n";
						double p[4];
						for (int i = 0; i < nrPts; i++)
						{
							GradientTransferFunction->GetNodeValue(i, p);


							//	OpacityTransferFunction jest w zakresie od 0-1
							// przeskaluję x na range i dodam dicom min value
							//p[0] = p[0] * data->GetMaxValue();
							//if (data->dicomMinValue > -100000) p[0] += minV;


							sett.setValue("grad_point_Pos_" + QString::number(i), p[0]);//* range1);
							sett.setValue("grad_opacity_" + QString::number(i), p[1]);
							//stream << p[0] * range1 << " " << p[1] << "\n";
						}
					}


					sett.endGroup();

					GUIPanel->standardVolOpacityComboBox->addItem(name, GUIPanel->standardVolOpacityComboBox->count());
					GUIPanel->standardVolOpacityComboBox2->addItem(name, GUIPanel->standardVolOpacityComboBox->count());
				}

			}
		}
	}
}

