///------------
void MainWindow::SetupMainWindowSettings()
{
	QSettings sett(configIniName, QSettings::IniFormat);
	QString txt;
	int x = 0;
	int y = 0;
	sett.beginGroup("Main-Window");
	if (sett.contains("x"))
	{
		x = sett.value("x").toInt();

	}
	if (sett.contains("y"))
	{
		x = sett.value("y").toInt();
	}

	bool maxim = false;
	if (sett.contains("ShowMaximized"))
	{
		txt = sett.value("ShowMaximized").toString();
		if (txt.compare("On") == 0)
		{
			maxim = true;
			showMaximized();
		}

	}

	if (maxim == false)this->move(x, y);
	sett.endGroup();
}
