//-------------------
void MainWindow::SlotUpdateVolumeSettings()
{
	if ((VolumeProperty != NULL) && (Volume != NULL))
	{
		//VolumeProperty->DisableGradientOpacityOff(1);
		VolumeProperty->SetComponentWeight(0, 1);
		VolumeProperty->SetComponentWeight(1, 1);


		bool shade = GUIPanel->volumeRenCheckBox[0]->isChecked();
		bool gradOp = GUIPanel->volumeRenCheckBox[1]->isChecked();
		bool volInter = GUIPanel->volumeRenCheckBox[2]->isChecked();
		bool autoSampledist = GUIPanel->volumeRenCheckBox[3]->isChecked();

		bool shade1 = GUIPanel->volumeRenCheckBox[4]->isChecked();
		bool gradOp1 = GUIPanel->volumeRenCheckBox[5]->isChecked();


		double ambient = GUIPanel->volumeRenSettingsSliders[0]->value() / 1000.0;
		double diffuse = GUIPanel->volumeRenSettingsSliders[1]->value() / 1000.0;
		double specular = GUIPanel->volumeRenSettingsSliders[2]->value() / 1000.0;
		double opDistance = GUIPanel->volumeRenSettingsSliders[3]->value() / 1000.0;
		double sampleDist = GUIPanel->volumeRenSettingsSliders[4]->value() / 1000.0;

		double ambient1 = GUIPanel->volumeRenSettingsSliders[5]->value() / 1000.0;
		double diffuse1 = GUIPanel->volumeRenSettingsSliders[6]->value() / 1000.0;
		double specular1 = GUIPanel->volumeRenSettingsSliders[7]->value() / 1000.0;

		int blendMode = GUIPanel->volumeBlendComboBox->currentIndex();
		VolumeProperty->SetShade(0, shade);

		VolumeProperty->SetAmbient(0, ambient);
		VolumeProperty->SetDiffuse(0, diffuse);
		VolumeProperty->SetSpecular(0, specular);



		VolumeProperty->SetShade(1, shade1);

		VolumeProperty->SetAmbient(1, ambient1);
		VolumeProperty->SetDiffuse(1, diffuse1);
		VolumeProperty->SetSpecular(1, specular1);

		if (gradOp == true)
		{
			VolumeProperty->DisableGradientOpacityOff(0);

		}
		else
		{
			VolumeProperty->DisableGradientOpacityOn(0);

		}


		if (gradOp1 == true)
		{
			VolumeProperty->DisableGradientOpacityOff(1);

		}
		else
		{
			VolumeProperty->DisableGradientOpacityOn(1);

		}
		VolumeProperty->SetScalarOpacityUnitDistance(0, opDistance);
		VolumeProperty->SetScalarOpacityUnitDistance(1, opDistance);

		bool currentVolInterpol = VolumeProperty->GetInterpolationType();

		if (currentVolInterpol != volInter)
		{

			if (volInter == false)
				VolumeProperty->SetInterpolationTypeToNearest();
			else
				VolumeProperty->SetInterpolationTypeToLinear();

			VolumeProperty->Modified();
			Volume->Modified();

			/*if (isVolumeVisible == true)
			{

				showHideVolume(0);
				showHideVolume(1);
			}*/


		}
		if (isVolumeVisible == true)
			if (VolumeMapper != NULL)
			{
				VolumeMapper->SetBlendMode(blendMode);

				VolumeMapper->SetAutoAdjustSampleDistances(autoSampledist);
				if (sampleDist > 0)
				{
					//VolumeMapper->SetAutoAdjustSampleDistances(0);
					VolumeMapper->SetSampleDistance(sampleDist);
					//VolumeProperty->SetScalarOpacityUnitDistance(sampleDist); 

				}
				else
				{
					//VolumeMapper->SetSampleDistance(MIN3(s[0],s[1],s[2])*0.1);
					VolumeMapper->SetAutoAdjustSampleDistances(1);


				}


				VolumeMapper->Update();
				if (Volume->GetMapper() != NULL)
				{
					Volume->Update();
					VWidget->Interactor->repaint();
				}
			}
	}
}
