void MainWindow::SlotUpdateFilterCompositions()
{


	//props

	QDir rDir(progDirPath);
	if (rDir.cd("filter_compositions"))
	{


		int ii;
		QString text = "";
		QString TMP;

		rDir.setFilter(QDir::Files | QDir::Hidden | QDir::NoSymLinks);

		QStringList nameFilters;
		nameFilters << "*.layers";
		rDir.setNameFilters(nameFilters);


		QFileInfoList list = rDir.entryInfoList();
		QListIterator<QFileInfo> it2(list);
		//QFileInfoListIterator it2( list.begin() );


		QFileInfo fi;
		int count = rDir.count();
		GUIPanel->filterCompositionsComboBox->clear();
		//for(it2=list.begin();it2!=list.end();++it2)
		while (it2.hasNext())
		{

			fi = it2.next();
			text = fi.fileName();
			text.remove(text.count() - 7, 7);
			GUIPanel->filterCompositionsComboBox->addItem(text);
		}
	}



}
