void MainWindow::SlotOnOffMask(int val)
{

	if (val == Qt::Unchecked)
	{
		currentMaskOpacity = TransversalView->MaskOpacity;
		TransversalView->SlotSetMaskOpacity(0);
		SagittalView->SlotSetMaskOpacity(0);
		CoronalView->SlotSetMaskOpacity(0);
	}
	else if (val = Qt::Checked)
	{

		TransversalView->SlotSetMaskOpacity(currentMaskOpacity);
		SagittalView->SlotSetMaskOpacity(currentMaskOpacity);
		CoronalView->SlotSetMaskOpacity(currentMaskOpacity);
	}
}

