void	MainWindow::SlotCreateMaskFromBarrier()
{
	addBarrier = true;
	if (data != NULL)
	{
		ImageShapes* shapes = this->TransversalView->GetShapes();
		if (shapes != NULL)
		{
			int nrShapes = shapes->shapeList.count();
			if (nrShapes > 0)
			{

				MyShape shape;

				QList<MyShape>* slist = &shapes->shapeList;
				QImage img(data->GetNx(), data->GetNy(), QImage::Format_RGB32);
				bool test = false;

				for (int i = 0; i < nrShapes; i++)
				{
					shape = slist->at(i);

					if (shape.poly.count() > 0)
					{

						if (shape.name.compare("areaPolys") == 0)
						{
							int nrPts = shape.poly.count();

							QPolygon pp;
							QPointF pointf;
							int x, y;
							int nn = nrPts / 2;
							for (int jj = 0; jj < nn; jj++)
							{

								x = shape.poly.at(jj * 2).x();
								y = shape.poly.at(jj * 2).y();
								pp.append(QPoint(x, y));

							}
							for (int jj = nn - 1; jj >= 0; jj--)
							{

								x = shape.poly.at(jj * 2 + 1).x();
								y = shape.poly.at(jj * 2 + 1).y();
								pp.append(QPoint(x, y));

							}


							img.fill(Qt::black);
							QPainter Painter2(&img);
							Painter2.setBrush(Qt::white);
							Painter2.setPen(1);
							Painter2.drawPolygon(pp);

							test = true;
							break;

						}
					}

				}

				if (test == true)
				{
					this->TransversalView->GetShapes()->polygonList.clear();
					this->TransversalView->GetShapes()->shapeList.clear();
					SlotAddMaskFromImageWidget(img);
				}
			}

		}
	}


	addBarrier = false;
}
