//--------------------------------------
void MainWindow::SlotKinectCalibrate()
{

	if (sBlock[0] >= 0)
	{

		kinectCrop[0] = sBlock[0];
		kinectCrop[1] = sBlock[1];

		kinectCrop[2] = sBlock[3 * 2] - sBlock[0];
		kinectCrop[3] = sBlock[3 * 2 + 1] - sBlock[1];

		QSettings sett(configIniName, QSettings::IniFormat);
		sett.beginGroup("Kinect-Vol");

		for (int i = 0; i < 8; i++)
		{

			kinectCorners[i] = sBlock[i];
			QString name = "kinectCorners" + QString::number(i);
			sett.setValue(name, kinectCorners[i]);

		}




		for (int i = 0; i < 4; i++)
		{
			QString name = "kinectCrop" + QString::number(i);
			sett.setValue(name, kinectCrop[i]);

		}

		GetHomographyMap();
		UpdateKinectVertexLabels();

		sett.endGroup();

	}
}
//--------------------------------------
void MainWindow::SlotKinectResetCrop()
{
	int W = kinect2Init ? m_depthWidth : 512;
	int H = kinect2Init ? m_depthHeight : 424;

	kinectCrop[0] = 0;
	kinectCrop[1] = 0;
	kinectCrop[2] = W;
	kinectCrop[3] = H;

	// Pełna klatka: 4 narożniki (0,0), (W-1,0), (W-1,H-1), (0,H-1)
	kinectCorners[0] = 0;   kinectCorners[1] = 0;
	kinectCorners[2] = W - 1; kinectCorners[3] = 0;
	kinectCorners[4] = W - 1; kinectCorners[5] = H - 1;
	kinectCorners[6] = 0;   kinectCorners[7] = H - 1;

	for (int i = 0; i < 8; i++)
		sBlock[i] = kinectCorners[i];

	QSettings sett(configIniName, QSettings::IniFormat);
	sett.beginGroup("Kinect-Vol");
	for (int i = 0; i < 8; i++)
		sett.setValue("kinectCorners" + QString::number(i), kinectCorners[i]);
	for (int i = 0; i < 4; i++)
		sett.setValue("kinectCrop" + QString::number(i), kinectCrop[i]);
	sett.endGroup();

	GetHomographyMap();
	UpdateKinectVertexLabels();
}
//--------------------------------------
void MainWindow::UpdateKinectVertexLabels()
{
	for (int i = 0; i < 4; i++)
		GUIPanel->kinectVertexLabel[i]->setText(QString("P%1: (%2, %3)").arg(i).arg(kinectCorners[i * 2]).arg(kinectCorners[i * 2 + 1]));
}
//-----------------------------
void MainWindow::GetHomographyMap()
{


	Point2 ptsProjInKin[4] = { { kinectCorners[0], kinectCorners[1] },
	{ kinectCorners[2], kinectCorners[3] },

	{ kinectCorners[6], kinectCorners[7] },
	{ kinectCorners[4], kinectCorners[5] } };

	// te same wierzchołki oznaczone w obrazie projektora
	Point2 ptsProj[4] = { { 0, 0 }, { 1, 0 }, { 0, 1 }, { 1, 1 } };
	arma::mat H = findHomography(ptsProj, ptsProjInKin);

	int pos = 0;
	Point2 P;
	double sc = 1.0 / homographyLookupSize;

	int xMin = homographyLookupSize;
	int xMax = homographyLookupSize;
	int yMin = homographyLookupSize;
	int yMax = homographyLookupSize;

	for (int j = 0; j < homographyLookupSize; j++)
	{
		P.y = j * sc;
		for (int i = 0; i < homographyLookupSize; i++)
		{
			P.x = i * sc;
			Point2 Q = projTransform(H, P); // TA-DA!
			homographyLookup[pos++] = Q.x;
			homographyLookup[pos++] = Q.y;

			if (Q.x > xMax) xMax = Q.x;
			if (Q.x < xMin)xMin = Q.x;
			if (Q.y > yMax) yMax = Q.y;
			if (Q.y < yMin)yMin = Q.y;

		}
	}

	QImage* img = new QImage(xMax, yMax, QImage::Format_ARGB32);


	QPainter p(img);;
	for (int j = 0; j < homographyLookupSize; j += 100)
	{
		P.y = j * sc;
		for (int i = 0; i < homographyLookupSize; i += 100)
		{
			P.x = i * sc;
			Point2 Q = projTransform(H, P); // TA-DA!


			p.drawLine(i, j, Q.x, Q.y);


		}
	}

	p.setPen(Qt::red);
	QPolygon poly;
	poly.append(QPoint(kinectCorners[0], kinectCorners[1]));
	poly.append(QPoint(kinectCorners[2], kinectCorners[3]));
	poly.append(QPoint(kinectCorners[4], kinectCorners[5]));
	poly.append(QPoint(kinectCorners[6], kinectCorners[7]));

	p.drawPolygon(poly);

	//img->save("d:\\pic2.png", "PNG");



	kinCalibrated = true;
}
