void	 MainWindow::SlotUpdateFastFilter()
{
	//trzeba zapisac filtr do pliku i tyle
	bool vis = GUIPanel->fastFilterParamsWidgets[0]->isVisible();
	if (vis == true)//gdy widac jakikowliek suwak z fastfilters - moge zapisac filtr 
	{
		QString name = GUIPanel->FilterCompositionNameLineEdit->text();

		//sprawdz czy istnieje taka nazwa wsrod settings
		//jesli tak dodaj do nazwy1
		QDir rDir(progDirPath);

		if (rDir.cd("filter_compositions"))
		{
			rDir.setFilter(QDir::Files | QDir::Hidden | QDir::NoSymLinks);
			QStringList nameFilters;
			nameFilters << "*.layers";
			rDir.setNameFilters(nameFilters);

			QFileInfoList list = rDir.entryInfoList();
			QListIterator<QFileInfo> it2(list);
			QFileInfo fi;
			QString text;
			int count = rDir.count();

			while (it2.hasNext())
			{
				fi = it2.next();
				text = fi.fileName();
				text.remove(text.count() - 7, 7);

				if (name.compare(text) == 0)
				{
					QString filename = rDir.absolutePath() + "/" + name + ".layers";
					mixer->SaveLayerSettings(filename);
					emit SendMessage("filter updated");
				}
			}
		}

	}
	else
	{
		emit SendMessage("nothing to update!");
	}
}
