void	MainWindow::SlotMixerFastFilterUpdate(int sel)
{
	//sprawdzam aktualny filterCompositionsComboBox - biore nazwe
	//sprawdzam czy jest w pliku .fastfilters
	//robie update .fastfilters dodajac albo usuwajac nazwe

	bool test = (sel != 0) ? true : false; //GUIPanel->enableFastFilterCheckBox->isChecked();

	QString txt = GUIPanel->filterCompositionsComboBox->itemText(GUIPanel->filterCompositionsComboBox->currentIndex());
	//sprawdz czy istnieje taka nazwa wsrod settings
	//jesli tak dodaj do nazwy1
	QDir rDir(progDirPath);

	if (rDir.cd("filter_compositions"))
	{

		QString filename = rDir.absolutePath() + "/.fastfilters";
		QFile file(filename);
		QStringList filefilters;
		bool deleted = false;
		if (file.open(QIODevice::ReadOnly))
		{
			QTextStream stream(&file);
			QString line;
			//bool test1 = false;
			do
			{
				line = stream.readLine();
				if ((line.compare(txt) != 0) || (test == true)) //nie dodawaj tego ktory aktualnie jest zaznaczony (test==false) - wtedy nic nie usuwaj
				{
					if (!line.isEmpty())
						filefilters << line;
				}
				else
				{
					deleted = true;
				}
			} while (!stream.atEnd());
			file.close();

			//odczytalem to co jest w pliku z wywaleniem aktualnego


			bool updateX = false;

			if (deleted == true) updateX = true;
			if ((deleted == false) && (test == true))
			{
				updateX = true;
				filefilters << txt;
			}

			if (updateX == true)
			{
				if (file.open(QIODevice::WriteOnly))
				{
					filefilters.sort();
					QTextStream stream(&file);
					for (int i = 0; i < filefilters.size(); i++)
					{
						stream << filefilters.at(i) << "\n";
					}
					file.close();

				}


			}


		}
		UpdateFastFiltersGUI();
	}
}

