	//LinkedList <RawDataLayer *>		*GetLayerList(){ return rawDataLayerList; };
	LinkedList <RawDataLayer*>* list = this->mixer->GetLayerList();
	int nrOfLayers = list->GetNumberOfItems();

	if (nrOfLayers > 1)
	{
		//schowaj całe gui
		for (int i = 0; i < PARAMS_NR; i++)
		{
			GUIPanel->fastFilterParamsWidgets[i]->HideWidgetAndTopLabel();
		}


		///pokazuj i lacz tylko te, ktore sa w danym filtrze
		nrOfCurrentFastFiltersParams = 0;

		for (int i = 1; i < nrOfLayers; i++)
		{
			RawDataLayer* layer = list->GetItemAtPos(i)->GetData();
			UpdateSliderSettings(layer, nrOfCurrentFastFiltersParams);
			//layer->Get
		}

	}
	ConnectAllFastFilters();
	ChangeGen3DFilterButtonVisibility();

	//if (test == true)
	//{
	//	for (int i = 0; i < 3; i++)
	//	{
	//		GUIPanel->disableSeparatedMixersCheckBox[i]->setChecked(true);
	//		
	//	}
	//}

	//dodac do pliku config

