bool MainWindow::ChangeGen3DFilterButtonVisibility()
{
	RawDataMixerLite* mixerX = mixer;
	LinkedList <RawDataLayer*>* rawDataLayerList = mixerX->GetLayerList();
	LinkedList <LayerFilter*>* layerFilterList = mixerX->GetLayerFilterList();
	int nrLayers = mixer->GetNumberOfLayers();
	bool test = false;
	if (nrLayers > 1)
	{
		RawDataLayer* layer;
		int filterMode;
		LayerMaskFilter* layerMaskFilter;
		LayerFilter* layerFilter;
		int j = 0;
		for (j = 1; j < nrLayers; j++)
		{
			layer = rawDataLayerList->GetItemAtPos(j)->GetData();



			filterMode = layer->GetFilterMode();
			layerFilter = layerFilterList->GetItemAtPos(filterMode)->GetData();
			QString filterName = layerFilter->GetFilterName();




			for (int i = 0; i < filters3DImplemented.count(); i++)
			{
				if (filterName.compare(filters3DImplemented[i]) == 0)
				{
					test = true;
					break;
				}
			}
			if (test == true) break;

		}
	}

	GUIPanel->apply3DFastFilterPushButton->setEnabled(test);
	return test;

}
