void MainWindow::UpdateSliderSettings(RawDataLayer* layer, int& pos)
{
	int filterMode = layer->GetFilterMode();
	LayerFilter* layerFilter = mixer->GetLayerFilterList()->GetItemAtPos(filterMode)->GetData();
	int nrOfFilterParams = layerFilter->GetNumberOfParams();

	double sliderParams[3];

	bool firstShowLabel = true;

	for (int i = 0; i < PARAMS_NR; i++)
	{
		if (i < layer->GetNumberOfMainParams())
		{
			if (layer->GetMainParamForGui(i) == false) continue;

			if (firstShowLabel == true)
			{
				firstShowLabel = false;
				GUIPanel->fastFilterParamsWidgets[pos]->SetTopLabel(layer->GetName(), true);
			}

			bool sel = layer->GetMainParamForGui(i);
			double val = layer->GetMainParam(i);

			GUIPanel->fastFilterParamsWidgets[pos]->UpdateSliderSettings((LayerGenericFilter*)mixer, i, sel, val, layer->GetParamsAddress(0, i), layer->GetColorsAddress(0, i));
			int col[3];
			layer->GetMainParamsColors(i, col);
			GUIPanel->fastFilterParamsWidgets[pos]->SetBackgroundColor(col[0], col[1], col[2]);
			pos++;

		}
		else
		{
			//	GUIPanel->fastFilterParamsWidgets[pos]->setVisible(false);
		}
	}

	////////

	for (int i = 0; i < PARAMS_NR; i++)
	{
		if (i < nrOfFilterParams)
		{
			if (layer->GetFilterParamForGui(i) == false) continue;

			bool sel = layer->GetFilterParamForGui(i);
			double val = layer->GetFilterParam(i);
			if (firstShowLabel == true)
			{
				firstShowLabel = false;
				GUIPanel->fastFilterParamsWidgets[pos]->SetTopLabel(layer->GetName(), true);
			}
			GUIPanel->fastFilterParamsWidgets[pos]->UpdateSliderSettings((LayerGenericFilter*)layerFilter, i, sel, val, layer->GetParamsAddress(1, i), layer->GetColorsAddress(1, i));
			int col[3];
			layer->GetFilterParamsColors(i, col);
			GUIPanel->fastFilterParamsWidgets[pos]->SetBackgroundColor(col[0], col[1], col[2]);
			pos++;

		}
		else
		{
			//	GUIPanel->fastFilterParamsWidgets[pos]->setVisible(false);
		}
	}

	//--------------------------------------------------------
	int MaskFilterMode = layer->GetMaskFilterMode();
	LayerMaskFilter* layerMaskFilter = mixer->GetLayerMaskFilterList()->GetItemAtPos(MaskFilterMode)->GetData();
	int nrOfMaskFilterParams = layerMaskFilter->GetNumberOfParams();

	//double sliderParams[3];
	for (int i = 0; i < PARAMS_NR; i++)
	{
		if (i < nrOfMaskFilterParams)
		{
			if (layer->GetMaskFilterParamForGui(i) == false) continue;
			bool sel = layer->GetMaskFilterParamForGui(i);
			double val = layer->GetMaskFilterParam(i);
			if (firstShowLabel == true)
			{
				firstShowLabel = false;
				GUIPanel->fastFilterParamsWidgets[pos]->SetTopLabel(layer->GetName(), true);
			}
			GUIPanel->fastFilterParamsWidgets[pos]->UpdateSliderSettings((LayerGenericFilter*)layerMaskFilter, i, sel, val, layer->GetParamsAddress(2, i), layer->GetColorsAddress(2, i)); // ind, paramName, sliderTest, sliderParams, ttext, sel);
			int col[3];
			layer->GetMaskFilterParamsColors(i, col);
			GUIPanel->fastFilterParamsWidgets[pos]->SetBackgroundColor(col[0], col[1], col[2]);
			pos++;
			//pos++;//superbug

		}
		else
		{
			//	GUIPanel->fastFilterParamsWidgets[pos]->setVisible(false);
		}
	}

}

