void MainWindow::SlotChangeCurrentWindowLevelSettings(QAction* action)
{
	if (data != NULL)
	{
		int pos = action->data().toInt();

		int maxx = data->GetMaxValue();
		double windowWidth = maxx;
		double level = maxx / 2;
		int lth = 0;
		int rth = maxx;
		double rescale = data->dicomRescaleValue;

		if (pos == 1)
		{
			if (data->dicomMinValue > -100000)
			{
				level = data->dicomLevelValue;
				windowWidth = data->dicomWindowWidthValue;
			}
		}
		else if (pos > 1)
		{
			windowWidth = this->hounsfieldSettings.at(pos).y();
			level = this->hounsfieldSettings.at(pos).x();
		}

		//if (pos > 0)
		//{

		//	//int wcenter = level;
		//	if (data->dicomMinValue > -100000)
		//	{
		//		//if (data->dicomMinValue < 0)

		//			level -= data->dicomMinValue;
		//	}
		//}


		level -= data->dicomMinValue;
		if (rescale > 0)
		{
			windowWidth /= rescale;
			level /= rescale;
		}

		//int wwidth = windowWidth;

		int minVal = level - windowWidth / 2;
		int maxVal = level + windowWidth / 2;



		lth = minVal;
		rth = maxVal;

		Histogram->Thresh1Slider->setValue(lth);
		Histogram->Thresh2Slider->setValue(rth);


	}
}
