void MainWindow::SlotUpdateVolumeFromMixerMixedData()
{
	if (isVolumeVisible == true)
	{
		RTimer.Start("Generating filtered Volume ...", false);
		//	int tmp=1;

		if ((MainListItem != NULL) && (this->mixer != NULL))
		{
			RawDataSet* datax = NULL;
			switch (LastClickedView)
			{
			case 0:
				datax = mixer->SlotGenerateMixedData();
				break;

			case 1:
				datax = mixer1->SlotGenerateMixedData();
				break;

			case 2:
				datax = mixer2->SlotGenerateMixedData();
				break;

			default:
				datax = mixer->SlotGenerateMixedData();

			}
			if (datax != NULL)
			{
				//// zrobie update i skasuje


				SlotSetNew3DView(datax);

				delete datax;
			}
		}
		RTimer.Stop();
	}
	else
	{
		emit SendMessage("volume invisible! (press CTRL+V to show)");
	}
}
