void	MainWindow::SlotResetClippingPlanes()
{

	if (data != NULL)
	{
		int n[3];
		data->GetN(n);
		int bounds[] = { 0,n[0] - 1,0,n[1] - 1,0,n[2] - 1 };


		for (int i = 0; i < 6; i++)
		{
			GUIPanel->planeSliders[i]->setRange(0, n[i / 2]);
		}

		for (int i = 0; i < 6; i++)
		{
			GUIPanel->planeSliders[i]->setValue(bounds[i]);
		}
	}

}


