void	MainWindow::SlotChangeMask3DOpacity(int)
{

	double val = GUIPanel->CurrentMask3DOpacitySlider->value() / 255.0;

	unsigned char opc = GUIPanel->CurrentMask3DOpacitySlider->value();
	double w1 = GUIPanel->MaskWeightsSlider1->value() / 255.0;

	if (isVolumeVisible == true)
	{
		if (OpacityTransferFunction2 != NULL)
		{
			OpacityTransferFunction2->RemoveAllPoints();


			//double w2 = GUIPanel->MaskWeightsSlider2->value() / 255.0;

		//	VolumeProperty->SetComponentWeight(0, w1);
		//	VolumeProperty->SetComponentWeight(1, w2);
			//for (int i=0;i<255;i++)

			OpacityTransferFunction2->AddPoint(0, 0);
			OpacityTransferFunction2->AddPoint(0.5, w1);
			OpacityTransferFunction2->AddPoint(2.5, w1);
			OpacityTransferFunction2->AddPoint(2.6, val);
			OpacityTransferFunction2->AddPoint(255, val);
			//	OpacityTransferFunction2->AddPoint(256, 0);
			//	OpacityTransferFunction2->AddPoint(10000, 0);

				/*OpacityTransferFunction2->AddPoint(0, 0);
				OpacityTransferFunction2->AddPoint(1, val);
				OpacityTransferFunction2->AddPoint(255, val);*/
				//	OpacityTransferFunction2->AddPoint(0, 0);

				/*	double p[4];
					OpacityTransferFunction2->GetNodeValue(1, p);		p[1] = val; OpacityTransferFunction2->SetNodeValue(1, p);
					OpacityTransferFunction2->GetNodeValue(255, p);		p[1] = val; OpacityTransferFunction2->SetNodeValue(255, p);*/
					//OpacityTransferFunction2->AddPoint(1, val);
					//OpacityTransferFunction2->AddPoint(255, val);

			if (MaskVolumeStructuredPoints != NULL)
			{
				MaskVolumeStructuredPoints->Modified();
				bool useMask = GUIPanel->useMaskFor3DViewCheckBox->isChecked();

				if (useMask == true)
				{
					VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);
				}
				else
				{
					VolumeMapper->SetMaskInput(NULL);
				}
				VolumeMapper->Modified();
				Volume->Update();
				VWidget->Interactor->update();
			}
		}
	}
	bool aa = disable3DUpdateFilter;

	TransversalView->SetBlockMixer(true); SagittalView->SetBlockMixer(true); CoronalView->SetBlockMixer(true);
	disable3DUpdateFilter = false;
	TransversalView->SlotSetVolumeOpacity(opc);
	SagittalView->SlotSetVolumeOpacity(opc);
	CoronalView->SlotSetVolumeOpacity(opc);
	SlotConnectAllViews();
	disable3DUpdateFilter = aa;
	TransversalView->SetBlockMixer(false); SagittalView->SetBlockMixer(false); CoronalView->SetBlockMixer(false);

}
