//int MainWindow::UpdateVolMaskToVolumeStructuredPoints(unsigned short *mask, int col, bool avoidZero, bool update3D, bool updateM2, bool avoidNonZeroM2)
int MainWindow::UpdateVolMaskToVolumeStructuredPoints(unsigned short* mask, int col, bool avoidNonZeroM2, bool update3D, bool updateM2, bool dontClear)

{
	//col - tym kolorem maluje, jesli -1 maluje tym co przyszlo
	//avoidZero - jesli true - przenosze z mask tylko wartosci >0
	//update - odswieza 3D
	//updateM2 - zamalowuje od razu m2

	if ((VolumeStructuredPoints != NULL))
	{
		unsigned short* ptr0 = (unsigned short*)(VolumeStructuredPoints->GetScalarPointer(0, 0, 0));
		//memcpy(volPointer, Data3D->GetDataArray(), Data3D->GetVolumeSize() * sizeof(unsigned short));

		int dims[3];
		data->GetN(dims);



		//for (int i = 0;i < data->GetVolumeSize();i++)
		//{
		//	if (mask[i] > 255)
		//	{
		//		i = i;
		//	}
		//}


		unsigned short* dArray = data->GetDataArray();

		int count = 0;
		int z;
		int* counters = new int[this->nrOfThreads];
		memset(counters, 0, nrOfThreads * sizeof(int));
#pragma omp parallel
		{

			int tid = omp_get_thread_num();
#pragma omp for   ordered schedule (guided) private(z)
			for (z = 0; z < dims[2]; ++z)
			{
				int pos = z * data->GetSliceSize();
				unsigned short* ptr = ptr0 + pos * 2;
				for (int y = 0; y < dims[1]; ++y)
				{
					for (int x = 0; x < dims[0]; ++x)
					{

						ptr++;


						if ((avoidNonZeroM2 == false) || ((avoidNonZeroM2 == true) && (Mask2Data[pos] == 0)))
						{
							if (mask[pos] > 0)
							{
								*ptr = (col == -1) ? mask[pos] : col;
								counters[tid]++;
								//count++;
							}
							else
							{
								if (dontClear == false)
									*ptr = 0;// 29999;
							}
						}

						ptr++;
						pos++;

					}
				}
			}
		}

		for (int i = 0; i < nrOfThreads; i++)
		{
			count += counters[i];
		}
		delete[]counters;

		if (update3D == true)
		{
			VolumeStructuredPoints->Modified();
			if (isVolumeVisible == true)
			{
				VolumeMapper->SetInputData(VolumeStructuredPoints);

				bool useMask = GUIPanel->useMaskFor3DViewCheckBox->isChecked();
				if (useMask == true)
				{
					VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);
				}
				else
				{
					VolumeMapper->SetMaskInput(NULL);
				}
				VolumeMapper->Modified();
				Volume->Update();
				VWidget->Interactor->update();
			}
		}

		if (updateM2 == true)
		{
			int i;
#pragma omp for   ordered schedule (guided) private(i)
			for (i = 0; i < data->GetVolumeSize(); i++)
			{
				if (mask[i] > 0) Mask2Data[i] = 1;
			}
			chgMaskTimeStamp = elapsedTimer.elapsed();

		}
		return count;
	}
	return 0;
}


