int MainWindow::UpdateVolMaskToVolumeStructuredPoints(unsigned char* mask, int col, bool avoidNonZeroM2, bool update3D, bool updateM2, bool dontClear)

{
	//col - tym kolorem maluje, jesli -1 maluje tym co przyszlo
	//avoidZero - jesli true - przenosze z mask tylko wartosci >0
	//update - odswieza 3D
	//updateM2 - zamalowuje od razu m2

	if ((VolumeStructuredPoints != NULL))
	{
		unsigned short* ptr = (unsigned short*)(VolumeStructuredPoints->GetScalarPointer(0, 0, 0));
		//memcpy(volPointer, Data3D->GetDataArray(), Data3D->GetVolumeSize() * sizeof(unsigned short));

		int dims[3];
		data->GetN(dims);



		unsigned short* dArray = data->GetDataArray();
		int pos = 0;
		int count = 0;

		for (int z = 0; z < dims[2]; ++z)
		{
			for (int y = 0; y < dims[1]; ++y)
			{
				for (int x = 0; x < dims[0]; ++x)
				{

					ptr++;


					if ((avoidNonZeroM2 == false) || ((avoidNonZeroM2 == true) && ((Mask2Data[pos] == 0))))
					{
						if (mask[pos] > 0)
						{
							*ptr = (col == -1) ? mask[pos] : col;
							count++;
						}
						else
						{
							if (dontClear == false)
								*ptr = 0;// 29999;
						}
					}

					ptr++;
					pos++;

				}
			}
		}



		if (update3D == true)
		{
			VolumeStructuredPoints->Modified();
			if (isVolumeVisible == true)
			{
				VolumeMapper->SetInputData(VolumeStructuredPoints);

				bool useMask = GUIPanel->useMaskFor3DViewCheckBox->isChecked();
				if (useMask == true)
				{
					VolumeMapper->SetMaskInput(MaskVolumeStructuredPoints);
				}
				else
				{
					VolumeMapper->SetMaskInput(NULL);
				}
				VolumeMapper->Modified();
				Volume->Update();
				VWidget->Interactor->update();
			}
		}

		if (updateM2 == true)
		{
			for (int i = 0; i < data->GetVolumeSize(); i++)
			{
				if (mask[i] > 0) Mask2Data[i] = 1;
			}
			chgMaskTimeStamp = elapsedTimer.elapsed();
		}

		return count;
	}
	return 0;
}
