void	MainWindow::SlotAddCurrentMaskForTree()
{
	if ((data != NULL) && (MaskData != NULL))
	{
		TransversalView->SetBlockMixer(true); SagittalView->SetBlockMixer(true); CoronalView->SetBlockMixer(true);

		int mode = GUIPanel->m2ComboBox->currentIndex();

		int count = 0;
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{
			count += MaskData[i];
			if (!((MaskData[i] == 0) || (MaskData[i] == 1)))
			{
				i = i;
			}
		}

		if ((count > 0) && (count < data->GetVolumeSize() * 0.9))
		{
			int col = FindFirstEmptyMaskUseHist();				volMaskUseHist[col] = 1;
			if (mode < 2)
			{
				ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
				masks->InsertNewMask(MaskData);
				ByteMask* newMask = masks->GetCurrentByteMask();
				newMask->SetMaskName(GUIPanel->CurrentMaskNameLineEdit->text());
				GUIPanel->SlotInsertMaskDataItem(newMask, col);
				newMask->SetColorIndex(col);
			}

			//bool addBlockMask = GUIPanel->AddCurrentAddToMask2CheckBox->isChecked();
		//	if (addBlockMask == true)
			if (mode > 0)
			{
				//AddMaskToMask2(MaskData);
				//AddMaskToVolumeStructuredPoints(MaskData, 1, true, true);

				UpdateVolMaskToVolumeStructuredPoints(MaskData, col, true, true, true);//avoidNonZeroM2, bool update3D, bool updateM2
			}


		}
		//TransversalView->SetBlockMixer(false); SagittalView->SetBlockMixer(false); CoronalView->SetBlockMixer(false);
		SlotUpdateDisableMixer(1);

	}
}
