QString MainWindow::GetUniqueMaskName()
{
	ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
	QString initName = GUIPanel->CurrentMaskNameLineEdit->text();
	if (masks != NULL)
	{
		//init name
		  //sprawdzam czy juz taka istnieje - jesli tak to sprawdzam czy ma _nr
		  //jesli są inne co mają _nr to szukam z najwiekszym i dodaje 1 i nowy
		QStringList list;
		bool found = false;
		for (int i = 0; i < masks->GetNumberOfMasks(); i++)
		{
			list.append(masks->GetMaskDataAtPos(i)->GetMaskName());
			if (initName.compare(list.at(i)) == 0)
			{
				found = true;
				//break;
			}
		}

		if (found == true)
		{
			//sprawdz czy ma numer i usun

			int nrr = initName.lastIndexOf("_");
			if (nrr > 0)
			{
				initName = initName.mid(0, nrr);
			}
			for (int j = 1; j < 100; j++)
			{
				QString tmpName = initName + "_" + QString::number(j);
				bool found = false;
				int i = 0;
				for (i = 0; i < masks->GetNumberOfMasks(); i++)
				{
					if (tmpName.compare(list.at(i)) == 0)
					{
						break;
					}

				}
				if (i == masks->GetNumberOfMasks())
				{
					//nie znalazl
					return tmpName;
				}

			}
			//if (tt.mid(tt.length() - 4, 4)



		}




	}
	return initName;//
}
