void MainWindow::SlotChangeVolMaskColor(int col)
{

	if ((VolumeStructuredPoints != NULL))
	{

		unsigned short* ptr = (unsigned short*)(VolumeStructuredPoints->GetScalarPointer(0, 0, 0));
		//memcpy(volPointer, Data3D->GetDataArray(), Data3D->GetVolumeSize() * sizeof(unsigned short));

		int dims[3];
		data->GetN(dims);



		unsigned short* dArray = data->GetDataArray();
		int pos = 0;
		int count = 0;

		ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nr = masks->GetMaskList()->GetNumberOfItems();
		unsigned  char* nMask = new unsigned char[data->GetVolumeSize()];
		//	int col = 2;
			//wyczysc dane na wolumenie volstructured points;
		for (int z = 0; z < dims[2]; ++z)
		{
			for (int y = 0; y < dims[1]; ++y)
			{
				for (int x = 0; x < dims[0]; ++x)
				{
					ptr++;
					*ptr++ = 0;
				}

			}
		}
		//zamaluj te co trzeba
		int selCount = 0;
		for (int i = 0; i < nr; i++)
		{
			if (masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected()) selCount++;

		}

		SlotClearVolMask(); //wyczysc jak cos jest zaznaczone w liscie zeby dodac


		for (int i = 0; i < nr; i++)
		{

			bool sel = masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected();
			if ((selCount == 0) || (sel == true))
			{


				//col = (rand()*254) / RAND_MAX + 2;
				//int col = FindFirstEmptyMaskUseHist();		
				volMaskUseHist[col] = 1;
				ptr = (unsigned short*)(VolumeStructuredPoints->GetScalarPointer(0, 0, 0));

				masks->GetMaskDataAtPosAndSetAsCurrent(i, nMask);

				UpdateVolMaskToVolumeStructuredPoints(nMask, col, true, true, true);
				masks->GetMaskDataAtPos(i)->GetTreeItem()->setIcon(1, GUIPanel->distinctColorIconsCirc[col + 1]);
				masks->GetMaskDataAtPos(i)->SetColorIndex(col);
			}

		}


		delete[]nMask;


		SlotUpdateDisableMixer(1);

	}


}

