void MainWindow::SlotClearVolMask()
{
	if ((VolumeStructuredPoints != NULL))
	{

		//AddMaskToVolumeStructuredPoints(NULL, 0);
		ClearVolumeStructuredPoints(0, true, true);
		ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nr = masks->GetMaskList()->GetNumberOfItems();
		for (int i = 0; i < nr; i++)
		{
			QTreeWidgetItem* item = masks->GetMaskDataAtPos(i)->GetTreeItem();
			//item->setIcon(1, GUIPanel->emptyIcon);

		}

		unsigned char opc = GUIPanel->CurrentMask3DOpacitySlider->value();
		TransversalView->SetBlockMixer(true); SagittalView->SetBlockMixer(true); CoronalView->SetBlockMixer(true);
		TransversalView->SlotSetVolumeOpacity(opc);	SagittalView->SlotSetVolumeOpacity(opc);	CoronalView->SlotSetVolumeOpacity(opc);
		TransversalView->SetBlockMixer(false); SagittalView->SetBlockMixer(false); CoronalView->SetBlockMixer(false);


	}

}



