void MainWindow::SlotDeleteVolMask()
{
	//	if ((VolumeStructuredPoints != NULL))
	{



		ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nr = masks->GetMaskList()->GetNumberOfItems();
		int selCount = 0;
		for (int i = 0; i < nr; i++)
		{
			if (masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected()) selCount++;

		}

		if (selCount > 0)
		{

			QMessageBox msgBox;
			msgBox.setText("Question ");
			msgBox.setInformativeText("Do you really want to delete selected maks? ");
			msgBox.setStandardButtons(QMessageBox::Yes | QMessageBox::No);
			msgBox.setDefaultButton(QMessageBox::No);
			int ret = msgBox.exec();

			if (ret == QMessageBox::Yes)
			{

				for (int i = nr - 1; i >= 0; i--)
				{
					if (masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected())
					{
						masks->DeleteMaskAtPos(i);

					}

				}
			}
		}


	}

}

