void	MainWindow::SlotUpdatedLiveMask(const unsigned char* mmask)
{
	if ((VolumeStructuredPoints != NULL) && (mmask != NULL) && (volumeTempData != NULL))
	{
		int count = 0;
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{

			if ((volumeTempData[i] > 0) && (mmask[i] == 0))
			{
				volumeTempData[i] = 0;
				count++;
			}
		}

		if (count > 0)
		{
			UpdateVolMaskToVolumeStructuredPoints(volumeTempData, -1, true, true, false);
			SlotUpdateDisableMixer(1);

		}
	}
}

