unsigned char* MainWindow::GetCurrentMaskForStats(QString& txt)
{

	int mode = GUIPanel->maskStatsSourceComboBox->currentIndex();
	unsigned char* mask = NULL;
	bool nothing = true;
	//if (mode != 1)
	{
		mask = new unsigned char[data->GetVolumeSize()];
		memset(mask, 0, data->GetVolumeSize());
	}
	//	QString txt;
	if (mode == 0)
	{
		txt += "Live Mask:";
		if ((volumeTempData != NULL))
		{
			for (int i = 0; i < data->GetVolumeSize(); i++)
			{
				if (volumeTempData[i] == 2)
					mask[i] = 1;

			}
			nothing = false;
		}
		else
		{
			txt += " Empty";
		}


	}
	if (mode == 1)
	{
		txt += "Main Mask:";
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{

			if (MaskData[i] == 1)
				mask[i] = 1;

		}
		nothing = false;
	}
	else if (mode == 2)
	{
		txt += "Selected Mask:";
		unsigned  char* nMask = new unsigned char[data->GetVolumeSize()];
		ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nr = masks->GetMaskList()->GetNumberOfItems();
		int anySel = 0;
		for (int i = 0; i < nr; i++)
		{

			bool sel = masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected();
			if (sel == true)
			{
				anySel++;
				masks->GetMaskDataAtPosAndSetAsCurrent(i, nMask);
				for (int j = 0; j < data->GetVolumeSize(); j++)
				{
					if (nMask[j] == 1) mask[j] = 1;

				}
				nothing = false;
			}
		}
		if (anySel == 0)
		{
			txt += " Nothing selected";
		}
		delete[]nMask;


	}


	if (nothing == true)
	{
		txt += "Main Mask:";
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{

			if (MaskData[i] == 1)
				mask[i] = 1;

		}
	}

	int count = 0;
	for (int i = 0; i < data->GetVolumeSize(); i++)
	{
		if (mask[i] == 1)
		{
			count++;
		}
	}
	if ((count == 0) || (count == data->GetVolumeSize() - 1))
	{
		delete[]mask;
		mask = NULL;
		txt += " - empty input";
	}

	return mask;
}
