void	MainWindow::CalculateMaskStatistics(unsigned char* mask, QString txt, bool drawHistogram, double* paramsTab, RawDataSet* data)
{

	stringstream ss;
	QString text0 = "---------------------------\n";
	//calciumScore

	int count130 = 0;
	int count200 = 0;
	int count300 = 0;
	int count400 = 0;
	double agatstonScore = 0;
	double calciumScore = 0;
	unsigned short* dd = data->GetDataArray();
	text0 += txt += "\n";
	if (mask != NULL)
	{
		double volume = 0;
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{
			if (mask[i] > 0)
			{
				volume++;

				double valX = dd[i] + data->dicomMinValue;
				//	double valx = dd[i] * data->dicomRescaleValue + data->dicomMinValue;
				if ((valX >= 130) && (valX < 200)) count130++;
				if ((valX >= 200) && (valX < 300)) count200++;
				if ((valX >= 300) && (valX < 400)) count300++;
				if ((valX >= 400)) count400++;

				if ((valX >= 130) && (valX < 400))
				{

					calciumScore += valX * 0.01;

				}
				else if (valX = 400)
				{
					calciumScore += 4.0;//nowa miara zwapnienia
				}
			}


		}


		if (count400 > 0)agatstonScore = 4;
		else if (count300 > 0)agatstonScore = 3;
		else if (count200 > 0)agatstonScore = 2;
		else if (count130 > 0)agatstonScore = 1;
		agatstonScore *= volume * data->GetXscale() * data->GetYscale();//** data->GetZscale()
		calciumScore *= data->GetXscale() * data->GetYscale() * data->GetZscale();
		double scale[3];
		data->GetScale(scale);
		int voxelCount = volume;
		volume *= scale[0] * scale[1] * scale[2];

		//qWarning() << " Total Volume: " << volume << " mm^3" << "  - " << volume*0.001 << " cm^3";

		ss << "Voxel Count: " << voxelCount << "\nTotal Volume: " << volume << "mm^3" << "  - " << volume * 0.001 << " cm^3\n";;

	}
	QString text = text0 + QString::fromStdString(ss.str());

	//	qWarning() << text;// " Total Volume: " << volume << " mm^3" << "  - " << volume*0.001 << " cm^3";
	SlotAddLogText(text);

	//wizualnych troche


	if (data != NULL)
	{
		double stats1[50] = { 0 };
		int* hist = GetStatisticsFromVolumeSampledTabUsingMask(data, mask, stats1);

		if (hist != NULL)
		{
			int bins = 8;
			int min = stats1[0];
			int max = stats1[1];
			bool useHistLogScale = true;
			QColor backCol = Qt::black;
			QColor col1 = Qt::green;







			if (max > 0)
			{
				int h[256] = { 0 };
				int range = max - min;
				if (range == 0)range = 1;

				double scale = 255.0 / range;
				for (int i = min; i < max; i++)
				{
					int val = (i - min) * scale;
					h[val] += hist[i];
				}
				if (drawHistogram == true)
				{
					QImage* img = GUIPanel->visImage->GetCurrentImage();
					//DrawHistogram(8, h, 0, 10, 255, 128, useHistLogScale, backCol, col1, img);
					DrawHistogram(8, h, 0, 0, 255, 255, false, Qt::black, Qt::cyan, img, false, false, false);
				}
				int minV = (data->dicomMinValue > -100000) ? data->dicomMinValue : 0;
				//korekta hounsfielda
				stats1[0] += minV;
				stats1[1] += minV;
				stats1[2] += minV;
				//3,4,5 - nie bo chyba relatywne?
				stats1[8] += minV;
				stats1[9] += minV;
				stats1[10] = agatstonScore;
				stats1[11] = calciumScore;








				QString text =
					"min: " + QString::number(stats1[0]) + "   " +
					"max: " + QString::number(stats1[1]) + "\n" +
					"avg: " + QString::number(stats1[2]) + "   " +
					"stddev: " + QString::number(stats1[3]) + "\n" +
					"skwewness: " + QString::number(stats1[4]) + "   " +
					"kurtosis: " + QString::number(stats1[5]) + "   " +
					"voxelCount: " + QString::number(stats1[6]) + "   " +
					"voxelVolume: " + QString::number(stats1[7]) + "   " +

					"median: " + QString::number(stats1[8]) + "   " +
					"maxPeak: " + QString::number(stats1[9]) + "   " +
					"AgatstonScore: " + QString::number(stats1[10]) + "   " +
					"CalciumScore: " + QString::number(stats1[11])
					;


				if (paramsTab != NULL)
				{
					for (int i = 0; i < 12; i++)
					{
						paramsTab[2 + i] = stats1[i];
					}
					/*paramsTab[2] = stats1[0];
					paramsTab[3] = stats1[1];
					paramsTab[4] = stats1[2];
					paramsTab[5] = stats1[3];
					paramsTab[6] = stats1[4];
					paramsTab[7] = stats1[5];
					paramsTab[8] = stats1[8];
					paramsTab[9] = stats1[9];
					paramsTab[10] = stats1[10];
					paramsTab[11] = stats1[11];*/
				}

				//MyShape shape;						shape.shapeText = QString(text);
				//shape.textPos.setX(5);				shape.textPos.setY(10);
				//shape.textColor.setRgb(255, 0, 0);	GUIPanel->visImage->GetShapes()->shapeList.append(shape);
				////qWarning() << text;
				SlotAddLogText(text);
				GUIPanel->visImage->repaint();

			}

			delete[]hist;
		}
	}

}
