void	MainWindow::SlotUpdateAirSpacesLineEdits(int pos)
{
	QObject* obj = sender();
	//if (sender == (QObject *)(GUIPanel->AirspacesOptionsButton[0]))
	if (pos == 0)
	{
		int minV = (data->dicomMinValue > -100000) ? data->dicomMinValue : 0;
		int val = -500 - minV;

		if (GUIPanel->AirspacesOptionsCheckBox[0]->isChecked() == false)
		{
			val = Histogram->GetUpperThreshold();
		}
		GUIPanel->AirspacesLineEdit[0]->setText(QString::number(val));
	}
	else
		if (pos == 1)
		{
			int minV = (data->dicomMinValue > -100000) ? data->dicomMinValue : 0;
			int val = -700 - minV;

			if (GUIPanel->AirspacesOptionsCheckBox[0]->isChecked() == false)
			{
				val = Histogram->GetLowerThreshold();
			}
			GUIPanel->AirspacesLineEdit[1]->setText(QString::number(val));

		}

}
