void	MainWindow::SlotCropAirSpaces()
{


	if (data != NULL)
	{

		RTimer.Start("Scanline Segmentation");


		unsigned char* newMask = new unsigned char[data->GetVolumeSize()];
		memset(newMask, 0, data->GetVolumeSize());


		bool directions[] = { true,true,false };



		int minV = (data->dicomMinValue > -100000) ? data->dicomMinValue : 0;


		int airLevel = -500;
		int boneLevel = 700;


		if (GUIPanel->AirspacesOptionsCheckBox[0]->isChecked() == true)//air  update?
		{
			airLevel = airLevel - minV;
		}
		else
		{
			airLevel = GUIPanel->AirspacesLineEdit[0]->text().toInt();
		}


		if (GUIPanel->AirspacesOptionsCheckBox[1]->isChecked() == true)//bones  update?
		{
			boneLevel = boneLevel - minV;
		}
		else
		{
			boneLevel = GUIPanel->AirspacesLineEdit[1]->text().toInt();
		}



		//-------- bone level air level do settings - z edits
		SlotUpdateCheckBoxes(0);


		//if ((minV < 0)|| (GUIPanel->AutoThresholdForAirspacesCheckBox->isChecked() == false))



		Segmentation* Segment = new Segmentation();
		int neighSize = 2;
		int neighType = 0;//0-cube 1-sphere
		double neighPercentage = 0.3;
		SegCriterion* cr;
		bool revth = false;
		/*int val = -500-minV;

		if (GUIPanel->AirspacesOptionsCheckBox[0]->isChecked() == false)
		{
			val = Histogram->GetUpperThreshold();
		}
		GUIPanel->AirspacesLineEdit[0]->setText(QString::number(val));
*/



		cr = new SegCriterionThresholds(data, airLevel, 65535, 65535, revth, neighPercentage, neighType, neighSize);
		Segment->SlotScanLineSegmentation(directions, data, newMask, cr);

		delete Segment;






		int count = 0;
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{
			if (newMask[i] > 0) count++;
		}

		SlotInsertNewMask(newMask);

		delete[]newMask;

		if (GUIPanel->AirspacesOptionsCheckBox[2]->isChecked() == true) //autocrop - i jeszcze raz ta sama segmentacja tylko na mniejszym
		{
			RawDataSet* nData = AutoCropWithMask();

			if (nData != NULL)
			{

				newMask = new unsigned char[nData->GetVolumeSize()];


				memset(newMask, 0, nData->GetVolumeSize());
				Segmentation* Segment = new Segmentation();
				cr = new SegCriterionThresholds(nData, airLevel, 65535, 65535, revth, neighPercentage, neighType, neighSize);
				Segment->SlotScanLineSegmentation(directions, nData, newMask, cr);

				delete Segment;
				int count = 0;
				for (int i = 0; i < nData->GetVolumeSize(); i++)
				{
					if (newMask[i] > 0) count++;
				}




				InsertRawDataSet(nData);

				SlotInsertNewMask(newMask);

				delete[]newMask;
			}

		}

		//threshold i odejmij na start
		newMask = new unsigned char[data->GetVolumeSize()];
		memset(newMask, 0, data->GetVolumeSize());
		unsigned short* tab = data->GetDataArray();

		//mindist from center
		int n[3];
		data->GetN(n);
		double center[3] = { n[0] / 2.0,n[1] / 2.0,n[2] / 2.0 };
		double minDist = INT_MAX;
		int minDistPos = 0;
		double dist = 0;;

		//for (int i = 0; i < data->GetVolumeSize(); i++)
		double actPos[3];
		int pos = 0;
		for (int k = 0; k < data->GetNz(); k++)
			for (int j = 0; j < data->GetNy(); j++)
				for (int i = 0; i < data->GetNx(); i++)
				{
					if ((tab[pos] < airLevel) && (MaskData[pos] > 0))
					{
						actPos[0] = i; actPos[1] = j; actPos[2] = k;
						dist = GetDistance(center, actPos);
						if (dist < minDist)
						{
							minDist = dist; minDistPos = pos;
						}
						newMask[pos] = 1;
					}

					pos++;
				}
		/*	int startPos = 0;///poszukam najblizszy srodka

			int n[3];
			data->GetN(n);

			int n2[3] = { (n[0] - 1) / 2.0, (n[1] - 1) / 2.0, (n[2] - 1) / 2 / 0 };

			int boundsMin[3], boundsMax[3];
			for (int i = 0; i < 3; i++)
			{
				boundsMin[i] = n2[i] - 1;
				boundsMax[i] = n2[i] + 1;
			}




			for(int k)
*/


		int counter = RegionGrowingOnMask(minDistPos, newMask, data, 1, 2, 3, data->GetVolumeSize() / 2, MaskData);


		//czyszcze nie dwojki
		for (int i = 0; i < data->GetVolumeSize(); i++)
		{
			if (newMask[i] == 2) newMask[i] = 1;
			else if (newMask[i] == 1) newMask[i] = 0;

		}

		SlotInsertNewMask(newMask);
		delete[]newMask;


		/*Segment->SlotScanLineSegmentation(GUIPanel->ScanXCheck->isChecked(),
				GUIPanel->ScanYCheck->isChecked(),
				GUIPanel->ScanZCheck->isChecked(),
				data, MaskData, Histogram->GetLowerThreshold(), GUIPanel->NeighSpinBox->value(), GUIPanel->PercentSpinBox->value(), GUIPanel->MaskAppendCheckBox->isChecked());*/



				//SlotInsertNewMask();

		RTimer.Stop();

	}
}

