void	MainWindow::SlotMiddleVolumeBetweenTwoMasks()
{

	//if ((VolumeStructuredPoints != NULL))
	{

		int size = 9;
		int kernelType = 0;
		unsigned char* blockMask = NULL;
		int dims[3];
		data->GetN(dims);




		int pos = 0;
		int count = 0;

		ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nr = masks->GetMaskList()->GetNumberOfItems();
		//unsigned  char *nMask = new unsigned char[data->GetVolumeSize()];

		//zamaluj te co trzeba
		int selCount = 0;
		for (int i = 0; i < nr; i++)
		{
			if (masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected()) selCount++;

		}

		//SlotClearVolMask(); //wyczysc jak cos jest zaznaczone w liscie zeby dodac



		if (selCount != 2)
		{
			SlotAddLogText("Select Exactly Two Masks!");
		}
		else
		{
			//1 daj obie maski do sobnych wolumenow
			//2 daj sumę do jednej
			//3 zrob closing o rozmiarze size - przypisz zamalowanym wartosc v1 -domknieciu
			//4 zrob dylacje o rozmiarze size na masce 1 i 2 - wartosc v2
			//5 wybierz do finalnej maski te woksele, ktore w sumie maja wartosc v1 (naleza do dokmniecia)
			// oraz w maskach 1 i 2 maja wawrtosc v2!
			unsigned  char* nMask = new unsigned char[data->GetVolumeSize()];
			unsigned  char* nMask1 = new unsigned char[data->GetVolumeSize()];
			unsigned  char* nMask2 = new unsigned char[data->GetVolumeSize()];
			//unsigned  char *nMaskTmp = new unsigned char[data->GetVolumeSize()];
			int pos = 0;
			int m1Pos, m2Pos = 0;
			for (int i = 0; i < nr; i++)
			{

				bool sel = masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected();
				if ((selCount == 0) || (sel == true))
				{
					unsigned char* mask = NULL;
					if (pos == 0)
					{
						mask = nMask1;
						m1Pos = i;
					}
					else
					{
						mask = nMask2;
						m2Pos = i;
					}
					masks->GetMaskDataAtPosAndSetAsCurrent(i, mask);
					pos++;
				}

			}
			int c0 = 0, c1 = 0, c2 = 0;
			for (int i = 0; i < data->GetVolumeSize(); i++)
			{
				nMask[i] = (bool)nMask1[i] | (bool)nMask2[i];

				c0 += nMask[i];
				c1 += nMask1[i];
				c2 += nMask2[i];
			}

			//zebralem maski 1 i 2



			//czas na dylacje i domykanie maskek

			int v1 = 10;
			int v2 = 20;



			int bounds[6];
			int is2d = false;
			GetBoundsWithMargin(data, nMask, size, is2d, bounds);


			//closing nMask

			//SlotInsertNewMask(nMask);

			SlotBinarySimpleMorphologyWithCriterion2(data, nMask, 1, size, kernelType, NULL, bounds, blockMask, NULL, is2d, 1, 1); //z criterion na danych
			SlotBinarySimpleMorphologyWithCriterion2(data, nMask, 0, size, kernelType, NULL, bounds, blockMask, NULL, is2d, 1, 1); //z criterion na danych
			c0 = 0;
			c1 = 0;
			//chce zostawic tylko to co wyszlo z closingu
			for (int i = 0; i < data->GetVolumeSize(); i++)
			{
				if ((nMask[i] == 1) && ((nMask1[i] == 1) || (nMask2[i] == 1)))
				{
					nMask[i] = 0;
					c1++;
				}
				if (nMask[i] == 1) c0++;
			}


			//SlotInsertNewMask(nMask1);
			// dilate n1
			SlotInsertNewMask(nMask1);
			//	SlotInsertNewMask(nMask2);
			SlotBinarySimpleMorphologyWithCriterion2(data, nMask1, 1, size, kernelType, NULL, bounds, blockMask, NULL, is2d, v2, 1); //z criterion na danych
			// dilate n2
		//	masks->GetMaskDataAtPosAndSetAsCurrent(m1Pos, nMaskTmp);

			SlotBinarySimpleMorphologyWithCriterion2(data, nMask2, 1, size, kernelType, NULL, bounds, blockMask, NULL, is2d, v2, 1); //z criterion na danych



			c0 = 0;
			c1 = 0;

			for (int i = 0; i < data->GetVolumeSize(); i++)
			{
				nMask1[i] = (nMask1[i] == v2) ? 1 : 0;

			}
			SlotInsertNewMask(nMask1);
			for (int i = 0; i < data->GetVolumeSize(); i++)
			{
				nMask2[i] = (nMask2[i] == v2) ? 1 : 0;
			}
			//SlotInsertNewMask(nMask2);
			SlotInsertNewMask(nMask);

			for (int i = 0; i < data->GetVolumeSize(); i++)
			{
				nMask[i] = ((nMask[i] == 1) && (nMask1[i] == 1) && (nMask2[i] == 1)) ? 1 : 0;
			}
			SlotInsertNewMask(nMask);
			//SlotInsertNewMask(nMask2);


			//for (int i = 0; i < data->GetVolumeSize(); i++)
			//{
			//	int a0 = nMask[i];
			//	int a1 = nMask1[i];
			//	int a2 = nMask2[i];


			//	//nMask[i] = ((a0 == 1) && (a1 == v2) && (a2 = v2)) ? 1 : 0;
			////	nMask[i] = (a0 == v1)? 1 : 0;

			//	if ((nMask[i] == 1))
			//	{
			//		if ((nMask1[i] == v2) || (nMask2[i] == v2))
			//		{
			//		
			//			nMask[i] == 0;
			//			c0++;
			//		}
			//		else
			//		{
			//			c1++;
			//		}
			//	}

			//}
		//	SlotInsertNewMask(nMask1);	
			//SlotInsertNewMask(nMask2);

			delete[]nMask;
			delete[]nMask1;
			delete[]nMask2;
			//	delete[]nMaskTmp;









		}
		//delete[]nMask;


		SlotUpdateDisableMixer(1);

	}




}


void	MainWindow::Slot_memorizeLowerLinePushButtonPressed()
{
	if (data != NULL)
	{
		QPolygonF poly;
		ImageShapes* shapes = this->TransversalView->GetShapes();
		if (shapes != NULL)
		{
			int nrShapes = shapes->shapeList.count();
			if (nrShapes > 0)
			{

				MyShape shape;

				QList<MyShape>* slist = &shapes->shapeList;
				//	QImage img(data->GetNx(), data->GetNy(), QImage::Format_RGB32);
				bool test = false;

				for (int i = 0; i < nrShapes; i++)
				{
					shape = slist->at(i);

					if (shape.poly.count() > 0)
					{

						if (shape.name.compare("lowerLine") == 0)
						{
							int nrPts = shape.poly.count();

							if (nrPts > 0)
							{
								poly = shape.poly;
								test = true;
							}

							break;

						}
					}

				}

				//dodaje kreche
				if (test == true)
				{
					ThicknessLineItem* item = new ThicknessLineItem();
					item->name = GUIPanel->lineNameLineEdit->text() + "_l";
					item->poly = poly;
					item->treeItem = new QTreeWidgetItem();
					item->treeItem->setText(0, item->name);
					thicknessLineList->InsertItem(item);
					GUIPanel->thicknesLinesTreeWidget->addTopLevelItem(item->treeItem);
					UpdateLineNameLineEdit();
				}


			}

		}
	}
}
