void	MainWindow::SlotLoadSeeds(const QString filename)
{

	if (!filename.isEmpty())
	{

		SlotUpdateDefaultDir(filename, 0);
		int n[3];
		int bits;
		double s[3];
		int depth = 16;
		bool ok;

		//sprawze czy ten raw ma dodatkowo plik dat o odpowiednim formacie

		//QString tt;
		//tt = filename;
		//if (tt.mid(tt.length() - 4, 4) == ".seeds")
		//	tt.remove(tt.length() - 4, 4);


		//tt += ".seeds";
		QFile file(filename);

		bool test = false;
		unsigned char xx[3] = { 0 };
		int count;
		double p[3];
		if (file.open(QIODevice::ReadOnly))
		{
			QTextStream stream(&file);

			QString line;//=stream.readLine();
			QStringList fields;// = line.split( " ");

			seeds.clear();

			do
			{
				line = stream.readLine();
				fields = line.split(QRegExp(" |\t|:"), QString::SkipEmptyParts);
				count = fields.count();
				if (count == 3)
				{
					p[0] = fields[0].toDouble();
					p[1] = fields[1].toDouble();
					p[2] = fields[2].toDouble();
					seeds.append(QVector3D(p[0], p[1], p[2]));
					SlotAddLogText("Added: " + QString::number(seeds.count()) + "  point(" + QString::number(p[0]) + "," + QString::number(p[1]) + "," + QString::number(p[2]) + ")");


					double* seedP = p;
					//SlotSetCurrentPointAndText(seedP,"");
					arteryData->SetSeedPoint(p);
					this->SlotSetSeedPoint(seedP);
					emit SendMessage("SeedPoint: (" + QString::number(seedP[0]) + " " + QString::number(seedP[1]) + " " + QString::number(seedP[2]) + ")");
					GUIPanel->seedLabel[0]->setText(QString::number(seedP[0]));
					GUIPanel->seedLabel[1]->setText(QString::number(seedP[1]));
					GUIPanel->seedLabel[2]->setText(QString::number(seedP[2]));


				}
			} while (!stream.atEnd());



			file.close();
		}

	}

}
//--------------
void	MainWindow::SaveSeeds(QString filename)
{
	if (!filename.isEmpty())
	{
		//SlotWriteUpdatedProps();
		if (seeds.count() > 0)
		{


			QFile file(filename);

			bool test = false;
			unsigned char xx[3] = { 0 };
			int count;
			double p[3];
			if (file.open(QIODevice::WriteOnly))
			{
				QTextStream stream(&file);
				for (int i = 0; i < seeds.count(); i++)
				{
					stream << seeds.at(i).x() << "\t";
					stream << seeds.at(i).y() << "\t";
					stream << seeds.at(i).z() << "\n";

				}

			}
			file.close();
		}
		else
		{
			SlotAddLogText("No seedds to save!");
		}
	}
}
