void	MainWindow::SlotAddIgnorePoint()
{
	int nr = SurfaceDataList->GetNumberOfItems();

	if (nr > 0)
	{
		int j;
		ListItem<PolygonSurfaceData*>* tmpItem;

		int start = 0;
		if (surfaceActivatedFromMenuIndex != -1) { nr = surfaceActivatedFromMenuIndex + 1; start = surfaceActivatedFromMenuIndex; };

		for (j = start; j < nr; j++)
		{
			tmpItem = SurfaceDataList->GetItemAtPos(j);

			if ((tmpItem->GetData()->GetTreeItem()->isSelected() == true) || (j == surfaceActivatedFromMenuIndex))
			{
				//biore jego center
				double* p = tmpItem->GetData()->GetVActor()->GetOrigin();

				double tol = ignoreTolerance;
				bool alreadyExist = false;
				for (int j = 0; j < ignorePoints.count(); j++)
				{
					double p1[3];

					p1[0] = ignorePoints.at(j).x(); p1[1] = ignorePoints.at(j).y(); p1[2] = ignorePoints.at(j).z();
					double dist = GetDistance(p, p1);
					if (dist < tol)
					{
						alreadyExist = true; break;
					}
				}

				if (alreadyExist == false)
				{
					ignorePoints.append(QVector3D(p[0], p[1], p[2]));
					SlotAddLogText("Added to ignorePoints: " + QString::number(ignorePoints.count()) + "  point(" + QString::number(p[0]) + "," + QString::number(p[1]) + "," + QString::number(p[2]) + ") " + tmpItem->GetData()->GetPolygonSurfaceName());

				}
				else
				{
					SlotAddLogText("Point Already Added");
				}

			}
		}
	}


}
//--------------
void	MainWindow::SlotRemoveIgnorePoint()
{

	int nr = SurfaceDataList->GetNumberOfItems();



	if (nr > 0)
	{
		int j;
		ListItem<PolygonSurfaceData*>* tmpItem;

		int start = 0;
		if (surfaceActivatedFromMenuIndex != -1) { nr = surfaceActivatedFromMenuIndex + 1; start = surfaceActivatedFromMenuIndex; };

		for (j = start; j < nr; j++)
		{
			tmpItem = SurfaceDataList->GetItemAtPos(j);

			if ((tmpItem->GetData()->GetTreeItem()->isSelected() == true) || (j == surfaceActivatedFromMenuIndex))
			{
				//biore jego center
				double* p = tmpItem->GetData()->GetOrigin();

				double tol = ignoreTolerance;
				bool alreadyExist = false;
				int j;
				for (j = 0; j < ignorePoints.count(); j++)
				{
					double p1[3];

					p1[0] = ignorePoints.at(j).x(); p1[1] = ignorePoints.at(j).y(); p1[2] = ignorePoints.at(j).z();
					double dist = GetDistance(p, p1);
					if (dist < tol)
					{
						alreadyExist = true; break;
					}
				}

				if (alreadyExist == true)
				{

					ignorePoints.removeAt(j);
					SlotAddLogText("Removed from ignorePoints: " + QString::number(ignorePoints.count()) + "  point(" + QString::number(p[0]) + "," + QString::number(p[1]) + "," + QString::number(p[2]) + ")");

				}

			}
		}
	}
}
