void	MainWindow::SlotGrabDepthMapToClipboard()
{
	vtkSmartPointer<vtkWindowToImageFilter> filter = vtkSmartPointer<vtkWindowToImageFilter>::New();

	vtkSmartPointer<vtkImageShiftScale> scale = vtkSmartPointer<vtkImageShiftScale>::New();

	vtkSmartPointer<vtkBMPWriter> imageWriter = vtkSmartPointer<vtkBMPWriter>::New();
	// Create Depth Map
	filter->SetInput(VWidget->GetRenderWindow());

	filter->SetInputBufferTypeToZBuffer();        //Extract z buffer value

	scale->SetOutputScalarTypeToUnsignedChar();
	scale->SetInputConnection(filter->GetOutputPort());
	scale->SetShift(0);
	scale->SetScale(-255);
	QString filename = QFileDialog::getSaveFileName(this, "", FileDefaultDir + "/" + CurrentSurfaceDataSetListItem->GetData()->GetPolygonSurfaceName(), "*.bmp");
	if ((!filename.isEmpty()))
	{
		// Write depth map as a .bmp image
		imageWriter->SetFileName(filename.toLocal8Bit());
		imageWriter->SetInputConnection(scale->GetOutputPort());
		imageWriter->Write();
	}



}
