void MainWindow::UpdateSegmentationToUseCropPlanes(unsigned char* maskData, RawDataSet* data)
{
	///czyszcze wszystko poza bounds
	if (Volume->GetMapper() != NULL)
		if (data != NULL)
		{

			vtkPlane* pl;
			vtkPlaneCollection* pcol = VolumeMapper->GetClippingPlanes();
			vtkPlanes* planes = vtkPlanes::New();

			double s[3];
			int nn[3];
			nn[0] = data->GetNx();
			nn[1] = data->GetNy();
			nn[2] = data->GetNz();
			s[0] = data->GetXscale();
			s[1] = data->GetYscale();
			s[2] = data->GetZscale();
			int i, j, k;
			double o[3];
			double n[3];
			double bounds[6];
			int dataN[3];
			data->GetN(dataN);
			for (i = 0; i < 6; i++)
			{
				pl = static_cast<vtkPlane*>(pcol->GetItemAsObject(i));
				pl->GetNormal(n);
				pl->GetOrigin(o);
				o[0] /= s[0];	o[1] /= s[1];	o[2] /= s[2];
				bounds[i] = o[0] + o[1] + o[2];
			}

			planes->SetBounds(bounds);


			vtkClipVolume* clip = vtkClipVolume::New();
			clip->SetInputData(VolumeStructuredPoints);
			clip->SetClipFunction(planes);


			double origX[3];
			data->GetOrigin(origX);
			double origSc[3];
			data->GetScale(origSc);
			for (i = 0; i < 3; i++)
			{
				origX[i] /= origSc[i];
			}


			for (i = 0; i < 6; i++)
			{
				bounds[i] -= origX[i / 2];
			}

			int N[3];
			int ibounds[6];
			for (i = 0; i < 6; i++)
				ibounds[i] = (int)bounds[i];
			N[0] = ibounds[1] - ibounds[0];
			N[1] = ibounds[3] - ibounds[2];
			N[2] = ibounds[5] - ibounds[4];

			RawDataSet* nData = new RawDataSet(N[0], N[1], N[2], s[0], s[1], s[2]);

			unsigned short* td = nData->GetDataArray();
			int pos = 0;

			int sliceSize = data->GetSliceSize();

			//czyszcze gore
			for (k = 0; k < ibounds[4]; k++)
			{
				memset(maskData + k * sliceSize, 0, sliceSize);
			}



			//srodek po z
			for (k = ibounds[4]; k < ibounds[5] + 1; k++)
			{

				pos = k * sliceSize;
				if (ibounds[2] > 0)				memset(maskData + pos, 0, ibounds[2] * dataN[0]);

				pos += ibounds[2] * dataN[0];
				//for(j= ibounds[2];j<ibounds[3]+1;j++)
				for (j = ibounds[2]; j < ibounds[3] + 1; j++)
				{
					if (ibounds[0] > 0)	memset(maskData + pos, 0, ibounds[0]);
					//	pos += ibounds[1];
					if (ibounds[1] < dataN[0]) memset(maskData + pos + ibounds[1] + 1, 0, dataN[0] - 1 - ibounds[1]);
					pos += dataN[0];// -1 - ibounds[1];
				}

				/*{
					pos += ibounds[0];
					for (i = bounds[0]; i < ibounds[1] + 1; i++)
					{
						maskData[pos++] = 0;
					}
					pos+= dataN[0] - 1 - ibounds[1];

				}*/



				if (ibounds[3] < dataN[1]) memset(maskData + pos, 0, (dataN[1] - 1 - ibounds[3]) * dataN[0]);



			}

			//czyszcze dol
			for (k = ibounds[5] + 1; k < dataN[2]; k++)
			{
				memset(maskData + k * sliceSize, 0, sliceSize);
			}




		}





}


