void	MainWindow::SlotGenerateRandomPointsAndPrepareJob2()
{
	//wez aktualną maskę z zaznaczonych - zbierz wszystkie do tablicy
	// wylosuj 50
	// zapisz plik w formie
	// arterydata name
	// number of pts
	// x,y,z list
	int numberOfSamples = GUIPanel->nrOfRandbomSamplesSpinBox->value();

	if (arteryDataName.contains(".arteryData", Qt::CaseInsensitive))
	{

		ByteMaskCollection* masks = MainListItem->GetData()->GetByteMaskInternal();
		int nrOfMasks = masks->GetNumberOfMasks();
		QVector<int> seedsRandom;
		QVector<int> allPossiblePts;
		for (int i = 0; i < nrOfMasks; i++)
		{
			bool sel = masks->GetMaskDataAtPos(i)->GetTreeItem()->isSelected();
			if ((sel == true))
			{
				// tu dodaje wszystkie maski co trzeba  uzupelniam volumeTempData i bedize do startu!!!!!
				unsigned char* nmask = NULL;
				nmask = new unsigned char[data->GetVolumeSize()];
				memset(nmask, 0, data->GetVolumeSize());
				masks->GetMaskDataAtPosAndSetAsCurrent(i, nmask);//pobrana maska mozna zbierac i oznaczac

				int nn[3];
				data->GetN(nn);
				int pos = 0;
				double center[3] = { 0 };
				int vCount = 0;
				for (int i = 0; i < data->GetVolumeSize(); i++)
				{
					if (nmask[i] > 0)
					{
						allPossiblePts.append(i);
					}
				}
				delete[]nmask;

			}
		}

		//zebralem seedspotencjalne

		if (allPossiblePts.count() >= numberOfSamples)
		{
			int nrOfPossiblePts = allPossiblePts.count();
			//wylosuj 50
			//
			qsrand(QDateTime::currentMSecsSinceEpoch() / 1000);
			for (int i = 0; i < numberOfSamples; i++)
			{
				int pos = (qrand() / (double)RAND_MAX) * nrOfPossiblePts;
				seedsRandom.append(allPossiblePts.at(pos));
			}



			//zebralem 50 do tablicy teraz moge sprobowac zrobic plik job2

			QString ext = ".job2";
			QString filename = QFileDialog::getSaveFileName(this, "", FileDefaultDir, "*" + ext);
			{
				SlotUpdateDefaultDir(filename);
				//zapisz do pliku nazwy!
				QFile file(filename);
				if (file.open(QIODevice::WriteOnly))


					//FILE *plik=fopen(ProgramDefaultDirPath.toLocal8Bit(),"wt");
					//if (plik==NULL) return;

				{
					QTextStream stream(&file);
					stream << arteryDataName << "\n";
					stream << seedsRandom.count() << "\n";

					for (int i = 0; i < seedsRandom.count(); i++)
					{
						int pos = seedsRandom.at(i);
						int pos3[3];
						data->GetVoxelXYZPos(pos, pos3);
						stream << pos3[0] << "," << pos3[1] << "," << pos3[2] << "\n";

					}
					file.close();
				}
			}

		}
		else
		{
			emit SendMessage("Mask is to small, available " + QString::number(allPossiblePts.count()) + " points and should be at least " + QString::number(numberOfSamples));
		}
	}
	else
	{
		emit SendMessage("Load .arterydata file first!");
	}

}
