void MainWindow::SlotFindTheBestCandidateForModelButton()
{
	QString fn = GUIPanel->job3FilePathSetLineEdit->text();

	QFile file(fn);
	if (file.open(QIODevice::ReadOnly))
	{


		int line_count = 0;


		QTextStream stream(&file);

		QString line;

		int pos = 0;
		int largestGlobalBlock = -1;
		int largestPos = -1;
		int* maxTab = NULL;
		//int largestBlockSize=0;
		bool stab = GUIPanel->genStabCheckBox->isChecked();

		do
		{
			line = stream.readLine();
			QString filename = line;

			bool skipData = SkipData(pos);
			int largestBlock = -1;
			if (skipData == false)
			{
				int largestBlock = 0;
				//GetLargestBlock(filename, pos, largestBlock);
				if (pos == 19)
				{
					pos;
				}
				maxTab = GetLargestBlock(filename, pos, largestBlock, true, stab);

				if (largestBlock > largestGlobalBlock)
				{
					largestGlobalBlock = largestBlock;
					largestPos = pos;
					if (maxTab != NULL)
					{
						int minZ = 0;
						int maxZ = 0;


						int first, last;

						first = 0;// maxTab[1];
						for (int i = 0; i < maxTab[0]; i++)
						{

							last = maxTab[1 + i];
							if (last - first == largestBlock + 1)
							{
								minZ = first;
								maxZ = last - 1;
								break;
							}

							first = last;
						}

						GUIPanel->minSliceModelLineEdit->setText(QString::number(minZ));
						GUIPanel->maxSliceModelLineEdit->setText(QString::number(maxZ));

						delete[]maxTab;
					}
				}
				SlotAddLogText2("Current Pos: " + QString::number(pos) + " LargestBlock: " + QString::number(largestBlock));
			}
			else
			{
				SlotAddLogText2("Current Pos: " + QString::number(pos) + " skipped");
			}
			pos++;





		} while (!stream.atEnd());

		SlotAddLogText2("---------------------------");
		SlotAddLogText2("Laegest Pos: " + QString::number(largestPos) + " LargestBlock: " + QString::number(largestGlobalBlock));
		GUIPanel->job3RegModelDataNumberLineEdit->setText(QString::number(largestPos));

		GUIPanel->job3RegModelDataNumberLineEdit->setText(QString::number(largestPos));


		file.close();
	}

}
