bool MainWindow::SkipData(int pos)
{
	bool skip = false;
	bool invMode = GUIPanel->inverseIndexListCheckBox->isChecked();

	QString indexList = GUIPanel->job3IndexListLineEdit->text();

	if (!indexList.isEmpty())
	{
		if (invMode == false)
		{
			bool currentFound = false;
			QStringList fields = indexList.split(",", QString::SkipEmptyParts);
			for (int l = 0; l < fields.count(); l++)
			{
				int nrr = fields.at(l).toInt();
				if (nrr == pos)
				{
					currentFound = true;
					break;
				}

			}
			if (currentFound == false) skip = true;//wtedy nie przetwarzam
		}
		else
		{
			skip = false;
			bool currentFound = false;
			QStringList fields = indexList.split(",", QString::SkipEmptyParts);
			for (int l = 0; l < fields.count(); l++)
			{
				int nrr = fields.at(l).toInt();
				if (nrr == pos)
				{
					currentFound = true;
					break;
				}

			}
			if (currentFound == true) skip = true;//wtedy nie przetwarzam
		}
	}
	return skip;
}

void MainWindow::processJob(QString fn, QString jobType)
{
	if (!fn.isEmpty())
	{
		SlotUpdateDefaultDir(fn);
		//zasada działania

			//sprawdzam czy isteniej plik o tej nazwie. job_inprogress
			//jesli tak - biore numer i startuje z parametrem tym program - argument

			//ApplyJobElement( fn);



		QFile file(fn);
		if (file.open(QIODevice::ReadOnly))
		{
			QFile file2(fn);
			int line_count = 0;
			file2.open(QIODevice::ReadOnly); //| QIODevice::Text)

			QTextStream in(&file2);
			while (!in.atEnd())
			{
				in.readLine();
				line_count++;
			}
			line_count--;
			file2.close();


			RTimer.Start("Processing Job");




			QTextStream stream(&file);
			QString line;//=stream.readLine();
			QString filePath = "";
			int pos = -1;
			{

				QSettings settings(fn + "_inprogress", QSettings::IniFormat);
				settings.beginGroup("JobProgress");// names[i]);
				int posInFile = -1;



				if (settings.contains("currentPos"))
				{
					pos = settings.value("currentPos").toInt();

					//QTextStream stream(&file);
					QString line;

					do
					{
						line = stream.readLine();
						posInFile++;
						if (posInFile == pos)
						{
							//moge odpalic ta czesc joba
							filePath = line;
							break;

						}

					} while (!stream.atEnd());


				}
				else
				{
					pos = 0;
					settings.setValue("currentPos", pos);

					filePath = stream.readLine();


				}
				settings.endGroup();
			}

			if ((pos > 0) && (pos <= line_count))
			{
				/*QMessageBox msgBox;

				msgBox.setStandardButtons(QMessageBox::Yes | QMessageBox::No);
				msgBox.setDefaultButton(QMessageBox::No);
				int ret = msgBox.exec();*/


				QMessageBox msgBox;
				QPushButton* bitButton[2];
				bitButton[0] = msgBox.addButton(tr("Continue"), QMessageBox::ActionRole);;
				bitButton[1] = msgBox.addButton(tr("Restart"), QMessageBox::ActionRole);;

				msgBox.setText("Process started previously ");
				msgBox.setInformativeText("Continue from data: " + QString::number(pos) + " or restart?");
				msgBox.exec();



				if (msgBox.clickedButton() == bitButton[1])
				{
					stream.seek(0);
					pos = 0;
					//settings.setValue("currentPos", pos);

					filePath = stream.readLine();

				}




			}
			if (pos > line_count)
			{
				//message


				QMessageBox msgBox;
				msgBox.setText("Already processed ");
				msgBox.setInformativeText("Delete progress and Process again? ");
				msgBox.setStandardButtons(QMessageBox::Yes | QMessageBox::No);
				msgBox.setDefaultButton(QMessageBox::No);
				int ret = msgBox.exec();

				if (ret == QMessageBox::Yes)
				{


					stream.seek(0);
					pos = 0;
					//settings.setValue("currentPos", pos);

					filePath = stream.readLine();

				}
			}

			bool start = true;
			if (!filePath.isEmpty())
			{
				do
				{
					if (start == true)
					{
						start = false;
					}
					else
					{
						filePath = stream.readLine();
					}

					if (!filePath.isEmpty())
					{


						QStringList nameList;

						nameList << jobType;

						QString joinedName = filePath;
						joinedName += ";";
						joinedName += QString::number(pos);

						nameList << joinedName;
						//nameList << QString::number(pos);


						SlotAddLogText("Processing Job: (" + QString::number(pos) + "/" + QString::number(line_count) + ") ");


						//sprawdzam czy przetwarzac czy skip



						//bool skip = false;
						bool skip = SkipData(pos);

						if (skip == false)
						{
							if (!GUIPanel->job3SegmentatorModeCheckBox->isChecked())
							{

								if (GUIPanel->job3TestModeCheckBox->isChecked())
								{
									ApplyJob3Element(joinedName);
									return;
								}

								QCoreApplication::processEvents();
								QProcess process;
								process.start(qApp->arguments()[0], nameList);
								process.waitForFinished(-1);
								process.close();

								QSettings settings(fn + "_inprogress", QSettings::IniFormat);
								settings.beginGroup("JobProgress");
								pos++;
								settings.setValue("currentPos", pos);
								settings.endGroup();
								SlotAddLogText("done");
							}
							else
							{
								//segmentator mode
								// tutaj odpalam apke Kuby do generowania maski
								//
								QStringList nameList2;
								QString paramText = "--rdata_path=\"" + filePath;
								paramText += "\"";
								nameList2 << paramText;
								int i = 1;
								QString Ntemp;

								int pos2 = dopplerSegmentatorPath.lastIndexOf("/");
								if (pos2 >= 0)
								{
									Ntemp = dopplerSegmentatorPath;
									Ntemp.remove(pos2, Ntemp.length());
								}

								if (!dopplerSegmentatorModelPath.isEmpty())
								{
									QString modelAdd = " --model_config=\"" + dopplerSegmentatorModelPath;
									modelAdd += "\"";
									paramText += modelAdd;
								}

								QCoreApplication::processEvents();
								QProcess process;
								process.setCreateProcessArgumentsModifier(
									[](QProcess::CreateProcessArguments* args) {
										args->flags |= CREATE_NEW_CONSOLE;
										args->startupInfo->dwFlags &= ~STARTF_USESTDHANDLES;
									});
								process.setWorkingDirectory(Ntemp);
								process.setNativeArguments(paramText);
								process.start(dopplerSegmentatorPath);
								process.waitForFinished(-1);
								process.close();

								if (GUIPanel->job3TestModeCheckBox->isChecked())
								{
									SlotLoadUniversalData(filePath);
									return;
								}

								QSettings settings(fn + "_inprogress", QSettings::IniFormat);
								settings.beginGroup("JobProgress");
								pos++;
								settings.setValue("currentPos", pos);
								settings.endGroup();
								SlotAddLogText("done");
							}

						}
						else
						{
							SlotAddLogText("skipped");
							pos++;
						}

					}

				} while (!stream.atEnd());
				SlotAddLogText2("Everything Processed");
			}
			file.close();
		}
		RTimer.Stop();

	}
}
