void	MainWindow::SlotGenerateMaskUsingNeuralSegmentator()
{

	if (data != NULL)
	{
		RTimer.Start("Nerual Network Segmentation");




		QString dataPath = data->GetRawDataSetPath();

		QStringList nameList2;
		QString paramText = "--rdata_path=\"" + dataPath;
		paramText += "\"";
		nameList2 << paramText;
		int i = 1;
		QString Ntemp;

		int pos2 = dopplerSegmentatorPath.lastIndexOf("/");
		if (pos2 >= 0)
		{
			Ntemp = dopplerSegmentatorPath;
			Ntemp.remove(pos2, Ntemp.length());
		}

		if (!dopplerSegmentatorModelPath.isEmpty())
		{
			QString modelAdd = " --model_config=\"" + dopplerSegmentatorModelPath;
			modelAdd += "\"";
			paramText += modelAdd;
		}

		QCoreApplication::processEvents();
		QProcess process;
		process.setCreateProcessArgumentsModifier(
			[](QProcess::CreateProcessArguments* args) {
				args->flags |= CREATE_NEW_CONSOLE;
				args->startupInfo->dwFlags &= ~STARTF_USESTDHANDLES;
			});
		process.setWorkingDirectory(Ntemp);
		process.setNativeArguments(paramText);
		process.start(dopplerSegmentatorPath);
		process.waitForFinished(-1);
		process.close();

		//sprobuje wczytac
		QString tt;
		tt = dataPath;
		if (tt.mid(tt.length() - 6, 6) == ".rdata")
			tt.remove(tt.length() - 6, 6);
		tt += ".mask";
		SlotLoadRawDataMaskAsUCharArray(tt);
		RTimer.Stop();

		if (this->isVolumeVisible == true)
		{
			VWidget->Interactor->repaint();
		}
	}


}

