void	MainWindow::SlotStartJob()
{
	QString fn = QFileDialog::getOpenFileName(this, "", FileDefaultDir, "Job files (*.job *.job2)");
	if (!fn.isEmpty())
	{
		if (fn.endsWith("job", Qt::CaseInsensitive))
		{
			SlotStartJob(fn);
		}
		else if (fn.endsWith("job2", Qt::CaseInsensitive))
		{
			SlotStartJob2(fn);
		}
	}
}
