void	MainWindow::SlotGenerateDistanceChart()
{


	int nrr = SurfaceDataList->GetNumberOfItems();
	if ((nrr > 1))
	{
		bool found = false;
		int i, j;
		int nrLines = 0;
		int* tab = new int[nrr];//indexy tych do ktorych mam liczyc miary 
		for (j = 0; j < SurfaceDataList->GetNumberOfItems(); j++)
		{
			if (SurfaceDataList->GetItemAtPos(j)->GetData()->GetTreeItem()->isSelected() == true)
			{
				tab[nrLines++] = j;
				found = true;
			}

		}

		if (nrLines > 1)
		{
			double* distance1Tab = new double[nrLines * nrLines];
			//double* distance2Tab = new double[nrLines * nrLines];
			memset(distance1Tab, 0, nrLines * nrLines * sizeof(double));
			//	memset(distance2Tab, 0, nrLines * nrLines * sizeof(double));

			vtkHausdorffDistancePointSetFilter* hDistanceFilter = vtkHausdorffDistancePointSetFilter::New();
			hDistanceFilter->SetTargetDistanceMethodToPointToPoint();
			//tu bym chcial policzyc wszystkie mozliwe odleglosci!!!
			int pos = 0;
			for (int i = 0; i < nrLines; i++)
			{
				vtkPolyData* tmpDataI = SurfaceDataList->GetItemAtPos(tab[i])->GetData()->GetVPolyData();
				hDistanceFilter->SetInputData(0, tmpDataI);
				for (int j = 0; j < nrLines; j++)
				{
					vtkPolyData* tmpDataJ = SurfaceDataList->GetItemAtPos(tab[j])->GetData()->GetVPolyData();
					hDistanceFilter->SetInputData(1, tmpDataJ);
					hDistanceFilter->Update();
					double dist1 = hDistanceFilter->GetHausdorffDistance();
					distance1Tab[pos++] = dist1;

					//double dist2 = hDistanceFilter->GetRelativeDistance();
				}

			}


			double stats1[12] = { 0 };
			double* hist = GetStatisticsFromDoubleTab(distance1Tab, nrLines * nrLines, 256, stats1);


			QString text =
				"min: " + QString::number(stats1[0]) + "   " +
				"max: " + QString::number(stats1[1]) + "\n" +
				"avg: " + QString::number(stats1[2]) + "   " +
				"stddev: " + QString::number(stats1[3]) + "\n" +
				"skwewness: " + QString::number(stats1[4]) + "   " +
				"kurtosis: " + QString::number(stats1[5]);


			SlotAddLogText(text);

			delete[]distance1Tab;
			//delete[]distance2Tab;
		}

		delete[]tab;
	}
}
