//------------------------------
void MainWindow::SlotApplyNewDevScale()
{
	if (data != NULL)
	{
		double minScMul = 0.01;
		double maxScMul = 100;
		double sc[3];
		data->GetScale(sc);
		double devScale[3];
		bool test = true;
		for (int i = 0; i < 3; i++)
		{
			devScale[i] = GUIPanel->scaleDevLineEdit[i]->text().toDouble();
			if (devScale[i] < minScMul * sc[i]) test = false;
			if (devScale[i] > maxScMul * sc[i]) test = false;
		}


		if (test == true)
		{


			data->SetScale(devScale);

			UpdateViews();
			if (isVolumeVisible == true)
			{
				VolumeStructuredPoints->SetSpacing(devScale);
				VolumeStructuredPoints->Modified();
				//VolumeMapper->SetInputData(VolumeStructuredPoints);


				VolumeMapper->Modified();
				Volume->Update();
				SlotApplyVolOpacitySettings();
				SlotChangeClippingPlanes(0);
				VWidget->Interactor->update();
			}

		}
		else
		{
			emit SendMessage("BadScale");
		}
	}

}
